/* "How to describe it" deck — model MRI findings dictations.
   Each card: front = the entity to describe; back = the report-style answer.
   Schema:
     {
       id:    "d###",                 // unique, d-prefixed
       front: "How would you describe a complete ACL tear?",
       find:  "...the Findings sentence (orange F: line)...",
       impr:  "...the one-line Impression (green I: line)...",   // optional
       pearl: "...a teaching note / secondary signs / pitfall...",// optional
       topic: "Cruciate ligaments",
       joint: "knee"                  // shoulder|knee|hip|ankle|foot|elbow|wrist|hand|general
     }
   Use literal [a/b/c] brackets for interchangeable options — they render as
   amber placeholder chips. See AUTHORING-CARDS.md to add your own.
   This file APPENDS to the terminology deck loaded by flashcards.js. */
window.FLASHCARDS = (window.FLASHCARDS || []).concat([
{"id":"d1","front":"How would you describe supraspinatus tendinosis without a tear?","find":"Intermediate increased signal within the supraspinatus tendon on fluid-sensitive sequences without the fluid-bright T2 signal of a tear. The tendon is mildly thickened with intact fiber continuity from myotendinous junction to the greater tuberosity footprint. No focal fiber gap or surface defect.","impr":"Supraspinatus tendinosis.","pearl":"Tendinosis shows intermediate signal that does NOT match fluid; a tear shows fluid-bright T2/STIR signal. Magic-angle artifact at 55 degrees on short-TE sequences is a mimic and resolves on long-TE T2.","topic":"Rotator cuff","joint":"shoulder"},
{"id":"d2","front":"How would you describe a low-grade partial articular-sided supraspinatus tear (PASTA)?","find":"Focal fluid-signal defect along the articular surface of the distal supraspinatus at the footprint, measuring < 3 mm in depth (< 25% of the [6-7 mm] tendon thickness), without extension to the bursal surface. The bursal-sided fibers and overlying subacromial-subdeltoid bursa are intact.","impr":"Low-grade (< 25%) partial articular-sided supraspinatus tear (PASTA).","pearl":"Grade by depth relative to tendon thickness: < 25% low-grade, 25-50% intermediate, > 50% high-grade. ABER positioning and MR arthrography improve detection of articular-sided tears.","topic":"Rotator cuff","joint":"shoulder"},
{"id":"d3","front":"How would you describe a high-grade partial articular-sided supraspinatus tear?","find":"Fluid-signal cleft along the articular surface of the distal supraspinatus measuring [4-5] mm in depth, involving > 50% of the tendon thickness, with intrasubstance delamination but intact bursal-sided fibers. No full-thickness defect or fiber retraction.","impr":"High-grade (> 50%) partial articular-sided supraspinatus tear.","pearl":"On MR arthrography, articular-sided partial tears fill with intra-articular contrast; high-grade tears (> 50%) are often treated like full-thickness tears surgically.","topic":"Rotator cuff","joint":"shoulder"},
{"id":"d4","front":"How would you describe a bursal-sided partial-thickness supraspinatus tear?","find":"Focal fluid-signal defect along the bursal surface of the distal supraspinatus with associated subacromial-subdeltoid bursal fluid, without extension to the articular surface. The articular-sided fibers remain intact. Mild undersurface acromial spurring is noted.","impr":"Bursal-sided partial-thickness supraspinatus tear.","pearl":"Bursal-sided tears do NOT fill with contrast on MR arthrography (contrast is intra-articular), so fluid-sensitive non-arthrographic sequences are key. Often associated with subacromial impingement.","topic":"Rotator cuff","joint":"shoulder"},
{"id":"d5","front":"How would you describe an intrasubstance (interstitial) supraspinatus tear?","find":"Linear fluid-signal cleft within the substance of the distal supraspinatus tendon, oriented along the tendon fibers, without extension to either the articular or bursal surface. No surface defect and no communication with the joint or bursa.","impr":"Intrasubstance (interstitial) partial-thickness supraspinatus tear.","pearl":"Intrasubstance tears do not fill on MR arthrography from either surface because they communicate with neither the joint nor bursa; best seen as fluid-bright clefts on fat-suppressed T2.","topic":"Rotator cuff","joint":"shoulder"},
{"id":"d6","front":"How would you describe a full-thickness supraspinatus tear with retraction?","find":"Full-thickness defect of the distal supraspinatus extending from the articular to the bursal surface, with an anteroposterior width of [N] mm at the footprint and fluid-bright T2 signal filling the gap. The tendon stump is retracted to the level of the [humeral head apex/glenoid (Patte 2)], and there is fluid communication between the glenohumeral joint and the subacromial-subdeltoid bursa.","impr":"Full-thickness supraspinatus tear with [Patte grade 2] retraction.","pearl":"Patte retraction: stage 1 = stump near footprint, stage 2 = at humeral head level, stage 3 = retracted to the glenoid. Always report AP tear width and retraction together to guide reparability.","topic":"Rotator cuff","joint":"shoulder"},
{"id":"d7","front":"How would you grade Goutallier fatty atrophy of the supraspinatus muscle?","find":"On the sagittal oblique Y-view, the supraspinatus muscle demonstrates fatty infiltration with [some fatty streaks (Goutallier 2) / fat equal to muscle (Goutallier 3) / fat greater than muscle (Goutallier 4)]. The muscle belly does not fill the supraspinatus fossa, with a tangent sign [positive/negative].","impr":"Goutallier grade [N] fatty atrophy of the supraspinatus.","pearl":"Goutallier 0 = normal, 1 = fatty streaks, 2 = fat < muscle, 3 = fat = muscle, 4 = fat > muscle. Goutallier >= 3 and a positive tangent sign predict poor repair outcomes and irreparability.","topic":"Rotator cuff","joint":"shoulder"},
{"id":"d8","front":"How would you describe calcific tendinopathy of the supraspinatus?","find":"Focal globular hypointense signal on all sequences within the distal supraspinatus tendon at the footprint, corresponding to hydroxyapatite calcification, with surrounding edema-like signal during the resorptive phase. Adjacent reactive subacromial-subdeltoid bursitis is present.","impr":"Calcific tendinopathy (hydroxyapatite deposition) of the supraspinatus.","pearl":"Calcium is signal-void on all MRI sequences and easily overlooked; correlate with radiographs or CT. Surrounding edema and bursitis indicate the painful resorptive phase amenable to barbotage.","topic":"Rotator cuff","joint":"shoulder"},
{"id":"d9","front":"How would you describe infraspinatus tendinosis with a partial articular-sided tear?","find":"Increased intermediate signal and thickening of the infraspinatus tendon with a focal articular-surface fluid-signal defect at its posterior footprint involving < 50% of tendon thickness. No full-thickness defect and no muscle retraction. Mild infraspinatus fossa fluid.","impr":"Infraspinatus tendinosis with low-grade partial articular-sided tear.","pearl":"Posterosuperior cuff tears (supraspinatus + infraspinatus) are typical of internal impingement in overhead athletes; pair with posterosuperior labral fraying.","topic":"Rotator cuff","joint":"shoulder"},
{"id":"d10","front":"How would you describe a full-thickness subscapularis tear with biceps medial dislocation?","find":"Full-thickness tear of the upper subscapularis tendon at the lesser tuberosity insertion with fluid-signal gap and [N] mm retraction of the torn fibers. The long head of the biceps tendon is medially dislocated out of the bicipital groove, lying medial to the lesser tuberosity over the torn subscapularis. The medial wall of the bicipital groove and the comma sign are disrupted.","impr":"Full-thickness subscapularis tear with medial dislocation of the long head of the biceps.","pearl":"The subscapularis and superior glenohumeral ligament form the biceps pulley/reflection sling; subscapularis tears uncover the medial groove wall and allow medial biceps dislocation. Look on axial images at the level of the coracoid.","topic":"Rotator cuff","joint":"shoulder"},
{"id":"d11","front":"How would you describe long head of biceps tendinosis?","find":"Mild thickening and intermediate increased signal of the intra-articular and intertubercular long head of the biceps tendon without a fluid-signal cleft or fiber discontinuity. A small amount of fluid is present within the biceps tendon sheath, communicating with the glenohumeral joint.","impr":"Long head of biceps tendinosis.","pearl":"Biceps sheath fluid normally communicates with the joint, so isolated sheath fluid is nonspecific; circumferential fluid disproportionate to joint fluid suggests tenosynovitis.","topic":"Biceps","joint":"shoulder"},
{"id":"d12","front":"How would you describe a partial tear of the long head of the biceps tendon?","find":"Focal caliber change and longitudinal split of the intertubercular long head of the biceps tendon with intrasubstance fluid signal and partial fiber attenuation, but maintained overall continuity. No complete discontinuity and no proximal retraction.","impr":"Partial tear of the long head of the biceps tendon.","pearl":"An abnormally enlarged or hourglass biceps can entrap within the joint; a markedly thinned or absent intra-articular segment with a normal-caliber groove tendon suggests partial tearing.","topic":"Biceps","joint":"shoulder"},
{"id":"d13","front":"How would you describe a complete tear of the long head of the biceps with retraction?","find":"Complete discontinuity of the long head of the biceps tendon with an empty bicipital groove and fluid filling the groove. The retracted tendon stump is identified within the distal arm, and there is bunching of the biceps muscle belly (Popeye deformity). Associated fluid in the biceps sheath.","impr":"Complete (full-thickness) rupture of the long head of the biceps with distal retraction.","pearl":"An empty bicipital groove is the key sign; trace the tendon distally to localize the retracted stump. Proximal LHB ruptures often coexist with rotator cuff tears.","topic":"Biceps","joint":"shoulder"},
{"id":"d14","front":"How would you describe medial subluxation of the long head of the biceps tendon?","find":"The long head of the biceps tendon is medially subluxated, perched over the medial wall of the bicipital groove but not fully dislocated medial to the lesser tuberosity. There is partial disruption of the biceps pulley with associated upper subscapularis and superior glenohumeral ligament fraying.","impr":"Medial subluxation of the long head of the biceps secondary to biceps pulley lesion.","pearl":"Pulley lesions are graded by which structures fail (SGHL, subscapularis, supraspinatus); even subtle medial perching of the biceps signals pulley compromise.","topic":"Biceps","joint":"shoulder"},
{"id":"d15","front":"How would you describe a SLAP type II lesion?","find":"On MR arthrography, contrast undermines the superior labrum at the biceps anchor, extending laterally between the labrum and the glenoid rim with a signal cleft that points toward the shoulder (laterally) rather than medially. The biceps-labral complex is detached from the superior glenoid. No paralabral cyst.","impr":"SLAP type II lesion (superior labral detachment of the biceps anchor).","pearl":"Distinguish from a sublabral recess/foramen: a recess follows the glenoid contour and points medially/superiorly, while a SLAP tear is irregular, extends laterally, and may show fluid posterior to the biceps anchor.","topic":"Labrum / Biceps","joint":"shoulder"},
{"id":"d16","front":"How would you describe a SLAP type III (bucket-handle) lesion?","find":"A bucket-handle tear of the superior labrum with a displaced labral fragment within the joint, while the biceps anchor itself remains attached to the residual labrum. Fluid signal separates the displaced fragment from the glenoid rim.","impr":"SLAP type III lesion (bucket-handle tear of the superior labrum with intact biceps anchor).","pearl":"Type I = fraying only; II = biceps anchor detachment; III = bucket-handle with intact anchor; IV = bucket-handle extending into the biceps tendon.","topic":"Labrum / Biceps","joint":"shoulder"},
{"id":"d17","front":"How would you describe an anteroinferior labral tear (Bankart lesion)?","find":"Fluid/contrast signal undermining and detaching the anteroinferior labrum from the glenoid rim at the [3 to 6 o'clock] position, with an irregular labral contour. The anteroinferior glenoid periosteum is disrupted (torn), and the adjacent osseous glenoid rim is intact.","impr":"Soft-tissue Bankart lesion (anteroinferior labroligamentous avulsion).","pearl":"The classic Bankart involves periosteal disruption; in an ALPSA the periosteum remains intact and the labroligamentous complex displaces medially. Best evaluated in the ABER position on MR arthrography.","topic":"Labrum / Instability","joint":"shoulder"},
{"id":"d18","front":"How would you describe a bony Bankart with glenoid bone loss?","find":"Anteroinferior labral tear with an associated fracture/attritional defect of the anteroinferior osseous glenoid rim. On the en-face sagittal best-fit circle, the glenoid bone loss measures approximately [N]% of the inferior glenoid width. The detached osseous fragment is identified with the attached labrum.","impr":"Bony Bankart lesion with [N]% anteroinferior glenoid bone loss.","pearl":"Glenoid bone loss > 20-25% (critical bone loss) typically requires bony augmentation (Latarjet) rather than soft-tissue repair. Quantify on the sagittal best-fit circle method.","topic":"Labrum / Instability","joint":"shoulder"},
{"id":"d19","front":"How would you describe an ALPSA lesion?","find":"The anteroinferior labroligamentous complex is avulsed and medially displaced along the scapular neck, but the scapular periosteum remains intact (non-disrupted), so the labrum rolls up medially in a chronic, rounded, blunted configuration without a discrete osseous fragment.","impr":"ALPSA lesion (anterior labroligamentous periosteal sleeve avulsion).","pearl":"ALPSA = intact periosteum with medial labral displacement; Bankart = torn periosteum. ALPSA medializes and can re-synovialize, making it easy to underestimate on imaging.","topic":"Labrum / Instability","joint":"shoulder"},
{"id":"d20","front":"How would you describe a Perthes lesion?","find":"The anteroinferior labrum is detached from the glenoid rim but remains medially attached by an intact, non-displaced scapular periosteum, so the labrum sits in a near-anatomic position. The subtle labral detachment is best demonstrated on ABER MR arthrography as contrast tracks beneath the labrum.","impr":"Perthes lesion (nondisplaced anteroinferior labral detachment with intact periosteum).","pearl":"Perthes lesions are notoriously occult on neutral imaging because the labrum is non-displaced; ABER positioning opens the lesion and is essential for detection.","topic":"Labrum / Instability","joint":"shoulder"},
{"id":"d21","front":"How would you describe a GLAD lesion?","find":"A superficial anteroinferior labral tear associated with a focal articular cartilage defect of the adjacent anteroinferior glenoid, with the inferior glenohumeral ligament remaining intact. There may be an associated osteochondral fragment.","impr":"GLAD lesion (glenolabral articular disruption).","pearl":"GLAD lesions are usually NOT associated with instability because the IGHL is intact; the clinical issue is the chondral defect and resultant pain.","topic":"Labrum / Instability","joint":"shoulder"},
{"id":"d22","front":"How would you describe a HAGL lesion?","find":"Avulsion of the inferior glenohumeral ligament from its humeral attachment, with fluid/contrast extravasation through the disrupted axillary pouch. The normal U-shaped axillary recess assumes a J-shaped configuration on coronal images, and the labrum is intact.","impr":"HAGL lesion (humeral avulsion of the glenohumeral ligament).","pearl":"The J-sign (J-shaped axillary pouch) on coronal fluid-sensitive images is the key clue; a bony fragment indicates a BHAGL. HAGL is frequently missed and is a cause of persistent instability with a normal labrum.","topic":"Labrum / Instability","joint":"shoulder"},
{"id":"d23","front":"How would you describe a posterior labral tear (reverse Bankart)?","find":"Fluid/contrast signal undermining and detaching the posteroinferior labrum from the glenoid rim at the [7 to 9 o'clock] position. There may be associated posterior capsular/periosteal stripping and a reverse Hill-Sachs impaction of the anteromedial humeral head.","impr":"Reverse Bankart lesion (posteroinferior labroligamentous avulsion).","pearl":"Posterior instability is associated with reverse Hill-Sachs (anteromedial humeral head) and reverse bony Bankart; consider seizure or electrocution if bilateral posterior dislocation.","topic":"Labrum / Instability","joint":"shoulder"},
{"id":"d24","front":"How would you describe a Hill-Sachs lesion?","find":"A wedge-shaped impaction defect of the posterosuperolateral humeral head with marrow edema (in the acute setting), located above the level of the coracoid, measuring approximately [N] mm in width and [N] mm in depth. The defect is best seen on superior axial images.","impr":"Hill-Sachs deformity (posterosuperolateral humeral head impaction) from prior anterior dislocation.","pearl":"A Hill-Sachs at or above the coracoid level is pathologic; below the coracoid the normal bare area / posterolateral flattening is a mimic. Report depth and width to assess engagement.","topic":"Labrum / Instability","joint":"shoulder"},
{"id":"d25","front":"How would you describe an engaging/off-track Hill-Sachs lesion?","find":"A Hill-Sachs interval (Hill-Sachs width plus the medial bone bridge) that exceeds the glenoid track width (0.83 x glenoid diameter minus anterior bone loss), indicating an off-track lesion. The Hill-Sachs defect extends medial to the medial margin of the glenoid track in abduction-external rotation.","impr":"Off-track (engaging) Hill-Sachs lesion.","pearl":"Glenoid track = 0.83 x glenoid diameter minus anterior glenoid bone loss. If the Hill-Sachs interval > glenoid track, the lesion is off-track/engaging and bipolar bone loss must be addressed surgically.","topic":"Labrum / Instability","joint":"shoulder"},
{"id":"d26","front":"How would you describe acromioclavicular joint osteoarthritis?","find":"Hypertrophic osteophytes and capsular thickening at the acromioclavicular joint with inferior osteophyte formation impinging on the underlying supraspinatus myotendinous junction. Subchondral cystic change and mild AC joint fluid are present.","impr":"Acromioclavicular joint osteoarthritis with inferior osteophytic impingement on the supraspinatus.","pearl":"Inferiorly directed AC osteophytes narrow the supraspinatus outlet and contribute to subacromial impingement; report whether they mass-effect the cuff.","topic":"AC joint","joint":"shoulder"},
{"id":"d27","front":"How would you describe distal clavicular osteolysis?","find":"Subchondral marrow edema and cystic resorption of the distal clavicle with cortical irregularity and a widened AC joint, while the acromial side is relatively spared. No discrete fracture.","impr":"Distal clavicular osteolysis.","pearl":"Edema predominantly on the clavicular side (sparing the acromion) is characteristic and is classically seen in weightlifters; differs from AC OA where both sides degenerate.","topic":"AC joint","joint":"shoulder"},
{"id":"d28","front":"How would you describe adhesive capsulitis on MRI?","find":"Thickening and edema/enhancement of the rotator interval soft tissues and the coracohumeral ligament, with thickening (> 4 mm) and T2-hyperintensity of the axillary recess/inferior glenohumeral ligament capsule. Obliteration of the normal subcoracoid fat triangle is present.","impr":"Adhesive capsulitis (frozen shoulder).","pearl":"Key signs: axillary pouch capsular thickening > 4 mm, edema/enhancement of the rotator interval, and subcoracoid fat triangle obliteration. Clinical correlation with restricted passive range of motion is essential.","topic":"Capsule","joint":"shoulder"},
{"id":"d29","front":"How would you describe os acromiale?","find":"An unfused accessory acromial ossification center with a well-corticated synchondrosis, most commonly at the meso-acromion. There is reactive marrow edema and cystic change across the synchondrosis with associated downward tilt narrowing the subacromial space and underlying supraspinatus tendinopathy.","impr":"Os acromiale (meso-acromion) with reactive synchondrosis edema and secondary impingement.","pearl":"Meso-acromion (between mid and anterior acromion) is the most common type; instability across the synchondrosis causes dynamic impingement and cuff disease. Best confirmed on axial images.","topic":"Acromion","joint":"shoulder"},
{"id":"d30","front":"How would you describe quadrilateral space syndrome on MRI?","find":"Isolated denervation edema and/or fatty atrophy of the teres minor muscle (and variably the deltoid), in the distribution of the axillary nerve traversing the quadrilateral space. A space-occupying paralabral cyst or fibrous band may be identified compressing the neurovascular bundle.","impr":"Quadrilateral space syndrome (axillary nerve denervation of teres minor).","pearl":"Isolated teres minor fatty atrophy is the hallmark; the quadrilateral space is bounded by teres minor, teres major, the humeral surgical neck, and the long head of triceps. Search for a compressive paralabral cyst or band.","topic":"Nerve","joint":"shoulder"},
{"id":"d31","front":"How would you describe subacromial-subdeltoid bursitis?","find":"Fluid distension and T2-hyperintensity of the subacromial-subdeltoid bursa with peripheral synovial thickening, exceeding the normal thin fluid sliver, extending around the greater tuberosity. The underlying rotator cuff is [intact/torn].","impr":"Subacromial-subdeltoid bursitis.","pearl":"A trace of SASD bursal fluid is normal; pathologic bursitis shows distension with wall thickening/enhancement. Communication of bursal and joint fluid implies a full-thickness cuff tear.","topic":"Bursa","joint":"shoulder"},
{"id":"d32","front":"How would you describe a paralabral cyst with spinoglenoid notch involvement?","find":"A well-defined T2-hyperintense, T1-hypointense cystic structure arising from a posterosuperior labral tear and extending into the spinoglenoid notch, with associated denervation edema/atrophy of the infraspinatus muscle from suprascapular nerve compression distal to the spinoglenoid notch.","impr":"Paralabral (ganglion) cyst in the spinoglenoid notch causing isolated infraspinatus denervation.","pearl":"Spinoglenoid notch cysts compress the nerve to infraspinatus only (isolated infraspinatus atrophy); suprascapular notch cysts affect both supraspinatus and infraspinatus. Always trace the cyst back to the labral tear.","topic":"Labrum / Nerve","joint":"shoulder"},
{"id":"d33","front":"How would you describe a normal, intact ACL?","find":"The ACL is uniformly low in signal on all sequences with taut, parallel fibers coursing along the expected oblique sagittal plane, parallel to the roof of the intercondylar notch (Blumensaat line). The femoral and tibial attachments are intact and the multiple discrete fascicles are well visualized. No fiber discontinuity, abnormal T2 signal, or increased ligament angulation.","impr":"Intact, normal ACL.","pearl":"A normal ACL parallels Blumensaat line; on extension the distal fibers should be parallel to or steeper than the intercondylar roof — a more horizontal course suggests laxity or tear.","topic":"Cruciate ligaments","joint":"knee"},
{"id":"d34","front":"How would you describe an ACL partial (incomplete) tear?","find":"Focal increased intrasubstance T2/fluid-sensitive signal and thickening of the ACL with disruption of [some/a portion of] the fibers, but with intact remaining fibers maintaining overall ligament continuity and a near-normal fiber orientation parallel to Blumensaat line. No frank fiber retraction. Secondary signs of complete tear are absent.","impr":"Partial-thickness ACL tear.","pearl":"Partial tears preserve some taut, low-signal fibers and a normal ACL angle; the diagnosis is supported by the ABSENCE of secondary signs (no pivot-shift contusions, no anterior tibial translation).","topic":"Cruciate ligaments","joint":"knee"},
{"id":"d35","front":"How would you describe a complete acute ACL tear (primary signs)?","find":"Complete discontinuity of the ACL fibers with abnormal horizontal fiber orientation, an edematous mass-like appearance of the disrupted ligament, and increased T2/fluid-sensitive signal spanning the expected course. The fibers no longer parallel Blumensaat line. The native ligament is not identified as a discrete taut structure.","impr":"Complete acute ACL tear.","pearl":"Primary signs = fiber discontinuity, abnormal (horizontal) orientation, and increased angle relative to Blumensaat line. An ACL angle that is more horizontal than the tibial plateau is suggestive of tear.","topic":"Cruciate ligaments","joint":"knee"},
{"id":"d36","front":"How would you describe the secondary signs of an acute ACL tear?","find":"Pivot-shift bone contusions with marrow edema in the lateral femoral condyle (at the condylopatellar sulcus) and the posterolateral tibial plateau. There is anterior translation of the tibia relative to the femur with uncovering of the posterior horn of the lateral meniscus (posterior drawer/uncovered meniscus sign), buckling of the PCL, and an associated deep lateral femoral notch (sulcus terminalis) deepening.","impr":"Secondary signs supporting acute ACL disruption.","pearl":"The kissing pivot-shift contusion pattern (lateral femoral condyle + posterolateral tibial plateau) is highly specific for ACL injury and reflects the impaction mechanism.","topic":"Cruciate ligaments","joint":"knee"},
{"id":"d37","front":"How would you describe chronic ACL tear / mucoid degeneration of the ACL?","find":"The ACL is thickened and ill-defined with intermediate T1 and increased T2 signal interspersed between intact fibers, producing a striated 'celery-stalk' appearance without fiber discontinuity or abnormal orientation. No mass-like edema or secondary pivot-shift contusions. Associated intraosseous ganglion-like cysts may be present at the tibial attachment.","impr":"Mucoid degeneration of the ACL.","pearl":"Celery-stalk ACL = mucoid degeneration; fibers remain continuous and parallel to Blumensaat line, distinguishing it from an acute tear. Often an incidental cause of posterior knee pain/limited extension.","topic":"Cruciate ligaments","joint":"knee"},
{"id":"d38","front":"How would you describe an ACL ganglion cyst?","find":"A well-defined, lobulated T2-hyperintense fluid-signal cystic structure interdigitating along and within the fibers of the ACL, paralleling the long axis of the ligament, without internal solid enhancement. The individual ACL fibers remain intact and low in signal. No fiber discontinuity.","impr":"Ganglion cyst of the ACL.","pearl":"ACL ganglia track along the ligament fibers and may extend through the intercondylar notch; unlike mucoid degeneration, signal is well-circumscribed fluid rather than diffuse intrasubstance striation, though the two coexist.","topic":"Cruciate ligaments","joint":"knee"},
{"id":"d39","front":"How would you describe an intact ACL reconstruction graft?","find":"The reconstructed ACL graft demonstrates uniformly low signal on all sequences with taut, continuous fibers extending from the femoral tunnel to the tibial tunnel. The graft parallels or is steeper than the roof of the intercondylar notch and does not contact the lateral wall or roof. Tunnels are appropriately positioned with no widening. No fiber discontinuity or abnormal fluid signal.","impr":"Intact ACL graft.","pearl":"Mild intermediate graft signal is expected during revascularization in the first 4-12 months ('ligamentization') and should not be mistaken for a tear if fibers are continuous and taut.","topic":"Cruciate ligaments","joint":"knee"},
{"id":"d40","front":"How would you describe a torn ACL graft?","find":"Discontinuity and increased T2 signal within the ACL graft fibers with a wavy, lax, or horizontal contour and absence of intact taut fibers spanning the tunnels. There is anterior tibial translation, PCL buckling, and uncovering of the posterior horn of the lateral meniscus. Tunnel widening may be present.","impr":"ACL graft tear/failure.","pearl":"Secondary signs (anterior tibial translation, PCL buckling, uncovered lateral meniscus) are especially valuable for grafts because intrasubstance signal is unreliable during remodeling.","topic":"Cruciate ligaments","joint":"knee"},
{"id":"d41","front":"How would you describe ACL graft roof impingement?","find":"The ACL graft demonstrates increased intrasubstance T2 signal predominantly in its distal/intra-articular portion with bowing or kinking against the intercondylar roof, associated with an excessively anterior tibial tunnel position. The graft contour is convex and abuts Blumensaat line in extension. Fibers remain in continuity.","impr":"Graft impingement (anterior tibial tunnel malposition).","pearl":"Anterior tibial tunnel placement causes roof impingement and increased distal graft signal — a common cause of graft signal change that mimics partial tear but is mechanical in origin.","topic":"Cruciate ligaments","joint":"knee"},
{"id":"d42","front":"How would you describe a normal, intact PCL?","find":"The PCL is a uniformly low-signal, smoothly curved (arcuate) band of thickness up to ~7 mm coursing from the medial femoral condyle to the posterior tibial sulcus. Fibers are continuous and taut throughout, with normal arcuate morphology and no increased T2 signal, thickening, or fiber disruption.","impr":"Intact, normal PCL.","pearl":"Normal PCL is curved (arcuate) on sagittal images and measures up to ~7 mm in AP diameter; straightening or thickening beyond this suggests injury.","topic":"Cruciate ligaments","joint":"knee"},
{"id":"d43","front":"How would you describe a grade I PCL sprain?","find":"Increased intrasubstance T2/fluid-sensitive signal within the PCL without ligament thickening or fiber disruption. The arcuate morphology and continuity are fully preserved and the AP diameter remains normal. No posterior tibial translation.","impr":"Grade I (mild) PCL sprain.","pearl":"Grade I = signal only, no fiber disruption or thickening. PCL injuries are graded by fiber involvement: I = intrasubstance signal, II = partial, III = complete.","topic":"Cruciate ligaments","joint":"knee"},
{"id":"d44","front":"How would you describe a grade II PCL sprain (partial tear)?","find":"Focal thickening and increased T2 signal within the [proximal/mid/distal] PCL with partial fiber disruption. Overall ligament continuity and arcuate morphology are preserved. No posterior tibial translation.","impr":"Grade II PCL sprain (partial-thickness tear).","pearl":"PCL diameter exceeding ~7 mm with intact spanning fibers is characteristic of a partial tear; the curved contour is typically maintained.","topic":"Cruciate ligaments","joint":"knee"},
{"id":"d45","front":"How would you describe a grade III PCL sprain / complete PCL tear?","find":"Complete discontinuity of the PCL fibers with a fluid-filled gap, marked thickening and high T2 signal, and loss of the normal arcuate contour. There is posterior translation of the tibia relative to the femur (positive posterior drawer/sag). Adjacent marrow contusion of the anterior tibia and anterior femoral condyle may be present.","impr":"Complete (grade III) PCL tear.","pearl":"An anterior tibia/anterior femur contusion pattern reflects the dashboard-injury mechanism. Always interrogate the posterolateral corner — combined PCL/PLC injury is common.","topic":"Cruciate ligaments","joint":"knee"},
{"id":"d46","front":"How would you describe a PCL tibial bony avulsion?","find":"An osseous fragment avulsed from the posterior tibial PCL insertion (posterior intercondylar fossa), displaced proximally, with the PCL fibers remaining intact and attached to the bony fragment. Surrounding marrow edema and a posterior tibial donor-site defect are present. The ligament substance itself is in continuity.","impr":"Bony avulsion of the PCL from the posterior tibia.","pearl":"Bony avulsions are more common at the tibial than femoral PCL attachment and are surgically repairable since the ligament is intact — a key distinction to convey to the surgeon.","topic":"Cruciate ligaments","joint":"knee"},
{"id":"d47","front":"How would you describe a normal MCL?","find":"The superficial and deep components of the medial collateral ligament complex are thin, uniformly low-signal, taut structures. The superficial MCL extends from the medial femoral epicondyle to the proximal medial tibia, and the deep MCL (meniscofemoral and meniscotibial ligaments) attaches to the medial meniscus. No periligamentous edema, thickening, or fiber disruption.","impr":"Intact, normal MCL complex.","topic":"Collateral ligaments","joint":"knee"},
{"id":"d48","front":"How would you describe a grade I MCL sprain?","find":"Periligamentous T2/fluid-sensitive signal and edema superficial to an intact, normal-caliber, low-signal MCL with no intrinsic fiber thickening or disruption. The ligament fibers themselves are uniformly hypointense and continuous.","impr":"Grade I MCL sprain.","pearl":"Grade I = edema around the ligament only, fibers normal. Grading: I = perifascial edema, II = partial fiber tear/thickening, III = complete disruption.","topic":"Collateral ligaments","joint":"knee"},
{"id":"d49","front":"How would you describe a grade II MCL sprain?","find":"Thickening and increased intrasubstance T2 signal of the MCL with partial fiber disruption and surrounding periligamentous edema. A subset of fibers remains intact and in continuity. No complete discontinuity and no full-thickness gap.","impr":"Grade II MCL sprain (partial tear).","topic":"Collateral ligaments","joint":"knee"},
{"id":"d50","front":"How would you describe a grade III MCL tear?","find":"Complete disruption of the MCL fibers with a fluid-filled gap, lax wavy retracted fiber ends, and extensive periligamentous edema and hemorrhage. The ligament is discontinuous over its full thickness, most commonly at the proximal femoral attachment.","impr":"Complete (grade III) MCL tear.","pearl":"Most MCL tears occur proximally at the femoral attachment. Combined with ACL and medial meniscus injury this constitutes the O'Donoghue unhappy triad.","topic":"Collateral ligaments","joint":"knee"},
{"id":"d51","front":"How would you describe Pellegrini-Stieda lesion (chronic MCL injury)?","find":"Curvilinear ossification/heterotopic bone paralleling the proximal superficial MCL at the medial femoral condyle attachment, low signal on all sequences with peripheral marrow-like signal when mature. The adjacent MCL is thickened and chronically scarred. No acute periligamentous edema.","impr":"Pellegrini-Stieda lesion (post-traumatic ossification of the proximal MCL).","pearl":"Pellegrini-Stieda represents chronic ossification at the femoral MCL origin from prior injury; on radiographs it is a well-known medial femoral condyle ossification.","topic":"Collateral ligaments","joint":"knee"},
{"id":"d52","front":"How would you describe a distal superficial MCL avulsion with Stener-like displacement?","find":"Distal avulsion of the superficial MCL from the tibial insertion with the torn ligament end displaced superficial to the pes anserinus tendons, preventing apposition to its footprint. There is a fluid-filled gap at the tibial attachment and surrounding edema. The proximal ligament is intact.","impr":"Distal superficial MCL tear with Stener-like displacement.","pearl":"A 'Stener-like' lesion of the knee MCL — where the avulsed distal end flips superficial to the pes tendons — may not heal with bracing and can require surgical repair, analogous to the thumb UCL Stener lesion.","topic":"Collateral ligaments","joint":"knee"},
{"id":"d53","front":"How would you describe a normal LCL (fibular collateral ligament)?","find":"The fibular collateral ligament is a thin, taut, uniformly low-signal cord extending obliquely from the lateral femoral epicondyle to the fibular head, where it joins the biceps femoris tendon to form the conjoined tendon. Fibers are continuous with no thickening, periligamentous edema, or disruption.","impr":"Intact, normal LCL/fibular collateral ligament.","pearl":"Follow the LCL on sequential coronal-oblique images to the fibular head; it courses posterolaterally and should not be confused with the iliotibial band (which inserts on Gerdy tubercle) or biceps tendon.","topic":"Posterolateral corner","joint":"knee"},
{"id":"d54","front":"How would you describe an LCL (fibular collateral ligament) tear?","find":"Discontinuity and increased T2 signal of the fibular collateral ligament with a wavy, lax contour and surrounding edema/hemorrhage [at the fibular head insertion/at the femoral origin/in the mid substance]. The conjoined tendon attachment is disrupted. A bony avulsion fragment from the fibular head may be present.","impr":"Tear of the fibular collateral ligament (LCL).","pearl":"LCL injury is rarely isolated — scrutinize the entire posterolateral corner (popliteus, popliteofibular ligament, biceps) and PCL, as combined injury risks instability and peroneal nerve involvement.","topic":"Posterolateral corner","joint":"knee"},
{"id":"d55","front":"How would you describe a popliteus tendon/musculotendinous injury?","find":"Increased T2/fluid-sensitive signal and thickening of the popliteus tendon or musculotendinous junction with [partial fiber disruption/feathery intramuscular edema], and fluid distending the popliteus tendon sheath. The femoral attachment within the popliteal sulcus may show edema or avulsion. Continuity is [preserved/disrupted].","impr":"Popliteus tendon/myotendinous injury (posterolateral corner).","pearl":"The popliteus is a key dynamic stabilizer of the posterolateral corner; isolated injury is uncommon, so assess the popliteofibular ligament, LCL, and biceps femoris together.","topic":"Posterolateral corner","joint":"knee"},
{"id":"d56","front":"How would you describe a biceps femoris tendon avulsion?","find":"Disruption or avulsion of the biceps femoris tendon from the fibular head with retraction, increased T2 signal, and surrounding edema/hemorrhage, with or without an avulsed osseous fragment from the fibular styloid. The conjoined tendon (biceps + LCL) attachment is compromised.","impr":"Biceps femoris tendon avulsion (posterolateral corner injury).","pearl":"An avulsion fragment from the fibular styloid (where the arcuate/popliteofibular complex and biceps attach) is the 'arcuate sign' — a marker of significant posterolateral corner injury.","topic":"Posterolateral corner","joint":"knee"},
{"id":"d57","front":"How would you describe the arcuate sign (arcuate complex avulsion)?","find":"An avulsed osseous fragment from the fibular styloid process, displaced superiorly, with adjacent marrow and soft-tissue edema, indicating avulsion of the arcuate ligament complex/popliteofibular ligament. Associated disruption of the posterolateral corner structures and frequently the PCL/ACL.","impr":"Arcuate sign — avulsion of the fibular styloid/arcuate complex indicating posterolateral corner injury.","pearl":"The arcuate sign on radiograph/MRI flags posterolateral corner instability and is a high-yield association with cruciate ligament tears; a tiny fibular styloid fleck should never be dismissed.","topic":"Posterolateral corner","joint":"knee"},
{"id":"d58","front":"How would you describe a conjoined tendon avulsion off the fibular head?","find":"Avulsion of the conjoined tendon (biceps femoris and fibular collateral ligament) from the fibular head with a displaced osseous fragment, fiber retraction, increased T2 signal, and surrounding hemorrhagic edema. The fibular head attachment site is denuded.","impr":"Conjoined tendon (LCL + biceps femoris) avulsion from the fibular head.","topic":"Posterolateral corner","joint":"knee"},
{"id":"d59","front":"How would you describe patellar tendinosis (jumper's knee)?","find":"Focal fusiform thickening and intermediate T1/increased T2 signal within the proximal patellar tendon at its inferior patellar pole origin, predominantly involving the posterior/deep fibers, without a discrete fluid-signal cleft of tear. The tendon remains in continuity. Adjacent Hoffa fat-pad and inferior patellar pole edema may be present.","impr":"Proximal patellar tendinosis (jumper's knee).","pearl":"Jumper's knee characteristically involves the deep posterior fibers at the inferior pole of the patella; intratendinous T2 signal short of a fluid-filled gap = tendinosis rather than tear.","topic":"Extensor mechanism","joint":"knee"},
{"id":"d60","front":"How would you describe a partial patellar tendon tear?","find":"Partial-thickness fiber disruption with a fluid-signal cleft and increased T2 signal within the patellar tendon, most often at the inferior patellar pole, with tendon thickening but maintained overall continuity of the remaining fibers. Surrounding edema and hemorrhage are present. No complete gap or retraction.","impr":"Partial-thickness patellar tendon tear.","topic":"Extensor mechanism","joint":"knee"},
{"id":"d61","front":"How would you describe a complete patellar tendon rupture?","find":"Full-thickness discontinuity of the patellar tendon with a fluid- and hemorrhage-filled gap, wavy retracted lax tendon fibers, and patella alta from proximal retraction of the patella. Marked surrounding edema and hemorrhage. The extensor mechanism is disrupted.","impr":"Complete patellar tendon rupture with patella alta.","pearl":"Patella alta indicates a complete extensor mechanism disruption at the patellar tendon; conversely patella baja suggests quadriceps tendon rupture.","topic":"Extensor mechanism","joint":"knee"},
{"id":"d62","front":"How would you describe a partial quadriceps tendon tear?","find":"Partial-thickness fiber disruption and increased T2 signal at the quadriceps tendon insertion on the superior patellar pole, typically involving the superficial (rectus femoris) layer, with thickening and a focal fluid cleft but preserved continuity of the deeper fibers. No retraction or patella baja.","impr":"Partial-thickness quadriceps tendon tear.","pearl":"The quadriceps tendon is trilaminar; partial tears often selectively involve the superficial rectus femoris layer while the deeper vastus layers remain intact.","topic":"Extensor mechanism","joint":"knee"},
{"id":"d63","front":"How would you describe a complete quadriceps tendon rupture?","find":"Full-thickness discontinuity of the quadriceps tendon at or just proximal to the superior patellar pole with a fluid- and hemorrhage-filled gap, retraction of the proximal tendon stump, and patella baja. Extensive surrounding edema and hemorrhage. The extensor mechanism is disrupted.","impr":"Complete quadriceps tendon rupture with patella baja.","pearl":"Quadriceps rupture is more common in older patients and those with predisposing systemic disease (diabetes, renal failure, gout); patella baja is the corollary to the patella alta of patellar tendon rupture.","topic":"Extensor mechanism","joint":"knee"},
{"id":"d64","front":"How would you describe an MPFL tear after transient lateral patellar dislocation?","find":"Disruption of the medial patellofemoral ligament with increased T2 signal, fiber discontinuity, and edema, most commonly at the medial femoral attachment (adductor tubercle) or patellar insertion. There is the characteristic bone contusion pattern: marrow edema in the inferomedial patellar facet and the anterolateral femoral condyle. A medial retinacular/MPFL osteochondral avulsion fragment and joint effusion/lipohemarthrosis may be present.","impr":"MPFL tear with bone contusion pattern of transient lateral patellar dislocation.","pearl":"The kissing contusion of the inferomedial patella and anterolateral lateral femoral condyle is pathognomonic of transient lateral patellar dislocation/relocation even when the patella has reduced. Always search for an intra-articular osteochondral body.","topic":"Extensor mechanism","joint":"knee"},
{"id":"d65","front":"How would you describe patellar maltracking / lateral patellar subluxation?","find":"Lateral subluxation/tilt of the patella with a shallow trochlear groove (trochlear dysplasia), increased TT-TG (tibial tuberosity-trochlear groove) distance >15-20 mm, patella alta (elevated Insall-Salvati ratio), and uncovering of the lateral trochlear facet. Lateral patellar facet chondral thinning and lateral retinacular thickening may be present.","impr":"Patellar maltracking with lateral subluxation and predisposing trochlear dysplasia.","pearl":"Quantify the contributors: TT-TG distance, trochlear morphology (sulcus angle/dysplasia), and patellar height (Insall-Salvati, Caton-Deschamps) — these guide surgical planning for recurrent instability.","topic":"Extensor mechanism","joint":"knee"},
{"id":"d66","front":"How would you describe a Segond fracture?","find":"A small curvilinear/elliptical osseous avulsion fragment from the lateral proximal tibial plateau just below the articular margin, at the attachment of the anterolateral ligament/lateral capsule, with adjacent marrow and soft-tissue edema. Best seen on coronal images.","impr":"Segond fracture — lateral tibial avulsion, highly associated with ACL tear.","pearl":"A Segond fracture is virtually pathognomonic of an ACL tear (and frequently lateral meniscus injury); always scrutinize the ACL when you see this lateral tibial fleck.","topic":"Avulsions and named signs","joint":"knee"},
{"id":"d67","front":"How would you describe a reverse Segond fracture?","find":"An avulsion fracture fragment from the MEDIAL tibial plateau at the deep MCL/medial capsular attachment, with adjacent marrow and soft-tissue edema. Associated with PCL injury and medial meniscus tear.","impr":"Reverse Segond fracture — medial tibial avulsion associated with PCL and medial meniscus injury.","pearl":"Reverse Segond (medial) pairs with PCL tear and medial meniscus injury, the mirror counterpart of the lateral Segond/ACL association.","topic":"Avulsions and named signs","joint":"knee"},
{"id":"d68","front":"How would you describe the deep lateral femoral notch sign?","find":"Abnormal deepening of the lateral femoral condylopatellar sulcus (sulcus terminalis) measuring >1.5 mm in depth on the sagittal image, often with associated marrow edema, reflecting the impaction injury of the pivot-shift mechanism.","impr":"Deep lateral femoral notch sign — secondary indicator of ACL tear.","pearl":"A condylopatellar sulcus depth >1.5-2 mm is abnormal and is a useful secondary sign of ACL injury, reflecting the same impaction that causes the lateral femoral condyle pivot-shift contusion.","topic":"Avulsions and named signs","joint":"knee"},
{"id":"d69","front":"How would you describe an anterosuperior acetabular labral tear?","find":"At the anterosuperior labrum (approximately 11-1 o'clock position), there is intrasubstance and surface-reaching high T2/intermediate signal with contrast undercutting the chondrolabral junction on MR arthrogram, consistent with a tear. The labral base shows fluid/contrast tracking between the labrum and acetabular rim. Adjacent acetabular cartilage demonstrates [intact/early delamination].","impr":"Anterosuperior acetabular labral tear at the chondrolabral junction.","pearl":"The anterosuperior quadrant is the most common location for labral tears; report tears by clock position with 12 superior, 3 anterior (right hip).","topic":"Labrum","joint":"hip"},
{"id":"d70","front":"How would you describe a normal acetabular labrum and a sublabral sulcus mimic?","find":"The acetabular labrum is uniformly low-signal and triangular in cross-section, firmly apposed to the bony rim. At the anteroinferior or posteroinferior margin a smooth, partial-thickness sublabral sulcus is present with regular margins, no contrast undercutting beyond the sulcus, and a normally seated labral tip - a normal variant.","impr":"Normal acetabular labrum; sublabral sulcus, a normal variant.","pearl":"A true sulcus is smooth, partial-thickness, and located inferiorly; a tear is irregular, reaches the articular surface, and is typically anterosuperior.","topic":"Labrum","joint":"hip"},
{"id":"d71","front":"How would you distinguish labral detachment from an intrasubstance labral tear?","find":"Labral detachment: contrast/fluid completely separates the labral base from the acetabular rim at the chondrolabral junction with displacement of the labrum. Intrasubstance tear: high signal is confined within the labral substance without reaching the base or articular surface, and the chondrolabral junction remains intact.","impr":"[Labral detachment from the acetabular rim / Intrasubstance labral degeneration].","topic":"Labrum","joint":"hip"},
{"id":"d72","front":"How would you describe a paralabral cyst of the hip?","find":"Arising from the anterosuperior labrum is a well-defined, lobulated T2-hyperintense cystic structure measuring ___ x ___ mm, communicating with an adjacent labral tear. No internal solid enhancement. The cyst may dissect along the iliopsoas or into the adjacent soft tissues.","impr":"Paralabral cyst arising from an anterosuperior labral tear.","pearl":"A paralabral cyst is essentially pathognomonic of an underlying labral tear even when the tear itself is subtle.","topic":"Labrum","joint":"hip"},
{"id":"d73","front":"How would you describe cam-type femoroacetabular impingement morphology?","find":"There is osseous prominence/aspherical contour at the anterosuperior femoral head-neck junction with loss of the normal concavity (decreased head-neck offset). The alpha angle measures ___ degrees (>55 degrees abnormal) on oblique axial images. Associated anterosuperior chondrolabral injury and a fibrocystic herniation pit at the head-neck junction may be present.","impr":"Cam-type FAI morphology with alpha angle of ___ degrees.","pearl":"Cam impingement classically causes outside-in cartilage delamination at the anterosuperior acetabulum from shear during flexion/internal rotation.","topic":"FAI","joint":"hip"},
{"id":"d74","front":"How would you describe pincer-type femoroacetabular impingement?","find":"There is acetabular overcoverage with a lateral center-edge angle of ___ degrees (>40 degrees abnormal) and/or a crossover sign indicating focal anterior overcoverage/acetabular retroversion. The labrum shows degeneration and intrasubstance ossification, with a posteroinferior contrecoup chondral injury.","impr":"Pincer-type FAI with acetabular overcoverage (lateral center-edge angle ___ degrees).","pearl":"Pincer impingement causes circumferential labral crush injury and a characteristic posteroinferior contrecoup cartilage lesion.","topic":"FAI","joint":"hip"},
{"id":"d75","front":"How would you describe mixed-type femoroacetabular impingement?","find":"Combined features are present: aspherical anterosuperior head-neck junction with alpha angle ___ degrees (cam) together with acetabular overcoverage, lateral center-edge angle ___ degrees and crossover sign (pincer). There is anterosuperior chondrolabral delamination and labral degeneration.","impr":"Mixed cam and pincer FAI morphology.","pearl":"Mixed FAI is the most common pattern clinically; report both alpha angle and center-edge angle.","topic":"FAI","joint":"hip"},
{"id":"d76","front":"How would you describe acetabular cartilage delamination in FAI?","find":"At the anterosuperior acetabulum there is a linear fluid/contrast cleft undercutting the articular cartilage and separating it from subchondral bone, with the cartilage flap remaining in situ (carpet phenomenon). Overlying cartilage signal is heterogeneous; the chondrolabral junction is disrupted.","impr":"Anterosuperior acetabular cartilage delamination.","pearl":"Delamination is the in-situ separation of cartilage from bone and may be occult on routine sequences without intra-articular contrast.","topic":"Cartilage","joint":"hip"},
{"id":"d77","front":"How would you describe full-thickness chondral loss in the hip?","find":"At the [anterosuperior/superior] acetabulum and/or apposing femoral head there is full-thickness cartilage loss with exposed subchondral bone, subchondral marrow edema, and subchondral cystic change. Joint space narrowing and marginal osteophytes indicate secondary osteoarthritis.","impr":"Full-thickness chondral loss with secondary osteoarthritis.","topic":"Cartilage","joint":"hip"},
{"id":"d78","front":"How would you describe gluteus medius/minimus tendinosis?","find":"The gluteus medius and/or minimus tendons show thickening and increased intratendinous T2 signal at their greater trochanteric insertions without a discrete fiber gap. Adjacent peritrochanteric T2-hyperintense edema and reactive trochanteric bursal fluid are present.","impr":"Gluteus medius/minimus tendinosis (greater trochanteric pain syndrome).","pearl":"The gluteal tendons are the rotator cuff of the hip; GTPS is more often tendinopathy/tears than isolated bursitis.","topic":"Tendons","joint":"hip"},
{"id":"d79","front":"How would you describe a gluteus medius tendon tear?","find":"There is a focal full-thickness fiber gap fluid signal cleft at the gluteus medius insertion on the [lateral/posterosuperior] facet of the greater trochanter with ___ mm tendon retraction and fatty atrophy of the muscle belly. A partial-thickness tear shows surface-reaching signal involving <50% of the tendon thickness.","impr":"[Partial-thickness / Full-thickness] gluteus medius tendon tear with ___ mm retraction.","pearl":"The lateral and posterosuperior facets are the medius footprint; T2 signal undermining the tendon footprint indicates a tear.","topic":"Tendons","joint":"hip"},
{"id":"d80","front":"How would you describe proximal hamstring origin tendinosis?","find":"The conjoint hamstring origin at the ischial tuberosity is thickened with increased intrasubstance T2 signal and ill-defined peritendinous edema, without discrete fiber discontinuity or retraction. Ischial enthesophyte and marrow edema may be present.","impr":"Proximal hamstring tendinosis at the ischial tuberosity.","topic":"Tendons","joint":"hip"},
{"id":"d81","front":"How would you describe a partial-thickness proximal hamstring tear?","find":"At the ischial tuberosity origin there is a partial fiber discontinuity involving the [semimembranosus/conjoint biceps femoris-semitendinosus] tendon with surrounding T2-hyperintense edema and hemorrhage, but maintained overall tendon continuity and no significant retraction.","impr":"Partial-thickness proximal hamstring tear without retraction.","topic":"Tendons","joint":"hip"},
{"id":"d82","front":"How would you describe a complete proximal hamstring avulsion?","find":"There is complete discontinuity of the conjoint hamstring origin from the ischial tuberosity with a fluid-filled gap and distal retraction of the stump measuring ___ cm. The intervening interval is filled with hematoma; the sciatic nerve lies in close proximity to the retracted stump.","impr":"Complete proximal hamstring avulsion with ___ cm retraction.","pearl":"Retraction >2 cm and 2-3 tendon involvement favor surgical repair; always comment on sciatic nerve proximity.","topic":"Tendons","joint":"hip"},
{"id":"d83","front":"How would you describe iliopsoas tendinopathy?","find":"The iliopsoas tendon is thickened with intrasubstance increased T2 signal near its insertion on the lesser trochanter, with adjacent iliopsoas bursal distension. No discrete tendon tear or retraction. Findings may relate to internal snapping hip.","impr":"Iliopsoas tendinopathy with reactive bursal distension.","topic":"Tendons","joint":"hip"},
{"id":"d84","front":"How would you describe a rectus femoris proximal tendon injury?","find":"At the proximal rectus femoris origin there is increased T2 signal and thickening involving the [direct head at the AIIS / indirect head along the superior acetabulum] with feathery intramuscular edema. A higher-grade injury shows partial fiber disruption with a focal fluid cleft and minimal retraction.","impr":"Proximal rectus femoris [tendinosis / partial tear] involving the [direct/indirect] head.","topic":"Tendons","joint":"hip"},
{"id":"d85","front":"How would you describe athletic pubalgia / adductor longus injury?","find":"There is increased T2 signal and a secondary cleft at the common adductor-rectus abdominis aponeurosis along the inferior pubic margin, with adductor longus origin tendinosis/partial tearing and adjacent pubic bone marrow edema (osteitis pubis). The rectus abdominis-adductor aponeurosis is disrupted from the pubis.","impr":"Athletic pubalgia with adductor longus origin injury and aponeurotic disruption.","pearl":"The secondary cleft sign - contrast/fluid tracking along the inferior pubis at the adductor origin - indicates aponeurotic detachment.","topic":"Tendons","joint":"hip"},
{"id":"d86","front":"How would you describe avascular necrosis of the femoral head?","find":"Within the anterosuperior subchondral femoral head is a serpiginous geographic lesion with a peripheral low-signal rim and inner high-signal granulation tissue (double-line sign on T2). The lesion involves ___% of the weight-bearing surface. The articular surface is [intact / shows a subchondral crescent fracture with cortical collapse and flattening].","impr":"Avascular necrosis of the femoral head, [precollapse / with subchondral fracture and collapse].","pearl":"The double-line sign is pathognomonic; the subchondral crescent sign signals impending or early collapse (changes staging and management).","topic":"Marrow","joint":"hip"},
{"id":"d87","front":"How would you describe transient osteoporosis of the hip?","find":"There is diffuse T2-hyperintense, T1-hypointense bone marrow edema involving the femoral head and neck extending into the intertrochanteric region, WITHOUT a focal subchondral low-signal line, geographic lesion, or cortical collapse. A small reactive joint effusion is present; the articular surface is preserved.","impr":"Transient osteoporosis of the hip (bone marrow edema syndrome).","pearl":"Distinguished from AVN by the absence of a focal subchondral demarcating line or double-line sign; transient osteoporosis is self-limiting and migratory.","topic":"Marrow","joint":"hip"},
{"id":"d88","front":"How would you describe a subchondral insufficiency fracture of the femoral head?","find":"There is an irregular, low-signal subchondral line paralleling the articular surface of the superolateral femoral head with surrounding extensive bone marrow edema. The line is irregular/serpiginous and convex to the articular surface, with possible focal subchondral collapse.","impr":"Subchondral insufficiency fracture of the femoral head.","pearl":"Differs from AVN: the low-signal line is subchondral, irregular, and convex to the cortex with surrounding edema but no double-line sign; seen in osteoporotic elderly patients.","topic":"Marrow","joint":"hip"},
{"id":"d89","front":"How would you describe a femoral neck stress fracture, tension versus compression side?","find":"There is a linear low-signal fracture line with surrounding T1-hypointense/T2-hyperintense marrow edema in the femoral neck. A compression-side fracture involves the inferomedial neck (stable). A tension-side fracture involves the superolateral neck and is high-risk for displacement.","impr":"Femoral neck stress fracture, [compression-side / tension-side].","pearl":"Tension-side (superolateral) femoral neck stress fractures are unstable and may require urgent fixation; flag them explicitly.","topic":"Marrow","joint":"hip"},
{"id":"d90","front":"How would you describe a sacral insufficiency fracture?","find":"There are bilateral vertically oriented low-signal fracture lines through the sacral ala with surrounding T1-hypointense, T2/STIR-hyperintense marrow edema, joined by a horizontal component across the sacral body producing an H-shaped (Honda sign) configuration.","impr":"Sacral insufficiency fracture with Honda sign.","pearl":"The H-shaped Honda sign is classic on bone scan and reflected on MRI as bilateral alar plus transverse marrow edema in the osteoporotic/post-radiation pelvis.","topic":"Marrow","joint":"hip"},
{"id":"d91","front":"How would you describe greater trochanteric bursitis?","find":"There is T2-hyperintense fluid distending the [subgluteus maximus / trochanteric] bursa lateral to the greater trochanter, with surrounding peritrochanteric soft-tissue edema. Frequently associated with underlying gluteus medius/minimus tendinopathy.","impr":"Trochanteric bursitis, part of greater trochanteric pain syndrome.","topic":"Bursae","joint":"hip"},
{"id":"d92","front":"How would you describe iliopsoas bursitis?","find":"There is a well-defined T2-hyperintense fluid collection anterior to the hip joint, deep to the iliopsoas tendon/musculotendinous junction, that may communicate with the joint. Mass effect on adjacent femoral vessels may be present when large.","impr":"Iliopsoas bursitis [with communication to the hip joint].","pearl":"The iliopsoas bursa communicates with the hip joint in ~15% and enlarges with intra-articular pathology (effusion, arthritis).","topic":"Bursae","joint":"hip"},
{"id":"d93","front":"How would you describe internal versus external snapping hip on MRI?","find":"Internal snapping: iliopsoas tendinopathy with peritendinous edema and iliopsoas bursitis as the tendon snaps over the iliopectineal eminence/femoral head. External snapping: thickening of the iliotibial band or gluteus maximus tendon overlying the greater trochanter with trochanteric bursitis.","impr":"Imaging findings of [internal (iliopsoas) / external (iliotibial band)] snapping hip.","pearl":"Snapping hip is a clinical diagnosis; MRI shows the secondary tendinopathy/bursitis - dynamic ultrasound confirms the snap.","topic":"Bursae","joint":"hip"},
{"id":"d94","front":"How would you describe sciatic nerve impingement / piriformis syndrome?","find":"The piriformis muscle is [hypertrophied / shows an anomalous split with the sciatic nerve passing through or over it]. The sciatic nerve is enlarged with increased T2 signal and loss of normal fascicular fat at the sciatic notch, with adjacent edema. No mass lesion.","impr":"Piriformis syndrome with sciatic neuropathy at the sciatic notch.","topic":"Other","joint":"hip"},
{"id":"d95","front":"How would you describe ischiofemoral impingement?","find":"There is narrowing of the ischiofemoral space (between the lateral ischium and the lesser trochanter, normal >17 mm) and the quadratus femoris space, with T2-hyperintense edema and atrophy of the quadratus femoris muscle.","impr":"Ischiofemoral impingement with quadratus femoris edema.","pearl":"An ischiofemoral space <17 mm and quadratus femoris edema are the key findings; quadratus femoris edema is the most sensitive sign.","topic":"Other","joint":"hip"},
{"id":"d96","front":"How would you describe developmental hip dysplasia in the adult?","find":"There is acetabular undercoverage with a shallow acetabulum, lateral center-edge angle of ___ degrees (<20 degrees abnormal) and increased acetabular index, with superolateral subluxation of the femoral head. The labrum is hypertrophied and torn, with superolateral chondral wear.","impr":"Acetabular dysplasia with undercoverage (lateral center-edge angle ___ degrees) and secondary labral tear.","pearl":"In dysplasia the labrum hypertrophies to compensate and frequently tears; the LCEA is low (overcoverage in pincer is high).","topic":"Other","joint":"hip"},
{"id":"d97","front":"How would you describe femoral head osteochondral injury / transient lateral patellar-type bone bruise pattern equivalent in hip dislocation?","find":"Following posterior hip dislocation there are impaction bone contusions of the posterosuperior acetabular rim and anteromedial femoral head, with possible intra-articular osteochondral fragments and posterior labral/capsular disruption. Assess for sciatic nerve injury.","impr":"Post-reduction findings of posterior hip dislocation with impaction contusions and labral injury.","topic":"Marrow","joint":"hip"},
{"id":"d98","front":"How would you describe os acetabuli / acetabular rim fracture as a labral variant pitfall?","find":"At the anterosuperior acetabular rim there is a well-corticated ossicle (os acetabuli) versus a non-corticated rim fragment. Associated labral degeneration and adjacent pincer-type overcoverage may be present.","impr":"Anterosuperior os acetabuli/rim ossicle, associated with pincer FAI.","pearl":"A corticated ossicle is a developmental os acetabuli or chronic rim stress reaction; correlate with pincer morphology and labral tear.","topic":"Labrum","joint":"hip"},
{"id":"d99","front":"How would you describe a horizontal cleavage tear of the meniscus?","find":"Linear intrameniscal increased T2 signal oriented parallel to the tibial plateau and extending to the [inferior/superior] articular surface of the [medial/lateral] meniscus [body/posterior horn], dividing the meniscus into upper and lower leaves. No displaced fragment.","impr":"Horizontal cleavage tear of the [medial/lateral] meniscus.","pearl":"Horizontal tears are degenerative, common in older patients, and frequently feed a parameniscal cyst — always look at the periphery for a cyst.","topic":"Meniscus","joint":"knee"},
{"id":"d100","front":"How would you describe an oblique (flap) meniscal tear?","find":"Obliquely oriented signal that begins on a meniscal surface and changes plane, with a free margin / flap fragment of meniscal tissue displaced into the [superior/inferior] recess or intercondylar region. Surface signal contacts the articular margin.","impr":"Oblique flap tear of the [medial/lateral] meniscus with displaced flap.","pearl":"Trace the flap — a displaced fragment in the meniscocapsular recess or intercondylar notch is easily overlooked and changes surgical planning.","topic":"Meniscus","joint":"knee"},
{"id":"d101","front":"How would you describe a radial meniscal tear?","find":"Vertically oriented tear perpendicular to the long axis of the meniscus extending from the free inner margin toward the periphery, producing the cleft (truncated triangle) sign on one slice and the ghost sign with apparent absence of meniscal tissue on the adjacent slice. Tear extends [partially / through full radial width].","impr":"Radial tear of the [medial/lateral] meniscus [free edge / extending to periphery].","pearl":"A full-width radial tear is functionally equivalent to a root tear — it disrupts hoop stress and predisposes to extrusion.","topic":"Meniscus","joint":"knee"},
{"id":"d102","front":"How would you describe a longitudinal (vertical) meniscal tear?","find":"Vertically oriented tear paralleling the long axis of the meniscus, extending to both the superior and inferior surfaces and confined to the peripheral [red / red-white] zone without a displaced fragment. Meniscal morphology and bow-tie configuration are preserved.","impr":"Peripheral vertical longitudinal tear of the [medial/lateral] meniscus, repairable.","pearl":"Peripheral red-zone longitudinal tears are vascularized and amenable to repair rather than meniscectomy — note zone explicitly.","topic":"Meniscus","joint":"knee"},
{"id":"d103","front":"How would you describe a bucket-handle meniscal tear?","find":"Vertical longitudinal tear with a displaced inner fragment flipped centrally into the intercondylar notch, producing the double PCL sign on sagittal images, an absent bow-tie sign with fewer than two bow-tie segments on consecutive 4-5 mm sagittal slices, and a flipped-fragment / fragment-in-notch appearance. The peripheral remnant is foreshortened and blunted.","impr":"Displaced bucket-handle tear of the [medial/lateral] meniscus.","pearl":"A double PCL sign occurs only with a medial bucket-handle; a displaced lateral fragment produces the double anterior horn sign instead.","topic":"Meniscus","joint":"knee"},
{"id":"d104","front":"How would you describe a meniscal root tear?","find":"Disruption of the [posterior/anterior] root attachment of the [medial/lateral] meniscus with the ghost sign (vertical linear high signal / cleft at the root with absent visualized root tissue), radial cleft at the insertion, and associated meniscal extrusion measuring ___ mm beyond the tibial margin. Subchondral marrow edema of the involved compartment.","impr":"[Medial/Lateral] posterior root tear with meniscal extrusion (___ mm).","pearl":"Medial posterior root tear behaves like a total meniscectomy and accelerates osteoarthritis; report extrusion in mm because >3 mm signifies functional incompetence.","topic":"Meniscus","joint":"knee"},
{"id":"d105","front":"How would you describe a meniscal ramp lesion?","find":"Increased T2/fluid signal at the meniscocapsular junction of the posterior horn of the medial meniscus with disruption of the meniscotibial (posterior coronary) ligament and posteromedial tibial marrow edema. Best seen on fluid-sensitive sagittal and axial images, frequently in the setting of an ACL tear.","impr":"Meniscal ramp lesion (meniscocapsular separation, posterior horn medial meniscus).","pearl":"Ramp lesions hide at the periphery and are strongly associated with ACL tears — scrutinize the posteromedial corner on every ACL injury.","topic":"Meniscus","joint":"knee"},
{"id":"d106","front":"How would you describe a parameniscal cyst?","find":"Well-defined T2-hyperintense, T1-hypointense cystic collection adjacent to the [medial/lateral] meniscus that communicates with a horizontal tear via a fluid-filled tract. Measures ___ x ___ mm. No internal solid enhancement.","impr":"Parameniscal cyst arising from a horizontal tear of the [medial/lateral] meniscus.","pearl":"Lateral parameniscal cysts can be large and present as a palpable mass; always trace the cyst back to its causative meniscal tear.","topic":"Meniscus","joint":"knee"},
{"id":"d107","front":"How would you describe a discoid meniscus?","find":"Abnormally enlarged, slab-like meniscus with three or more contiguous 5 mm sagittal bow-tie segments, transverse body width >15 mm, and coverage of >2/3 of the tibial plateau on coronal images. [Increased internal signal / horizontal tear] indicates associated degeneration or tear.","impr":"Discoid [lateral] meniscus [with associated tear].","pearl":"Discoid menisci are usually lateral and prone to tears in children; >2 bow-tie segments on consecutive 5 mm sagittals is the key threshold.","topic":"Meniscus","joint":"knee"},
{"id":"d108","front":"How would you describe a postoperative meniscal re-tear?","find":"In the postmeniscectomy/repair [medial/lateral] meniscus, fluid-equivalent high signal (matching joint fluid) extends into the meniscal substance to an articular surface, or a displaced fragment is present. Findings differ from intermediate granulation-tissue signal, indicating recurrent tear.","impr":"Recurrent tear of the postoperative [medial/lateral] meniscus.","pearl":"After meniscal surgery, only fluid-bright signal (T2) extending to the surface or a displaced fragment proves re-tear; intermediate signal alone may be granulation tissue. MR arthrogram improves specificity.","topic":"Meniscus","joint":"knee"},
{"id":"d109","front":"How would you describe meniscal extrusion?","find":"The [medial/lateral] meniscal body extends ___ mm beyond the edge of the tibial plateau (excluding osteophytes) on the mid-coronal image, measuring ≥3 mm, consistent with meniscal extrusion. Associated [root tear / radial tear / chondrosis].","impr":"[Medial/Lateral] meniscal extrusion (___ mm).","pearl":"Measure extrusion on the coronal slice through the MCL/tibial spines, exclude osteophytes from the tibial reference edge; ≥3 mm is significant.","topic":"Meniscus","joint":"knee"},
{"id":"d110","front":"How would you describe a normal meniscus?","find":"The [medial/lateral] meniscus demonstrates uniform low T1/T2 signal with a normal bow-tie configuration on peripheral sagittal slices, smooth triangular morphology of the anterior and posterior horns, intact free margins, and no surface-extending signal, displaced fragment, or extrusion.","impr":"Intact [medial/lateral] meniscus.","topic":"Meniscus","joint":"knee"},
{"id":"d111","front":"How would you describe an intrasubstance (grade 2) meniscal degeneration?","find":"Globular or linear intrameniscal increased signal that does NOT extend to an articular surface within the [medial/lateral] meniscus, consistent with myxoid/intrasubstance degeneration rather than a tear. Meniscal contour is preserved.","impr":"Intrasubstance (grade 2) degeneration without surface-extending tear.","pearl":"Only grade 3 signal (reaching an articular surface) is reported as a tear; grade 1-2 signal is degeneration and should not be called a tear.","topic":"Meniscus","joint":"knee"},
{"id":"d112","front":"How would you describe ICRS/modified Outerbridge grade 1 chondromalacia?","find":"Focal area of abnormal intrachondral increased T2 signal of the [patellar/femoral/tibial] articular cartilage with an intact, smooth chondral surface and no contour defect or thinning.","impr":"Grade 1 chondral signal heterogeneity, [location].","pearl":"Grade 1 is signal change only with an intact surface — no fissure, no thinning; describe location and avoid overcalling thinning.","topic":"Cartilage","joint":"knee"},
{"id":"d113","front":"How would you describe ICRS/modified Outerbridge grade 2 chondral lesion?","find":"Superficial chondral fibrillation/fissuring with surface irregularity and partial-thickness cartilage loss involving less than 50 percent of the cartilage depth at the [location]. Subchondral bone is intact.","impr":"Grade 2 partial-thickness chondral lesion (<50% depth), [location].","pearl":"Grade 2 = fissures/loss involving less than half the cartilage thickness; quantify depth as a percentage in the report.","topic":"Cartilage","joint":"knee"},
{"id":"d114","front":"How would you describe ICRS/modified Outerbridge grade 3 chondral lesion?","find":"Deep partial-thickness cartilage loss/fissuring extending greater than 50 percent of the cartilage depth but not exposing subchondral bone, with fluid undermining the involved [patellar/femoral/tibial] cartilage at the [location], measuring ___ mm in greatest dimension.","impr":"Grade 3 deep partial-thickness chondral defect (>50% depth, bone not exposed), [location].","pearl":"Grade 3 spans >50% depth down to (but not through) the subchondral plate; the distinction from grade 4 is whether bone is exposed.","topic":"Cartilage","joint":"knee"},
{"id":"d115","front":"How would you describe ICRS/modified Outerbridge grade 4 chondral lesion?","find":"Full-thickness cartilage loss with exposure of the subchondral bone (denuded bone) at the [location], measuring ___ x ___ mm, with [associated subchondral marrow edema / subchondral cyst]. Adjacent reactive subchondral sclerosis may be present.","impr":"Grade 4 full-thickness chondral defect with exposed subchondral bone, [location] (___ mm).","pearl":"Grade 4 means full-thickness loss to bone; always report defect size in mm because it dictates candidacy for cartilage restoration procedures.","topic":"Cartilage","joint":"knee"},
{"id":"d116","front":"How would you describe a chondral flap or cartilage delamination?","find":"Linear fluid signal undercutting the deep cartilage at the chondral-bone interface (delamination) with a partially detached cartilage flap that is elevated/displaced from the subchondral plate at the [location]. The overlying surface may appear intact (closed delamination).","impr":"Chondral delamination/flap at [location].","pearl":"Delamination can have a deceptively normal surface — look for the fluid-filled cleft at the cartilage-bone junction; it is unstable and surgically relevant.","topic":"Cartilage","joint":"knee"},
{"id":"d117","front":"How would you describe a cartilage defect with an associated subchondral cyst?","find":"Full-thickness chondral defect at the [location] overlying a well-defined T2-hyperintense subchondral cyst (geode) measuring ___ mm, with surrounding subchondral marrow edema and reactive sclerosis. The cyst communicates with the chondral defect.","impr":"Full-thickness chondral defect with underlying subchondral cyst, [location].","pearl":"Subchondral cysts form where joint fluid is forced through a full-thickness cartilage defect — their presence confirms overlying cartilage breakdown.","topic":"Cartilage","joint":"knee"},
{"id":"d118","front":"How would you describe an osteochondral defect (osteochondral lesion)?","find":"Focal defect involving both the articular cartilage and the underlying subchondral bone at the [weight-bearing femoral condyle/trochlea], measuring ___ x ___ x ___ mm, with subchondral marrow edema. [No / Presence of] an associated displaced osteochondral fragment.","impr":"Osteochondral defect of the [location] (___ mm).","pearl":"Osteochondral injury involves cartilage AND bone (unlike pure chondral); report all three dimensions and search the joint for a displaced osteochondral body.","topic":"Bone","joint":"knee"},
{"id":"d119","front":"How would you describe a STABLE osteochondritis dissecans (OCD) lesion?","find":"Osteochondral fragment at the classic lateral aspect of the medial femoral condyle measuring ___ mm with an overlying intact cartilage surface and NO high-T2 fluid signal undercutting the fragment-host interface. Sclerotic but stable margin.","impr":"Stable osteochondritis dissecans of the medial femoral condyle.","pearl":"Stability hinges on the fragment interface — intact cartilage and no fluid rim indicate stability; this is the single most important determinant for management.","topic":"Bone","joint":"knee"},
{"id":"d120","front":"How would you describe an UNSTABLE osteochondritis dissecans (OCD) lesion?","find":"Osteochondral fragment of the medial femoral condyle with a high-T2 fluid-signal line completely undercutting the fragment-host interface, cysts >5 mm at the interface, a focal cartilage defect/fracture overlying the fragment, and/or a displaced fragment with an empty donor crater.","impr":"Unstable osteochondritis dissecans of the [medial femoral condyle] [with displaced fragment].","pearl":"Four instability signs: encircling fluid line, subchondral cysts >5 mm, full-thickness cartilage breach, and fluid-filled focal defect — fluid undercutting is the most reliable.","topic":"Bone","joint":"knee"},
{"id":"d121","front":"How would you describe a subchondral insufficiency fracture of the knee (SIFK / formerly SONK)?","find":"Subchondral T2-hyperintense, T1-hypointose linear focus paralleling the articular surface of the [medial femoral condyle] with extensive surrounding marrow edema, an epicenter low-signal line, and [intact / focal collapse of] the overlying subchondral plate. No discrete fragment.","impr":"Subchondral insufficiency fracture (SIFK) of the [medial femoral condyle].","pearl":"SIFK (the entity formerly called spontaneous osteonecrosis, SONK) is actually an insufficiency fracture in older patients, often with an adjacent meniscal root tear; subchondral collapse predicts poor outcome.","topic":"Bone","joint":"knee"},
{"id":"d122","front":"How would you describe osteonecrosis / avascular necrosis of the femoral condyle?","find":"Serpiginous geographic subchondral lesion with a peripheral T1-low / T2 double-line sign (inner T2-bright granulation tissue, outer T2-dark sclerosis) in the [femoral condyle], with central marrow signal following fat or necrotic debris. [Subchondral collapse / crescent sign present or absent].","impr":"Osteonecrosis (AVN) of the [femoral condyle].","pearl":"The double-line sign is pathognomonic for AVN; distinguish from SIFK, which is subarticular and lacks the serpiginous double-line pattern.","topic":"Bone","joint":"knee"},
{"id":"d123","front":"How would you describe pivot-shift bone contusions?","find":"Bone marrow edema pattern (T2-hyperintense, T1-hypointense, ill-defined, non-cortical) involving the lateral femoral condyle (mid/sulcus terminalis) and the posterolateral tibial plateau, characteristic of the pivot-shift mechanism associated with an acute ACL tear.","impr":"Pivot-shift bone contusion pattern, consistent with ACL injury.","pearl":"This kissing-contusion pattern (lateral femoral condyle + posterolateral tibial plateau) is virtually diagnostic of ACL tear even before evaluating the ligament.","topic":"Bone","joint":"knee"},
{"id":"d124","front":"How would you describe a dashboard / hyperflexion bone contusion pattern?","find":"Bone marrow edema involving the anterior tibia from a direct anterior blow with the knee flexed (dashboard mechanism), associated with PCL injury; or kissing contusions of the anterior femoral condyle and anterior tibia in a hyperflexion mechanism.","impr":"Anterior tibial / dashboard contusion pattern, raising concern for PCL injury.","pearl":"Recognizing the contusion pattern points you to the at-risk ligament — anterior tibial edema should prompt close PCL evaluation.","topic":"Bone","joint":"knee"},
{"id":"d125","front":"How would you describe a clip / valgus (MCL) injury bone contusion pattern?","find":"Bone marrow edema of the lateral femoral condyle and lateral tibial plateau from a direct lateral valgus blow (clip injury), associated with medial collateral ligament injury (the O'Donoghue / unhappy triad mechanism).","impr":"Lateral compartment contusions from a valgus mechanism, with concern for MCL injury.","pearl":"A pure valgus blow drives the lateral structures together (impaction) while the medial side fails in tension (MCL) — the contusion side and the ligament-injury side are opposite.","topic":"Bone","joint":"knee"},
{"id":"d126","front":"How would you describe a tibial plateau impaction fracture?","find":"Depression/impaction of the [lateral] tibial plateau articular surface measuring ___ mm of depression with a subchondral fracture line, surrounding marrow edema, and overlying chondral injury. [Lipohemarthrosis present].","impr":"Impacted [lateral] tibial plateau fracture with ___ mm articular depression.","pearl":"Quantify articular step-off/depression in mm — >2-3 mm of depression often changes management toward surgical reduction; CT better characterizes the fragments.","topic":"Bone","joint":"knee"},
{"id":"d127","front":"How would you describe an occult / insufficiency fracture of the knee?","find":"Linear T1-hypointense, T2-hyperintense fracture line with surrounding marrow edema in the [proximal tibia / distal femur] without cortical disruption or displacement, not visible on radiographs. [Insufficiency type in osteopenic bone without significant trauma].","impr":"Occult [insufficiency] fracture of the [location].","pearl":"A discrete hypointense line within marrow edema distinguishes a true fracture from a contusion or transient edema; insufficiency fractures occur with normal stress on weak bone.","topic":"Bone","joint":"knee"},
{"id":"d128","front":"How would you describe transient bone marrow edema of the knee?","find":"Geographic, ill-defined T2-hyperintense / T1-hypointense marrow signal in the [femoral condyle/tibia] WITHOUT a discrete fracture line, subchondral collapse, double-line sign, or focal low-signal lesion. Overlying cartilage and subchondral plate are intact.","impr":"Transient bone marrow edema, [location].","pearl":"Diagnosis of exclusion — edema without a fracture line, AVN double-line, or collapse; usually self-limiting, but follow-up may be warranted to exclude evolving SIFK.","topic":"Bone","joint":"knee"},
{"id":"d129","front":"How would you describe a Baker (popliteal) cyst?","find":"Well-defined T2-hyperintense fluid collection extending between the medial head of gastrocnemius and the semimembranosus tendon, with a characteristic neck at that interval, measuring ___ x ___ x ___ mm. [Simple fluid / internal septations / loose bodies]. [Intact / ruptured with fluid tracking into the calf].","impr":"Baker (popliteal) cyst, [simple / complicated / ruptured].","pearl":"A true Baker cyst must have its neck between the medial gastrocnemius and semimembranosus; rupture produces a crescentic fluid collection dissecting inferiorly into the calf, mimicking DVT.","topic":"Synovial","joint":"knee"},
{"id":"d130","front":"How would you describe Hoffa fat pad impingement / edema?","find":"Ill-defined T2-hyperintense edema-like signal within the superolateral aspect of the Hoffa (infrapatellar) fat pad between the patellar tendon and lateral femoral condyle/trochlea, consistent with fat pad impingement. [Mass effect / maltracking].","impr":"Hoffa fat pad impingement (superolateral fat pad edema).","pearl":"Superolateral Hoffa edema is associated with patellar maltracking and a high-riding patella — assess patellar height and trochlear morphology.","topic":"Synovial","joint":"knee"},
{"id":"d131","front":"How would you describe a medial (mediopatellar) plica?","find":"Thin low-signal synovial fold arising from the medial wall of the joint and coursing toward the medial patellar facet, measuring ___ mm in thickness, best seen on axial images with a joint effusion. [Thickened/fibrotic with adjacent medial facet chondral wear suggesting symptomatic plica syndrome].","impr":"Medial plica [thickened, with adjacent chondral changes].","pearl":"A plica becomes pathologic when thickened/fibrotic with adjacent medial patellar facet chondrosis — report the chondral findings that support plica syndrome.","topic":"Synovial","joint":"knee"},
{"id":"d132","front":"How would you describe a lipohemarthrosis / fat-fluid level?","find":"Joint effusion with a horizontal fat-fluid (or fat-fluid-fluid) level in the suprapatellar recess on a cross-table/axial image, with supernatant fat (high T1, suppresses on fat-sat) above dependent serum and dependent hemorrhage, indicating an intra-articular fracture.","impr":"Lipohemarthrosis — implies an intra-articular fracture; scrutinize for a (radiographically occult) fracture.","pearl":"A fat-fluid level is a hard sign of an intra-articular fracture releasing marrow fat — even if no fracture is seen, recommend dedicated evaluation (CT).","topic":"Synovial","joint":"knee"},
{"id":"d133","front":"How would you describe pigmented villonodular synovitis (PVNS) / diffuse-type tenosynovial giant cell tumor?","find":"Lobulated synovial proliferation with characteristic blooming low-signal foci on gradient-echo/SWI sequences (hemosiderin), low-to-intermediate T1/T2 signal, frondlike villonodular masses, a joint effusion, and possible bony erosions on both sides of the joint.","impr":"Pigmented villonodular synovitis (diffuse TGCT).","pearl":"GRE blooming from hemosiderin is the key discriminator; PVNS does not contain calcification (unlike synovial chondromatosis) and characteristically causes pressure erosions.","topic":"Synovial","joint":"knee"},
{"id":"d134","front":"How would you describe an intra-articular loose body?","find":"Discrete intra-articular ___ mm body within a [posterior recess / suprapatellar pouch / intercondylar notch], with signal following [cartilage / ossified marrow fat with a sclerotic rim], freely mobile and outlined by joint fluid. [Donor osteochondral defect identified].","impr":"Intra-articular [osteochondral/chondral] loose body in the [location].","pearl":"Ossified bodies show fatty marrow signal with a peripheral cortical rim; purely cartilaginous bodies are subtle and best seen against an effusion — count and locate them, and seek the donor site.","topic":"Synovial","joint":"knee"},
{"id":"d135","front":"How would you describe a normal ulnar collateral ligament (anterior bundle)?","find":"The anterior bundle of the ulnar collateral ligament is a thin, taut, uniformly low-signal band extending from the inferior margin of the medial epicondyle to its insertion on the sublime tubercle of the medial coronoid. Fibers are continuous, smooth, and well defined, with no periligamentous edema. The sublime tubercle cortex is intact.","impr":"Normal anterior bundle of the UCL.","pearl":"The anterior bundle is the primary restraint to valgus stress and the most clinically relevant component to evaluate, especially in overhead-throwing athletes.","topic":"Ligaments","joint":"elbow"},
{"id":"d136","front":"How would you describe an anterior bundle UCL sprain (low grade)?","find":"Diffuse thickening and intermediate-to-increased intrasubstance T2 signal within the anterior bundle of the UCL with surrounding periligamentous edema. The ligament remains continuous from the medial epicondyle to the sublime tubercle without a discrete fiber gap or detachment.","impr":"Low-grade UCL sprain (grade I) without fiber discontinuity.","topic":"Ligaments","joint":"elbow"},
{"id":"d137","front":"How would you describe a partial undersurface (deep) tear of the anterior bundle UCL — the T sign?","find":"Increased T2 signal extending along the deep undersurface of the distal anterior bundle with contrast or joint fluid insinuating between the ligament and the sublime tubercle, producing the T sign on MR arthrography. The superficial fibers remain attached, and overall ligament continuity is maintained.","impr":"Partial-thickness undersurface (sublime tubercle) tear of the anterior bundle UCL — positive T sign.","pearl":"The T sign reflects fluid tracking distal to the sublime tubercle attachment; it is the classic appearance of a partial undersurface tear in throwing athletes and is best seen on MR arthrography or with a joint effusion.","topic":"Ligaments","joint":"elbow"},
{"id":"d138","front":"How would you describe a complete (full-thickness) tear of the anterior bundle UCL?","find":"Complete discontinuity of the anterior bundle UCL fibers with a fluid-filled gap and lax, wavy retracted ligament margins. The tear most commonly involves the [proximal humeral origin/distal sublime tubercle insertion]. There is associated periligamentous edema and hemorrhage, and increased valgus laxity of the ulnohumeral joint.","impr":"Complete (grade III) tear of the anterior bundle UCL.","pearl":"In professional throwers, the distal/sublime tubercle location and chronic attritional changes favor reconstruction (Tommy John) over repair.","topic":"Ligaments","joint":"elbow"},
{"id":"d139","front":"How would you describe a lateral ulnar collateral ligament (LUCL) tear at the humeral origin with posterolateral rotatory instability?","find":"Disruption and increased T2 signal of the LUCL at its origin from the lateral epicondyle with fiber discontinuity, laxity, and periligamentous edema. The ligament fails to course normally posterolateral to the radial head to insert on the supinator crest of the ulna. Findings indicate posterolateral rotatory instability (PLRI), often accompanied by associated common extensor tendon and lateral capsular injury.","impr":"LUCL tear at the humeral origin — posterolateral rotatory instability (PLRI).","pearl":"The LUCL is the primary restraint to PLRI; injury is the essential lesion of recurrent posterolateral instability and is frequently iatrogenic after lateral epicondylitis surgery or seen after elbow dislocation.","topic":"Ligaments","joint":"elbow"},
{"id":"d140","front":"How would you describe a normal annular ligament?","find":"The annular ligament is a thin uniformly low-signal band encircling the radial head and neck, attaching to the anterior and posterior margins of the radial notch of the ulna, maintaining congruent radiocapitellar and proximal radioulnar alignment without thickening, edema, or discontinuity.","impr":"Intact annular ligament with normal radial head containment.","pearl":"Annular ligament disruption or interposition is key in radial head subluxation/dislocation and in chronic proximal radioulnar instability.","topic":"Ligaments","joint":"elbow"},
{"id":"d141","front":"How would you describe common extensor tendinosis (lateral epicondylitis)?","find":"Thickening and intermediate-to-increased T1 and intermediate T2 signal within the common extensor tendon origin at the lateral epicondyle (predominantly the ECRB component) without a fluid-signal fiber gap. Tendon fibers remain in continuity. There is no significant adjacent marrow edema or LUCL involvement.","impr":"Common extensor tendinosis (lateral epicondylitis) without tear.","pearl":"Intermediate (not fluid-bright) signal that does not extend through the full tendon thickness distinguishes tendinosis from a tear; the ECRB is the most commonly involved.","topic":"Tendons","joint":"elbow"},
{"id":"d142","front":"How would you describe a partial-thickness tear of the common extensor tendon?","find":"Background tendinosis of the common extensor origin with a focal fluid-signal cleft on T2/PD involving a portion of the tendon thickness, measuring [X] mm in craniocaudal extent, without complete fiber detachment from the lateral epicondyle. Adjacent reactive marrow edema may be present.","impr":"Partial-thickness tear of the common extensor tendon superimposed on tendinosis.","topic":"Tendons","joint":"elbow"},
{"id":"d143","front":"How would you describe a full-thickness tear of the common extensor tendon?","find":"Complete fluid-filled gap through the full thickness of the common extensor origin with discontinuity and retraction of tendon fibers from the lateral epicondyle, measuring [X] mm. There is reactive marrow edema of the lateral epicondyle and often associated injury of the underlying LUCL/lateral collateral ligament complex.","impr":"Full-thickness tear of the common extensor tendon; assess associated LUCL injury.","pearl":"Always interrogate the LUCL when a full-thickness extensor tear is present — combined injury predisposes to posterolateral rotatory instability.","topic":"Tendons","joint":"elbow"},
{"id":"d144","front":"How would you describe common flexor tendinosis (medial epicondylitis / golfer's elbow)?","find":"Thickening and intermediate-to-increased intrasubstance signal of the common flexor-pronator tendon origin at the medial epicondyle without a full-thickness fluid-signal gap. Fibers remain in continuity. Evaluate the immediately deep anterior bundle UCL, which frequently shows concomitant injury.","impr":"Common flexor (flexor-pronator) tendinosis — medial epicondylitis.","pearl":"Medial epicondylitis and anterior bundle UCL injury commonly coexist; the ulnar nerve in the adjacent cubital tunnel should also be assessed.","topic":"Tendons","joint":"elbow"},
{"id":"d145","front":"How would you describe distal biceps tendinosis?","find":"Thickening and mild increased intrasubstance signal of the distal biceps tendon near the radial tuberosity insertion without a discrete fiber gap. The tendon remains continuous and there is no retraction. Mild bicipitoradial bursal fluid may be present.","impr":"Distal biceps tendinosis without tear.","pearl":"The FABS (flexed abducted supinated) view best displays the distal biceps tendon along its long axis for grading partial versus complete tears.","topic":"Tendons","joint":"elbow"},
{"id":"d146","front":"How would you describe a partial tear of the distal biceps tendon?","find":"Distal biceps tendinosis with a focal fluid-signal cleft involving a portion of the tendon thickness near the radial tuberosity, without complete detachment or retraction. There is associated bicipitoradial bursitis with bursal distension and surrounding edema.","impr":"Partial-thickness tear of the distal biceps tendon with bicipitoradial bursitis.","topic":"Tendons","joint":"elbow"},
{"id":"d147","front":"How would you describe a complete distal biceps tendon tear with retraction?","find":"Complete discontinuity of the distal biceps tendon at the radial tuberosity with a fluid- and hemorrhage-filled gap and proximal retraction of the tendon stump, retracted [X] cm proximal to the tuberosity. The status of the lacertus fibrosus determines the degree of retraction. Surrounding edema, hematoma, and bicipitoradial bursitis are present.","impr":"Complete distal biceps tendon rupture with [X] cm retraction; report lacertus fibrosus integrity.","pearl":"An intact lacertus fibrosus limits retraction and can mask the rupture clinically; reporting the retraction distance and lacertus status guides surgical timing and approach.","topic":"Tendons","joint":"elbow"},
{"id":"d148","front":"How would you describe triceps tendinosis and a partial triceps tear?","find":"Thickening and increased intrasubstance signal of the distal triceps tendon at the olecranon insertion with mild fraying. A partial tear shows a focal fluid-signal cleft involving part of the tendon thickness without complete detachment from the olecranon; a small avulsed osseous fleck may be seen.","impr":"Triceps tendinosis with partial-thickness tear at the olecranon insertion.","topic":"Tendons","joint":"elbow"},
{"id":"d149","front":"How would you describe a complete triceps tendon avulsion?","find":"Complete discontinuity of the distal triceps tendon at the olecranon with a fluid-filled gap and proximal retraction of the tendon, retracted [X] cm. An avulsed osseous flake from the olecranon is frequently present (flake sign). Surrounding hemorrhage and edema are noted.","impr":"Complete triceps tendon avulsion from the olecranon with retraction.","pearl":"A small avulsed osseous fragment posterior to the distal humerus on radiographs (flake sign) is highly suggestive of complete triceps rupture.","topic":"Tendons","joint":"elbow"},
{"id":"d150","front":"How would you describe a stable osteochondritis dissecans of the capitellum?","find":"A focal subchondral lesion of the anterolateral capitellum with low T1 signal and an intact overlying articular cartilage surface. No high T2 signal line or fluid undercutting the fragment, no cystic interface, and no displaced osteochondral body. Stability criteria are not met for instability.","impr":"Stable osteochondritis dissecans of the capitellum.","pearl":"OCD typically affects adolescent throwers/gymnasts and involves the anterolateral capitellum; stability hinges on cartilage integrity and absence of a fluid line beneath the fragment.","topic":"Cartilage/Bone","joint":"elbow"},
{"id":"d151","front":"How would you describe an unstable osteochondritis dissecans of the capitellum?","find":"Capitellar osteochondral lesion with a high T2 signal line completely undercutting the fragment, cystic foci at the interface, overlying cartilage fissuring/defect, and/or a displaced osteochondral fragment within the joint. Fluid surrounding the fragment indicates loss of fixation.","impr":"Unstable osteochondritis dissecans of the capitellum.","pearl":"A T2-hyperintense rim or cyst-like foci beneath the fragment, cartilage breach, and intra-articular bodies are the key instability signs.","topic":"Cartilage/Bone","joint":"elbow"},
{"id":"d152","front":"How would you describe Panner disease?","find":"Diffuse low T1 and high T2/STIR marrow signal involving the capitellar ossification center in a young child (typically under 10 years) with maintained cartilage and articular contour, without fragmentation or intra-articular bodies. Findings reflect osteochondrosis with subsequent revascularization.","impr":"Panner disease (osteochondrosis of the capitellum).","pearl":"Panner disease occurs in younger children and is self-limited with restitution of the capitellum, in contradistinction to OCD in older adolescents which can fragment and destabilize.","topic":"Cartilage/Bone","joint":"elbow"},
{"id":"d153","front":"How would you describe a radial head fracture, including the occult fracture with fat pad signs?","find":"A radial head fracture line with low signal and adjacent marrow edema; when nondisplaced, the fracture may be occult on radiographs with only a joint effusion. There is elevation of the anterior fat pad (sail sign) and a visible posterior fat pad, indicating a hemarthrosis. Assess articular step-off and fragment displacement.","impr":"Radial head fracture; positive fat pad signs indicating hemarthrosis.","pearl":"In an adult with elbow trauma, a displaced anterior fat pad (sail sign) or any visible posterior fat pad implies an occult intra-articular fracture, most commonly of the radial head.","topic":"Cartilage/Bone","joint":"elbow"},
{"id":"d154","front":"How would you describe an olecranon stress reaction/fracture?","find":"Linear or geographic marrow edema (low T1, high STIR) within the olecranon, with or without a discrete low-signal stress fracture line oriented [transverse/oblique], without displacement. Periosteal edema may be present. Findings are consistent with chronic repetitive valgus extension overload.","impr":"Olecranon stress reaction/fracture from repetitive overload.","pearl":"Olecranon stress injury is part of the throwing athlete's valgus extension overload spectrum and may coexist with posteromedial impingement and UCL injury.","topic":"Cartilage/Bone","joint":"elbow"},
{"id":"d155","front":"How would you describe a supracondylar fracture with joint effusion and fat pad signs?","find":"A supracondylar humeral fracture line with surrounding marrow and soft-tissue edema, accompanied by a tense joint effusion that elevates the anterior fat pad (sail sign) and displaces the posterior fat pad. Evaluate angulation, displacement, and integrity of the anterior humeral line.","impr":"Supracondylar fracture with hemarthrosis and positive fat pad signs.","pearl":"Supracondylar fracture is the most common pediatric elbow fracture; in children, fat pad signs plus disruption of the anterior humeral line raise concern for an occult fracture.","topic":"Cartilage/Bone","joint":"elbow"},
{"id":"d156","front":"How would you describe ulnar neuritis / cubital tunnel syndrome?","find":"Enlargement (caliber increase) and increased T2/STIR signal of the ulnar nerve within the cubital tunnel posterior to the medial epicondyle, with loss of the normal fascicular pattern. There may be associated nerve subluxation over the medial epicondyle and crowding of the cubital tunnel. Assess for denervation edema in the flexor carpi ulnaris/medial forearm musculature.","impr":"Ulnar neuropathy at the cubital tunnel (cubital tunnel syndrome).","pearl":"Nerve caliber enlargement plus T2 hyperintensity and downstream denervation muscle edema are the most reliable MRI signs of clinically significant ulnar neuropathy.","topic":"Nerve","joint":"elbow"},
{"id":"d157","front":"How would you describe posterior interosseous nerve (PIN) / radial tunnel syndrome?","find":"Increased T2 signal and mild caliber enlargement of the posterior interosseous nerve as it passes through the radial tunnel and the arcade of Frohse at the proximal supinator. Denervation edema or fatty change may be evident in the supinator and the wrist/finger extensor compartment. Evaluate for a compressive mass such as a ganglion or lipoma.","impr":"Posterior interosseous neuropathy (radial tunnel syndrome).","pearl":"The arcade of Frohse at the proximal edge of the supinator is the classic compression point; PIN palsy produces extensor denervation while sparing the ECRL.","topic":"Nerve","joint":"elbow"},
{"id":"d158","front":"How would you describe a denervation muscle edema pattern in the elbow/forearm?","find":"Diffuse T2/STIR hyperintensity within a muscle group conforming to a single peripheral nerve territory, with preserved muscle architecture in the acute/subacute phase; chronic denervation shows fatty infiltration and volume loss. The distribution localizes the affected nerve ([ulnar/radial-PIN/median]).","impr":"Subacute (or chronic) denervation in a [named] nerve distribution.","pearl":"Edema confined to one nerve's muscle territory is the imaging hallmark of denervation and helps localize the level and identity of the compressed nerve.","topic":"Nerve","joint":"elbow"},
{"id":"d159","front":"How would you describe olecranon bursitis?","find":"Distension of the olecranon bursa superficial to the olecranon by fluid signal, with [simple/complex] internal content, synovial thickening, and peribursal soft-tissue edema. Enhancement and complex debris suggest an inflammatory or infected/septic bursitis; rice bodies or hyperintense crystalline foci may indicate gout or chronic inflammatory bursitis.","impr":"Olecranon bursitis; assess for septic versus inflammatory etiology.","topic":"Other","joint":"elbow"},
{"id":"d160","front":"How would you describe an intra-articular (loose) body in the elbow?","find":"A discrete intra-articular body following [ossified/cartilaginous] signal, typically lodged in the anterior coronoid fossa or posterior olecranon fossa, outlined by joint fluid. There is an associated joint effusion. Search for a corresponding donor osteochondral defect (e.g., capitellar OCD).","impr":"Intra-articular body; correlate with osteochondral donor site.","pearl":"The coronoid and olecranon fossae are the favored resting sites for loose bodies; correlate with capitellar OCD or osteoarthritis as the source.","topic":"Other","joint":"elbow"},
{"id":"d161","front":"How would you describe valgus extension overload with posteromedial impingement?","find":"Posteromedial olecranon osteophytosis with subchondral marrow edema and chondral wear along the posteromedial olecranon and trochlea, an associated joint effusion, and frequently an osteochondral loose body in the olecranon fossa. There is commonly concurrent anterior bundle UCL attenuation/injury reflecting the throwing-athlete kinetic chain.","impr":"Valgus extension overload syndrome with posteromedial impingement.","pearl":"The classic triad in throwers is UCL insufficiency, posteromedial olecranon osteophyte/chondral wear, and loose bodies; the valgus instability drives the posteromedial impingement.","topic":"Other","joint":"elbow"},
{"id":"d162","front":"How would you describe a normal anterior talofibular ligament (ATFL)?","find":"The ATFL is identified as a thin, uniform low-signal band coursing from the anterior margin of the lateral malleolus to the talar neck, best seen on axial images at the level of the malleolar fossa. Fibers are taut, continuous, and of uniform caliber without thickening, intrasubstance T2 hyperintensity, or surrounding edema. No joint effusion or capsular disruption.","impr":"Intact, normal ATFL.","pearl":"The ATFL is the weakest and most commonly injured lateral ligament; it is best evaluated on axial images with the foot in neutral or slight plantarflexion.","topic":"Lateral Ligaments","joint":"ankle"},
{"id":"d163","front":"How would you describe a grade I ATFL sprain?","find":"Periligamentous edema and increased T2 signal surrounding the ATFL with preserved fiber continuity, uniform caliber, and normal taut morphology. No fiber attenuation, discontinuity, or laxity. The ligament remains a continuous low-signal band from the lateral malleolus to the talar neck.","impr":"Grade I (mild) ATFL sprain — ligamentous stretch without fiber disruption.","topic":"Lateral Ligaments","joint":"ankle"},
{"id":"d164","front":"How would you describe a grade II ATFL sprain?","find":"Thickening and intrasubstance T2 hyperintensity of the ATFL with partial-thickness fiber disruption and surrounding periligamentous edema. The ligament demonstrates an irregular, wavy contour but maintains overall continuity. No complete gap or frank discontinuity. Associated small lateral gutter joint effusion may be present.","impr":"Grade II (partial-thickness) ATFL tear.","topic":"Lateral Ligaments","joint":"ankle"},
{"id":"d165","front":"How would you describe a grade III (complete) ATFL tear?","find":"Complete discontinuity of the ATFL fibers with a fluid-filled gap between the torn ends and adjacent periligamentous and soft-tissue edema. The ligament is wavy, lax, or non-visualized. Associated joint effusion extending into the lateral gutter, with possible bone contusion of the lateral talus or fibula. Evaluate for concomitant CFL injury.","impr":"Grade III (complete) ATFL tear.","pearl":"In acute inversion injury the ATFL tears first; with progressive force the CFL tears next, then the PTFL. Isolated PTFL tear is rare.","topic":"Lateral Ligaments","joint":"ankle"},
{"id":"d166","front":"How would you describe a calcaneofibular ligament (CFL) tear?","find":"Thickening, intrasubstance T2 hyperintensity, and fiber discontinuity of the CFL, which normally courses deep to the peroneal tendons from the fibular tip to the lateral calcaneus. Fluid surrounds and displaces the overlying peroneus longus and brevis tendons. Associated peroneal tenosynovitis and lateral gutter effusion. Coronal images best demonstrate the tear.","impr":"CFL tear, commonly accompanying ATFL injury.","pearl":"Fluid tracking around the peroneal tendons in the setting of inversion injury is a useful secondary sign of CFL disruption, since the CFL forms the floor of the peroneal tendon sheath.","topic":"Lateral Ligaments","joint":"ankle"},
{"id":"d167","front":"How would you describe a posterior talofibular ligament (PTFL) injury?","find":"Thickening and increased T2 signal within the normally striated PTFL extending from the malleolar fossa to the posterolateral talus, with partial or complete fiber disruption and surrounding edema. Best assessed on axial images. Isolated injury is uncommon and implies a high-energy inversion mechanism with associated ATFL and CFL disruption.","impr":"PTFL injury — indicates severe lateral ligamentous complex disruption.","pearl":"The PTFL has a normal striated/fibrillated appearance due to interposed fat and fibrous tissue; do not mistake this for a tear.","topic":"Lateral Ligaments","joint":"ankle"},
{"id":"d168","front":"How would you describe chronic lateral ligament scarring?","find":"Thickening, irregularity, and intermediate signal of the ATFL and/or CFL without surrounding acute edema, reflecting chronic post-traumatic remodeling. The ligament may appear attenuated, elongated, or replaced by ill-defined scar tissue. No acute periligamentous fluid. Associated chronic synovial thickening in the lateral gutter and findings of mechanical instability.","impr":"Chronic lateral ligamentous scarring and laxity from prior inversion injury.","topic":"Lateral Ligaments","joint":"ankle"},
{"id":"d169","front":"How would you describe a high ankle sprain (syndesmotic injury)?","find":"Increased T2 signal, thickening, and partial or complete fiber disruption of the anterior inferior tibiofibular ligament (AITFL) and/or interosseous ligament with surrounding edema and fluid in the syndesmotic recess extending more than 1 cm above the tibial plafond. Widening of the tibiofibular clear space >6 mm on axial images. Evaluate for proximal fibular (Maisonneuve) fracture.","impr":"Syndesmotic (high ankle) sprain.","pearl":"Fluid in the syndesmosis extending >1 cm above the plafond and tibiofibular clear space >6 mm are key signs; always check the proximal fibula for a Maisonneuve fracture.","topic":"Syndesmosis","joint":"ankle"},
{"id":"d170","front":"How would you describe an anterior inferior tibiofibular ligament (AITFL) tear?","find":"Thickening, waviness, and intrasubstance T2 hyperintensity of the AITFL with partial or complete fiber discontinuity and surrounding edema in the anterior syndesmotic recess. Best seen on axial images at the level of the tibial plafond. The normal multifascicular low-signal band is disrupted. Assess for tibiofibular clear space widening and PITFL involvement.","impr":"AITFL tear — most commonly injured syndesmotic component.","topic":"Syndesmosis","joint":"ankle"},
{"id":"d171","front":"How would you describe a posterior inferior tibiofibular ligament (PITFL) injury?","find":"Thickening and increased T2 signal within the PITFL with partial or complete fiber disruption at the posterolateral tibia and fibula, accompanied by edema in the posterior syndesmotic recess. May be associated with an avulsion fracture of the posterior malleolus (posterior tibial tubercle). PITFL injury indicates more severe syndesmotic disruption.","impr":"PITFL injury, indicating advanced syndesmotic instability.","pearl":"The PITFL is the strongest syndesmotic ligament; injury often manifests as a posterior malleolar avulsion rather than midsubstance tear.","topic":"Syndesmosis","joint":"ankle"},
{"id":"d172","front":"How would you describe a normal superficial deltoid ligament?","find":"The superficial deltoid is identified as a fan-shaped band of low-signal fibers extending from the medial malleolus to the navicular, spring ligament, sustentaculum tali, and talus, with normal interposed fat producing a striated appearance on coronal images. Fibers are continuous and of uniform thickness without intrasubstance T2 hyperintensity or surrounding edema.","impr":"Intact superficial deltoid ligament.","pearl":"The striated appearance of the superficial deltoid is normal and should not be mistaken for a tear.","topic":"Medial Ligaments","joint":"ankle"},
{"id":"d173","front":"How would you describe a deltoid ligament sprain?","find":"Thickening, periligamentous edema, and increased T2 signal involving the superficial and/or deep deltoid fibers with preserved continuity, consistent with a low-grade sprain. No frank fiber gap or avulsion. Coronal images demonstrate intact but edematous fibers from the medial malleolus to the talus and sustentaculum.","impr":"Deltoid ligament sprain without complete disruption.","topic":"Medial Ligaments","joint":"ankle"},
{"id":"d174","front":"How would you describe a deep deltoid (tibiotalar) ligament tear?","find":"Complete discontinuity and fluid-filled gap within the deep deltoid (anterior and posterior tibiotalar) fibers between the medial malleolus and talus, with surrounding edema and medial gutter effusion. Widening of the medial clear space. Often associated with lateral malleolar/syndesmotic injury or pronation-external rotation mechanism.","impr":"Deep deltoid ligament tear with medial clear space widening.","pearl":"In a bimalleolar-equivalent injury, a deltoid tear takes the place of a medial malleolar fracture; medial clear space widening >4 mm signals instability requiring surgical attention.","topic":"Medial Ligaments","joint":"ankle"},
{"id":"d175","front":"How would you describe a spring (plantar calcaneonavicular) ligament tear?","find":"Thickening, intrasubstance T2 hyperintensity, and partial or complete fiber disruption of the superomedial spring ligament between the sustentaculum tali and the navicular, best seen on axial and coronal images. Loss of the normal low-signal band beneath the talar head with surrounding edema. Frequently associated with posterior tibial tendon dysfunction and acquired pes planovalgus.","impr":"Spring ligament tear contributing to medial longitudinal arch collapse.","pearl":"The spring ligament supports the talar head; its failure, in concert with PTT dysfunction, drives progressive adult acquired flatfoot deformity.","topic":"Medial Ligaments","joint":"ankle"},
{"id":"d176","front":"How would you describe posterior tibial tendon dysfunction stage I (tenosynovitis)?","find":"Circumferential fluid within the posterior tibial tendon sheath with preserved tendon caliber, morphology, and low signal, consistent with tenosynovitis. The tendon courses normally posterior to the medial malleolus without thickening, attenuation, or intrasubstance tear. Normal hindfoot alignment and medial longitudinal arch.","impr":"Stage I posterior tibial tendon dysfunction (tenosynovitis) without tendon degeneration.","pearl":"A small amount of fluid in the PTT sheath can be physiologic; pathologic tenosynovitis shows circumferential fluid disproportionate to other tendon sheaths.","topic":"Tendons","joint":"ankle"},
{"id":"d177","front":"How would you describe posterior tibial tendon dysfunction stage II?","find":"Tendinosis with thickening (>6 mm) or attenuation of the posterior tibial tendon, intrasubstance T2 hyperintensity, and longitudinal partial-thickness splitting, accompanied by tenosynovial fluid. Associated spring ligament attenuation and a flexible pes planovalgus deformity with hindfoot valgus and forefoot abduction. Subfibular impingement may be present.","impr":"Stage II posterior tibial tendon dysfunction with flexible flatfoot deformity.","pearl":"Stage II is the most common surgical stage; the deformity is still flexible/reducible, distinguishing it from rigid stage III.","topic":"Tendons","joint":"ankle"},
{"id":"d178","front":"How would you describe a complete posterior tibial tendon rupture (stage III/IV)?","find":"Complete discontinuity of the posterior tibial tendon with a fluid-filled gap, tendon retraction, and an empty tendon sheath posterior to the medial malleolus. Rigid pes planovalgus with hindfoot valgus, talonavicular uncoverage, and lateral subfibular impingement. In stage IV, valgus tilt of the talus within the ankle mortise with lateral tibiotalar degenerative change.","impr":"Complete posterior tibial tendon rupture with rigid flatfoot (stage III), or with ankle valgus deformity (stage IV).","pearl":"Stage IV is defined by valgus angulation of the talus in the mortise and tibiotalar joint degeneration, distinguishing it from the rigid but mortise-preserved stage III.","topic":"Tendons","joint":"ankle"},
{"id":"d179","front":"How would you describe a peroneus brevis longitudinal split tear?","find":"Boomerang or chevron-shaped flattening of the peroneus brevis tendon at the retromalleolar groove, split into two distinct fragments by an interposed, often centrally positioned, peroneus longus tendon. Linear intrasubstance T2 hyperintensity along the tendon axis on axial images. Associated peroneal tenosynovitis, low-lying peroneus brevis muscle belly, or a peroneus quartus accessory muscle.","impr":"Longitudinal (split) tear of the peroneus brevis at the retromalleolar groove.","pearl":"Predisposing factors include a convex/shallow retromalleolar groove, a torn or lax superior peroneal retinaculum, and a low-lying peroneus brevis muscle belly.","topic":"Tendons","joint":"ankle"},
{"id":"d180","front":"How would you describe peroneal tendon subluxation with superior peroneal retinaculum (SPR) injury?","find":"Anterolateral displacement of the peroneus brevis and/or longus tendons over or anterior to the lateral malleolus with stripping, thickening, or avulsion of the superior peroneal retinaculum from its fibular attachment. Cortical avulsion (rim) fracture of the posterolateral fibula may be present. Associated peroneal tenosynovitis and a flat or convex retromalleolar groove.","impr":"Peroneal tendon subluxation/dislocation due to superior peroneal retinaculum disruption.","pearl":"A fibular rim avulsion fracture is the classic plain-film and MRI clue to SPR avulsion and recurrent peroneal subluxation.","topic":"Tendons","joint":"ankle"},
{"id":"d181","front":"How would you describe a peroneus longus tear with os peroneum dysfunction?","find":"Thickening, intrasubstance T2 hyperintensity, and partial or complete fiber disruption of the peroneus longus distal to the os peroneum at the cuboid tunnel, with tenosynovial fluid. Proximal retraction of the os peroneum or diastasis of a bipartite os peroneum indicates complete rupture (painful os peroneum syndrome). Edema within the os peroneum and adjacent plantar lateral foot.","impr":"Peroneus longus tear with painful os peroneum syndrome.","topic":"Tendons","joint":"ankle"},
{"id":"d182","front":"How would you describe Achilles tendinosis?","find":"Fusiform thickening of the Achilles tendon with loss of its normally flat or concave anterior margin and intermediate intrasubstance signal that does not reach fluid intensity, typically 2-6 cm above the calcaneal insertion in the hypovascular watershed zone. No fiber discontinuity or tendon gap. Absence of a true acute tear; no peritendinous fluid.","impr":"Mid-substance Achilles tendinosis (non-insertional).","pearl":"The watershed zone 2-6 cm proximal to the insertion is hypovascular and the most common site of degeneration and rupture.","topic":"Tendons","joint":"ankle"},
{"id":"d183","front":"How would you describe a partial-thickness Achilles tendon tear?","find":"Background tendinosis with focal intrasubstance fluid-signal clefts and partial fiber disruption involving a portion of the tendon cross-section, without complete discontinuity. The tendon remains in continuity with intact remaining fibers. Surrounding peritendinous edema. Quantify the percentage of cross-sectional involvement.","impr":"Partial-thickness Achilles tendon tear superimposed on tendinosis.","topic":"Tendons","joint":"ankle"},
{"id":"d184","front":"How would you describe a complete (full-thickness) Achilles tendon rupture?","find":"Complete discontinuity of the Achilles tendon fibers with a fluid- and hemorrhage-filled gap, typically in the watershed zone 2-6 cm above the calcaneal insertion. Report the gap measurement (e.g., [X] cm) with the ankle in neutral, the degree of tendon-end retraction, and the morphology of the frayed, retracted stumps. Associated hematoma and loss of normal Achilles tension. Note any plantaris tendon, which may remain intact.","impr":"Complete Achilles tendon rupture; gap [X] cm with tendon retraction.","pearl":"Report the gap distance in plantarflexion and neutral — apposition of tendon ends in plantarflexion may favor nonoperative management.","topic":"Tendons","joint":"ankle"},
{"id":"d185","front":"How would you describe insertional Achilles tendinopathy with Haglund deformity?","find":"Thickening and intrasubstance signal of the distal Achilles at its calcaneal insertion with insertional enthesophyte formation and adjacent intratendinous or insertional partial tearing. Prominent posterosuperior calcaneal tuberosity (Haglund deformity) with retrocalcaneal bursitis (fluid in the retrocalcaneal recess), Achilles insertional bone marrow edema, and superficial (retro-Achilles) bursitis.","impr":"Insertional Achilles tendinopathy with Haglund deformity and retrocalcaneal bursitis.","pearl":"The Haglund triad: prominent posterosuperior calcaneal tuberosity, retrocalcaneal bursitis, and insertional Achilles tendinopathy.","topic":"Tendons","joint":"ankle"},
{"id":"d186","front":"How would you describe flexor hallucis longus (FHL) tenosynovitis?","find":"Circumferential fluid distending the flexor hallucis longus tendon sheath as it courses through the fibro-osseous tunnel between the posterolateral and posteromedial talar tubercles, with or without tendinosis. Fluid may communicate with the tibiotalar joint. Frequently seen in dancers (en pointe). Evaluate for an os trigonum or posterior impingement as a contributing cause.","impr":"FHL tenosynovitis, the dancer's tendinitis.","pearl":"FHL tendon sheath fluid can communicate with the ankle joint in up to 20% of people; isolated sheath distension without tendon abnormality may be physiologic.","topic":"Tendons","joint":"ankle"},
{"id":"d187","front":"How would you describe a stable osteochondral lesion of the talar dome?","find":"Focal subchondral marrow edema and a low-signal osteochondral fragment at the talar dome (classically medial in posteromedial or lateral in anterolateral location) with an intact overlying cartilage surface and no high-signal fluid undercutting the fragment interface. Report size (AP x transverse x depth in mm) and location. No displaced fragment or intra-articular body.","impr":"Stable osteochondral lesion of the talar dome.","pearl":"Medial talar dome lesions are typically deeper/cup-shaped and more posterior; lateral lesions are shallower/wafer-shaped, more anterior, and more often unstable.","topic":"Osteochondral/Bone","joint":"ankle"},
{"id":"d188","front":"How would you describe an unstable osteochondral lesion of the talar dome?","find":"Osteochondral lesion of the talar dome with high T2-signal fluid completely undermining the fragment-host interface (fluid cleft sign), a surrounding cyst >5 mm, overlying cartilage fracture/defect, or a displaced fragment within the joint. Report size, location, and the specific instability sign. Associated subchondral marrow edema and joint effusion.","impr":"Unstable osteochondral lesion of the talar dome.","pearl":"A linear T2-hyperintense rim fully encircling the fragment indicates instability; if it mirrors signal of the joint effusion it represents fluid rather than granulation tissue.","topic":"Osteochondral/Bone","joint":"ankle"},
{"id":"d189","front":"How would you describe a talar/calcaneal stress fracture?","find":"Ill-defined bone marrow edema with a linear low-signal fracture line oriented perpendicular to the trabeculae on T1 and fluid-sensitive sequences, without cortical break or displacement. In the calcaneus, the line typically parallels the posterior tuberosity; in the talus, the neck or body. No discrete fracture on prior radiographs. Surrounding periosteal/endosteal reactive edema.","impr":"Stress fracture with surrounding marrow edema.","pearl":"A discrete low-signal fracture line distinguishes a true stress fracture from a stress reaction (marrow edema without a line).","topic":"Osteochondral/Bone","joint":"ankle"},
{"id":"d190","front":"How would you describe nonspecific bone marrow edema of the ankle?","find":"Geographic, ill-defined T1-hypointense and fluid-sensitive hyperintense marrow signal without a discrete fracture line, cortical disruption, or subchondral collapse. Report distribution and any associated overlying chondral or ligamentous abnormality. Differential includes contusion, stress response, transient osteoporosis, early osteonecrosis, and reactive edema adjacent to impingement.","impr":"Nonspecific bone marrow edema; correlate with mechanism and chronicity.","topic":"Osteochondral/Bone","joint":"ankle"},
{"id":"d191","front":"How would you describe anterolateral soft-tissue impingement of the ankle?","find":"Nodular or masslike intermediate-signal scar/synovial tissue filling the anterolateral gutter between the talus and fibula, often with low-signal fibrotic foci and adjacent capsular thickening. Best appreciated with a joint effusion or on post-contrast/arthrographic images. Sequela of prior ATFL injury. No discrete loose body.","impr":"Anterolateral soft-tissue (meniscoid) impingement.","pearl":"The anterolateral gutter normally contains fat; replacement by intermediate-signal scar tissue in a patient with chronic lateral ankle pain after inversion injury supports impingement.","topic":"Impingement/Sinus Tarsi","joint":"ankle"},
{"id":"d192","front":"How would you describe posterior ankle impingement with os trigonum syndrome?","find":"Bone marrow edema within an os trigonum or a prominent posterolateral talar (Stieda) process, edema across the os trigonum-talus synchondrosis, and surrounding soft-tissue/capsular edema in the posterior recess. Associated flexor hallucis longus tenosynovitis. Symptoms provoked by plantarflexion (dancers, soccer players).","impr":"Posterior ankle impingement syndrome with symptomatic os trigonum.","pearl":"Edema spanning the os trigonum synchondrosis plus FHL tenosynovitis in a plantarflexion athlete is the classic combination.","topic":"Impingement/Sinus Tarsi","joint":"ankle"},
{"id":"d193","front":"How would you describe sinus tarsi syndrome?","find":"Replacement of the normal fat within the sinus tarsi by ill-defined intermediate to low T1 signal and fluid-sensitive hyperintense edema or fibrosis, with disruption of the interosseous talocalcaneal and cervical ligaments. Frequently associated with posterior tibial tendon dysfunction, lateral ligament injury, or hindfoot malalignment.","impr":"Sinus tarsi syndrome with obliteration of the normal sinus tarsi fat.","pearl":"Loss of the normal T1-bright fat in the sinus tarsi is the hallmark; assess the interosseous and cervical ligaments for tear and look for associated PTT or lateral ligament pathology.","topic":"Impingement/Sinus Tarsi","joint":"ankle"},
{"id":"d194","front":"How would you describe anterior bony impingement of the ankle?","find":"Osteophytes projecting from the anterior distal tibial plafond and the talar neck that approximate on dorsiflexion, with adjacent reactive bone marrow edema and anterior capsular/synovial thickening. A kissing-osteophyte configuration may be present. Anterior joint effusion and possible intra-articular ossific body.","impr":"Anterior bony (athlete's ankle) impingement with anterior tibiotalar osteophytes.","pearl":"Anterior tibial and talar neck osteophytes are common in footballers and dancers from repetitive forced dorsiflexion.","topic":"Impingement/Sinus Tarsi","joint":"ankle"},
{"id":"d195","front":"How would you describe a talocalcaneal tarsal coalition?","find":"Osseous, cartilaginous, or fibrous bridging across the middle subtalar facet at the sustentaculum tali, with downsloping/dysmorphic sustentaculum, narrowing/irregularity of the facet, reactive subchondral marrow edema and cystic change, and absence of the normal joint space. Talar beaking and hindfoot valgus may be present. Specify osseous (continuous marrow) versus non-osseous (irregular sclerotic margins) type.","impr":"Talocalcaneal coalition at the middle facet.","pearl":"Subtalar marrow edema and a dysplastic, downsloping sustentaculum (the C-sign correlate) point to a non-osseous middle-facet coalition.","topic":"Coalition/Tarsal Tunnel","joint":"ankle"},
{"id":"d196","front":"How would you describe a calcaneonavicular tarsal coalition?","find":"Abnormal osseous, cartilaginous, or fibrous bridging between the anterior process of the calcaneus and the navicular, with elongation of the anterior calcaneal process (the anteater nose sign) and reactive marrow edema/cystic change at a non-osseous bar. Sagittal and axial images best demonstrate the coalition. Associated hindfoot valgus.","impr":"Calcaneonavicular coalition.","pearl":"The elongated anterior calcaneal process producing the anteater nose sign on the lateral radiograph and sagittal MRI is characteristic.","topic":"Coalition/Tarsal Tunnel","joint":"ankle"},
{"id":"d197","front":"How would you describe tarsal tunnel syndrome?","find":"A space-occupying lesion within the tarsal tunnel deep to the flexor retinaculum compressing the posterior tibial nerve, such as a ganglion cyst, varicosities, accessory muscle, lipoma, or perineural fibrosis. Denervation edema or fatty atrophy of the abductor hallucis, abductor digiti minimi, and quadratus plantae innervated by the tibial nerve branches. Report the compressive lesion and the muscles affected.","impr":"Tarsal tunnel syndrome with posterior tibial nerve compression.","pearl":"Look for denervation change in the intrinsic plantar muscles; a ganglion or varicosities are the most common identifiable causes.","topic":"Coalition/Tarsal Tunnel","joint":"ankle"},
{"id":"d198","front":"How would you describe a plantaris tendon abnormality?","find":"Thickening, increased signal, or discontinuity of the small plantaris tendon coursing between the medial gastrocnemius and soleus, with surrounding edema/fluid in the interval. An isolated plantaris rupture or strain produces fluid tracking along the medial gastrocnemius-soleus interface (tennis leg) while the Achilles remains intact.","impr":"Plantaris tendon strain/rupture; the Achilles is intact.","pearl":"An intact plantaris tendon may be preserved as a discrete cord within the gap of a complete Achilles rupture; conversely, isolated plantaris rupture is a cause of tennis leg.","topic":"Tendons","joint":"ankle"},
{"id":"d199","front":"How would you describe a normal plantar plate of the second MTP joint?","find":"The plantar plate appears as a homogeneously low-signal fibrocartilaginous structure on all sequences, with a uniform low-signal distal attachment to the base of the proximal phalanx. No T2 hyperintense fluid cleft, attenuation, or discontinuity is identified. The collateral ligaments and flexor tendon are intact, and the MTP joint is congruently aligned without subluxation.","impr":"Intact second MTP plantar plate.","pearl":"The normal plate inserts on the proximal phalangeal base (not the metatarsal head); a small physiologic recess of fluid at the metatarsal attachment is normal and should not be called a tear.","topic":"Forefoot","joint":"foot"},
{"id":"d200","front":"How would you describe a grade 2-3 plantar plate tear of the second MTP joint?","find":"Partial-thickness disruption of the plantar plate at its distal insertion onto the base of the second proximal phalanx, with focal T2 hyperintense fluid signal extending into the substance of the plate and attenuation/thinning of its fibers. The flexor tendon remains located plantar to the plate. Mild dorsal subluxation of the proximal phalanx is present. Findings correspond to Yao/anatomic grade 2-3 with a partial distal tear.","impr":"Partial-thickness distal plantar plate tear, second MTP joint, with mild dorsal subluxation.","pearl":"Grade is determined by the extent of insertional detachment; the distal (phalangeal) attachment is the most common site of tearing and the key location to scrutinize on sagittal and short-axis images.","topic":"Forefoot","joint":"foot"},
{"id":"d201","front":"How would you describe a complete (grade 4) plantar plate tear of the second MTP joint?","find":"Full-thickness discontinuity of the plantar plate with a fluid-filled gap at the phalangeal insertion and retraction of the plate fibers. There is dorsal dislocation/marked dorsal subluxation of the proximal phalanx with a positive drawer configuration, and associated lateral deviation of the second toe (crossover toe). The collateral ligaments are also disrupted, and there is reactive synovitis and intermetatarsal soft-tissue edema.","impr":"Complete plantar plate rupture, second MTP joint, with dorsal dislocation and crossover-toe deformity.","pearl":"Complete tears commonly coexist with collateral ligament disruption, producing the crossover-toe; always assess both the lateral collateral ligament and the contralateral second-toe alignment.","topic":"Forefoot","joint":"foot"},
{"id":"d202","front":"How would you describe turf toe (first MTP plantar plate/sesamoid complex injury)?","find":"Disruption of the plantar plate-sesamoid complex of the first MTP joint with T2 hyperintense edema and partial fiber discontinuity at the plantar plate, and edema or avulsion at the sesamoidophalangeal ligament. There is proximal retraction of a sesamoid (increased sesamoid-to-joint distance compared with the contralateral side), bone marrow edema of the sesamoids and first metatarsal head, and capsular edema. Hyperextension mechanism is supported.","impr":"Turf toe — plantar plate/sesamoid complex injury of the first MTP joint.","pearl":"A grade III injury shows complete capsuloligamentous rupture with proximal sesamoid migration; a diastasis of a bipartite sesamoid or proximal pole retraction is a clue to plantar plate avulsion.","topic":"Forefoot","joint":"foot"},
{"id":"d203","front":"How would you describe a Morton neuroma?","find":"A well-defined, ovoid, teardrop-shaped mass centered in the [second/third] intermetatarsal space at the plantar aspect of the intermetatarsal ligament, measuring [size] mm in transverse diameter, demonstrating low-to-intermediate T1 and characteristically LOW T2 signal due to fibrous content, with avid homogeneous post-contrast enhancement. It is contiguous with the plantar digital nerve and produces a positive Mulder configuration with plantar displacement on the short-axis images.","impr":"Morton neuroma of the [third] intermetatarsal space.","pearl":"A transverse diameter >5 mm correlates with symptomatic lesions; the low T2 signal (perineural fibrosis, not a true neoplasm) distinguishes a neuroma from an intermetatarsal bursa, which is T2 bright.","topic":"Forefoot","joint":"foot"},
{"id":"d204","front":"How would you describe intermetatarsal bursitis?","find":"A well-circumscribed fluid-signal collection in the [second/third] intermetatarsal space, T2 hyperintense and T1 hypointense, located DORSAL to the intermetatarsal ligament, with thin peripheral enhancement and a non-enhancing fluid center. It measures [size] mm and may show a teardrop shape but lacks the solid low-T2 fibrous tissue of a neuroma.","impr":"Intermetatarsal bursitis.","pearl":"Position relative to the deep transverse intermetatarsal ligament helps: bursae lie dorsal and are T2 bright with peripheral enhancement; Morton neuromas lie plantar and are T2 dark with solid enhancement. Bursal distension <3 mm can be physiologic in the first and second spaces.","topic":"Forefoot","joint":"foot"},
{"id":"d205","front":"How would you describe sesamoiditis of the first MTP joint?","find":"Diffuse bone marrow edema within the [medial/tibial or lateral/fibular] hallucal sesamoid, T1 hypointense and T2/STIR hyperintense, with preserved cortical margins and normal sesamoid contour, accompanied by surrounding plantar soft-tissue edema and mild first MTP joint effusion. No discrete fracture line or fragmentation is identified.","impr":"Sesamoiditis of the [medial] hallucal sesamoid.","pearl":"Sesamoiditis is a marrow-edema diagnosis of exclusion; look for an absent fracture line, intact contour, and preserved fragment perfusion to separate it from acute fracture and AVN.","topic":"Forefoot","joint":"foot"},
{"id":"d206","front":"How would you describe a sesamoid stress fracture versus AVN of the hallucal sesamoid?","find":"Stress fracture: a linear T1/T2 hypointense fracture line traversing the [medial] sesamoid with surrounding marrow edema and intact overall perfusion. AVN: fragmentation, irregular flattening, and patchy or globally LOW T1 and LOW T2 signal of the sesamoid with loss of normal marrow fat and absent enhancement of devitalized fragments, with collapse of the cortical contour.","impr":"Hallucal sesamoid [stress fracture / osteonecrosis].","pearl":"Diffuse low T2 plus fragmentation and non-enhancement favor AVN; a discrete low-signal line with bright surrounding edema and preserved enhancement favors a stress fracture. A smooth, corticated bipartite sesamoid is a normal variant, not a fracture.","topic":"Forefoot","joint":"foot"},
{"id":"d207","front":"How would you describe hallux valgus on MRI?","find":"Lateral deviation of the great toe at the first MTP joint with an increased hallux valgus angle (>15 degrees) and an increased first-second intermetatarsal angle (>9 degrees), lateral subluxation of the sesamoids relative to the crista, medial first metatarsal head osteophyte/eminence with overlying medial bursitis, and attenuation of the medial collateral ligament with thickening of the lateral structures. Associated second-toe overload changes may be present.","impr":"Hallux valgus deformity with lateral sesamoid subluxation.","pearl":"Lateral sesamoid subluxation off the crista is the key driver of recurrence after surgery; report sesamoid station and the intermetatarsal angle.","topic":"Forefoot","joint":"foot"},
{"id":"d208","front":"How would you describe Freiberg infraction?","find":"Subchondral collapse and flattening of the [second] metatarsal head with low T1 and variable T2 marrow signal, articular surface irregularity, an intra-articular osteochondral fragment, secondary MTP joint effusion and synovitis, and widening/deformity of the metatarsal head. Reactive sclerosis of the residual head is present in chronic cases.","impr":"Freiberg infraction (osteochondrosis) of the [second] metatarsal head.","pearl":"Most commonly affects the second metatarsal head; the flattened, collapsed articular surface distinguishes it from a simple subchondral stress reaction.","topic":"Forefoot","joint":"foot"},
{"id":"d209","front":"How would you describe a Lisfranc ligament injury on MRI?","find":"Disruption of the dorsal and/or interosseous Lisfranc ligament between the medial cuneiform (C1) and the base of the second metatarsal (M2), with T2 hyperintense edema, fiber laxity or frank discontinuity, and diastasis of the C1-M2 interval (>2 mm) with malalignment of the medial M2 base relative to the medial border of the middle cuneiform. Bone marrow edema at the bases of the first and second metatarsals and the cuneiforms is present.","impr":"Lisfranc ligamentous injury with C1-M2 diastasis.","pearl":"The plantar (interosseous) component is the most important for stability; an intact dorsal band with a torn plantar band can still be unstable, so assess all three bundles and consider weight-bearing radiographs.","topic":"Midfoot","joint":"foot"},
{"id":"d210","front":"How would you describe a Lisfranc fleck sign and its MRI correlate?","find":"A small bony avulsion fragment (fleck sign) is identified within the C1-M2 interval, representing avulsion at the Lisfranc ligament attachment, with adjacent T2 hyperintense ligament edema and marrow edema at the donor site on the medial cuneiform or second metatarsal base. There is associated tarsometatarsal malalignment and dorsal soft-tissue edema.","impr":"Lisfranc ligament avulsion (fleck sign) with tarsometatarsal instability.","pearl":"The fleck sign is pathognomonic of a Lisfranc injury; even a tiny avulsion fragment signifies a potentially unstable midfoot requiring surgical evaluation.","topic":"Midfoot","joint":"foot"},
{"id":"d211","front":"How would you describe midfoot (tarsometatarsal) osteoarthritis?","find":"Joint space narrowing, subchondral sclerosis and cyst formation, and marginal osteophytes at the tarsometatarsal and intertarsal joints, most pronounced at the second and third TMT joints, with low-grade subchondral marrow edema, dorsal osteophyte ridging, and overlying soft-tissue/bursal edema. No acute fracture or diastasis.","impr":"Midfoot (tarsometatarsal) osteoarthritis, most severe at the second-third TMT joints.","pearl":"Post-traumatic OA following an occult Lisfranc injury classically centers on the second TMT joint; dorsal osteophytes can compress the deep peroneal nerve and dorsalis pedis.","topic":"Midfoot","joint":"foot"},
{"id":"d212","front":"How would you describe a symptomatic type II accessory navicular?","find":"A type II accessory navicular (os tibiale externum) is present, joined to the navicular tuberosity by a fibrocartilaginous synchondrosis. There is bone marrow edema on both sides of the synchondrosis (in the accessory ossicle and the adjacent navicular) with T2 hyperintensity across the synchondrosis, consistent with chronic stress/incipient micromotion. The distal posterior tibialis tendon inserts onto the accessory ossicle with associated tendinosis.","impr":"Symptomatic type II accessory navicular with synchondrosis stress reaction.","pearl":"Marrow edema flanking the synchondrosis is the imaging hallmark of a symptomatic os tibiale externum; the posterior tibialis tendon insertion onto the ossicle predisposes to dysfunction.","topic":"Midfoot","joint":"foot"},
{"id":"d213","front":"How would you describe a navicular stress fracture?","find":"A vertically oriented, sagittal stress fracture line in the central-to-lateral third of the navicular, T1 and T2 hypointense, with surrounding ill-defined marrow edema (T2/STIR hyperintense). In higher grades there is a complete fracture line extending to both the dorsal and plantar cortices with sclerosis along the margins. No significant fragment displacement.","impr":"Navicular stress fracture (high-risk site).","pearl":"The central third is a watershed zone, making this a high-risk (prone to nonunion) stress fracture; sagittal orientation and central location are characteristic, and CT best defines cortical extension for management.","topic":"Midfoot","joint":"foot"},
{"id":"d214","front":"How would you describe Charcot neuroarthropathy of the midfoot?","find":"Marked destruction, fragmentation, and dislocation centered at the tarsometatarsal/midfoot (Lisfranc) joints with subluxation producing a rocker-bottom deformity, diffuse periarticular bone marrow edema, joint effusions, debris and osseous fragments, and surrounding soft-tissue edema, all in a typically neuropathic (diabetic) patient. Subchondral cysts and sclerosis indicate chronicity. No rim-enhancing fluid collection, sinus tract, or focal cortical 'ghost' to suggest superimposed osteomyelitis.","impr":"Charcot neuroarthropathy of the midfoot (active phase).","pearl":"Distinguishing Charcot from osteomyelitis: Charcot centers on joints with multifocal involvement and lacks a skin defect/sinus tract; osteomyelitis follows an ulcer, shows the 'ghost sign,' and demonstrates secondary signs (abscess, sinus tract, cellulitis) tracking to bone.","topic":"Midfoot","joint":"foot"},
{"id":"d215","front":"How would you describe plantar fasciitis?","find":"Fusiform thickening of the proximal plantar fascia at its calcaneal origin measuring [>4] mm (normal <4 mm), with intrasubstance T2/STIR hyperintensity, perifascial edema in the adjacent fat, and reactive marrow edema at the calcaneal enthesis. The fascia remains in continuity without a discrete tear.","impr":"Plantar fasciitis (proximal plantar fasciopathy).","pearl":"A proximal fascial thickness greater than 4 mm is the key quantitative threshold; perifascial and calcaneal enthesal edema support an active inflammatory process.","topic":"Plantar","joint":"foot"},
{"id":"d216","front":"How would you describe a partial versus complete tear of the plantar fascia?","find":"Partial tear: focal high-T2 fluid cleft and partial fiber discontinuity within a thickened plantar fascia, usually near the calcaneal origin, with surrounding perifascial edema and intact remaining fibers. Complete tear: full-thickness discontinuity with a fluid-filled gap, frayed retracted fascial margins, marked perifascial and adjacent muscle edema, and loss of the normal taut low-signal band.","impr":"[Partial-thickness / full-thickness] plantar fascia tear.","pearl":"Acute plantar fascia rupture is often associated with prior corticosteroid injection or athletic push-off injury; assess for a fluid gap and retraction to distinguish from severe fasciitis.","topic":"Plantar","joint":"foot"},
{"id":"d217","front":"How would you describe plantar fibromatosis (Ledderhose disease)?","find":"One or more nodular, fusiform masses arising along the plantar aponeurosis, typically at the medial cord and superficial to the fascia, T1 isointense-to-low and characteristically LOW-to-intermediate T2 signal due to fibrous (collagen) content, with variable mild enhancement. Lesions are often multiple and may infiltrate adjacent plantar fat with a 'fascial tail' along the aponeurosis.","impr":"Plantar fibromatosis (Ledderhose disease).","pearl":"Low T2 signal reflects dense collagen; multiplicity, bilaterality, and contiguity with the plantar aponeurosis distinguish fibromatosis from a discrete soft-tissue sarcoma.","topic":"Plantar","joint":"foot"},
{"id":"d218","front":"How would you describe a solitary plantar fibroma?","find":"A solitary well-defined nodule along the plantar aponeurosis measuring [size] cm, T1 hypointense-to-isointense and predominantly LOW T2 signal, contiguous with and arising from the plantar fascia, with a tail-like extension along the aponeurosis and mild heterogeneous enhancement. No aggressive marrow or cortical involvement.","impr":"Plantar fibroma arising from the plantar aponeurosis.","pearl":"The 'fascial tail sign' (linear extension along the aponeurosis) and low T2 signal are characteristic and help confirm the fibrous, benign nature.","topic":"Plantar","joint":"foot"},
{"id":"d219","front":"How would you describe a calcaneal stress fracture?","find":"A linear band of low T1/T2 signal oriented perpendicular to the trabecular lines and parallel to the posterior calcaneal cortex, with surrounding ill-defined STIR/T2 hyperintense marrow edema in the posterior calcaneal tuberosity. No cortical disruption or displacement. Findings are consistent with an insufficiency/fatigue fracture.","impr":"Calcaneal stress (insufficiency) fracture.","pearl":"The fracture line classically runs vertically/obliquely in the posterior tuberosity perpendicular to the trabeculae; marrow edema may be the only early finding before a discrete line appears.","topic":"Hindfoot","joint":"foot"},
{"id":"d220","front":"How would you describe a benign calcaneal bone cyst (intraosseous lipoma/simple cyst)?","find":"A well-defined lucent lesion in the central calcaneal neutral triangle with a thin sclerotic rim, no aggressive features, no cortical breakthrough, and no soft-tissue mass. A simple unicameral cyst follows fluid signal (low T1, high T2); an intraosseous lipoma shows internal fat signal that suppresses on fat-saturated sequences, often with a central calcified nidus (T2 hypointense focus).","impr":"Benign calcaneal [intraosseous lipoma / simple bone cyst].","pearl":"The calcaneal neutral triangle is a relatively trabeculae-sparse region prone to pseudocysts; internal fat signal that follows subcutaneous fat on all sequences confirms an intraosseous lipoma.","topic":"Hindfoot","joint":"foot"},
{"id":"d221","front":"How would you describe retrocalcaneal bursitis?","find":"Distension of the retrocalcaneal bursa with T2 hyperintense fluid in the recess between the anterior Achilles tendon and the posterosuperior calcaneus, measuring greater than the physiologic limit (AP >1 mm, transverse >11 mm, craniocaudal >7 mm), with thin synovial enhancement, adjacent Achilles insertional tendinosis, and reactive marrow edema in the posterosuperior calcaneal tuberosity (Haglund deformity). Kager fat pad edema may be present.","impr":"Retrocalcaneal bursitis with insertional Achilles tendinosis.","pearl":"Haglund syndrome links a prominent posterosuperior calcaneal tuberosity, retrocalcaneal bursitis, and insertional Achilles tendinosis; distinguish the deep retrocalcaneal bursa from the superficial (subcutaneous) Achilles bursa.","topic":"Hindfoot","joint":"foot"},
{"id":"d222","front":"How would you describe flexor hallucis longus (FHL) tenosynovitis/tendinosis at the foot?","find":"Tendon thickening and intrasubstance intermediate signal of the flexor hallucis longus with fluid distending the tendon sheath along its course through the fibro-osseous tunnel between the talar tubercles and beneath the sustentaculum tali, extending toward the knot of Henry. There may be partial longitudinal splitting and reactive synovitis. Because the FHL sheath communicates with the tibiotalar joint in many patients, an ankle effusion may be present.","impr":"Flexor hallucis longus tenosynovitis (dancer's tendon).","pearl":"Fluid in the FHL sheath can simply reflect communication with the ankle joint; call tenosynovitis only when the fluid is disproportionate or there is tendon thickening/synovial enhancement. At the knot of Henry, FHL and FDL intersect and can develop adhesions.","topic":"Hindfoot","joint":"foot"},
{"id":"d223","front":"How would you describe a metatarsal (march) stress fracture?","find":"A transverse low-signal fracture line in the diaphysis/distal shaft of the [second or third] metatarsal with surrounding circumferential periosteal edema, endosteal callus, and intramedullary T2/STIR hyperintense marrow edema. No displacement. Findings are consistent with a fatigue (march) fracture.","impr":"Metatarsal march (fatigue) stress fracture, [second metatarsal].","pearl":"The second and third metatarsal shafts are the classic march-fracture sites; periosteal edema and the transverse line distinguish a stress fracture from an osteoid osteoma or tumor.","topic":"Hindfoot","joint":"foot"},
{"id":"d224","front":"How would you describe a Jones fracture versus a pseudo-Jones (avulsion) fracture of the fifth metatarsal?","find":"Jones fracture: a transverse fracture at the metaphyseal-diaphyseal junction of the fifth metatarsal, within 1.5 cm distal to the tuberosity, involving the fourth-fifth intermetatarsal articulation, with marrow edema and a transverse low-signal line — a watershed zone prone to nonunion. Pseudo-Jones: an avulsion fracture at the base/tuberosity at the insertion of the peroneus brevis, oriented transverse-to-the-shaft, proximal to the intermetatarsal joint.","impr":"[Jones fracture at the metadiaphyseal junction / pseudo-Jones tuberosity avulsion] of the fifth metatarsal.","pearl":"Location drives prognosis: the Jones fracture (zone 2) sits in a vascular watershed and risks nonunion, whereas the avulsion (zone 1) heals well; do not mistake the normal apophysis (oriented parallel to the shaft) or the os vesalianum for a fracture.","topic":"Hindfoot","joint":"foot"},
{"id":"d225","front":"How would you describe plantar vein thrombosis of the foot?","find":"A distended, non-compressible plantar vein with intraluminal T1/T2 intermediate-to-hyperintense thrombus and absent flow void, located within the plantar musculature (commonly the lateral plantar veins), surrounded by perivenous soft-tissue edema and mild stranding. Adjacent muscles are normal in bulk without abscess.","impr":"Plantar vein thrombosis.","pearl":"An underrecognized cause of plantar foot pain mimicking plantar fasciitis or a soft-tissue mass; look for a tubular structure following a venous course with internal thrombus rather than a true soft-tissue lesion.","topic":"Hindfoot","joint":"foot"},
{"id":"d226","front":"How would you describe a soft-tissue ganglion of the foot?","find":"A well-defined, lobulated, T1 hypointense and markedly T2 hyperintense (near-fluid) cystic lesion adjacent to a tarsal/tarsometatarsal joint or tendon sheath, with a thin or absent wall, no internal solid enhancing nodule, and thin peripheral rim enhancement only. A neck/pedicle may be seen connecting it to the adjacent joint or sheath.","impr":"Soft-tissue ganglion cyst of the foot.","pearl":"A traceable neck to a joint or tendon sheath plus uniform fluid signal without solid enhancement confirms a ganglion; solid internal enhancement should prompt consideration of a soft-tissue neoplasm.","topic":"Hindfoot","joint":"foot"},
{"id":"d227","front":"How would you describe a Palmer 1A traumatic central TFCC perforation?","find":"Focal full-thickness defect within the central thin avascular disc of the triangular fibrocartilage, seen as a linear fluid-signal cleft on coronal T2/PD fat-saturated images extending from the proximal (ulnar) to distal (radial) surface. The peripheral ulnar attachment to the fovea and styloid and the radial attachment at the sigmoid notch are intact. No ulnar-sided fluid extravasation into the DRUJ beyond expected, and the ulnar variance is neutral.","impr":"Palmer class 1A traumatic central perforation of the TFCC disc.","pearl":"1A is the central avascular zone and is not amenable to repair (debridement only); always report whether the peripheral vascular zone is intact since that determines reparability.","topic":"TFCC","joint":"wrist"},
{"id":"d228","front":"How would you describe a Palmer 1B peripheral/ulnar foveal TFCC avulsion?","find":"Disruption of the deep and superficial limbs of the radioulnar ligaments at their foveal insertion on the ulna, with fluid signal undercutting the foveal footprint and loss of the normal low-signal striated attachment (positive foveal sign). On coronal PD fat-saturated images there is increased T2 signal and discontinuity at the ulnar periphery of the TFC. The DRUJ may demonstrate widening/instability. The central disc is intact.","impr":"Palmer class 1B peripheral (foveal) TFCC tear; assess for associated DRUJ instability.","pearl":"The foveal attachment is the key stabilizer of the DRUJ; peripheral 1B tears are vascularized and reparable, unlike central 1A tears.","topic":"TFCC","joint":"wrist"},
{"id":"d229","front":"How would you describe a Palmer 1C distal TFCC (ulnocarpal ligament) tear?","find":"Disruption of the distal volar attachment of the TFCC, involving the ulnolunate and/or ulnotriquetral ligaments, with abnormal T2 hyperintensity and discontinuity of these volar fascicles. The proximal radioulnar ligament attachment and central disc remain intact. May be associated with ulnar-sided volar instability.","impr":"Palmer class 1C tear of the distal ulnocarpal (ulnolunate/ulnotriquetral) ligament complex.","topic":"TFCC","joint":"wrist"},
{"id":"d230","front":"How would you describe a Palmer 1D radial-sided TFCC avulsion?","find":"Avulsion of the radial attachment of the triangular fibrocartilage from the sigmoid notch of the distal radius, with fluid signal and discontinuity at the radial margin of the disc, with or without a small osseous fragment from the sigmoid notch. The peripheral ulnar/foveal attachment is preserved.","impr":"Palmer class 1D traumatic avulsion of the TFCC from its radial (sigmoid notch) attachment.","topic":"TFCC","joint":"wrist"},
{"id":"d231","front":"How would you describe ulnar impaction syndrome (Palmer class 2 degenerative TFCC)?","find":"Positive ulnar variance with degenerative thinning and central perforation of the TFC disc. Subchondral cystic change and marrow edema in the proximal ulnar aspect of the lunate (and often the opposing ulnar head and triquetrum), with chondromalacia of the apposing surfaces. Spectrum follows the Palmer 2A-2E stages: 2A TFCC wear without perforation, 2B with lunate/ulnar chondromalacia, 2C with TFCC perforation, 2D with lunotriquetral ligament perforation, 2E with ulnocarpal/DRUJ arthritis.","impr":"Ulnar impaction (abutment) syndrome; Palmer class 2 degenerative TFCC with positive ulnar variance.","pearl":"Lunate marrow edema in the proximal ulnar corner plus positive ulnar variance is the imaging signature; load-bearing position (pronated grip) worsens variance.","topic":"TFCC","joint":"wrist"},
{"id":"d232","front":"How would you describe a normal intact triangular fibrocartilage complex?","find":"Uniformly low-signal homogeneous triangular disc interposed between the ulnar head and the proximal lunate/triquetrum, with intact radial attachment at the sigmoid notch and intact ulnar attachment via the deep and superficial limbs to the fovea and styloid. No fluid-signal clefts, no surface fraying. Neutral ulnar variance. Intermediate signal at the ulnar attachment representing the ligamentum subcruentum is normal and should not be mistaken for a tear.","impr":"Intact triangular fibrocartilage complex without tear.","pearl":"The ligamentum subcruentum (loose vascular tissue at the foveal insertion) shows intermediate signal and is a common pitfall mimicking a 1B tear.","topic":"TFCC","joint":"wrist"},
{"id":"d233","front":"How would you describe a complete scapholunate interosseous ligament tear with DISI?","find":"Complete disruption of all three components of the scapholunate ligament, including the critical dorsal band, with fluid signal traversing the entire interval and absence of the normal low-signal ligament. Widening of the scapholunate interval >3 mm (Terry-Thomas sign) on coronal images. Rotary subluxation of the scaphoid with the cortical ring sign. Dorsal intercalated segment instability with dorsiflexed lunate: scapholunate angle >60 degrees (normal 30-60) and capitolunate angle >30 degrees.","impr":"Complete scapholunate ligament tear with rotary scaphoid subluxation and DISI deformity.","pearl":"The dorsal band is the strongest and most important biomechanical component; an isolated dorsal band tear is the most clinically significant.","topic":"Wrist ligaments","joint":"wrist"},
{"id":"d234","front":"How would you describe a partial (grade I-II) scapholunate ligament tear?","find":"Focal increased T2 signal and attenuation within the scapholunate ligament, most often involving the membranous/volar portion, with an intact or only partially attenuated dorsal band. The scapholunate interval measures <3 mm and there is no carpal malalignment; scapholunate angle remains 30-60 degrees. No cortical ring sign.","impr":"Partial-thickness scapholunate ligament tear without static instability.","topic":"Wrist ligaments","joint":"wrist"},
{"id":"d235","front":"How would you describe a lunotriquetral ligament tear with VISI?","find":"Disruption of the lunotriquetral interosseous ligament with fluid signal and loss of the normal low-signal C-shaped ligament across the LT interval. Volar intercalated segment instability with volar (palmar) tilt of the lunate: scapholunate angle <30 degrees and capitolunate angle increased volarly. The lunate follows the triquetrum into flexion. The scaphoid and SL ligament remain intact.","impr":"Lunotriquetral ligament tear with VISI deformity.","pearl":"VISI = volar-flexed lunate from LT disruption; DISI = dorsiflexed lunate from SL disruption. Remember the lunate tips toward the intact side.","topic":"Wrist ligaments","joint":"wrist"},
{"id":"d236","front":"How would you describe an acute scaphoid waist fracture?","find":"Transverse low-signal fracture line through the mid (waist) of the scaphoid with surrounding ill-defined marrow edema (T1 hypointense, T2/STIR hyperintense) on both fracture margins. No fracture-line sclerosis, cyst formation, or gap. Both poles enhance and demonstrate preserved marrow signal indicating maintained vascularity. No humpback (volar flexion) deformity.","impr":"Acute nondisplaced scaphoid waist fracture with surrounding marrow edema.","pearl":"MRI is the gold standard for the radiographically occult scaphoid fracture; edema on both sides of the line favors acute over chronic/nonunion.","topic":"Carpal bones","joint":"wrist"},
{"id":"d237","front":"How would you describe a scaphoid nonunion (SNAC wrist)?","find":"Persistent fracture line through the scaphoid waist with sclerotic, well-corticated margins and an intervening gap, without bridging trabeculae. Humpback deformity with volar flexion of the distal fragment and dorsal angulation. Secondary scaphoid nonunion advanced collapse (SNAC) arthritic change progressing from the radial styloid-scaphoid articulation to the scaphocapitate and midcarpal joints, with sparing of the radiolunate joint.","impr":"Established scaphoid waist nonunion with humpback deformity and early SNAC arthrosis.","pearl":"SNAC mirrors SLAC arthritis but starts from a scaphoid fracture; the radiolunate joint is characteristically preserved in both.","topic":"Carpal bones","joint":"wrist"},
{"id":"d238","front":"How would you describe scaphoid proximal pole avascular necrosis?","find":"Diffuse low T1 signal throughout the proximal pole of the scaphoid that fails to enhance after gadolinium, indicating devascularization. Variable T2 signal depending on chronicity (low in sclerotic late-stage, high if revascularizing). May accompany a waist fracture/nonunion. Eventual fragmentation and collapse of the proximal pole.","impr":"Avascular necrosis of the scaphoid proximal pole.","pearl":"The scaphoid receives retrograde blood supply via the dorsal carpal branch entering distally, so proximal pole fractures are at high risk for AVN; non-enhancement after contrast is the most specific sign.","topic":"Carpal bones","joint":"wrist"},
{"id":"d239","front":"How would you describe Kienbock disease (lunate osteonecrosis) and its stages?","find":"Osteonecrosis of the lunate, frequently associated with negative ulnar variance. Lichtman staging: Stage I - normal radiographs with diffuse low T1/high T2 marrow edema and possible linear fracture; Stage II - lunate sclerosis (low T1 and low T2) without collapse; Stage IIIA - lunate collapse without fixed scaphoid rotation; Stage IIIB - lunate collapse with fixed scaphoid rotation and carpal height loss; Stage IV - secondary radiocarpal and midcarpal osteoarthritis.","impr":"Kienbock disease (lunate avascular necrosis), Lichtman stage [I/II/IIIA/IIIB/IV].","pearl":"Negative ulnar variance is a predisposing factor; early disease (stage I) is occult on radiographs and only detected by MRI marrow signal change.","topic":"Carpal bones","joint":"wrist"},
{"id":"d240","front":"How would you describe a hook of hamate fracture?","find":"Low-signal fracture line through the base of the hook (hamulus) of the hamate with surrounding marrow edema on STIR/fat-saturated T2 images. Best seen on axial images at the level of the carpal tunnel. Assess for displacement, nonunion (sclerotic margins), and proximity to the ulnar nerve in Guyon canal and the flexor tendons of the small finger (risk of attritional rupture).","impr":"Fracture of the hook of the hamate.","pearl":"Classic in golfers, racquet and baseball/bat athletes from the butt of the handle; watch for ulnar nerve symptoms and flexor tendon attrition rupture.","topic":"Carpal bones","joint":"wrist"},
{"id":"d241","front":"How would you describe SLAC (scapholunate advanced collapse) wrist?","find":"Predictable pattern of degenerative arthritis following chronic scapholunate ligament insufficiency. Stage I: arthrosis between the radial styloid and distal scaphoid. Stage II: arthrosis involving the entire radioscaphoid articulation. Stage III: capitolunate (midcarpal) joint arthrosis with proximal migration of the capitate into the SL gap. The radiolunate joint is characteristically spared throughout. Associated DISI alignment.","impr":"Scapholunate advanced collapse (SLAC) wrist, stage [I/II/III].","pearl":"The radiolunate joint is spared because the lunate fossa is congruent and well-supported; this preservation guides surgical planning (proximal row carpectomy vs four-corner fusion).","topic":"Carpal bones","joint":"wrist"},
{"id":"d242","front":"How would you describe ECU tendinosis versus a longitudinal split tear?","find":"Tendinosis: enlargement of the extensor carpi ulnaris tendon with intrasubstance intermediate T2 signal but no discrete fluid cleft, often with peritendinous fluid. Tenosynovitis: circumferential fluid within the ECU tendon sheath. Split (longitudinal) tear: linear longitudinally oriented fluid-signal cleft dividing the tendon into two slips, often with surrounding tenosynovitis. Evaluate the position within the ulnar groove and the integrity of the overlying subsheath.","impr":"ECU [tendinosis/tenosynovitis/longitudinal split tear].","topic":"Wrist tendons","joint":"wrist"},
{"id":"d243","front":"How would you describe ECU subluxation/dislocation due to subsheath injury?","find":"Disruption of the fibro-osseous subsheath overlying the ulnar groove, with medial/volar-ulnar displacement of the extensor carpi ulnaris tendon out of its groove on the dorsal ulna. The tendon lies medial to the ulnar styloid rather than within the osseous groove. Best demonstrated in supination; often dynamic. Associated tendinosis or split tearing of the ECU and TFCC injury are common.","impr":"ECU subluxation secondary to subsheath (linea jugata) disruption.","pearl":"ECU instability is best provoked with the forearm in supination, ulnar deviation, and wrist flexion; a shallow/convex ulnar groove predisposes.","topic":"Wrist tendons","joint":"wrist"},
{"id":"d244","front":"How would you describe de Quervain tenosynovitis?","find":"Thickening and fluid distension of the tendon sheath of the first extensor compartment containing the abductor pollicis longus and extensor pollicis brevis, with peritendinous edema and enhancement at the level of the radial styloid. Thickening of the extensor retinaculum overlying the compartment and adjacent radial styloid periosteal/marrow edema. Evaluate for an intracompartmental septum separating APL and EPB.","impr":"De Quervain tenosynovitis of the first extensor compartment.","pearl":"A vertical intracompartmental septum separating APL and EPB is present in a majority of symptomatic cases and is a cause of treatment failure if a sub-sheath is missed.","topic":"Wrist tendons","joint":"wrist"},
{"id":"d245","front":"How would you describe intersection syndrome?","find":"Peritendinous edema, fluid, and fat-stranding centered approximately 4-6 cm proximal to Lister tubercle at the crossover point where the first extensor compartment muscle bellies (APL and EPB) cross over the second compartment tendons (ECRL and ECRB). T2 hyperintense fluid surrounds the tendons at this intersection with adjacent muscle and soft-tissue edema.","impr":"Intersection syndrome (proximal) at the first-over-second extensor compartment crossover.","pearl":"Distinguish from de Quervain by location: de Quervain is at the radial styloid; classic (proximal) intersection syndrome is several centimeters more proximal at the crossover point.","topic":"Wrist tendons","joint":"wrist"},
{"id":"d246","front":"How would you describe flexor or extensor tenosynovitis of the wrist?","find":"Circumferential T2 hyperintense fluid and synovial thickening surrounding one or more flexor (or extensor) tendons within their sheath, with peritendinous enhancement after contrast. The tendon itself maintains normal caliber and signal in simple tenosynovitis. Look for rice bodies, frondlike synovial proliferation (suggesting inflammatory/infectious or tuberculous etiology), and any associated tendon thinning or rupture.","impr":"Flexor (or extensor) tenosynovitis.","topic":"Wrist tendons","joint":"wrist"},
{"id":"d247","front":"How would you describe FCR (flexor carpi radialis) tendinopathy/tear?","find":"Thickening and intermediate intrasubstance signal of the flexor carpi radialis tendon with peritendinous fluid as it courses through its fibro-osseous tunnel adjacent to the trapezial ridge and scaphotrapezial joint. Often associated with adjacent STT (scaphotrapeziotrapezoid) osteoarthritis or trapezial osteophytes causing mechanical irritation. Partial or full-thickness tearing manifests as fiber attenuation or discontinuity.","impr":"FCR tendinosis/tenosynovitis, commonly associated with STT osteoarthritis.","topic":"Wrist tendons","joint":"wrist"},
{"id":"d248","front":"How would you describe an A2 pulley rupture in a rock climber?","find":"Discontinuity and non-visualization of the A2 pulley at the proximal phalanx with volar bowstringing of the flexor tendons away from the underlying bone. Tendon-to-bone distance is increased (>2 mm at the level of the proximal phalanx is abnormal, and is accentuated with resisted flexion). Edema and fluid in the volar soft tissues at the pulley site. Single A2 rupture causes mild bowstringing.","impr":"A2 pulley rupture with flexor tendon bowstringing.","pearl":"A2 is the most important and most commonly injured climbing pulley; bowstringing is best provoked with resisted flexion (dynamic stress imaging) where tendon-bone distance exceeds 2 mm.","topic":"Hand/finger","joint":"hand"},
{"id":"d249","front":"How would you describe an A4 pulley rupture and multiple-pulley injury?","find":"Disruption of the A4 pulley at the middle phalanx with bowstringing of the flexor tendons at that level and increased tendon-bone distance. Combined A2-A3-A4 multi-pulley rupture produces marked bowstringing along the entire finger. Assess each pulley individually and report associated flexor tendon and volar plate injury.","impr":"A4 pulley rupture (or combined multi-pulley injury) with bowstringing.","pearl":"Isolated A4 rupture causes minimal bowstringing; combined A2+A3+A4 disruption produces the most dramatic clinically significant bowstringing.","topic":"Hand/finger","joint":"hand"},
{"id":"d250","front":"How would you describe a flexor digitorum profundus avulsion (jersey finger)?","find":"Avulsion of the flexor digitorum profundus tendon from its insertion at the volar base of the distal phalanx, most commonly the ring finger, with a wavy retracted tendon stump and fluid in the flexor sheath. A small avulsed osseous fragment may be present at the volar distal phalangeal base. The level of tendon retraction (to the PIP, to the palm, or to the A1 pulley) determines the Leddy-Packer classification and surgical urgency.","impr":"Flexor digitorum profundus avulsion (jersey finger); report the level of tendon retraction.","pearl":"Leddy-Packer type I (retraction into palm, vincula disrupted) needs urgent repair due to compromised blood supply; ring finger is most commonly affected.","topic":"Hand/finger","joint":"hand"},
{"id":"d251","front":"How would you describe a central slip tear (boutonniere deformity)?","find":"Disruption of the central slip of the extensor tendon at its insertion on the dorsal base of the middle phalanx, with fluid and retraction. Resultant volar migration of the lateral bands creates the boutonniere deformity: flexion at the PIP joint and hyperextension at the DIP joint. Associated dorsal soft-tissue edema and possible small avulsion fragment.","impr":"Central slip rupture with boutonniere deformity.","pearl":"Boutonniere (PIP flexion, DIP hyperextension) results from central slip injury and volar subluxation of the lateral bands; contrast with swan-neck (PIP hyperextension, DIP flexion).","topic":"Hand/finger","joint":"hand"},
{"id":"d252","front":"How would you describe a sagittal band rupture (boxer knuckle)?","find":"Disruption of the sagittal band at the metacarpophalangeal joint, most often the radial sagittal band of the middle finger, with edema and discontinuity of the band. Resultant ulnar subluxation/dislocation of the extensor digitorum tendon into the intermetacarpal groove, best demonstrated with the MCP joint in flexion. Adjacent dorsal soft-tissue edema.","impr":"Sagittal band rupture with extensor tendon subluxation.","pearl":"The radial sagittal band of the long finger is most commonly torn (boxer knuckle), allowing ulnar dislocation of the extensor tendon; dynamic flexion imaging accentuates the subluxation.","topic":"Hand/finger","joint":"hand"},
{"id":"d253","front":"How would you describe a thumb UCL tear with a Stener lesion (gamekeeper/skier thumb)?","find":"Full-thickness disruption of the ulnar collateral ligament of the thumb MCP joint, typically avulsed from its distal insertion at the proximal phalanx. In a Stener lesion the torn, retracted ligament is displaced superficial and proximal to the adductor pollicis aponeurosis, producing the yo-yo on a string appearance: a rounded mass of balled-up ligament proximal to the MCP joint with the interposed aponeurosis preventing apposition to its footprint.","impr":"Complete thumb UCL tear with Stener lesion.","pearl":"A Stener lesion cannot heal without surgery because the adductor aponeurosis is interposed between the torn ligament and its insertion; it is the key finding to report.","topic":"Hand/finger","joint":"hand"},
{"id":"d254","front":"How would you describe a partial (non-displaced) thumb UCL injury without Stener lesion?","find":"Thickening and increased T2 signal within the ulnar collateral ligament of the thumb MCP joint with partial fiber disruption but maintained continuity and a normal anatomic position deep to the adductor aponeurosis. No proximal balled-up retraction. Adjacent soft-tissue and capsular edema. No displaced osseous avulsion fragment.","impr":"Partial thumb UCL tear without Stener lesion; ligament remains in anatomic position.","topic":"Hand/finger","joint":"hand"},
{"id":"d255","front":"How would you describe a volar plate injury at the PIP joint?","find":"Disruption or detachment of the volar plate from its insertion at the volar base of the middle phalanx, with fluid and edema at the volar PIP. May be associated with a small avulsion fragment from the volar base of the middle phalanx. Hyperextension mechanism; assess for dorsal PIP dislocation/subluxation and collateral ligament injury.","impr":"Volar plate avulsion/injury at the PIP joint.","topic":"Hand/finger","joint":"hand"},
{"id":"d256","front":"How would you describe a dorsal wrist ganglion cyst?","find":"Well-circumscribed unilocular or multilocular lobulated cystic lesion with homogeneous fluid signal (low T1, markedly high T2) and a thin imperceptible wall, no internal enhancement (only thin peripheral/wall enhancement). Arises from the dorsal scapholunate interval/joint capsule, often connected by a thin neck or pedicle to the SL joint. No solid mural nodularity.","impr":"Dorsal wrist ganglion cyst arising from the scapholunate region.","pearl":"Dorsal ganglia classically arise from the SL joint; tracing the cyst neck to a joint or tendon sheath confirms the diagnosis. Lack of internal enhancement distinguishes from a solid mass.","topic":"Masses","joint":"wrist"},
{"id":"d257","front":"How would you describe a giant cell tumor of the tendon sheath?","find":"Well-defined solid soft-tissue mass intimately related to a flexor tendon sheath of a finger, characteristically low-to-intermediate on both T1 and T2 with areas of marked T2/gradient-echo blooming susceptibility from hemosiderin. Avid solid enhancement. May produce extrinsic pressure erosion (scalloping) of the adjacent phalanx.","impr":"Giant cell tumor of the tendon sheath (localized tenosynovial giant cell tumor).","pearl":"The hemosiderin-laden tissue blooms on gradient-echo sequences, mirroring intra-articular PVNS; it is the most common solid tumor of the hand.","topic":"Masses","joint":"hand"},
{"id":"d258","front":"How would you describe a glomus tumor of the fingertip?","find":"Small (typically <1 cm) well-circumscribed subungual or pulp soft-tissue nodule that is low/intermediate on T1, markedly hyperintense on T2, and demonstrates intense avid enhancement following contrast. May cause smooth scalloping/erosion of the dorsal distal phalanx. Clinical triad of severe focal pain, point tenderness, and cold sensitivity.","impr":"Glomus tumor, subungual fingertip.","pearl":"A tiny intensely enhancing T2-bright subungual nodule with the classic clinical triad (pain, pinpoint tenderness, cold hypersensitivity) is virtually diagnostic.","topic":"Masses","joint":"hand"},
{"id":"d259","front":"How would you describe carpal tunnel syndrome with median nerve changes?","find":"Enlargement and increased T2 signal of the median nerve at the proximal carpal tunnel (pisiform level) with relative flattening/effacement at the distal tunnel (hook of hamate level), and volar bowing of the flexor retinaculum. Quantitatively, an increased cross-sectional area of the median nerve at the pisiform (>10-12 mm2) supports the diagnosis. Assess for a space-occupying cause (ganglion, persistent median artery, anomalous muscle, tenosynovitis).","impr":"Imaging findings of median nerve compression consistent with carpal tunnel syndrome.","pearl":"The nerve swells proximally and flattens distally with volar retinacular bowing; always search for a treatable space-occupying lesion within the tunnel.","topic":"Nerve","joint":"wrist"},
{"id":"d260","front":"How would you describe a distal radius fracture with marrow edema on MRI?","find":"Linear low-signal fracture line through the distal radial metaphysis with surrounding geographic marrow edema (T1 hypointense, STIR/T2 hyperintense). Assess for intra-articular extension to the radiocarpal or distal radioulnar joint, articular step-off, dorsal/volar angulation and comminution, and associated TFCC, scapholunate, or lunotriquetral ligament injury and ulnar styloid fracture.","impr":"Distal radius fracture; report articular extension, angulation, and associated soft-tissue/ligamentous injury.","pearl":"Always assess for associated intracarpal soft-tissue injury (SL/LT ligament, TFCC) which is common with distal radius fractures and frequently overlooked.","topic":"Carpal bones","joint":"wrist"},
{"id":"d261","front":"How would you describe a grade 1 muscle strain?","find":"Feathery interstitial and perifascicular high T2/STIR signal tracking along the myotendinous junction without architectural distortion. No discrete fiber discontinuity, intramuscular fluid collection, or hematoma. Less than 5% of the muscle cross-section is involved with preserved overall muscle volume and pennate architecture.","impr":"Grade 1 (low-grade) muscle strain at the myotendinous junction.","pearl":"Grade 1 is purely edematous/microscopic injury — if you see any gap or hematoma it is no longer grade 1.","topic":"Muscle injury","joint":"general"},
{"id":"d262","front":"How would you describe a grade 2 muscle strain?","find":"Partial-thickness fiber disruption at the myotendinous junction with associated intramuscular and perifascicular T2/STIR edema and a small intramuscular hematoma. There is partial loss of the normal pennate architecture involving an estimated [25/50]% of the cross-sectional area, without complete discontinuity or tendon retraction.","impr":"Grade 2 (partial-thickness) myotendinous strain.","pearl":"Quantify the percent cross-section torn — this drives return-to-play prognosis far more than the edema.","topic":"Muscle injury","joint":"general"},
{"id":"d263","front":"How would you describe a grade 3 muscle strain (complete rupture)?","find":"Complete discontinuity of the muscle/tendon fibers with a fluid- and hematoma-filled gap and wavy, retracted torn fiber stumps. The torn ends are retracted by ___ cm. Surrounding hyperintense T2/STIR edema and hemorrhage outline the disrupted muscle, which demonstrates a bunched-up pseudomass configuration.","impr":"Grade 3 complete muscle/myotendinous rupture with ___ cm retraction.","pearl":"Always state the retraction gap distance — it determines whether surgical reapproximation is feasible.","topic":"Muscle injury","joint":"general"},
{"id":"d264","front":"How would you describe a myotendinous junction injury?","find":"Feathery high T2/STIR signal radiating from the central tendon along the myotendinous junction, the most common site of indirect muscle injury. The intramuscular tendon is intact and continuous without fiber gap. Edema tracks longitudinally along the muscle fibers without a focal collection.","impr":"Myotendinous junction strain.","pearl":"The myotendinous junction is the weakest link in eccentric loading injuries — most strains center here, not in the muscle belly.","topic":"Muscle injury","joint":"general"},
{"id":"d265","front":"How would you describe complete muscle rupture with retraction?","find":"Full-thickness transection of the muscle belly with complete fiber discontinuity and a large hematoma filling the resultant defect. The proximal and distal muscle stumps are retracted and bunched, separated by a gap of ___ cm. Adjacent fascial planes are disrupted with extravasated hemorrhagic fluid.","impr":"Complete muscle rupture with ___ cm retraction and intervening hematoma.","topic":"Muscle injury","joint":"general"},
{"id":"d266","front":"How would you describe a hyperacute/acute intramuscular hematoma?","find":"Intramuscular collection that is isointense to mildly hyperintense to muscle on T1 and heterogeneously hyperintense on T2/STIR in the hyperacute phase (oxyhemoglobin), evolving to T1 hypointense/T2 hypointense in the acute phase (intracellular deoxyhemoglobin). No internal enhancement; surrounding muscle edema is present. Measures ___ x ___ x ___ cm.","impr":"Acute intramuscular hematoma.","pearl":"Acute deoxyhemoglobin is dark on both T1 and T2 — do not mistake the dark T2 signal for absence of blood.","topic":"Muscle injury","joint":"general"},
{"id":"d267","front":"How would you describe a subacute intramuscular hematoma?","find":"Intramuscular collection demonstrating intrinsic high T1 and high T2 signal (extracellular methemoglobin), often with a peripheral T1/T2 hypointense hemosiderin rim. A fluid-fluid or hematocrit level may be present. No nodular internal enhancement. Measures ___ x ___ x ___ cm.","impr":"Subacute intramuscular hematoma.","pearl":"Bright-on-T1 subacute blood is the classic mimicker; the key reassurance is the absence of nodular/solid enhancement that would suggest hemorrhagic sarcoma.","topic":"Muscle injury","joint":"general"},
{"id":"d268","front":"How would you describe a chronic intramuscular hematoma/seroma?","find":"Well-defined chronic collection with a thick peripheral T1/T2 hypointense hemosiderin and fibrous rim, demonstrating blooming on gradient-echo/SWI sequences. Internal contents are serous to seroma-like with layering debris. No solid enhancing nodularity.","impr":"Chronic resolving intramuscular hematoma/seroma.","topic":"Muscle injury","joint":"general"},
{"id":"d269","front":"How would you describe delayed-onset muscle soreness (DOMS) edema?","find":"Diffuse feathery high T2/STIR signal involving one or more muscles of a single functional group, peaking 24-72 hours after unaccustomed eccentric exercise. No fiber disruption, hematoma, or architectural distortion. Mild associated volume increase from edema.","impr":"Delayed-onset muscle soreness (exertional myoedema), no structural tear.","pearl":"DOMS follows a functional muscle group and a clear exercise history — distinguish from a true strain by the absence of a torn-fiber gap.","topic":"Muscle injury","joint":"general"},
{"id":"d270","front":"How would you describe a muscle fascial injury?","find":"Disruption of the hyperintense T2/STIR fluid signal tracking along and through the epimysial/fascial plane with focal fascial discontinuity. A muscle herniation may protrude through the fascial defect. No intramuscular tendon tear.","impr":"Fascial injury/defect with perifascial fluid.","topic":"Muscle injury","joint":"general"},
{"id":"d271","front":"How would you describe a muscle contusion?","find":"Ill-defined geographic high T2/STIR signal within the muscle belly, typically at the site of direct impact and often deep against the underlying bone (crush against cortex). Feathery edema crosses fascial boundaries with interstitial hemorrhage but preserved fiber continuity and no discrete gap.","impr":"Muscle contusion from direct blunt trauma.","pearl":"Contusion edema is at the impact site and deep near bone; strain edema is at the myotendinous junction — location separates the two.","topic":"Muscle injury","joint":"general"},
{"id":"d272","front":"How would you describe acute/subacute muscle denervation edema?","find":"Diffuse high T2/STIR signal uniformly involving all muscles supplied by a single peripheral nerve or its branch, without architectural distortion, fatty change, or fiber tear. Muscle bulk is preserved or mildly increased. The distribution conforms to a specific nerve territory.","impr":"Acute/subacute denervation edema in a [named nerve] distribution.","pearl":"Denervation edema respects a nerve territory and involves the whole muscle uniformly — strain/contusion edema is feathery and focal.","topic":"Muscle injury","joint":"general"},
{"id":"d273","front":"How would you describe chronic muscle denervation (fatty atrophy)?","find":"Volume loss of the affected muscle group with diffuse fatty infiltration manifest as high T1 signal interdigitating between and replacing muscle fibers, conforming to a single nerve distribution. T2/STIR edema has resolved. Goutallier/fatty replacement is graded as moderate to severe.","impr":"Chronic denervation with fatty atrophy in a [named nerve] distribution.","pearl":"Chronic fatty replacement is generally irreversible — its presence implies the denervation is long-standing and limits surgical benefit.","topic":"Muscle injury","joint":"general"},
{"id":"d274","front":"How would you describe normal hematopoietic (red) marrow?","find":"Marrow signal that is mildly hypointense to but greater than skeletal muscle and intervertebral disc on T1-weighted images, slightly hyperintense to muscle on fluid-sensitive sequences, with signal drop-out on opposed-phase chemical-shift imaging confirming admixed fat. Symmetric distribution without focal mass or replacement.","impr":"Normal red (hematopoietic) marrow.","pearl":"Normal red marrow is always brighter than muscle and disc on T1 — that single rule excludes most marrow-replacing disease.","topic":"Marrow","joint":"general"},
{"id":"d275","front":"How would you describe a marrow-replacing lesion?","find":"Focal marrow lesion that is hypointense to or equal to skeletal muscle and intervertebral disc on T1-weighted images, hyperintense on fluid-sensitive sequences, with enhancement after contrast and absent signal drop on opposed-phase imaging (no intravoxel fat). Measures ___ cm.","impr":"Marrow-replacing lesion, suspicious; T1 signal below muscle is the key feature.","pearl":"The cardinal rule: a true marrow-replacing lesion is darker than (or equal to) muscle on T1. Brighter-than-muscle favors benign red marrow or hemangioma.","topic":"Marrow","joint":"general"},
{"id":"d276","front":"How would you describe diffuse marrow infiltration?","find":"Diffuse, confluent reduction of marrow T1 signal to below that of adjacent skeletal muscle and intervertebral disc, with corresponding fluid-sensitive hyperintensity and loss of the normal opposed-phase signal drop. Distribution is widespread rather than focal.","impr":"Diffuse marrow infiltration/replacement (e.g., neoplastic or marrow-packing process).","pearl":"Use the disc and muscle as your internal control on T1 — diffuse infiltration is easy to overlook when bilaterally symmetric.","topic":"Marrow","joint":"general"},
{"id":"d277","front":"How would you describe focal (reactive) bone marrow edema?","find":"Ill-defined region of decreased T1 and increased T2/STIR marrow signal with indistinct margins, sparing the cortex and showing variable enhancement. Marrow signal remains higher than muscle on T1, consistent with edema rather than replacement.","impr":"Nonspecific reactive bone marrow edema.","pearl":"Edema has fuzzy margins and stays brighter than muscle on T1; replacement is sharply marginated and drops below muscle.","topic":"Marrow","joint":"general"},
{"id":"d278","front":"How would you describe a geographic marrow lesion pattern?","find":"Well-defined lesion with a sharp, often sclerotic or fatty rim and a narrow zone of transition between abnormal marrow and normal marrow. The cortex is intact without permeation.","impr":"Geographic, narrow-zone-of-transition marrow lesion favoring a non-aggressive process.","pearl":"Narrow zone of transition = slow biology; this is the marrow equivalent of a benign radiographic margin.","topic":"Marrow","joint":"general"},
{"id":"d279","front":"How would you describe a permeative/moth-eaten marrow lesion pattern?","find":"Ill-defined marrow infiltration with a wide zone of transition, indistinct margins blending into normal marrow, frequently with cortical permeation and an associated soft-tissue component. No sclerotic rim.","impr":"Permeative, wide-zone-of-transition marrow lesion, aggressive.","pearl":"Wide zone of transition plus cortical breakthrough and soft-tissue mass = aggressive biology until proven otherwise.","topic":"Marrow","joint":"general"},
{"id":"d280","front":"How would you describe osteomyelitis?","find":"Confluent marrow signal abnormality, hypointense on T1 and hyperintense on T2/STIR, with avid enhancement and loss of the normal marrow fat (T1 marrow replacement). Associated features include cortical destruction, periosteal reaction, an adjacent soft-tissue phlegmon/abscess, and a sinus tract. Devitalized non-enhancing sequestrum may be present.","impr":"Osteomyelitis.","pearl":"Confluent T1 marrow replacement (not just T2/STIR edema) is the most specific MRI sign of osteomyelitis — STIR alone overcalls it.","topic":"Infection","joint":"general"},
{"id":"d281","front":"How would you describe septic arthritis?","find":"Complex joint effusion with synovial thickening and avid synovial enhancement, periarticular T2/STIR marrow edema, and surrounding soft-tissue edema/fluid. The effusion may show debris, restricted diffusion, and irregular cartilage and subchondral erosive change.","impr":"Findings concerning for septic arthritis; aspiration recommended.","pearl":"MRI cannot exclude septic arthritis — a complex enhancing effusion with periarticular edema should prompt aspiration regardless of imaging confidence.","topic":"Infection","joint":"general"},
{"id":"d282","front":"How would you describe a soft-tissue abscess?","find":"Well-defined fluid collection with a thick, irregular, avidly enhancing rim and central non-enhancing necrotic/purulent content that is T2 hyperintense and shows marked restricted diffusion (low ADC). Surrounding T2/STIR edema and stranding are present. Measures ___ x ___ x ___ cm.","impr":"Soft-tissue abscess.","pearl":"Restricted diffusion of the central content is the most reliable discriminator of abscess from non-infected fluid/necrotic tumor.","topic":"Infection","joint":"general"},
{"id":"d283","front":"How would you describe cellulitis?","find":"Reticulated, lacy high T2/STIR signal infiltrating the subcutaneous fat with skin thickening and diffuse, non-rim enhancement of the involved subcutaneous tissues. No drainable rim-enhancing fluid collection.","impr":"Cellulitis without organized abscess.","pearl":"Cellulitis enhances diffusely without a discrete rim; once a rim-enhancing collection appears it has progressed to abscess.","topic":"Infection","joint":"general"},
{"id":"d284","front":"How would you describe necrotizing fasciitis?","find":"Thick (>3 mm) abnormal T2/STIR fluid signal tracking along the deep intermuscular fascia, often involving multiple compartments, with non-enhancement of necrotic fascia/muscle and possible foci of T1/T2 signal void representing gas (susceptibility blooming on gradient-echo). Extensive surrounding soft-tissue edema.","impr":"Findings concerning for necrotizing fasciitis — surgical emergency.","pearl":"Deep fascial fluid >3 mm thickness and non-enhancing fascia are the key MRI red flags; do not delay surgery awaiting imaging.","topic":"Infection","joint":"general"},
{"id":"d285","front":"How would you describe septic tenosynovitis?","find":"Distended tendon sheath with complex fluid, thickened avidly enhancing synovium, and surrounding T2/STIR soft-tissue edema. The fluid may restrict diffusion. The enclosed tendon shows reactive signal but is typically intact.","impr":"Septic (infectious) tenosynovitis.","pearl":"Thick enhancing synovium and surrounding edema distinguish septic from bland tenosynovitis, where the sheath fluid is simple and the wall is thin.","topic":"Infection","joint":"general"},
{"id":"d286","front":"How would you describe a simple lipoma?","find":"Well-circumscribed mass following subcutaneous fat signal on all sequences — homogeneously hyperintense on T1 and T2 with uniform suppression on fat-saturated sequences. Thin (<2 mm) septa only, no nodular non-adipose component, and no enhancement. Measures ___ cm.","impr":"Simple lipoma.","pearl":"A lipoma is pure fat with at most a few thin septa — any thick septa or nodules push you toward atypical lipomatous tumor.","topic":"Soft-tissue mass","joint":"general"},
{"id":"d287","front":"How would you describe an atypical lipomatous tumor/well-differentiated liposarcoma?","find":"Predominantly fatty mass containing thick (>2 mm) and/or nodular enhancing non-adipose septa, prominent areas of non-fatty soft tissue, and incomplete fat suppression. Often large (>10 cm) and deep. Measures ___ cm.","impr":"Fat-containing lesion with thick/nodular septa, concerning for atypical lipomatous tumor/well-differentiated liposarcoma.","pearl":"Thick or nodular enhancing septa, large size, and deep location are the features that separate ALT/liposarcoma from a benign lipoma.","topic":"Soft-tissue mass","joint":"general"},
{"id":"d288","front":"How would you describe a peripheral nerve sheath tumor?","find":"Well-defined fusiform mass arising along the expected course of a nerve, entering and exiting at its poles (split-fat sign with a rim of fat at the tapered ends). Shows the target sign (central T2 hypointensity, peripheral hyperintensity) and a fascicular sign internally. Measures ___ cm.","impr":"Peripheral nerve sheath tumor (schwannoma/neurofibroma).","pearl":"Split-fat, fusiform shape along a nerve, target and fascicular signs are the quartet that confidently identifies a nerve sheath tumor.","topic":"Soft-tissue mass","joint":"general"},
{"id":"d289","front":"How would you describe a ganglion/synovial cyst?","find":"Well-circumscribed, lobulated, uniformly T2 hyperintense and T1 hypointense fluid-signal lesion arising adjacent to a joint or tendon sheath, often with a thin neck/pedicle connecting to the joint. Thin peripheral enhancement only, no internal nodular enhancement. Measures ___ cm.","impr":"Ganglion (or synovial) cyst.","pearl":"Look for the connecting stalk/neck to the joint or tendon sheath — it confirms the cystic nature and the diagnosis.","topic":"Soft-tissue mass","joint":"general"},
{"id":"d290","front":"How would you describe a myxoid soft-tissue tumor?","find":"Lobulated mass markedly hyperintense on T2 (near-fluid signal) but intermediate on T1, which fails to fully suppress like simple fluid and shows internal solid enhancement (cloud-like or reticular) distinguishing it from a true cyst. Measures ___ cm.","impr":"Myxoid soft-tissue tumor; tissue sampling advised.","pearl":"A near-fluid-bright T2 mass that enhances internally is myxoid tumor masquerading as a cyst — the enhancement is the giveaway.","topic":"Soft-tissue mass","joint":"general"},
{"id":"d291","front":"How would you describe features that distinguish a hematoma from a hemorrhagic sarcoma?","find":"A benign hematoma shows a complete T2 hypointense hemosiderin rim, evolving blood-product signal, and no solid internal nodular enhancement, decreasing in size over follow-up. A hemorrhagic sarcoma shows nodular/solid enhancing tissue beyond the blood products, fluid-fluid levels, surrounding mass effect, and growth over time.","impr":"Hemorrhagic collection — solid enhancing nodularity favors hemorrhagic sarcoma over simple hematoma.","pearl":"Any soft-tissue hematoma without clear trauma history, or one that does not resolve, must be evaluated for an underlying hemorrhagic sarcoma.","topic":"Soft-tissue mass","joint":"general"},
{"id":"d292","front":"How would you describe fluid-fluid levels in a soft-tissue or bone lesion?","find":"Lesion containing multiple internal fluid-fluid levels from layering hemorrhagic/proteinaceous debris of differing signal intensities, best seen on T2-weighted images with the patient stationary. Located within a cystic/multiseptated lesion.","impr":"Multiple fluid-fluid levels — nonspecific; seen in aneurysmal bone cyst, telangiectatic osteosarcoma, and synovial sarcoma among others.","pearl":"Fluid-fluid levels are nonspecific — they occur in both benign (ABC) and malignant (telangiectatic osteosarcoma) lesions, so do not equate them with benignity.","topic":"Soft-tissue mass","joint":"general"},
{"id":"d293","front":"How would you describe inflammatory synovitis with pannus?","find":"Lobulated, thickened synovium that is intermediate-to-low on T1, variable on T2, and demonstrates avid enhancement (active hypervascular pannus), filling the joint and recesses. Associated joint effusion, periarticular marrow edema, and marginal erosions are present.","impr":"Active inflammatory synovitis/pannus.","pearl":"Avid synovial enhancement indicates active, hypervascular pannus; fibrous burnt-out pannus is low signal and enhances poorly — this distinction guides therapy response.","topic":"Arthropathy","joint":"general"},
{"id":"d294","front":"How would you describe a marginal erosion of inflammatory arthritis?","find":"Well-defined defect in the cortical bone at the bare area (marginal zone uncovered by cartilage) with associated T1 hypointense, T2/STIR hyperintense reactive marrow edema (osteitis) and enhancing pannus filling the erosion.","impr":"Marginal erosion with surrounding osteitis, typical of inflammatory arthropathy.","pearl":"Erosions begin at the bare areas where synovium directly contacts unprotected bone; accompanying osteitis signals active, erosive disease.","topic":"Arthropathy","joint":"general"},
{"id":"d295","front":"How would you describe a gouty tophus?","find":"Periarticular and intra-articular soft-tissue deposits that are intermediate-to-low on T1 and heterogeneous intermediate-to-low on T2 with variable peripheral enhancement, associated with well-corticated 'punched-out' erosions with overhanging edges and preserved joint space.","impr":"Tophaceous gout.","pearl":"The intermediate-to-low T2 signal of tophi (versus the bright T2 of most inflammatory tissue) plus overhanging-edge erosions is the classic gout fingerprint.","topic":"Arthropathy","joint":"general"},
{"id":"d296","front":"How would you describe osteoarthritis on MRI?","find":"Asymmetric joint space (cartilage) loss with marginal osteophytes, subchondral T1 hypointense/T2 hyperintense cystic change (geodes), subchondral sclerosis (low on all sequences), and subchondral bone marrow edema-like signal at areas of cartilage loss. Effusion is typically simple.","impr":"Osteoarthritis.","pearl":"Osteophytes plus subchondral cysts and sclerosis at sites of focal cartilage loss define OA — bone marrow edema-like signal here correlates with pain.","topic":"Arthropathy","joint":"general"},
{"id":"d297","front":"How would you describe generic bursitis?","find":"Distended bursa containing T2/STIR hyperintense, T1 hypointense fluid with a thin enhancing wall. Simple uncomplicated fluid lacks internal debris or thick synovial enhancement; complicated/inflamed bursitis shows wall thickening, synovial enhancement, and internal complexity. Measures ___ cm.","impr":"Bursitis (simple versus complicated as above).","topic":"Bursa","joint":"general"},
{"id":"d298","front":"How would you describe enthesitis/enthesopathy?","find":"Thickening and intrasubstance T2/STIR hyperintensity at the tendon/ligament bony attachment with adjacent enthesophyte formation, subentheseal bone marrow edema, and enhancement in active disease. Cortical irregularity or erosion may be present at the insertion.","impr":"Enthesitis (active) / enthesopathy (chronic).","pearl":"Subentheseal marrow edema plus enhancement signals active inflammatory enthesitis (seronegative spondyloarthropathy), versus bland degenerative enthesopathy.","topic":"Enthesis","joint":"general"},
{"id":"d299","front":"How would you describe tenosynovitis?","find":"Increased T2/STIR fluid distending the tendon sheath circumferentially around an intact tendon, with synovial thickening and enhancement in inflammatory/infectious cases. The enclosed tendon may show intrasubstance signal but maintains continuity.","impr":"Tenosynovitis.","pearl":"Sheath fluid that exceeds the volume expected for a normal tendon, particularly when circumferential and asymmetric, defines tenosynovitis.","topic":"Tendon","joint":"general"},
{"id":"d300","front":"How would you describe a stress reaction versus a stress fracture?","find":"Stress reaction: periosteal and/or marrow T2/STIR edema without a discrete fracture line, with normal T1 marrow. Stress fracture: a linear T1 and T2 hypointense fracture line within the surrounding marrow edema, oriented perpendicular to the cortex, with periosteal reaction.","impr":"Stress reaction (edema only) versus stress fracture (discrete low-signal fracture line).","pearl":"The presence of a low-signal fracture line on T1 upgrades a stress reaction to a true stress fracture — graded by the Fredericson/Arendt system.","topic":"Stress injury","joint":"general"},
{"id":"d301","front":"How would you describe an insufficiency fracture?","find":"Linear T1 and T2 hypointense fracture line, often with a serpiginous or band-like configuration, surrounded by diffuse marrow edema in osteoporotic/abnormal bone subjected to normal stress. Common sites include the sacrum (H-shaped/Honda sign), pubic rami, and proximal femur.","impr":"Insufficiency fracture.","pearl":"Insufficiency fractures occur in weakened bone under normal load (vs fatigue fractures in normal bone under abnormal load) — the sacral H/Honda sign is pathognomonic.","topic":"Stress injury","joint":"general"},
{"id":"d302","front":"How would you describe a Morel-Lavallee lesion?","find":"Closed degloving collection between the subcutaneous fat and the underlying deep fascia, typically over the greater trochanter/lateral thigh, with a fluid-fluid level and a peripheral fibrous capsule. Signal varies with chronicity of blood and lymph; chronic lesions show a hemosiderin-laden capsule and internal fat globules.","impr":"Morel-Lavallee lesion (closed degloving injury).","pearl":"A fluid collection at the deep fat-fascia interface over the trochanter after shearing trauma is a Morel-Lavallee lesion until proven otherwise.","topic":"Soft-tissue injury","joint":"general"},
{"id":"d303","front":"How would you describe a deep venous thrombosis?","find":"Distended, non-compressible vein with an intraluminal filling defect that is T1 intermediate-to-hyperintense (depending on clot age), with loss of normal flow void and absent enhancement of the thrombosed segment on post-contrast/MR venography. Surrounding perivenous edema may be present.","impr":"Deep venous thrombosis.","pearl":"An expanded vein with an enhancing wall but non-enhancing intraluminal content (versus enhancing tumor thrombus) indicates bland DVT.","topic":"Vascular","joint":"general"},
{"id":"d304","front":"How would you describe a foreign body granuloma?","find":"Focal soft-tissue mass surrounding a central T1/T2 hypointense, non-enhancing foreign body (often signal-void wood/metal), with a peripheral rim of T2 hyperintense granulation tissue and rim enhancement. Adjacent reactive edema and possible sinus tract.","impr":"Foreign body granuloma.","pearl":"A signal-void center surrounded by enhancing granulation tissue, with a penetrating-injury history, points to retained foreign body; wood and plastic are radiographically occult but conspicuous on MRI.","topic":"Soft-tissue mass","joint":"general"},
{"id":"d305","front":"How would you describe myositis ossificans?","find":"Soft-tissue lesion demonstrating zonal organization: a non-mineralized center that is T2 hyperintense and enhances, surrounded by a maturing peripheral rim of ossification that is T1/T2 hypointense with peripheral mature fatty marrow signal in chronic stages. Early lesions show extensive surrounding edema; mature lesions show a complete peripheral ossified rim with central fat.","impr":"Myositis ossificans (post-traumatic heterotopic ossification).","pearl":"The zonal/centripetal maturation pattern (peripheral ossification, central immature tissue) is the inverse of malignant osteosarcoma (which mineralizes centrally) — this distinction avoids misdiagnosing sarcoma.","topic":"Soft-tissue mass","joint":"general"},
{"id":"d306","front":"How would you describe a normal lumbar intervertebral disc?","find":"Normal disc height and T2 signal with preserved central nucleus pulposus hyperintensity and intact peripheral annulus fibrosus low signal. The posterior disc margin remains concave or flat and does not extend beyond the adjacent vertebral endplate margins. No annular fissure, herniation, or endplate change.","impr":"Normal intervertebral disc; no herniation or stenosis.","pearl":"By nomenclature, normal discs show no extension of disc material beyond the ring apophysis edges.","topic":"Disc","joint":"spine"},
{"id":"d307","front":"How would you describe a diffuse disc bulge?","find":"Symmetric, circumferential extension of disc material beyond the ring apophyses involving > 25% (> 90 degrees) of the disc circumference, with smooth uniform displacement measuring < 3 mm beyond the endplate margins. T2 signal of the nucleus is reduced consistent with desiccation. Mild ventral thecal sac flattening without focal herniation or nerve root displacement.","impr":"Diffuse disc bulge; not a focal herniation.","pearl":"A bulge involves > 25% of the circumference by definition and is not a herniation; reserve protrusion/extrusion for focal (< 25%) displacement.","topic":"Disc","joint":"spine"},
{"id":"d308","front":"How would you describe a focal/broad-based disc protrusion?","find":"Focal posterior displacement of disc material involving < 25% of the disc circumference, where the base (width in any plane) is GREATER than the distance the herniated material extends beyond the disc margin. Broad-based subtype spans 25-50% of circumference; focal subtype spans < 25%. Measures [X] mm AP with ventral thecal sac effacement; the herniation remains contained by the outer annulus/posterior longitudinal ligament.","impr":"[Broad-based/focal] central [or paracentral] disc protrusion at L[X]-L[X].","pearl":"Protrusion = base wider than the protruded apex (greatest dimension is the base). Contrast with extrusion where the apex is wider than the base.","topic":"Disc","joint":"spine"},
{"id":"d309","front":"How would you describe a disc extrusion?","find":"Focal herniation in which the distance the disc material extends beyond the disc margin (the dome) is GREATER than the width of its base at the parent disc, OR in which there is no continuity of the displaced material with the parent disc in any plane. Measures [X] mm in cranio-caudal extent with [cranial/caudal] migration. The herniated material may breach the posterior longitudinal ligament (uncontained), effacing the ventral CSF and displacing/compressing the traversing L[X] nerve root.","impr":"Disc extrusion at L[X]-L[X] with [traversing/exiting] nerve root compression.","pearl":"Extrusion = neck (base) narrower than the body of herniated material, or cranio-caudal extent exceeding the disc space. Often uncontained.","topic":"Disc","joint":"spine"},
{"id":"d310","front":"How would you describe a sequestered disc (free fragment)?","find":"Disc extrusion in which the displaced fragment has lost ALL continuity with the parent disc — a free fragment lying within the epidural space, frequently migrated cranially or caudally posterior to the vertebral body and separated from the disc of origin. The fragment is iso- to hyperintense on T2 and shows peripheral (rim) enhancement of surrounding granulation tissue post-contrast. Measures [X] mm; displaces the [traversing] nerve root and effaces the lateral recess/thecal sac.","impr":"Sequestered disc fragment at the L[X] level with migration and nerve root displacement.","pearl":"Sequestration is by definition a free fragment with no continuity to the parent disc. Peripheral enhancement distinguishes it from an enhancing epidural tumor (which enhances solidly).","topic":"Disc","joint":"spine"},
{"id":"d311","front":"How would you describe an annular fissure with a high-intensity zone (HIZ)?","find":"Focal high T2 signal within the posterior annulus fibrosus (high-intensity zone), brighter than the desiccated nucleus and approaching CSF signal, representing a radial annular fissure with fluid/granulation tissue. May enhance post-contrast. No frank herniation; the posterior annular contour is preserved or minimally bulging.","impr":"Posterior annular fissure (HIZ) at L[X]-L[X]; potential pain generator.","pearl":"HIZ denotes a radial annular tear; the older term anular tear is replaced by anular fissure to avoid implying trauma.","topic":"Disc","joint":"spine"},
{"id":"d312","front":"How would you describe disc desiccation with loss of disc height?","find":"Diminished T2 signal of the nucleus pulposus reflecting desiccation, with loss of disc space height and intranuclear cleft. Associated endplate spondylotic ridging and vacuum phenomenon (linear T1/T2 hypointense gas) may be present. Graded along the Pfirrmann scale for disc degeneration.","impr":"Degenerative disc desiccation and height loss at L[X]-L[X].","pearl":"Vacuum disc phenomenon (gas signal void) is a reliable sign of advanced degeneration and argues against infection.","topic":"Disc","joint":"spine"},
{"id":"d313","front":"How would you describe a Schmorl node?","find":"Focal herniation of disc material vertically through a defect in the vertebral endplate into the adjacent cancellous bone, with a well-defined intraosseous indentation rimmed by sclerosis. Acute/active Schmorl nodes show surrounding marrow edema (T2/STIR hyperintense, T1 hypointense) and may enhance; chronic nodes show fatty marrow rim.","impr":"Schmorl node at the [superior/inferior] endplate of L[X]; [acute/chronic].","pearl":"An acute Schmorl node with edema can mimic an aggressive lesion — the intraosseous disc continuity and endplate defect confirm the benign diagnosis.","topic":"Endplate","joint":"spine"},
{"id":"d314","front":"How would you describe central canal stenosis with grading?","find":"Narrowing of the central spinal canal from a combination of disc bulge/herniation, ligamentum flavum hypertrophy, and facet arthropathy. Graded by thecal sac CSF effacement: mild (CSF still visible, no rootlet aggregation), moderate (partial CSF effacement with crowding of cauda equina rootlets), and severe (complete CSF obliteration with no rootlet separation, sedimentation sign positive). AP thecal diameter [X] mm (< 10 mm = absolute stenosis, 10-12 mm = relative).","impr":"[Mild/moderate/severe] central canal stenosis at L[X]-L[X].","pearl":"Positive sedimentation sign (failure of nerve roots to settle dependently on supine T2) supports significant stenosis.","topic":"Canal","joint":"spine"},
{"id":"d315","front":"How would you describe lateral recess stenosis?","find":"Narrowing of the lateral recess (subarticular zone) by a combination of superior articular facet hypertrophy, ligamentum flavum thickening, and posterolateral disc protrusion, with effacement of perineural fat and impingement of the TRAVERSING nerve root before it enters the foramen. Lateral recess height measures < 3-4 mm; the traversing root is flattened/displaced posteromedially.","impr":"Lateral recess stenosis at L[X]-L[X] with traversing L[X] nerve root impingement.","pearl":"The lateral recess compresses the traversing root (e.g., L4-5 disc affects L5 root); distinguish from foraminal pathology, which affects the exiting root.","topic":"Canal","joint":"spine"},
{"id":"d316","front":"How would you describe neural foraminal narrowing with grading?","find":"Reduction of foraminal dimensions from disc bulge, uncovertebral/endplate osteophytes, facet hypertrophy, and loss of disc height with foraminal collapse. Graded by perineural fat obliteration around the EXITING root: grade 0 normal; grade 1 mild (fat partially obliterated, two opposing directions); grade 2 moderate (fat obliterated in all four directions without morphologic root change); grade 3 severe (root collapse/flattening). The exiting L[X] root is [contacted/displaced/compressed].","impr":"[Mild/moderate/severe] neural foraminal narrowing at L[X]-L[X] with exiting L[X] root effacement.","pearl":"Use the Lee grading system (0-3) based on circumferential perineural fat loss; sagittal images best display foraminal narrowing.","topic":"Foramen","joint":"spine"},
{"id":"d317","front":"How would you describe nerve root compression/displacement?","find":"The [traversing/exiting] L[X] nerve root is [contacted/displaced/compressed/flattened] by the [disc herniation/osteophyte/synovial cyst], with loss of surrounding fat or CSF and posterior/medial displacement. The contralateral root and the conus appear normal. No abnormal root T2 hyperintensity or enhancement to suggest a more proximal lesion.","impr":"L[X] nerve root [compression/displacement] by [lesion].","pearl":"Always specify traversing vs exiting root and the precise relationship (abutment vs displacement vs frank compression) — this drives the surgical level.","topic":"Canal","joint":"spine"},
{"id":"d318","front":"How would you describe Modic type I endplate/marrow changes?","find":"Endplate and subchondral marrow signal change that is T1 HYPOINTENSE and T2/STIR HYPERINTENSE, reflecting edema and vascularized fibrous tissue (active inflammatory phase). The endplates show enhancement post-contrast. No disc-space fluid, paraspinal collection, or aggressive endplate destruction to suggest infection.","impr":"Modic type I (edematous) endplate changes at L[X]-L[X].","pearl":"Modic I (edema) can mimic discitis — but discitis shows abnormal T2-bright DISC signal and endplate erosion; Modic I spares the disc and preserves cortical endplates.","topic":"Marrow","joint":"spine"},
{"id":"d319","front":"How would you describe Modic type II endplate/marrow changes?","find":"Endplate and subchondral marrow signal that is T1 HYPERINTENSE and T2 ISO- to mildly HYPERINTENSE, suppressing on fat-saturated sequences, reflecting fatty (yellow) marrow replacement (chronic phase). No enhancement beyond normal fatty marrow. Stable, non-aggressive.","impr":"Modic type II (fatty) endplate changes at L[X]-L[X].","pearl":"Modic II is fat — it follows subcutaneous fat on all sequences and suppresses on STIR/fat-sat; this is the most common and most stable Modic type.","topic":"Marrow","joint":"spine"},
{"id":"d320","front":"How would you describe Modic type III endplate changes?","find":"Endplate and subchondral marrow signal that is HYPOINTENSE on BOTH T1 and T2, corresponding to dense subchondral bony sclerosis, and hyperdense/sclerotic on correlative CT. Represents the chronic sclerotic phase of degenerative endplate change.","impr":"Modic type III (sclerotic) endplate changes at L[X]-L[X].","pearl":"Modic III (low T1/low T2) correlates with the bone sclerosis seen on radiograph/CT; mixed Modic patterns (I/II) are common and reflect transition.","topic":"Marrow","joint":"spine"},
{"id":"d321","front":"How would you describe degenerative endplate irregularity?","find":"Irregular, undulating vertebral endplate contours with subchondral cystic change, marginal osteophytosis, and adjacent Modic marrow signal. The cortical endplate line remains intact without the focal destruction or paraspinal soft-tissue mass that characterizes infection.","impr":"Degenerative endplate irregularity at L[X]-L[X].","pearl":"Preserved cortical endplate continuity and absence of disc T2 hyperintensity favor degenerative change over discitis-osteomyelitis.","topic":"Endplate","joint":"spine"},
{"id":"d322","front":"How would you describe facet arthropathy with effusion?","find":"Hypertrophic facet osteoarthrosis with articular surface irregularity, marginal osteophytes, subchondral cysts, and hypertrophy of the superior and inferior articular processes narrowing the lateral recess and foramen. A facet joint effusion measuring [X] mm of fluid signal distends the capsule; a large effusion (> 1.5 mm) is associated with underlying degenerative spondylolisthesis that may reduce on supine imaging.","impr":"Facet arthropathy with [X]-mm effusion at L[X]-L[X].","pearl":"A facet effusion > 1.5 mm on supine MRI suggests dynamic/occult spondylolisthesis that may only manifest on upright/flexion radiographs.","topic":"Facet","joint":"spine"},
{"id":"d323","front":"How would you describe a facet synovial cyst?","find":"Well-circumscribed extradural cystic lesion arising from a degenerated facet joint, projecting into the posterolateral canal/lateral recess. Variable signal — typically T2 hyperintense with a T2-hypointense (hemosiderin/calcified) rim — with peripheral capsular enhancement and a connecting stalk to the facet. Effaces the lateral recess and compresses the traversing nerve root. Measures [X] mm.","impr":"Facet synovial cyst at L[X]-L[X] with traversing nerve root compression.","pearl":"Synovial cysts almost always accompany facet arthrosis and a facet effusion; the T2-dark hemosiderin rim and facet connection are diagnostic.","topic":"Facet","joint":"spine"},
{"id":"d324","front":"How would you describe ligamentum flavum hypertrophy?","find":"Thickening of the ligamentum flavum measuring > 4-5 mm, with posterolateral indentation of the thecal sac contributing to central canal and lateral recess stenosis. The ligament may show buckling and intermediate T2 signal; calcification or ossification appears as low signal foci.","impr":"Ligamentum flavum hypertrophy contributing to canal stenosis at L[X]-L[X].","pearl":"Ligamentum flavum thickness > 4 mm is abnormal; it is a major posterior contributor to acquired central stenosis along with disc and facet disease.","topic":"Facet","joint":"spine"},
{"id":"d325","front":"How would you describe spondylolysis (pars defect)?","find":"Defect through the pars interarticularis (par defect), best seen as a break in the cortical ring at the posterosuperior aspect of the neural arch, with adjacent marrow edema in acute/active lysis (T2/STIR hyperintense, enhancing). Usually bilateral at L5 > L4. May be accompanied by elongation/sclerosis of the pars and a widened/extended neural foramen if anterolisthesis is present.","impr":"[Unilateral/bilateral] L[X] pars interarticularis defect (spondylolysis), [acute/chronic].","pearl":"Acute/stress lysis shows pars marrow edema and is potentially healable; chronic established lysis shows sclerotic, corticated margins. CT best depicts the cortical defect.","topic":"Posterior","joint":"spine"},
{"id":"d326","front":"How would you describe spondylolisthesis with Meyerding grading?","find":"Anterior translation of L[X] on L[X], graded by the Meyerding classification by percentage of AP endplate displacement: grade I 0-25%, grade II 25-50%, grade III 50-75%, grade IV 75-100%, grade V (spondyloptosis) > 100%. [Isthmic — secondary to bilateral pars defects with a widened canal] or [degenerative — intact pars with facet arthrosis and resultant central/foraminal stenosis]. Measures [X] mm of slip.","impr":"Grade [I-V] [isthmic/degenerative] spondylolisthesis at L[X]-L[X].","pearl":"Isthmic listhesis (pars defect) tends to WIDEN the canal; degenerative listhesis (intact arch) NARROWS the canal and foramina — opposite effects on stenosis.","topic":"Posterior","joint":"spine"},
{"id":"d327","front":"How would you describe anterolisthesis with dynamic instability features?","find":"Anterior slippage of the superior on the inferior vertebral body with disruption of the smooth posterior vertebral body line, foraminal collapse, and traction effects. A large facet effusion or pseudobulging of the disc suggests dynamic instability that may be underestimated on supine MRI; correlate with flexion-extension radiographs. Measures [X] mm.","impr":"Degenerative anterolisthesis at L[X]-L[X] with possible dynamic instability.","pearl":"MRI is supine and may reduce/underestimate the slip; flag a facet effusion as a clue to occult instability requiring upright imaging.","topic":"Posterior","joint":"spine"},
{"id":"d328","front":"How would you describe the conus medullaris level and morphology?","find":"The conus medullaris terminates at the [L1/L1-L2] level with normal cord caliber and signal and an unremarkable filum terminale (< 2 mm). No abnormal cord T2 signal, syrinx, or low-lying conus.","impr":"Conus medullaris at normal level (L1-L2); no cord signal abnormality.","pearl":"A conus terminating below the L2-L3 disc is abnormal (low-lying) and raises concern for tethered cord, especially with a thickened (> 2 mm) or fat-infiltrated filum.","topic":"Other","joint":"spine"},
{"id":"d329","front":"How would you describe cauda equina compression and nerve root clumping?","find":"Compression of the cauda equina with crowding and clumping of the lumbar nerve roots and complete effacement of the surrounding CSF at L[X]-L[X]. In arachnoiditis, roots are abnormally clumped centrally, adherent peripherally to the thecal sac wall (empty thecal sac sign), or matted into a soft-tissue mass; may enhance. Correlate clinically for cauda equina syndrome.","impr":"Cauda equina compression/clumping at L[X]-L[X]; [stenosis vs arachnoiditis].","pearl":"Arachnoiditis patterns: central clumping, peripheral adherence (empty sac), or a soft-tissue mass; differentiate from acute mechanical compression by stenosis.","topic":"Other","joint":"spine"},
{"id":"d330","front":"How would you describe a Tarlov (perineural) cyst?","find":"Well-defined CSF-signal cystic dilatation arising at the dorsal nerve root ganglion, following CSF signal on all sequences without enhancement, most common in the sacral region (S2-S3). Contains nerve root fibers and may cause smooth bony scalloping/remodeling of the adjacent sacral foramen/canal. Measures [X] mm.","impr":"Tarlov (perineural) cyst at the S[X] level; benign.","pearl":"Tarlov cysts follow CSF on all sequences, contain neural tissue, and cause smooth osseous remodeling — features that distinguish them from solid lesions; usually incidental.","topic":"Other","joint":"spine"},
{"id":"d331","front":"How would you describe epidural lipomatosis?","find":"Excess of normal, non-encapsulated T1/T2 HYPERINTENSE fat (suppressing on fat-sat) in the epidural space, circumferentially compressing and deforming the thecal sac into a stellate/Y-shaped (polygonal) configuration, most pronounced in the lower thoracic and lumbar dorsal epidural space. Contributes to canal narrowing.","impr":"Epidural lipomatosis with thecal sac compression at L[X]-L[X].","pearl":"The Y-shaped or polygonal deformity of the thecal sac surrounded by fat is characteristic; associated with steroid use, obesity, and Cushing syndrome.","topic":"Other","joint":"spine"},
{"id":"d332","front":"How would you describe discitis-osteomyelitis?","find":"Confluent T2/STIR HYPERINTENSE marrow edema and T1 hypointensity in two adjacent vertebral bodies bridging the L[X]-L[X] disc, with DESTRUCTION/erosion of the endplate cortices, abnormal T2-bright signal and enhancement within the disc space, loss of the intranuclear cleft, and marrow/disc enhancement post-contrast. Associated phlegmon or paravertebral/epidural inflammatory soft tissue.","impr":"Discitis-osteomyelitis at L[X]-L[X] with [paravertebral/epidural phlegmon].","pearl":"The combination of endplate erosion + abnormal disc T2 signal/enhancement + adjacent marrow edema distinguishes pyogenic spondylodiscitis from degenerative Modic change (which spares the disc and cortex). Disc sparing favors TB.","topic":"Other","joint":"spine"},
{"id":"d333","front":"How would you describe an epidural abscess/collection?","find":"Epidural fluid collection that is T2 hyperintense and T1 hypointense, with PERIPHERAL/RIM enhancement of a non-enhancing necrotic center (liquid pus), as opposed to homogeneously enhancing phlegmon. Restricts diffusion centrally. Spans [X] vertebral levels in the [ventral/dorsal] epidural space, compressing the thecal sac and cord/cauda equina. Usually contiguous with discitis-osteomyelitis.","impr":"Spinal epidural abscess at L[X]-L[X] with thecal sac compression.","pearl":"Rim enhancement with a non-enhancing center and central diffusion restriction indicates drainable abscess vs solidly enhancing phlegmon; a surgical emergency when cord/cauda compressed.","topic":"Other","joint":"spine"},
{"id":"d334","front":"How would you describe a benign (osteoporotic) compression fracture?","find":"Vertebral height loss with a band-like or horizontal T1/T2-hypointense fracture line and preserved NORMAL fatty marrow signal elsewhere in the body (no diffuse marrow replacement), a retropulsed posterior cortical fragment without convex bulging, intact posterior elements, and a fluid sign/cleft. Adjacent levels are normal. Edema resolves with healing.","impr":"Benign (osteoporotic) compression fracture of L[X].","pearl":"Benign features: spared normal marrow, retropulsion without convex posterior margin, horizontal fracture line, fluid cleft, no soft-tissue mass; chemical-shift signal drop on opposed-phase supports benignity.","topic":"Other","joint":"spine"},
{"id":"d335","front":"How would you describe a pathologic (malignant) compression fracture?","find":"Vertebral collapse with COMPLETE diffuse T1-hypointense marrow replacement, CONVEX posterior cortical bulging/expansion, pedicle/posterior element involvement, an associated paravertebral or epidural soft-tissue mass, and frequently other focal marrow lesions at non-collapsed levels. Lacks the chemical-shift signal drop on opposed-phase imaging.","impr":"Pathologic compression fracture of L[X], suspicious for malignancy.","pearl":"Malignant red flags: convex posterior bulge, pedicle involvement, soft-tissue mass, diffuse marrow replacement, multiple lesions, no opposed-phase signal drop (< 20% drop suggests tumor).","topic":"Other","joint":"spine"},
{"id":"d336","front":"How would you describe Baastrup disease (kissing spines)?","find":"Approximation and contact of adjacent lumbar spinous processes with flattening/sclerosis of the apposing cortices, interspinous T2/STIR hyperintense edema and bursal fluid, and occasionally a midline retrodural fluid collection. Most common at L4-L5.","impr":"Baastrup disease (kissing spinous processes) at L[X]-L[X].","pearl":"Interspinous bursal fluid from kissing spines can dissect retrodurally and mimic a cyst; recognize the spinous-process apposition as the source.","topic":"Posterior","joint":"spine"},
{"id":"d337","front":"How would you describe a limbus vertebra?","find":"A well-corticated, triangular osseous fragment at the anterosuperior (or anteroinferior) corner of a vertebral body, separated from the parent body by intervening disc material that herniated through the ring apophysis before fusion. No marrow edema or aggressive features.","impr":"Limbus vertebra at L[X]; developmental, no acute fracture.","pearl":"The smooth corticated margins and characteristic anterior corner location distinguish a limbus vertebra from an acute avulsion or corner fracture.","topic":"Endplate","joint":"spine"},
{"id":"d338","front":"How would you describe a cervical disc-osteophyte complex with central canal stenosis?","find":"At C5-C6 there is a broad-based posterior disc-osteophyte complex composed of disc material and overlying ventral osteophyte, extending across the disc level. This produces moderate central canal narrowing with effacement of the ventral CSF and mild flattening of the ventral cord margin. The AP canal diameter measures approximately 8 mm (normal >12 mm). No abnormal cord signal at this level.","impr":"C5-C6 disc-osteophyte complex with moderate central canal stenosis and ventral cord deformity.","pearl":"Distinguish soft disc (T2-bright, may resolve) from hard disc/osteophyte (T1/T2 dark, fixed) — affects surgical approach.","topic":"Disc","joint":"spine"},
{"id":"d339","front":"How would you describe uncovertebral and facet hypertrophy causing foraminal stenosis?","find":"At C6-C7 on the right there is uncovertebral (joint of Luschka) hypertrophic spurring anteriorly and facet/superior articular process hypertrophy posteriorly, combining with the posterolateral disc margin to produce severe right neural foraminal narrowing. The exiting C7 nerve root is effaced with loss of perineural fat. Left foramen patent.","impr":"Severe right C6-C7 foraminal stenosis from uncovertebral and facet hypertrophy, impinging the exiting C7 root.","pearl":"In the cervical spine the exiting root takes the number of the pedicle below — C6-C7 foramen transmits C7.","topic":"Foramen","joint":"spine"},
{"id":"d340","front":"How would you describe multilevel cervical central canal stenosis with cord effacement?","find":"Multilevel spondylotic change from C3-C4 through C6-C7 with disc-osteophyte complexes and ligamentum flavum thickening produces serial central canal narrowing. The stenosis is most severe at C4-C5 and C5-C6 where there is circumferential CSF effacement and the cord assumes a flattened, pancake configuration. Maximal canal compromise of approximately 50%.","impr":"Multilevel cervical spondylotic stenosis, most severe at C4-C5 and C5-C6 with circumferential cord effacement.","pearl":"Cord flattening without T2 signal change is mechanically significant but reversible; signal change implies established myelopathy.","topic":"Canal","joint":"spine"},
{"id":"d341","front":"How would you describe cervical cord compression with myelomalacia?","find":"At C5-C6 a disc-osteophyte complex and ligamentum flavum buckling produce severe central canal stenosis with circumferential cord compression and AP cord narrowing to approximately 5 mm. Within the compressed cord there is intramedullary T2/STIR hyperintensity without T1 hypointensity or expansion, consistent with myelomalacia/gliosis. No enhancement.","impr":"Severe C5-C6 cord compression with intramedullary signal change indicating myelomalacic cervical spondylotic myelopathy.","pearl":"T2-bright + T1-isointense + non-enhancing favors gliosis (worse prognosis); ill-defined T2 with cord swelling favors edema (more reversible).","topic":"Cord","joint":"spine"},
{"id":"d342","front":"How would you describe the snake-eyes appearance of spondylotic myelopathy?","find":"On axial T2 imaging at the level of maximal stenosis there is bilaterally symmetric paramedian intramedullary hyperintensity within the anterior horn gray matter, producing the snake-eyes (owl-eyes) appearance. The cord is mildly atrophic at this level without expansion or enhancement.","impr":"Snake-eyes anterior horn signal change indicating chronic cervical spondylotic myelopathy with poor prognostic implication.","pearl":"Snake-eyes reflects anterior horn cell cystic necrosis/microcavitation and predicts limited surgical recovery.","topic":"Cord","joint":"spine"},
{"id":"d343","front":"How would you describe ossification of the posterior longitudinal ligament (OPLL)?","find":"There is a band of low T1/T2 signal along the dorsal vertebral body margins from C3 through C5 corresponding to ossification of the posterior longitudinal ligament, confirmed as ossific density on companion CT. The ossified segment is continuous in type and produces ventral central canal stenosis with cord deformity; AP canal compromise approximately 60%.","impr":"Continuous-type cervical OPLL producing significant central canal stenosis and ventral cord compression.","pearl":"CT is essential to confirm ossification and measure the occupying ratio; double-layer sign on CT indicates dural penetration and higher surgical risk.","topic":"Ligament","joint":"spine"},
{"id":"d344","front":"How would you describe acute cord edema/contusion from cervical trauma?","find":"There is fusiform intramedullary T2/STIR hyperintensity within the cervical cord centered at C5 spanning approximately two vertebral segments, with mild cord expansion and indistinct margins consistent with acute edema/contusion. No focal T2 hypointense hemorrhagic core. Associated prevertebral soft tissue edema and posterior ligamentous injury.","impr":"Acute cervical cord contusion/edema centered at C5 without macroscopic hemorrhage.","pearl":"Longer length of edema and presence of intramedullary hemorrhage (T2-dark core) both predict worse neurologic outcome.","topic":"Trauma","joint":"spine"},
{"id":"d345","front":"How would you describe hemorrhagic cord injury?","find":"Within the contused cervical cord there is a focal central T2 hypointense focus with corresponding susceptibility blooming on GRE/SWI, consistent with intramedullary hemorrhage, surrounded by a larger rim of T2-hyperintense edema. The cord is expanded at this level.","impr":"Hemorrhagic cervical cord injury (contusion with intramedullary hematoma) — poor prognostic indicator.","pearl":"Any intramedullary hemorrhage upgrades the BASIC score and correlates strongly with complete and persistent deficit.","topic":"Trauma","joint":"spine"},
{"id":"d346","front":"How would you describe SCIWORA?","find":"In this pediatric trauma patient there is intramedullary cervical cord T2/STIR hyperintensity with mild expansion at C4-C5 without associated fracture or malalignment on CT or radiographs. Ligamentous structures are intact to mildly edematous.","impr":"Spinal cord injury without radiographic abnormality (SCIWORA) — cord signal change without osseous injury.","pearl":"SCIWORA reflects ligamentous laxity in children allowing transient deformation; MRI cord findings drive prognosis and management.","topic":"Trauma","joint":"spine"},
{"id":"d347","front":"How would you describe posterior ligamentous complex injury in cervical trauma?","find":"There is high STIR/T2 signal within the interspinous and supraspinous ligaments and ligamentum flavum at C6-C7 with associated widening of the interspinous distance and facet joint, indicating disruption of the posterior ligamentous complex. The anterior longitudinal ligament and disc appear intact.","impr":"Posterior ligamentous complex disruption at C6-C7 indicating an unstable flexion-distraction injury.","pearl":"PLC integrity is the key MRI determinant of stability in distraction injuries and guides operative fixation.","topic":"Trauma","joint":"spine"},
{"id":"d348","front":"How would you describe anterior ligamentous/discoligamentous injury in hyperextension?","find":"There is high T2/STIR signal and discontinuity of the anterior longitudinal ligament with widening of the anterior disc space at C4-C5 and prevertebral edema, consistent with hyperextension discoligamentous injury. Associated ventral epidural hematoma.","impr":"Anterior discoligamentous (hyperextension) injury at C4-C5 with prevertebral edema and ventral epidural hematoma.","pearl":"Hyperextension injuries in the stiff/ankylosed or stenotic spine commonly cause central cord syndrome.","topic":"Trauma","joint":"spine"},
{"id":"d349","front":"How would you describe perched and jumped facets?","find":"At C6-C7 the inferior articular facet of C6 sits at the apex of the C7 superior facet (perched facet) on the left with anterolisthesis; on the right the C6 inferior facet has passed anterior to the C7 superior facet and is locked (jumped/locked facet), producing roughly 50% anterolisthesis and focal canal narrowing. Disrupted PLC with facet joint fluid and edema.","impr":"Bilateral facet injury at C6-C7 (perched on the left, jumped/locked on the right) with anterolisthesis — highly unstable.","pearl":"The naked facet/uncovered facet sign and reversal of normal shingled overlap on sagittal images signal dislocation.","topic":"Trauma","joint":"spine"},
{"id":"d350","front":"How would you describe a vertebral body fracture with retropulsion and canal compromise?","find":"There is an acute compression-burst fracture of the C7 vertebral body with loss of anterior and posterior body height, a sagittal cleft, and retropulsion of the posterosuperior fragment into the ventral canal causing approximately 40% canal compromise and ventral cord deformity. Marrow edema on STIR confirms acuity.","impr":"Acute C7 burst fracture with retropulsed fragment and canal compromise deforming the cord.","pearl":"Posterior cortex involvement and retropulsion distinguish a burst from a stable compression fracture.","topic":"Trauma","joint":"spine"},
{"id":"d351","front":"How would you describe prevertebral soft tissue edema as a trauma marker?","find":"There is increased STIR signal and thickening of the prevertebral soft tissues anterior to the cervical spine, measuring beyond the normal limit (>6 mm at C2, >22 mm at C6), indicating prevertebral hemorrhage/edema and raising concern for occult ligamentous or osseous injury.","impr":"Prevertebral soft tissue edema — a sentinel sign of underlying cervical spine injury warranting close scrutiny.","pearl":"Prevertebral edema can be the only clue to a subtle hyperextension or ligamentous injury on an otherwise normal-alignment study.","topic":"Trauma","joint":"spine"},
{"id":"d352","front":"How would you describe a syrinx/syringomyelia?","find":"There is a longitudinally oriented intramedullary cavity within the cervical cord following CSF signal on all sequences (T1-hypointense, T2-hyperintense) with smooth, well-defined margins and associated cord expansion, extending from C2 to C5. No abnormal enhancement or nodular wall. [Associated with: Chiari I tonsillar ectopia / prior trauma / no clear cause].","impr":"Cervical syringomyelia; evaluate for Chiari malformation and exclude an underlying tumor.","pearl":"Tense syrinx + tonsillar ectopia >5 mm suggests Chiari I; nodular enhancement or non-CSF signal should prompt search for an associated neoplasm (presyrinx).","topic":"Cord","joint":"spine"},
{"id":"d353","front":"How would you describe transverse myelitis pattern of cord signal?","find":"There is longitudinally extensive intramedullary T2 hyperintensity spanning more than three vertebral segments and involving more than two-thirds of the cord cross-sectional area, with mild cord swelling and patchy enhancement, without a compressive lesion or osteophyte. The signal is centrally located.","impr":"Longitudinally extensive transverse myelitis pattern — consider NMOSD/MOG, sarcoid, paraneoplastic, or infectious/idiopathic etiologies.","pearl":"LETM (≥3 segments) favors neuromyelitis optica spectrum disorder over MS, which typically produces short peripheral lesions <2 segments.","topic":"Cord","joint":"spine"},
{"id":"d354","front":"How would you describe a short-segment demyelinating (MS) cord plaque?","find":"There is a short-segment ovoid intramedullary T2 hyperintense lesion spanning less than two vertebral segments, located peripherally in the dorsal/lateral cord and occupying less than half the cross-sectional area. [Acute: faint enhancement and mild swelling / Chronic: no enhancement, focal atrophy].","impr":"Short-segment peripheral cord lesion consistent with a demyelinating (multiple sclerosis) plaque.","pearl":"MS cord lesions are short, peripheral, and partial cross-section, unlike the long central lesions of NMOSD.","topic":"Cord","joint":"spine"},
{"id":"d355","front":"How would you describe cord atrophy?","find":"The cervical cord demonstrates diffuse volume loss with reduced AP and transverse diameters and prominence of the surrounding subarachnoid space, most pronounced at C4-C6. [With/without] residual intramedullary T2 signal change at the prior level of injury.","impr":"Cervical cord atrophy, sequela of prior compression/injury or chronic demyelination.","pearl":"Established atrophy with gliosis at a decompressed level explains persistent deficits and predicts limited further recovery.","topic":"Cord","joint":"spine"},
{"id":"d356","front":"How would you describe an enhancing intramedullary lesion (cord tumor pattern)?","find":"There is an expansile intramedullary cervical cord lesion with T2 hyperintensity, fusiform cord widening, and avid heterogeneous enhancement, accompanied by extensive rostral/caudal non-enhancing T2 edema and a polar/intratumoral cyst. The enhancing component is [eccentric — favoring astrocytoma / central with a hemosiderin cap — favoring ependymoma].","impr":"Expansile enhancing intramedullary cord neoplasm — ependymoma versus astrocytoma; recommend full-spine and brain MRI.","pearl":"Central location with a T2-dark hemosiderin cap favors ependymoma; eccentric/infiltrative favors astrocytoma; intense homogeneous nodule with cap favors hemangioblastoma.","topic":"Cord","joint":"spine"},
{"id":"d357","front":"How would you describe cord signal in acute ischemia (cord infarct)?","find":"There is intramedullary T2/STIR hyperintensity in an anterior spinal artery territory producing an axial owl-eyes/pencil-like longitudinal configuration centered on the central gray matter, with diffusion restriction and minimal early enhancement. Associated vertebral body endplate (disc-level) infarct may be present.","impr":"Cervicothoracic cord infarction in the anterior spinal artery territory.","pearl":"Restricted diffusion and adjacent vertebral body infarct help distinguish cord ischemia from inflammatory myelitis.","topic":"Cord","joint":"spine"},
{"id":"d358","front":"How would you describe a thoracic disc herniation?","find":"At T8-T9 there is a focal central/paracentral disc protrusion with a broad-based posterior contour, partially calcified with low T2 signal, indenting the ventral thoracic cord and effacing the ventral CSF. The cord is displaced and mildly deformed; [without / with] T2 cord signal change.","impr":"Calcified T8-T9 thoracic disc herniation with ventral cord deformity.","pearl":"Thoracic discs are frequently calcified and may be intradural — CT helps assess calcification and surgical approach.","topic":"Disc","joint":"spine"},
{"id":"d359","front":"How would you describe thoracic cord compression from spondylosis/disc?","find":"At the mid-thoracic level a calcified disc-osteophyte complex and posterior osteophytes produce ventral cord compression with AP cord narrowing and circumferential CSF effacement. There is intramedullary T2 hyperintensity at the level of compression indicating myelopathy.","impr":"Thoracic cord compression with intramedullary signal change consistent with thoracic myelopathy.","pearl":"The thoracic cord has tenuous watershed vascular supply, so compression here carries higher ischemic/myelopathic risk.","topic":"Cord","joint":"spine"},
{"id":"d360","front":"How would you describe Scheuermann disease?","find":"There is anterior wedging of three or more contiguous thoracic vertebral bodies exceeding 5 degrees each, with endplate irregularity, multiple Schmorl nodes, disc space narrowing, and an exaggerated thoracic kyphosis. Vertebral body shape is mildly elongated in the AP dimension.","impr":"Scheuermann disease (juvenile kyphosis) with multilevel anterior wedging and Schmorl nodes.","pearl":"The diagnostic criterion is anterior wedging ≥5 degrees across at least 3 contiguous vertebrae.","topic":"Marrow","joint":"spine"},
{"id":"d361","front":"How would you describe an acute vs chronic vertebral compression fracture?","find":"There is loss of vertebral body height at T12. Acute features: diffuse marrow STIR/T2 hyperintensity and T1 hypointensity (marrow edema), retropulsion, and a fluid cleft. Chronic features: marrow signal following normal fatty marrow with preserved fat on T1 and no STIR edema. [This fracture shows acute / chronic features].","impr":"T12 vertebral compression fracture, [acute with marrow edema / chronic and healed].","pearl":"Marrow edema on STIR/T1 indicates acuity and identifies which level to treat with vertebroplasty.","topic":"Marrow","joint":"spine"},
{"id":"d362","front":"How would you describe a benign vs malignant (metastatic) vertebral marrow lesion?","find":"At T7 there is a focal marrow lesion. Malignant features: complete T1 marrow replacement (signal below adjacent disc/muscle), convex posterior cortical bulging, pedicle/posterior element involvement, an associated soft tissue mass, and a diffusion-restricting/enhancing nodule. Benign features: preserved fat on T1, retained fatty band, lack of cortical destruction.","impr":"T7 vertebral lesion with [malignant — favoring metastasis / benign] features.","pearl":"Pedicle involvement, posterior cortical convexity, and an epidural/paraspinal soft tissue mass favor metastasis over a benign compression fracture.","topic":"Marrow","joint":"spine"},
{"id":"d363","front":"How would you describe a thoracic burst fracture?","find":"There is a comminuted fracture of the L1/T12-region vertebral body with involvement of both the anterior and posterior cortices, loss of height, interpedicular widening, and retropulsion of a posterosuperior fragment into the canal. STIR confirms marrow edema. Posterior ligamentous complex [intact / disrupted with high STIR signal].","impr":"Thoracolumbar burst fracture with canal retropulsion; PLC status determines surgical management.","pearl":"PLC integrity (assessed on MRI) is the pivotal factor in the TLICS score directing operative versus conservative treatment.","topic":"Trauma","joint":"spine"},
{"id":"d364","front":"How would you describe basilar invagination?","find":"The tip of the odontoid projects above the foramen magnum, measuring more than 5 mm above the Chamberlain line (hard palate to opisthion) and more than 7 mm above the McRae line, with crowding of the foramen magnum and ventral indentation of the cervicomedullary junction. [Associated with platybasia / Chiari / os odontoideum].","impr":"Basilar invagination with cervicomedullary crowding.","pearl":"Dens >5 mm above Chamberlain line defines basilar invagination; assess for secondary brainstem deformity and syrinx.","topic":"Craniovertebral","joint":"spine"},
{"id":"d365","front":"How would you describe atlantoaxial instability/subluxation?","find":"There is widening of the atlantodental interval beyond 3 mm in the adult (>5 mm in children) with [increase on flexion], indicating transverse ligament insufficiency. The available space for the cord behind the dens is reduced; the cervicomedullary junction is [normal / deformed]. [Context: rheumatoid pannus / trauma / Down syndrome].","impr":"Atlantoaxial instability with increased atlantodental interval and reduced space for the cord.","pearl":"In rheumatoid arthritis, look for periodontoid pannus and cranial settling; the space available for the cord (SAC) is more predictive than the ADI.","topic":"Craniovertebral","joint":"spine"},
{"id":"d366","front":"How would you describe a type II odontoid (dens) fracture?","find":"There is a transverse lucent fracture line at the base of the odontoid process (junction of the dens and C2 body) with surrounding marrow STIR edema, classified as Anderson-D'Alonzo type II. There is [mild posterior / anterior] displacement of the dens. No cord signal change.","impr":"Type II odontoid fracture at the dens base — unstable and prone to nonunion.","pearl":"Type II is the most common and most prone to nonunion due to the watershed blood supply at the dens base; distinguish from os odontoideum (smooth corticated, chronic).","topic":"Craniovertebral","joint":"spine"},
{"id":"d367","front":"How would you describe a thoracic epidural abscess/compression in infection?","find":"At the mid-thoracic level there is a rim-enhancing ventral epidural collection with restricted diffusion, contiguous with T2-hyperintense enhancing endplates and disc (discitis-osteomyelitis), producing cord compression and edema. Paraspinal phlegmon/abscess is present.","impr":"Thoracic discitis-osteomyelitis with epidural abscess and cord compression.","pearl":"Endplate destruction with disc T2 hyperintensity distinguishes infection from the typical endplate-sparing pattern of degenerative Modic change.","topic":"Cord","joint":"spine"},
{"id":"d368","front":"How would you describe an epidural hematoma in spinal trauma?","find":"There is a biconvex/lentiform extradural collection in the dorsal canal spanning several segments, hyperintense on T2 with heterogeneous T1 signal reflecting blood products, displacing the dura and compressing the cord with associated edema. No abnormal enhancement.","impr":"Spinal epidural hematoma causing cord compression — surgical emergency if neurologically progressive.","pearl":"Epidural collections are biconvex and can cross the disc level, displacing the dorsal dura, in contrast to subdural collections which conform to the thecal sac.","topic":"Trauma","joint":"spine"},
{"id":"d369","front":"How would you describe active sacroiliitis (ASAS-positive) on MRI?","find":"Subchondral bone marrow edema/osteitis manifest as ill-defined T2/STIR hyperintense, T1-hypointense signal in the periarticular bone of the sacrum and ilium, most pronounced in the synovial (anteroinferior) portion of the joint. To satisfy the ASAS definition the lesion is either present on >=2 consecutive slices at one site, or in >=2 sites on a single slice. Associated active features may include capsulitis (capsular fluid signal/enhancement), synovitis (enhancing synovium in the joint space on post-contrast fat-saturated T1), and enthesitis at capsular/ligamentous attachments. No fatty conversion within the edematous segment.","impr":"Active sacroiliitis meeting ASAS criteria, compatible with axial spondyloarthritis","pearl":"BME alone is not specific; ASAS requires the edema to be clearly subchondral/periarticular and meet the quantity threshold to count as positive.","topic":"Axial spondyloarthritis","joint":"general"},
{"id":"d370","front":"How would you describe capsulitis and synovitis of the SI joint on MRI?","find":"Capsulitis: STIR/T2-hyperintense signal and post-gadolinium enhancement involving the anterior and posterior joint capsule extending along the capsular attachments to the periosteum, beyond the cartilaginous joint margins. Synovitis: enhancing thickened synovium within the cartilaginous (anteroinferior) compartment on fat-saturated post-contrast T1, with corresponding intermediate T2 signal in the joint space.","impr":"Active capsulitis and synovitis, supportive inflammatory SI-joint features","topic":"Axial spondyloarthritis","joint":"general"},
{"id":"d371","front":"How would you describe SI-joint enthesitis on MRI?","find":"High STIR/T2 signal and enhancement at and immediately adjacent to ligamentous/tendinous insertions (interosseous and dorsal sacroiliac ligaments), with bone marrow edema in the underlying bone at the enthesis and soft-tissue edema tracking along the ligament. May extend beyond the joint margin into the retroarticular bone.","impr":"Active enthesitis, supportive of spondyloarthritis","topic":"Axial spondyloarthritis","joint":"general"},
{"id":"d372","front":"How would you describe the structural (chronic) lesions of sacroiliitis on MRI?","find":"Erosions: focal full-thickness defects of the subchondral cortical bone with loss of the dark cortical line and irregular widening of the joint space, often confluent. Sclerosis: bands of low signal on all sequences within the periarticular bone, typically >5 mm from the joint space, without high T2 signal. Fat metaplasia: well-defined, homogeneous T1-hyperintense subchondral signal that suppresses on fat-saturated sequences, reflecting prior inflammation. Backfill: bright T1/T2 signal filling an eroded joint space, bordered by a sclerotic rim, representing repair tissue. Ankylosis: bony bridging across the joint with continuous marrow signal and loss of the joint cleft.","impr":"Chronic structural changes of sacroiliitis (erosion, sclerosis, fat metaplasia, backfill, ankylosis)","pearl":"Fat metaplasia and backfill are markers of prior/healed inflammation and carry diagnostic weight for established axSpA.","topic":"Axial spondyloarthritis","joint":"general"},
{"id":"d373","front":"How would you describe ankylosing spondylitis spine changes on MRI/radiograph?","find":"Romanus lesions (shiny corner sign): bone marrow edema at the anterior/posterior vertebral body corners on STIR, evolving to fatty corners and corner erosions, with reactive sclerosis (shiny corners on radiograph). Squaring of the vertebral bodies from anterior corner erosion and ossification. Marginal, vertically oriented thin syndesmophytes bridging adjacent vertebral bodies producing the bamboo spine. Aseptic spondylodiscitis (Andersson lesion): destructive/inflammatory changes spanning the disc and adjacent endplates with extensive marrow edema, which may become a mobile pseudarthrosis through the fused spine. Enthesitis of interspinous and supraspinous ligaments (dagger sign).","impr":"Findings of ankylosing spondylitis with active and structural spinal lesions","topic":"Axial spondyloarthritis","joint":"spine"},
{"id":"d374","front":"How would you describe rheumatoid synovitis/pannus on MRI?","find":"Thickened, frond-like synovium lining the joint and tendon sheaths, intermediate signal on T1, intermediate-to-high on T2, with avid early post-gadolinium enhancement (active vascular pannus); fibrous pannus enhances less. Associated joint effusion. In the wrist/MCP distribution, pannus fills the radiocarpal and intercarpal compartments and erodes at the bare areas.","impr":"Active inflammatory pannus/synovitis, in keeping with rheumatoid arthritis","pearl":"Dynamic early enhancement distinguishes vascular (active) pannus from joint fluid and from fibrous pannus.","topic":"Rheumatoid arthritis","joint":"general"},
{"id":"d375","front":"How would you describe rheumatoid marginal erosions and osteitis on MRI?","find":"Marginal (bare-area) erosions: sharply marginated juxta-articular cortical defects with loss of the cortical line, T1-hypointense, filled with enhancing synovial tissue, classically at the radial aspects of the metacarpal heads, ulnar styloid, and carpus. Bone marrow edema/osteitis: ill-defined T2/STIR-hyperintense, T1-hypointense subchondral signal adjacent to erosions, representing the imaging correlate of osteitis and a predictor of erosive progression. Symmetric bilateral distribution favoring MCP, PIP, and wrist with sparing of the DIP.","impr":"Erosive rheumatoid arthritis with active osteitis","topic":"Rheumatoid arthritis","joint":"hand"},
{"id":"d376","front":"How would you describe rheumatoid tenosynovitis and rice bodies on MRI?","find":"Tenosynovitis: distended tendon sheath with synovial thickening and fluid, peritendinous enhancement, most often involving the extensor carpi ulnaris and the flexor tendons at the wrist and MCPs, with tendon thinning/attenuation at risk for rupture. Rice bodies: multiple small ovoid intra-articular/intrasheath bodies, low-to-intermediate on T1 and low on T2, non-enhancing, suspended within enhancing fluid.","impr":"Inflammatory tenosynovitis with rice bodies, compatible with rheumatoid arthritis","topic":"Rheumatoid arthritis","joint":"wrist"},
{"id":"d377","front":"How would you describe enthesitis in psoriatic/seronegative arthritis on MRI?","find":"Thickening and high STIR/T2 signal of the affected tendon or ligament at its insertion with adjacent perientheseal soft-tissue edema and bone marrow edema in the underlying bone (e.g., plantar fascia, Achilles, quadriceps/patellar tendon, collateral ligaments). Enhancement at the enthesis on post-contrast imaging. Periosteal new bone/erosion may develop at chronic sites.","impr":"Active enthesitis, characteristic of seronegative spondyloarthritis","pearl":"Enthesitis with perientheseal soft-tissue edema, rather than synovium-centered disease, is the hallmark of spondyloarthritis.","topic":"Psoriatic / seronegative","joint":"general"},
{"id":"d378","front":"How would you describe dactylitis on MRI?","find":"Diffuse fusiform soft-tissue swelling of the entire digit with flexor tenosynovitis (sheath fluid and enhancement), perientheseal and subcutaneous edema, often with adjacent small-joint synovitis and bone marrow edema. Enhancement spans multiple anatomic structures of the digit (sausage digit).","impr":"Dactylitis, characteristic of psoriatic arthritis","topic":"Psoriatic / seronegative","joint":"hand"},
{"id":"d379","front":"How would you describe DIP-predominant psoriatic arthritis and periostitis on MRI/radiograph?","find":"DIP-centered synovitis, erosions, and bone marrow edema with relative MCP sparing. Enthesitis of the extensor tendon and nail-bed involvement. Periostitis: fluffy, irregular periosteal new bone along the shafts of the phalanges with low-signal lamellar/solid periosteal reaction; chronic disease shows bone proliferation, ankylosis, and the pencil-in-cup deformity.","impr":"DIP-predominant psoriatic arthritis with periostitis and proliferative bone change","topic":"Psoriatic / seronegative","joint":"hand"},
{"id":"d380","front":"How would you describe gouty tophi on MRI?","find":"Para-articular soft-tissue masses that are intermediate-to-low signal on T1 and heterogeneous intermediate-to-low signal on T2 (variable depending on calcium/protein content), with peripheral or heterogeneous enhancement of the surrounding granulomatous rim. Adjacent juxta-articular and intraosseous erosions with sclerotic, overhanging margins and preserved joint space until late. Classic first MTP and foot/ankle distribution. On dual-energy CT, monosodium urate deposits color-code green.","impr":"Tophaceous gout with characteristic erosions and intermediate-signal tophi","pearl":"Erosions with overhanging edges and a maintained joint space distinguish gout from rheumatoid arthritis.","topic":"Crystal arthropathy","joint":"foot"},
{"id":"d381","front":"How would you describe CPPD / chondrocalcinosis on MRI/radiograph?","find":"Linear or punctate low-signal calcific deposits within hyaline articular cartilage and fibrocartilage (knee menisci, triangular fibrocartilage of the wrist, symphysis pubis, glenoid/acetabular labrum), best appreciated on radiograph/CT as chondrocalcinosis and as signal voids on MRI. Pyrophosphate arthropathy shows degenerative change in non-weight-bearing/atypical joints (radiocarpal, patellofemoral, MCP) with subchondral cysts and prominent osteophytes; SLAC-like scapholunate widening in the wrist.","impr":"CPPD deposition disease with chondrocalcinosis and pyrophosphate arthropathy","pearl":"Isolated radiocarpal or patellofemoral and MCP arthropathy with chondrocalcinosis should prompt CPPD.","topic":"Crystal arthropathy","joint":"general"},
{"id":"d382","front":"How would you describe HADD (hydroxyapatite / calcific tendinopathy) on MRI/radiograph?","find":"Globular or amorphous calcific deposit within a tendon or bursa, low signal on all MR sequences (radiograph/CT confirms dense calcification), with surrounding tendon thickening, peritendinous and bursal edema and enhancement during the resorptive phase. Most common in the rotator cuff (supraspinatus), gluteal tendons, and longus colli. Intraosseous migration may cause cortical erosion and reactive marrow edema mimicking infection/tumor.","impr":"Hydroxyapatite deposition disease (calcific tendinitis) in the resorptive phase","topic":"Crystal arthropathy","joint":"shoulder"},
{"id":"d383","front":"How would you describe septic arthritis on MRI?","find":"Joint effusion, often complex/loculated with debris and synovial thickening that enhances avidly. Periarticular and subchondral bone marrow edema on both sides of the joint with possible early erosions/cartilage loss. Surrounding soft-tissue edema, myositis, and reactive periarticular enhancement; possible adjacent abscess or sinus tract. Restricted diffusion within purulent fluid supports infection.","impr":"Findings concerning for septic arthritis; aspiration recommended","pearl":"Bone marrow edema on both sides of the joint with a complex enhancing effusion should raise concern for infection over a sterile reactive effusion.","topic":"Infection","joint":"general"},
{"id":"d384","front":"How would you describe acute osteomyelitis on MRI?","find":"Confluent geographic replacement of the normal fatty marrow: low T1 signal, high T2/STIR signal, with marrow enhancement after contrast. Penumbra sign: a thin rim of T1-isointense to mildly hyperintense granulation tissue lining an intraosseous abscess. Adjacent cortical destruction, periosteal reaction, soft-tissue edema/cellulitis, and possible subperiosteal or soft-tissue abscess. Restricted diffusion within abscess collections.","impr":"Acute osteomyelitis","pearl":"Confluent T1-marrow replacement is the most reliable sign; reactive edema alone (preserved T1 fat) is not diagnostic of osteomyelitis.","topic":"Infection","joint":"general"},
{"id":"d385","front":"How would you describe chronic osteomyelitis (sequestrum, involucrum, sinus tract) on MRI/CT?","find":"Sequestrum: a devitalized necrotic bone fragment, low signal on MRI and dense on CT, lying within an area of osteolysis, non-enhancing and surrounded by enhancing granulation tissue. Involucrum: a shell of viable periosteal new bone enveloping the sequestrum. Cloaca: cortical defect through which the cavity communicates. Sinus tract: a linear T2-hyperintense, enhancing tract extending from bone to the skin surface. Brodie abscess: well-defined intraosseous abscess with a penumbra sign.","impr":"Chronic osteomyelitis with sequestrum and involucrum","topic":"Infection","joint":"general"},
{"id":"d386","front":"How would you describe a soft-tissue abscess on MRI?","find":"Rim-enhancing fluid collection that is T1-hypointense and T2-hyperintense centrally, with a thick irregular enhancing wall and surrounding soft-tissue edema. The central contents show restricted diffusion (low ADC). Possible gas (signal void/susceptibility) and communication with bone via a sinus tract.","impr":"Soft-tissue abscess","pearl":"Central restricted diffusion with peripheral enhancement reliably distinguishes an abscess from a non-infected fluid collection or necrotic tumor.","topic":"Infection","joint":"general"},
{"id":"d387","front":"How would you describe septic (infectious) tenosynovitis on MRI?","find":"Markedly distended tendon sheath with complex fluid, thick irregular enhancing synovium, and surrounding soft-tissue edema and cellulitis, often with restricted diffusion of the sheath fluid. The tendon itself may show intrasubstance signal abnormality at risk for rupture; flexor tendon sheaths of the hand are typical, sometimes with adjacent abscess.","impr":"Septic tenosynovitis","topic":"Infection","joint":"hand"},
{"id":"d388","front":"How would you describe primary osteoarthritis on MRI/radiograph?","find":"Asymmetric joint-space narrowing maximal in the weight-bearing/contact zone, with marginal osteophytes, subchondral sclerosis (low signal on all sequences), and subchondral cysts (geodes) that are well-defined, T2-hyperintense, and may enhance peripherally. Focal full-thickness cartilage loss with subchondral bone marrow edema-like signal and small reactive effusion. No marginal erosions or pannus.","impr":"Degenerative osteoarthritis","topic":"Osteoarthritis","joint":"general"},
{"id":"d389","front":"How would you describe erosive (inflammatory) osteoarthritis on MRI/radiograph?","find":"DIP- and PIP-centered osteoarthritis with central subchondral erosions producing the gull-wing deformity (central erosion flanked by marginal osteophytes), bone marrow edema, synovitis, and joint-space loss. Erosions are central (not marginal as in RA), with bony proliferation; may progress to ankylosis.","impr":"Erosive osteoarthritis with gull-wing erosions","pearl":"Central erosions and the gull-wing configuration separate erosive OA from the marginal erosions of rheumatoid arthritis.","topic":"Osteoarthritis","joint":"hand"},
{"id":"d390","front":"How would you describe SAPHO syndrome on MRI/imaging?","find":"Osteitis and hyperostosis of the anterior chest wall (sternoclavicular, manubriosternal, costochondral) with bone marrow edema, sclerosis, and cortical thickening; the bull's-head sign on bone scan reflects increased uptake of the manubrium and clavicular heads. Associated spondylodiscitis, sacroiliitis, and chronic recurrent multifocal osteomyelitis-type lesions with sterile osteitis.","impr":"SAPHO syndrome with anterior chest wall osteitis/hyperostosis","topic":"Inflammatory arthropathy","joint":"general"},
{"id":"d391","front":"How would you describe juvenile idiopathic arthritis on MRI?","find":"Synovial thickening and enhancement with joint effusion, bone marrow edema, and early cartilage thinning; chronic disease causes epiphyseal overgrowth and ballooning, premature physeal fusion with limb-length discrepancy, and marginal erosions. Symmetric or oligoarticular distribution depending on subtype; cervical spine and TMJ involvement are characteristic.","impr":"Juvenile idiopathic arthritis with synovitis and growth disturbance","topic":"Inflammatory arthropathy","joint":"general"},
{"id":"d392","front":"How would you describe pigmented villonodular synovitis / TGCT on MRI?","find":"Lobulated synovial proliferative mass with characteristic blooming low-signal artifact on gradient-echo sequences due to hemosiderin, low-to-intermediate T1 and predominantly low T2 signal, with diffuse enhancement and associated effusion. Diffuse form fills the joint with villonodular synovium and causes pressure erosions on both sides of the joint with preserved joint space; localized form is a focal nodule (e.g., Hoffa fat pad or tendon sheath).","impr":"Tenosynovial giant cell tumor / PVNS","pearl":"Gradient-echo blooming from hemosiderin is the key discriminator from other proliferative synovitides.","topic":"Inflammatory arthropathy","joint":"knee"},
{"id":"d393","front":"How would you describe Lyme or reactive arthritis on MRI?","find":"Monoarticular or oligoarticular synovitis with effusion and enhancing synovial thickening, frequently large-joint (knee), with relatively preserved cartilage and minimal erosion early; reactive arthritis additionally shows enthesitis and periostitis with a lower-extremity, asymmetric distribution. Myositis and perientheseal edema may accompany.","impr":"Inflammatory synovitis compatible with reactive/Lyme arthritis","topic":"Inflammatory arthropathy","joint":"knee"},
{"id":"d394","front":"How would you describe amyloid arthropathy (dialysis-related) on MRI?","find":"Bilateral, symmetric synovial thickening that is characteristically low-to-intermediate signal on T1 and low signal on T2 (amyloid deposition), with juxta-articular subchondral cysts/erosions that have well-defined margins and preserved joint space, and minimal effusion. Common in the shoulders, hips, wrists (carpal tunnel), and spine of long-term hemodialysis patients.","impr":"Dialysis-related amyloid arthropathy","pearl":"Low-T2-signal synovial deposits with large cysts in a chronic dialysis patient suggest beta-2-microglobulin amyloid.","topic":"Inflammatory arthropathy","joint":"shoulder"},
{"id":"d395","front":"How would you describe neuropathic (Charcot) arthropathy on MRI?","find":"Joint disorganization with subluxation/dislocation, fragmentation of subchondral bone, marrow edema, large effusion with intra-articular debris and loose bodies, and subchondral cysts. Midfoot/Lisfranc distribution in diabetics. Edema centered on the joint and subchondral region with relative sparing of soft tissues and absence of a sinus tract or rim-enhancing collection favors Charcot over superimposed osteomyelitis.","impr":"Neuropathic (Charcot) arthropathy","pearl":"Subchondral cyst-like marrow signal, joint-centered distribution, and the ghost sign help separate Charcot from osteomyelitis.","topic":"Osteoarthritis","joint":"foot"},
{"id":"d396","front":"How would you describe a Brodie abscess on MRI?","find":"Well-circumscribed intraosseous (typically metaphyseal) lytic abscess with central T2-hyperintense fluid, surrounded by a penumbra sign (T1-iso/hyperintense rim of granulation tissue) and an outer rim of T2-hypointense reactive sclerosis. The cavity does not enhance centrally but shows rim enhancement; perilesional marrow edema and possible serpiginous channel toward the physis.","impr":"Brodie abscess (subacute osteomyelitis)","topic":"Infection","joint":"general"},
{"id":"d397","front":"How would you describe RA atlantoaxial involvement on MRI?","find":"Enhancing pannus surrounding the odontoid (periodontoid soft tissue) with erosion of the dens, atlantoaxial subluxation (widened anterior atlantodental interval), and potential cranial settling/basilar invagination. Cord compression with myelomalacic T2 signal in advanced cases.","impr":"Rheumatoid atlantoaxial pannus with instability","pearl":"Periodontoid pannus with an increased atlantodental interval is a surgically important finding in long-standing RA.","topic":"Rheumatoid arthritis","joint":"spine"},
{"id":"d398","front":"How would you describe a non-aggressive periosteal reaction?","find":"There is a smooth, solid, uninterrupted band of periosteal new bone paralleling the cortex, of uniform thickness and well corticated. The reaction is mature and continuous without lamellation or interruption, reflecting a slowly evolving process.","impr":"Solid non-aggressive periosteal reaction, favoring a benign/indolent process.","pearl":"Solid uninterrupted periosteum = slow growth; the host bone has time to wall off the lesion.","topic":"General descriptors","joint":"tumor"},
{"id":"d399","front":"How would you describe an aggressive periosteal reaction?","find":"There is an interrupted periosteal reaction with a multilaminated <onion-skin> appearance, perpendicular <sunburst/hair-on-end> spiculation, and a <Codman triangle> formed by elevated periosteum at the margin of the lesion where the central reaction has been destroyed. The pattern indicates a rapidly growing process outpacing the periosteal response.","impr":"Aggressive (interrupted) periosteal reaction, concerning for malignancy.","pearl":"Lamellated, sunburst, and Codman triangle all imply rapid growth — Ewing classically onion-skin, osteosarcoma classically sunburst.","topic":"General descriptors","joint":"tumor"},
{"id":"d400","front":"How would you describe a narrow zone of transition?","find":"The lesion demonstrates a narrow zone of transition with a sharply defined, sometimes sclerotic, marginating rim allowing the edge to be drawn with a fine pencil. The interface between lesion and host bone is abrupt and well demarcated.","impr":"Narrow zone of transition, a non-aggressive feature.","pearl":"Narrow zone = the bone keeps pace with a slow lesion. Best single plain-film/CT predictor of biological behavior.","topic":"General descriptors","joint":"tumor"},
{"id":"d401","front":"How would you describe a wide zone of transition?","find":"The lesion shows a wide, imperceptible zone of transition with an ill-defined margin that blends imperceptibly into the adjacent marrow, such that the true extent cannot be cleanly outlined. There is no marginal sclerosis.","impr":"Wide zone of transition, an aggressive feature concerning for malignancy or infection.","pearl":"Wide/imperceptible margin = rapid growth; the host bone cannot wall it off.","topic":"General descriptors","joint":"tumor"},
{"id":"d402","front":"How would you describe geographic bone destruction?","find":"There is a single, well-circumscribed area of lucent bone destruction with a geographic margin, with or without a sclerotic rim, and a narrow zone of transition. The pattern reflects a slowly growing, generally non-aggressive lesion.","impr":"Geographic lytic pattern, favoring a non-aggressive lesion.","pearl":"Lodwick IA (sclerotic rim) most indolent; IC (ill-defined geographic) more aggressive than IA/IB.","topic":"General descriptors","joint":"tumor"},
{"id":"d403","front":"How would you describe a moth-eaten pattern of bone destruction?","find":"There are multiple, coalescent, poorly marginated lucent lytic foci of varying size scattered through the medullary and cortical bone, with a moderately wide zone of transition. The lesions blur together without a discrete circumscribed margin.","impr":"Moth-eaten destruction, an aggressive pattern concerning for malignancy or osteomyelitis.","pearl":"Moth-eaten = intermediate aggressiveness; classic for lymphoma, metastases, myeloma, osteomyelitis.","topic":"General descriptors","joint":"tumor"},
{"id":"d404","front":"How would you describe a permeative pattern of bone destruction?","find":"There are innumerable tiny, uniform, ill-defined lucencies permeating the medullary cavity and cortex with a very wide imperceptible zone of transition, giving the bone a hazy, washed-out appearance without discrete margins. Cortical permeation may be present without overt destruction.","impr":"Permeative pattern, highly aggressive — small round blue cell tumor, lymphoma, or aggressive osteomyelitis.","pearl":"Permeative = most aggressive lytic pattern; Ewing sarcoma and lymphoma in children/young adults, myeloma/mets in older.","topic":"General descriptors","joint":"tumor"},
{"id":"d405","front":"How would you describe the marrow-replacement rule for a focal bone lesion on MRI?","find":"The lesion is hypointense to skeletal muscle and adjacent intervertebral disc on T1-weighted images, replacing the normal fatty marrow signal, with corresponding T2/STIR hyperintensity and enhancement. A focal lesion that does not retain T1 signal greater than muscle is considered a true marrow-replacing process.","impr":"Marrow-replacing lesion (T1 less than or equal to muscle/disc), warranting characterization and not dismissable as benign red marrow.","pearl":"Benign red marrow stays brighter than muscle/disc on T1; if a focus drops to or below muscle, treat as a real lesion.","topic":"Marrow","joint":"tumor"},
{"id":"d406","front":"How would you describe an enchondroma?","find":"There is a well-defined, lobulated, geographic medullary lesion in the metadiaphysis (commonly the small tubular bones of the hand or proximal humerus/femur), with a narrow zone of transition and no aggressive features. It is markedly T2 hyperintense with a lobular <bunch-of-grapes> architecture, low-to-intermediate T1 signal, and demonstrates peripheral and septal <arcs-and-rings> enhancement. Chondroid matrix shows punctate/popcorn/ring-and-arc calcification on CT. There is no deep endosteal scalloping (less than two-thirds cortical thickness), no periosteal reaction, and no soft-tissue mass.","impr":"Enchondroma; benign chondroid lesion.","pearl":"Endosteal scalloping greater than two-thirds of cortex, cortical breakthrough, soft-tissue mass, size greater than 5 cm, or pain at rest should raise concern for chondrosarcoma.","topic":"Bone tumor","joint":"tumor"},
{"id":"d407","front":"How would you describe an osteochondroma?","find":"There is a sessile or pedunculated bony excrescence arising from the metaphysis and pointing away from the adjacent joint, with uninterrupted continuity of both the cortex and the medullary cavity of the host bone into the lesion. A hyaline cartilage cap caps the lesion, markedly T2 hyperintense, measuring [X] mm in maximal thickness.","impr":"Osteochondroma with corticomedullary continuity.","pearl":"Cartilage cap greater than 1.5-2 cm in a skeletally mature patient (or growth after closure, new pain) suggests malignant transformation to secondary chondrosarcoma.","topic":"Bone tumor","joint":"tumor"},
{"id":"d408","front":"How would you describe a non-ossifying fibroma / fibrous cortical defect?","find":"There is an eccentric, cortically based, geographic lucent lesion in the metaphysis of a long bone (classically distal femur/proximal tibia) with a well-defined, lobulated, thin sclerotic rim and a narrow zone of transition. It is low-to-intermediate on T1, variably hyperintense on T2 with low-signal fibrous regions, and shows no periosteal reaction or soft-tissue component. Smaller cortically confined lesions are termed fibrous cortical defects.","impr":"Non-ossifying fibroma; do-not-touch benign fibroxanthoma.","pearl":"Classic do-not-touch lesion; scleroses and involutes with age. Larger lesions risk pathologic fracture.","topic":"Bone tumor","joint":"tumor"},
{"id":"d409","front":"How would you describe a bone island (enostosis)?","find":"There is a focal, ovoid, intramedullary sclerotic focus with characteristic brush-border thorny spiculated margins blending into surrounding trabeculae. It is uniformly low signal on all MRI pulse sequences, follows cortical bone, and shows no marrow edema, no periosteal reaction, and no uptake (or only minimal uptake) on bone scan.","impr":"Enostosis (bone island); benign.","pearl":"Stable size and absent/low radiotracer uptake distinguish it from osteoblastic metastasis; significant interval growth warrants concern.","topic":"Bone tumor","joint":"tumor"},
{"id":"d410","front":"How would you describe an osteoid osteoma?","find":"There is a small (less than 1.5 cm) round lucent nidus, often with central calcification, surrounded by dense reactive cortical sclerosis and fusiform cortical thickening. The nidus is T2 hyperintense with avid enhancement, and there is prominent surrounding marrow and soft-tissue edema. Dynamic imaging shows early arterial nidal enhancement with washout.","impr":"Osteoid osteoma; classic night pain relieved by NSAIDs/aspirin.","pearl":"It is the nidus, not the surrounding sclerosis/edema, that is the lesion; the dramatic edema can mimic a more aggressive process if the nidus is overlooked.","topic":"Bone tumor","joint":"tumor"},
{"id":"d411","front":"How would you describe a simple (unicameral) bone cyst?","find":"There is a centrally located, well-defined, geographic lucent lesion in the metaphysis abutting the physis (classically proximal humerus/femur), oriented along the long axis with mild expansion that does not exceed the width of the physis. It follows simple fluid signal (low T1, high T2) without internal enhancing solid components, and a dependent <fallen fragment> of fractured cortex may be seen within the dependent fluid.","impr":"Unicameral bone cyst.","pearl":"The fallen-fragment sign (a cortical fragment sinking through fluid to the dependent portion) is pathognomonic and confirms the lesion is fluid-filled and hollow.","topic":"Bone tumor","joint":"tumor"},
{"id":"d412","front":"How would you describe an aneurysmal bone cyst?","find":"There is an eccentric, expansile, multiloculated lytic lesion with a thin shell of periosteal bone and internal septations, classically in the metaphysis of a long bone or the posterior elements of the spine. Multiple <fluid-fluid levels> are present on T2 due to layering of blood-degradation products, with enhancing internal septa but no large enhancing solid nodule.","impr":"Aneurysmal bone cyst.","pearl":"Fluid-fluid levels are not specific (also seen in telangiectatic osteosarcoma, GCT, TGCT); a solid enhancing component or aggressive features mandates excluding telangiectatic osteosarcoma.","topic":"Bone tumor","joint":"tumor"},
{"id":"d413","front":"How would you describe a giant cell tumor of bone?","find":"There is an eccentric, geographic lytic lesion in the epiphysis of a long bone extending to and abutting the subarticular surface, arising after physeal closure, with a narrow but non-sclerotic zone of transition. It shows low-to-intermediate T1 and heterogeneous, often low-to-intermediate T2 signal (hemosiderin/dense cellularity), solid enhancement, and may contain secondary aneurysmal cystic change with fluid-fluid levels.","impr":"Giant cell tumor; locally aggressive.","pearl":"Subarticular epiphyseal location extending to the articular surface in a skeletally mature adult is the hallmark; non-sclerotic margin and low-T2 solid tissue help distinguish from a cyst.","topic":"Bone tumor","joint":"tumor"},
{"id":"d414","front":"How would you describe fibrous dysplasia?","find":"There is an expansile, geographic medullary lesion with a characteristic <ground-glass> hazy matrix and a thick sclerotic rind, classically in the proximal femur, ribs, craniofacial bones, or pelvis, without periosteal reaction. On MRI it is low-to-intermediate T1 with variable T2 signal and homogeneous or heterogeneous enhancement; the ground-glass matrix can appear deceptively low on T2.","impr":"Fibrous dysplasia.","pearl":"Ground-glass matrix and a long lesion in a long bone with a thick sclerotic rind are classic; proximal femoral involvement may produce a <shepherd's crook> varus deformity.","topic":"Bone tumor","joint":"tumor"},
{"id":"d415","front":"How would you describe an intraosseous lipoma?","find":"There is a well-defined geographic medullary lesion that follows macroscopic fat signal on all sequences, bright on T1 and T2 with complete signal suppression on fat-saturated sequences. A central dystrophic calcification or ossification and cystic/fatty involution may be present, classically in the calcaneus or proximal femur. There is no aggressive feature, periosteal reaction, or soft-tissue mass.","impr":"Intraosseous lipoma; benign.","pearl":"Uniform fat suppression confirms the diagnosis; central calcification reflects fat necrosis in involuting lesions (Milgram staging).","topic":"Bone tumor","joint":"tumor"},
{"id":"d416","front":"How would you describe a vertebral hemangioma?","find":"There is a well-defined intravertebral lesion with thickened vertical trabeculae producing a <corduroy/jail-bar> appearance on sagittal and a <polka-dot> appearance on axial imaging. The classic lesion is hyperintense on both T1 and T2 owing to fat and slow-flow vascular tissue. An atypical/aggressive hemangioma is low on T1 (less fat) with cortical expansion, soft-tissue/epidural extension, and avid enhancement.","impr":"Vertebral hemangioma.","pearl":"T1 hyperintensity (fatty) is reassuring; a T1-hypointense aggressive hemangioma with epidural soft tissue can mimic a malignant marrow lesion.","topic":"Bone tumor","joint":"tumor"},
{"id":"d417","front":"How would you describe a conventional osteosarcoma?","find":"There is an aggressive, ill-defined metaphyseal medullary lesion in the distal femur/proximal tibia of an adolescent with a wide zone of transition, mixed lytic and dense <cloud-like> osteoid matrix mineralization, aggressive interrupted periosteal reaction (sunburst spiculation and Codman triangle), cortical destruction, and a large enhancing soft-tissue mass. On MRI there is marrow replacement (low T1, heterogeneous high T2) with skip lesions to assess and possible epiphyseal/transphyseal extension; measure the full intramedullary and soft-tissue extent.","impr":"Conventional osteosarcoma.","pearl":"Always report intramedullary length, joint/neurovascular involvement, transphyseal and epiphyseal spread, and skip metastases for surgical planning.","topic":"Bone tumor","joint":"tumor"},
{"id":"d418","front":"How would you describe a chondrosarcoma (and distinguish from enchondroma)?","find":"There is a lobulated chondroid lesion with ring-and-arc matrix mineralization showing deep endosteal scalloping greater than two-thirds the cortical thickness, cortical thickening/expansion or breakthrough, and an associated soft-tissue mass. It is markedly T2 hyperintense with peripheral and septal enhancement; size is typically greater than 5 cm with active pain. Report the location (axial/proximal appendicular favored) and any aggressive features.","impr":"Chondrosarcoma.","pearl":"Versus enchondroma: deep endosteal scalloping (>2/3 cortex), cortical destruction, soft-tissue mass, marrow/peritumoral edema, size >5 cm, axial location, and pain favor chondrosarcoma.","topic":"Bone tumor","joint":"tumor"},
{"id":"d419","front":"How would you describe a Ewing sarcoma?","find":"There is a permeative, ill-defined diaphyseal/metadiaphyseal medullary lesion in a child or young adult with a wide zone of transition, lamellated <onion-skin> periosteal reaction, cortical permeation often without gross destruction (saucerization), and a disproportionately large soft-tissue mass. On MRI there is marrow replacement (low T1, intermediate-high T2) with avid enhancement; quantify intramedullary and soft-tissue extent.","impr":"Ewing sarcoma (small round blue cell tumor).","pearl":"A large soft-tissue mass out of proportion to the bone destruction, with permeative pattern and onion-skin periosteum in a young patient, is classic.","topic":"Bone tumor","joint":"tumor"},
{"id":"d420","front":"How would you describe a chondroblastoma?","find":"There is a small, well-defined, geographic lytic lesion centered in the epiphysis or apophysis of a skeletally immature patient, with a thin sclerotic rim and a narrow zone of transition. It shows low-to-intermediate T1, characteristically heterogeneous low-to-intermediate T2 signal (chondroid plus hemosiderin/calcification) with surrounding marrow and soft-tissue edema disproportionate to lesion size, and may show internal chondroid calcification and secondary ABC change.","impr":"Chondroblastoma.","pearl":"Epiphyseal/apophyseal lesion in an open-physis patient with prominent peritumoral edema; the edema and low-T2 components distinguish it from a simple cyst.","topic":"Bone tumor","joint":"tumor"},
{"id":"d421","front":"How would you describe osseous metastatic disease on MRI?","find":"There are multiple marrow-replacing foci that are hypointense to muscle/disc on T1 and hyperintense on T2/STIR with enhancement, distributed in the axial skeleton and proximal long bones. Lytic deposits are expansile/destructive while blastic deposits are low on T1 and low on T2 with sclerosis on CT; a <halo> or <bull's-eye> sign may help distinguish a lesion from benign red marrow. Assess for cortical breakthrough, soft-tissue extension, and pathologic/impending fracture.","impr":"Osseous metastatic disease.","pearl":"Multiple discrete marrow-replacing T1-hypointense foci in an adult older than 40 strongly favor metastases; report cortical involvement and fracture risk (e.g., Mirels criteria).","topic":"Bone tumor","joint":"tumor"},
{"id":"d422","front":"How would you describe multiple myeloma on MRI?","find":"There are multiple focal marrow-replacing lesions (low T1, high T2/STIR, enhancing) plus or minus a diffuse heterogeneous <salt-and-pepper> or variegated marrow infiltration pattern. In the spine, residual fat between lesions and a preserved fatty <mini-brain> appearance of a collapsed vertebra (residual posterior cortical struts) are characteristic. Lytic punched-out lesions without reactive sclerosis are seen on CT.","impr":"Multiple myeloma / plasma cell myeloma.","pearl":"Patterns: normal, focal, diffuse, variegated, and combined focal-on-diffuse; diffuse marrow involvement correlates with higher tumor burden. The mini-brain sign suggests myelomatous vertebral collapse.","topic":"Bone tumor","joint":"tumor"},
{"id":"d423","front":"How would you describe primary lymphoma of bone?","find":"There is a permeative or moth-eaten medullary lesion with a relatively preserved cortex despite extensive marrow infiltration, and a disproportionately large soft-tissue mass extending through small cortical channels. On MRI there is diffuse marrow replacement (low T1, intermediate T2) with avid homogeneous enhancement and restricted diffusion. Periosteal reaction is variable.","impr":"Primary lymphoma of bone.","pearl":"Marked marrow and soft-tissue disease with a deceptively intact cortex and low-to-intermediate T2 signal (high cellularity) is characteristic of lymphoma.","topic":"Bone tumor","joint":"tumor"},
{"id":"d424","front":"How would you describe a solitary plasmacytoma?","find":"There is a solitary, expansile, multiloculated lytic lesion with a <mini-brain> or <soap-bubble> trabeculated appearance, classically in a vertebral body or pelvis, with intermediate T1 and T2 signal and homogeneous enhancement. There is endosteal scalloping and cortical thinning; assess for epidural and soft-tissue extension.","impr":"Solitary plasmacytoma of bone.","pearl":"A single lesion may herald or progress to multiple myeloma; correlate with marrow biopsy and serum/urine paraproteins and survey the rest of the skeleton.","topic":"Bone tumor","joint":"tumor"},
{"id":"d425","front":"How would you describe a chordoma?","find":"There is a midline, destructive, lobulated lytic lesion centered in the sacrococcygeal region or clivus/spheno-occiput, with a large soft-tissue mass. It is markedly T2 hyperintense (high water content) with low-to-intermediate T1, internal low-signal septa, scattered foci of intratumoral hemorrhage/calcification, and heterogeneous <honeycomb> enhancement.","impr":"Chordoma.","pearl":"Midline location (sacrum, clivus, vertebral body) with very high T2 signal and a large soft-tissue component is classic; arises from notochordal remnants.","topic":"Bone tumor","joint":"tumor"},
{"id":"d426","front":"How would you describe red marrow reconversion versus marrow infiltration?","find":"Red marrow reconversion shows symmetric, bilateral, hazy marrow signal that remains hyperintense to skeletal muscle and disc on T1, spares the epiphyses/apophyses, and follows the expected reverse-order distribution (axial then proximal-to-distal appendicular). It signal-drops on opposed-phase chemical-shift imaging owing to admixed fat. Marrow infiltration/replacement is hypointense to muscle/disc on T1, may be focal or asymmetric, can involve epiphyses, and shows no opposed-phase signal drop.","impr":"Red marrow reconversion (benign) versus pathologic marrow infiltration.","pearl":"T1 brighter than muscle/disc plus opposed-phase signal drop (>20%) supports benign red marrow; loss of signal drop and T1 below muscle favors tumor.","topic":"Marrow","joint":"tumor"},
{"id":"d427","front":"How would you describe focal nodular marrow hyperplasia (focal red marrow)?","find":"There is a focal island of marrow that is mildly hypointense on T1 but remains hyperintense to skeletal muscle and adjacent disc, isointense to slightly hyperintense on T2/STIR, with feathery indistinct margins and interspersed fatty marrow. It demonstrates signal loss on opposed-phase imaging and shows no cortical destruction, soft-tissue mass, or restricted diffusion.","impr":"Focal nodular marrow hyperplasia (benign focal red marrow).","pearl":"The key reassurance is T1 signal greater than muscle, internal/peripheral fat, and opposed-phase signal drop; a focus dropping below muscle warrants further workup.","topic":"Marrow","joint":"tumor"},
{"id":"d428","front":"How would you describe post-treatment fatty marrow change?","find":"Within the prior radiation port or treated lesion there is sharply demarcated, geographic marrow that is hyperintense on T1 and follows fat on all sequences with suppression on fat-saturated images, corresponding to fatty marrow replacement. The margin often conforms to a radiation field with a straight, anatomically non-respecting border.","impr":"Post-treatment/post-radiation fatty marrow conversion; treatment response or radiation effect.","pearl":"A geographic, fat-signal region with straight field-shaped margins indicates radiation marrow; reappearance of T1-hypointense tissue suggests recurrence.","topic":"Marrow","joint":"tumor"},
{"id":"d429","front":"How would you describe avascular necrosis (osteonecrosis) of bone?","find":"There is a serpentine, geographic subchondral lesion with a peripheral low-signal sclerotic rim bordered internally by a hyperintense granulation rim on T2 producing the <double-line sign>, encircling a central segment that maintains fatty or fluid signal depending on stage. There may be subchondral fracture (crescent sign), articular surface flattening/collapse, and surrounding marrow edema in advanced disease.","impr":"Avascular necrosis / osteonecrosis.","pearl":"The double-line sign on T2 is characteristic; subchondral crescent and articular collapse mark progression and prognosis (ARCO/Ficat staging).","topic":"Marrow","joint":"tumor"},
{"id":"d430","front":"How would you describe a myxoid liposarcoma?","find":"Deep intramuscular mass that is markedly T2 hyperintense (myxoid matrix mimicking fluid/cyst) and T1 hypointense, with only small lacy or amorphous foci of macroscopic fat (often <10% of volume) seen as T1 hyperintensity suppressing on fat-sat. Shows internal lacy, reticular, and nodular enhancement that distinguishes it from a true cyst. Frequently arises in the thigh of a younger adult. Measures [size] cm.","impr":"Myxoid liposarcoma — deep myxoid mass with internal enhancement and minimal fat.","pearl":"A bright-T2 'cyst-like' deep mass that ENHANCES internally is not a cyst — think myxoid neoplasm (myxoid liposarcoma, myxoma, myxofibrosarcoma). Myxoid liposarcoma has a propensity for extrapulmonary (spine, retroperitoneum, other soft tissue) metastases.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d431","front":"How would you describe a schwannoma?","find":"Well-defined, ovoid mass oriented along the long axis of a peripheral nerve, eccentric to the parent nerve. T1 isointense to muscle, heterogeneously T2 hyperintense with avid enhancement. Classic signs: split-fat sign (rim of preserved fat at the proximal/distal poles), entering-and-exiting nerve, target sign (central low-to-intermediate T2 fibrocollagenous core with peripheral high T2 myxoid rim), and fascicular sign (multiple small ring-like fascicles). Cystic change and the split-fat sign favor schwannoma. Measures [size] cm.","impr":"Benign peripheral nerve sheath tumor, favoring schwannoma.","pearl":"Schwannoma is eccentric to the nerve (resectable with nerve preservation) whereas neurofibroma is centric/fusiform; cystic/hemorrhagic degeneration and the split-fat sign favor schwannoma.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d432","front":"How would you describe a neurofibroma?","find":"Fusiform mass arising centrally within and along a peripheral nerve, with the nerve entering and exiting. T1 isointense to muscle, T2 hyperintense often with a prominent target sign — central low T2 (dense central fibrocollagenous tissue) surrounded by peripheral high T2 myxoid stroma, with corresponding central enhancement. Split-fat sign at the poles. Plexiform neurofibroma appears as a multinodular 'bag of worms' along a nerve trunk and is pathognomonic for NF1. Measures [size] cm.","impr":"Benign peripheral nerve sheath tumor, favoring neurofibroma; plexiform form is NF1-associated.","pearl":"Target sign favors a benign PNST (more typical of neurofibroma); plexiform neurofibroma is diagnostic of NF1 and carries malignant transformation risk.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d433","front":"How would you describe a malignant peripheral nerve sheath tumor (MPNST)?","find":"Large (>5 cm) heterogeneous mass arising along a major nerve, with ill-defined or infiltrative margins, intratumoral cystic change/necrosis, peripheral enhancement, and surrounding edema. Loss of the target sign, presence of central T2 heterogeneity, rapid interval growth, and perilesional edema are concerning. Often arises within a pre-existing plexiform neurofibroma in NF1. Measures [size] cm.","impr":"Aggressive nerve sheath tumor concerning for MPNST; recommend biopsy.","pearl":"In NF1, suspicious features for malignant transformation include size >5 cm, rapid growth, peripheral enhancement pattern, intratumoral lobulation/cystic change, perilesional edema, and loss of the target sign; FDG-PET avidity supports MPNST.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d434","front":"How would you describe a ganglion cyst?","find":"Well-defined, unilocular or multilocular cystic lesion arising adjacent to a joint capsule or tendon sheath, markedly T2/STIR hyperintense and T1 hypointense, following fluid signal. Thin imperceptible wall with no internal enhancement (thin rim enhancement only). A connecting stalk/neck to the adjacent joint or tendon sheath may be identified. No solid enhancing nodularity. Measures [size] cm.","impr":"Ganglion cyst.","pearl":"A bright-T2 mass with NO internal enhancement is a cyst; if it enhances internally, reconsider a myxoid neoplasm. Common sites: dorsal wrist, around the knee (proximal tibiofibular joint), and along tendon sheaths.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d435","front":"How would you describe a synovial (juxta-articular) cyst?","find":"Fluid-signal cystic structure in direct continuity with a joint, lined by synovium, T2 hyperintense and T1 hypointense with a thin enhancing wall. A demonstrable neck communicating with the joint distinguishes it; complicated cysts may show internal debris/synovial proliferation and wall enhancement (e.g., a Baker cyst arising between the medial gastrocnemius and semimembranosus). Measures [size] cm.","impr":"Synovial cyst communicating with the joint.","pearl":"Ganglion cysts lack a true synovial lining and may not communicate with the joint, whereas synovial cysts demonstrate a joint connection; both are benign fluid collections without internal enhancement.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d436","front":"How would you describe a soft-tissue hematoma and its age-dependent signal?","find":"Focal collection with signal evolving by age. Acute (<1 wk): T1 isointense, T2 hypointense (deoxyhemoglobin). Subacute: T1 hyperintense (methemoglobin) with a T1/T2 hyperintense rim. Chronic: T2 hypointense hemosiderin rim with possible fluid-fluid levels from layering blood products and blooming on GRE. No internal nodular enhancement (only thin rim/granulation tissue enhancement). Measures [size] cm.","impr":"Soft-tissue hematoma; recommend follow-up to resolution to exclude underlying hemorrhagic neoplasm.","pearl":"Any enhancing soft-tissue nodule within a presumed hematoma, or a 'hematoma' that fails to resolve/decrease over follow-up, should raise concern for hemorrhagic sarcoma — follow to resolution.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d437","front":"How would you describe an intramuscular myxoma?","find":"Well-defined ovoid intramuscular mass, homogeneously markedly T2/STIR hyperintense and T1 hypointense (myxoid matrix), often with a surrounding rim of fat (peripheral fat cap) and a thin rim of perilesional muscle edema on fluid-sensitive sequences — the 'bright rim and cap' signs. Faint internal lacy/heterogeneous enhancement that is less than a sarcoma. Measures [size] cm.","impr":"Intramuscular myxoma.","pearl":"Perilesional fat rim and adjacent muscle edema favor benign myxoma over a myxoid sarcoma; multiple myxomas with fibrous dysplasia = Mazabraud syndrome.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d438","front":"How would you describe elastofibroma dorsi?","find":"Ill-defined, non-encapsulated lentiform soft-tissue mass in the plane between the chest wall (ribs/serratus anterior) and the inferior tip of the scapula, deep to latissimus dorsi. Characteristic alternating strands of fibrous tissue (intermediate signal, isointense to muscle) interleaved with entrapped fat (following fat signal) on T1 and T2. Frequently bilateral. Minimal/no enhancement. Measures [size] cm.","impr":"Elastofibroma dorsi — benign; no further workup needed.","pearl":"The pathognomonic location (subscapular/periscapular), bilaterality, and fat-interlaced fibrous architecture allow a confident benign diagnosis without biopsy.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d439","front":"How would you describe a soft-tissue hemangioma / venous malformation?","find":"Lobulated, infiltrative mass with serpentine/tubular vascular channels that are markedly T2 hyperintense, with interspersed regions of macroscopic fat (T1 hyperintense, suppressing on fat-sat) and feeding/draining vessels showing flow voids. Rounded T2-hypointense foci with blooming on GRE represent phleboliths. Gradual, progressive fill-in enhancement of the vascular channels. Measures [size] cm.","impr":"Soft-tissue vascular malformation/hemangioma; phleboliths are characteristic.","pearl":"Phleboliths (signal-void calcified foci with GRE blooming) plus interspersed fat and serpentine vessels are nearly diagnostic; slow-flow venous malformations show gradual fill-in, whereas high-flow AVMs show flow voids and arterialized draining veins.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d440","front":"How would you describe a lymphatic malformation (cystic hygroma)?","find":"Multiloculated cystic mass with thin internal septa, transspatial growth that insinuates between structures, markedly T2 hyperintense, and variable T1 signal. Macrocystic lesions show fluid-fluid levels from hemorrhage/proteinaceous content. Only thin septal/wall enhancement (no solid nodular enhancement). Slow-flow malformation without flow voids. Measures [size] cm.","impr":"Lymphatic (or mixed lymphovenous) malformation.","pearl":"Fluid-fluid levels and transspatial, insinuating growth across fascial planes favor a lymphatic malformation; absence of phleboliths and flow voids distinguishes it from a venous/high-flow lesion.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d441","front":"How would you describe desmoid-type fibromatosis (aggressive fibromatosis)?","find":"Infiltrative, ill-defined deep soft-tissue mass along fascial planes, T1 isointense to muscle and variably T2 hyperintense, containing characteristic low-signal bands/strands on all sequences (collagenous bands) that do not enhance. A 'fascial tail sign' of linear extension along fascia is typical. Avid enhancement of the cellular/myxoid components. No fat, no calcification. Measures [size] cm.","impr":"Desmoid-type fibromatosis; locally aggressive, non-metastasizing.","pearl":"Low-T2 collagen bands and a fascial tail sign favor desmoid; lesions become more T2-hypointense and less enhancing as they mature/become collagenized — useful for tracking response.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d442","front":"How would you describe nodular fasciitis?","find":"Small (usually <3-4 cm), rapidly growing subcutaneous or fascial-based nodule, often attached to or extending along the deep fascia (fascial tail). T1 isointense to muscle, T2 hyperintense (myxoid) to intermediate (cellular/fibrous), with avid enhancement and possible perilesional edema. The volar forearm is a classic site in a young adult. Measures [size] cm.","impr":"Imaging features compatible with nodular fasciitis (benign reactive proliferation); tissue confirmation recommended given overlap with sarcoma.","pearl":"A small, superficial, rapidly enlarging fascia-based lesion with a fascial tail in a young patient suggests nodular fasciitis — a benign mimic of sarcoma that often spontaneously regresses.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d443","front":"How would you describe localized tenosynovial giant cell tumor (giant cell tumor of the tendon sheath)?","find":"Well-defined, lobulated solid mass intimately related to a tendon sheath, most often the volar fingers/hand. Characteristically T1 and T2 hypointense (hemosiderin) with marked blooming/susceptibility on GRE sequences, and solid enhancement. Adjacent bone may show pressure erosion with sclerotic margins. Measures [size] cm.","impr":"Localized tenosynovial giant cell tumor (giant cell tumor of the tendon sheath).","pearl":"Low T1/T2 signal with GRE blooming reflects hemosiderin — the hallmark of the tenosynovial giant cell tumor family; the localized form favors the digits.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d444","front":"How would you describe diffuse tenosynovial giant cell tumor / PVNS?","find":"Diffuse villonodular synovial proliferation with frond-like or masslike synovial thickening, joint effusion, and characteristic low T1/T2 signal foci with prominent blooming artifact on GRE/SWI from hemosiderin deposition. Solid enhancement of the synovial masses. Pressure erosions on both sides of the joint with preserved joint space; the knee and hip are common. Measures extent across [compartments].","impr":"Diffuse tenosynovial giant cell tumor (pigmented villonodular synovitis).","pearl":"GRE blooming hemosiderin within hypertrophied synovium is the key feature; the diffuse intra-articular form is locally aggressive with a high recurrence rate after synovectomy.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d445","front":"How would you describe a synovial sarcoma?","find":"Deep soft-tissue mass typically near (but not within) a joint in a young adult, classically about the knee/foot. The 'triple sign' on T2 reflects mixed hyperintense (cystic/hemorrhagic), isointense (solid cellular), and hypointense (fibrous/calcified) components; multiple internal fluid-fluid levels produce a 'bowl of grapes' appearance. Heterogeneous enhancement. Internal calcification (better on CT/radiograph) is suggestive. Often deceptively small at presentation. Measures [size] cm.","impr":"Aggressive soft-tissue mass concerning for synovial sarcoma; recommend biopsy.","pearl":"A juxta-articular soft-tissue mass with the triple sign, fluid-fluid levels (bowl of grapes), and calcification in a young adult is highly suspicious for synovial sarcoma — and small size does NOT exclude malignancy.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d446","front":"How would you describe an undifferentiated pleomorphic sarcoma (UPS/MFH)?","find":"Large (>5 cm) deep soft-tissue mass, most commonly in the thigh of an older adult, with heterogeneous intermediate T1 and high T2 signal, internal necrosis/hemorrhage, ill-defined infiltrative margins, and heterogeneous nodular enhancement with non-enhancing necrotic regions. May contain hemosiderin or rare calcification. Measures [size] cm.","impr":"Aggressive high-grade soft-tissue sarcoma, favoring undifferentiated pleomorphic sarcoma.","pearl":"UPS is one of the most common adult soft-tissue sarcomas — a large, deep, heterogeneous, necrotic thigh mass in an older patient is the prototype; nonspecific imaging mandates biopsy.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d447","front":"How would you describe a myxofibrosarcoma?","find":"Predominantly myxoid mass, often superficial/subcutaneous in an older adult, markedly T2 hyperintense with intermediate solid components and heterogeneous enhancement. Characteristic infiltrative curvilinear 'tail sign' — enhancing fascia-based tumor extension tracking along fascial planes beyond the main mass on contrast-enhanced and fluid-sensitive images. Measures [size] cm.","impr":"Myxofibrosarcoma; the infiltrative tail sign portends a high local recurrence rate.","pearl":"The enhancing infiltrative tail along fascia is the imaging hallmark and explains the propensity for positive margins and local recurrence; surgical planning should account for this extension.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d448","front":"How would you describe a soft-tissue metastasis?","find":"Intramuscular or subcutaneous nodule/mass, T1 isointense to muscle and T2 hyperintense with surrounding perilesional edema disproportionate to size, showing solid or rim enhancement and possible central necrosis. Often multiple. A known primary (lung, melanoma, renal, breast) supports the diagnosis. Measures [size] cm.","impr":"Soft-tissue mass(es) concerning for metastatic disease in the setting of known primary.","pearl":"Intramuscular metastases often show prominent perilesional edema and enhancement; multiplicity and a known primary favor metastasis, but a solitary lesion may be indistinguishable from primary sarcoma and warrants biopsy.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d449","front":"How would you describe the aggressive-features checklist for a soft-tissue mass?","find":"Report features that favor malignancy: size >5 cm, deep (subfascial/intramuscular) location, ill-defined or infiltrative margins, marked heterogeneity of signal and enhancement, internal necrosis or hemorrhage, neurovascular or bony involvement, rapid interval growth, and perilesional/peritumoral edema. Conversely, small, superficial, well-circumscribed, homogeneous lesions with a determinate benign signal pattern (fat, fluid, hemosiderin, phleboliths) are reassuring.","impr":"Indeterminate soft-tissue mass with aggressive imaging features — recommend tissue sampling and referral to a sarcoma center.","pearl":"No single feature is diagnostic, but size >5 cm + deep location + heterogeneity/necrosis is the high-yield triad; only ~5 of the WHO benign categories (lipoma, hemangioma, etc.) can be confidently called benign by MRI — most indeterminate masses require biopsy before any intervention.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d450","front":"How would you describe bursitis as a soft-tissue lesion?","find":"Well-defined fluid collection conforming to a known bursal location (e.g., trochanteric, olecranon, retrocalcaneal, iliopsoas, pes anserine), markedly T2/STIR hyperintense and T1 hypointense. Simple bursitis shows thin wall and no internal enhancement; complicated/infected or inflammatory bursitis shows wall thickening, internal debris/septations, synovial enhancement, and surrounding soft-tissue edema. Rice bodies (small T2-hypointense nodules) suggest chronic inflammatory/tuberculous bursitis. Measures [size] cm.","impr":"Bursitis at the [named] bursa.","pearl":"Anatomic location at a known bursa plus simple fluid signal confirms bursitis; wall thickening, internal complexity, and surrounding edema suggest infection or inflammatory arthropathy.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d451","front":"How would you describe a superficial (subcutaneous) lipoma versus a deep/intramuscular lipomatous lesion for risk stratification?","find":"A small, superficial, encapsulated mass following fat signal with complete fat suppression and no/few thin septa is a benign superficial lipoma. In contrast, a deep intramuscular or retroperitoneal fatty mass that is large (>10 cm), contains thick/nodular septa, prominent non-fatty enhancing soft tissue, or shows interval growth should be treated as an atypical lipomatous tumor / well-differentiated liposarcoma until proven otherwise. Measures [size] cm.","impr":"Superficial benign lipoma vs deep fatty lesion requiring atypical-lipomatous-tumor workup, depending on the above features.","pearl":"Depth and size are the most useful clinical discriminators: superficial small fatty masses are almost always benign, while deep/large fatty masses with septal nodularity warrant biopsy or excision.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d452","front":"How would you describe a soft-tissue abscess (to distinguish from tumor)?","find":"Rim-enhancing fluid collection with central non-enhancing necrotic/purulent contents that are T2 hyperintense and show restricted diffusion (high DWI signal, low ADC). Thick irregular enhancing wall, surrounding ill-defined T2-hyperintense phlegmonous edema, and possible internal gas (signal voids/blooming) or adjacent sinus tract. Measures [size] cm.","impr":"Soft-tissue abscess with surrounding cellulitis/phlegmon.","pearl":"Central restricted diffusion in a rim-enhancing soft-tissue collection favors an abscess over a necrotic tumor; clinical correlation for infection and presence of gas/sinus tract supports the diagnosis.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d453","front":"How would you describe an epidermal inclusion cyst in the soft tissues?","find":"Well-defined subcutaneous lesion, often round/ovoid, intermediate-to-high T2 signal that may be heterogeneous due to keratin debris, with variable restricted diffusion. Thin wall with only peripheral rim enhancement and no solid internal enhancement; a punctum or tract to the skin surface may be seen. Rupture incites surrounding inflammatory edema and wall enhancement. Measures [size] cm.","impr":"Epidermal inclusion cyst.","pearl":"A superficial dermal/subcutaneous lesion with a skin punctum, internal keratin (variable DWI), and only rim enhancement is characteristic; rupture causes a brisk inflammatory reaction that can mimic infection or tumor.","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d454","front":"How would you describe an arteriovenous (high-flow) malformation?","find":"Tangle of vessels (nidus) without an associated soft-tissue mass, demonstrating multiple serpentine flow voids on spin-echo sequences, enlarged feeding arteries and early-filling arterialized draining veins, and high signal on time-of-flight/dynamic angiographic sequences. No discrete enhancing parenchymal mass; absence of phleboliths. Measures extent across [region].","impr":"High-flow arteriovenous malformation.","pearl":"Flow voids and arterialized early-draining veins WITHOUT a soft-tissue mass characterize a high-flow AVM, distinguishing it from a slow-flow venous malformation (gradual fill-in, phleboliths) and from a true vascular neoplasm (enhancing soft-tissue mass).","topic":"Soft tissue tumor","joint":"tumor"},
{"id":"d455","front":"How would you describe an intact rotator cuff repair on MRI?","find":"Supraspinatus tendon reapproximated to the greater tuberosity footprint with low-to-intermediate signal. Susceptibility artifact from suture anchors at the footprint without surrounding marrow edema. Tendon thickness preserved; no full-thickness fluid-signal defect. Mild intrasubstance intermediate signal and irregular contour are expected postoperative findings. No fluid gap on T2/PD fat-saturated sequences.","impr":"Intact rotator cuff repair with expected postoperative signal and suture anchor artifact.","pearl":"Repaired tendons rarely return to normal low signal; persistent intermediate T2 signal WITHOUT a fluid-filled gap is expected and should not be called a re-tear.","topic":"Postoperative","joint":"shoulder"},
{"id":"d456","front":"How would you describe a recurrent/re-torn rotator cuff repair (full-thickness)?","find":"Fluid-signal-intensity gap on T2/PD fat-saturated images extending through the full thickness of the repaired supraspinatus, measuring [X] mm in AP width, with tendon retraction to the level of the [glenoid/mid-humeral head]. Discontinuity at the suture anchor footprint with fluid undermining the repair. Associated muscle atrophy and fatty infiltration (Goutallier grade [X]).","impr":"Full-thickness re-tear of the rotator cuff repair with [X] mm defect and tendon retraction.","pearl":"The diagnostic finding is FLUID signal (not just intermediate signal) traversing the repair; use a 2-week-or-greater postop interval, as early granulation tissue can mimic fluid.","topic":"Postoperative","joint":"shoulder"},
{"id":"d457","front":"How would you describe a partial re-tear of a rotator cuff repair?","find":"Focal fluid-signal defect involving the [articular-sided/bursal-sided] fibers of the repaired supraspinatus measuring [X] mm in depth without full-thickness extension. Partial-thickness gap at the footprint with intact overlying/underlying fibers. No tendon retraction.","impr":"Partial-thickness re-tear of the rotator cuff repair, [articular/bursal]-sided, measuring [X] mm.","pearl":"Distinguish partial re-tear (fluid through part of the tendon) from expected intermediate signal; articular-sided defects are more common after repair.","topic":"Postoperative","joint":"shoulder"},
{"id":"d458","front":"How would you describe suture anchor artifact after rotator cuff repair?","find":"Foci of susceptibility (blooming) artifact along the greater tuberosity footprint corresponding to suture anchors, most conspicuous on gradient-echo and reduced on fast spin-echo sequences. No surrounding marrow edema or osteolysis. Anchors seated within the cortex without proud positioning into the joint or pull-out.","impr":"Expected suture anchor susceptibility artifact without evidence of loosening.","pearl":"Use FSE/MARS sequences and align frequency-encoding to minimize anchor artifact; new marrow edema or a lucent halo around an anchor suggests loosening or infection.","topic":"Postoperative","joint":"shoulder"},
{"id":"d459","front":"How would you describe expected granulation tissue after rotator cuff repair?","find":"Intermediate T2/PD signal and mild enhancement at the repaired tendon-footprint interface without a discrete fluid-filled gap. Tendon remains in continuity to the tuberosity. Mild subacromial/subdeltoid fluid and synovial reaction.","impr":"Expected postoperative granulation tissue and reactive change at the repair site; no re-tear.","pearl":"Granulation tissue enhances and shows intermediate (not fluid-bright) signal on T2 — fluid-bright signal traversing the repair is the key to a re-tear.","topic":"Postoperative","joint":"shoulder"},
{"id":"d460","front":"How would you describe a torn/ruptured ACL graft?","find":"Discontinuity of the graft fibers with a focal fluid-signal-intensity gap, abnormal lax or wavy graft contour, and increased graft signal on T2. Anterior tibial translation and uncovering of the posterior horn of the lateral meniscus. Empty/widened tunnels. Secondary signs: PCL buckling and bone contusions if acute.","impr":"Full-thickness tear of the ACL graft with discontinuity and abnormal laxity.","pearl":"A horizontal or near-horizontal graft (parallel to the tibial plateau) with anterior tibial translation indicates failure even without a discrete gap.","topic":"Postoperative","joint":"knee"},
{"id":"d461","front":"How would you describe a cyclops lesion after ACL reconstruction?","find":"Focal nodular soft-tissue mass of intermediate-to-low T2 signal in the anterior intercondylar notch, anterior to the distal ACL graft, measuring [X] mm, composed of fibrous/granulation tissue. Causes a mechanical block to full extension. May contain low-signal fibrous foci.","impr":"Cyclops lesion in the anterior intercondylar notch causing loss of terminal extension.","pearl":"Clinically presents with loss of terminal extension; the nodule is anterior to the graft in the notch and is the arthrofibrosis differential when focal.","topic":"Postoperative","joint":"knee"},
{"id":"d462","front":"How would you describe arthrofibrosis after ACL reconstruction?","find":"Diffuse intermediate-to-low signal scar tissue filling the intercondylar notch and infrapatellar fat (Hoffa) region with thickening and scarring of the anterior soft tissues. Patella baja and restricted motion may be present. Distinguished from focal cyclops lesion by its diffuse distribution.","impr":"Diffuse arthrofibrosis with notch and infrapatellar scarring causing motion restriction.","pearl":"Arthrofibrosis is DIFFUSE scar versus the FOCAL nodule of a cyclops lesion; both restrict extension.","topic":"Postoperative","joint":"knee"},
{"id":"d463","front":"How would you describe ACL tunnel widening?","find":"Enlargement of the femoral and/or tibial bone tunnels with a smooth sclerotic or fluid-signal-lined margin, tunnel diameter measuring [X] mm (compared with expected drill diameter). Best assessed on the obliquely reformatted images along the tunnel axis.","impr":"ACL reconstruction tunnel widening, likely related to [bioabsorbable screw resorption/micromotion/synovial fluid influx].","pearl":"Tunnel widening is multifactorial (mechanical micromotion plus biologic synovial response/cytokines) and matters most when revision is contemplated, as it may require staged bone grafting.","topic":"Postoperative","joint":"knee"},
{"id":"d464","front":"How would you describe malposition of an ACL femoral tunnel?","find":"Femoral tunnel aperture positioned [too anterior/too vertical] on the lateral femoral condyle rather than at the native footprint, producing a [vertical/non-anatomic] graft orientation. Vertical grafts control anterior translation but not rotational laxity. Associated graft impingement or laxity may be present.","impr":"Non-anatomic ACL femoral tunnel position with vertical graft orientation.","pearl":"An overly vertical graft from a high/anterior femoral tunnel leaves rotational instability (positive pivot shift) despite a taut-appearing graft.","topic":"Postoperative","joint":"knee"},
{"id":"d465","front":"How would you describe a postoperative meniscal re-tear after repair?","find":"Linear fluid-signal-intensity (T2-bright) extending into the meniscal substance and reaching the articular surface at the prior repair site, exceeding the expected intermediate signal of healing fibrocartilage. Displaced fragment may be present. On MR arthrography, intra-articular contrast tracks into the tear.","impr":"Recurrent meniscal tear at the prior repair site with fluid signal reaching the articular surface.","pearl":"After repair, intermediate (granulation) signal can persist for years — only FLUID-bright T2 signal or contrast extending into/through the meniscus reliably indicates a re-tear; MR arthrography improves specificity.","topic":"Postoperative","joint":"knee"},
{"id":"d466","front":"How would you describe the expected appearance after partial meniscectomy?","find":"Truncated, blunted meniscal contour with reduced size at the resection margin. Intermediate intrasubstance signal that does NOT unequivocally reach the new articular surface is expected. No displaced fragment. Less than 25% versus greater resection affects re-tear interpretation thresholds.","impr":"Expected postoperative appearance following partial meniscectomy without evidence of recurrent tear.","pearl":"When less than 25% of the meniscus is resected, standard criterion (fluid/signal touching the surface) applies; with greater than 25% resection, only fluid-signal or a displaced fragment reliably indicates a re-tear, and MR arthrography is preferred.","topic":"Postoperative","joint":"knee"},
{"id":"d467","front":"How would you describe a successful microfracture cartilage repair?","find":"Fibrocartilage repair tissue filling the prior chondral defect with surface congruity and signal approaching adjacent native cartilage. Good integration with the defect margins and intact subchondral plate. Expected mild persistent subchondral marrow edema and small subchondral cysts/intralesional osteophyte formation may occur.","impr":"Microfracture chondral repair with good defect fill and integration.","pearl":"Microfracture produces fibrocartilage (type I), which is mechanically inferior to native hyaline cartilage; persistent subchondral edema and intralesional osteophytes are common over time.","topic":"Postoperative","joint":"knee"},
{"id":"d468","front":"How would you describe a failed/incomplete microfracture repair?","find":"Incomplete fill of the chondral defect with a depressed or fissured repair surface, fluid-signal cleft between repair tissue and adjacent cartilage indicating poor integration, and persistent or worsening subchondral marrow edema and cyst formation. Delamination of repair tissue from the subchondral plate.","impr":"Failed microfracture repair with poor fill, peripheral integration failure, and subchondral changes.","pearl":"Fluid signal at the repair-native cartilage interface (delamination/poor integration) and worsening subchondral edema/cysts are the key markers of failure.","topic":"Postoperative","joint":"knee"},
{"id":"d469","front":"How would you describe a well-integrated osteochondral autograft (OATS/mosaicplasty)?","find":"Cylindrical osteochondral plug(s) with the cartilage surface flush with adjacent native cartilage and a congruent articular surface. Bony portion incorporated with the recipient with bridging trabeculae and resolving marrow edema. No fluid-signal cleft at the bone or cartilage interface.","impr":"Well-incorporated osteochondral autograft with flush surface and osseous integration.","pearl":"Assess BOTH the cartilage surface (flush, no surface cleft) and the osseous base (bony incorporation, resolving edema); proud or sunken plugs predict failure.","topic":"Postoperative","joint":"knee"},
{"id":"d470","front":"How would you describe a failed osteochondral autograft (OATS)?","find":"Persistent fluid-signal-intensity cleft at the osteochondral plug interface (bone or cartilage) indicating nonintegration, with proud or depressed plug positioning relative to the articular surface, persistent/increasing subchondral marrow edema and cyst formation, and cartilage surface fibrillation or fragmentation.","impr":"Failed/non-incorporated osteochondral autograft with interface fluid and subchondral changes.","pearl":"A persistent T2-bright fluid cleft surrounding the plug base beyond 6-12 months indicates failed osseous incorporation.","topic":"Postoperative","joint":"knee"},
{"id":"d471","front":"How would you describe a successful MACI/ACI cartilage repair?","find":"Defect filled with repair tissue at or near the level of adjacent native cartilage with a smooth congruent surface and signal isointense to slightly hyperintense to native hyaline cartilage. Good peripheral integration without fluid cleft, intact subchondral plate. MOCART scoring used to grade fill, integration, surface, and signal.","impr":"Matrix-associated autologous chondrocyte implantation with good fill, integration, and surface congruity.","pearl":"MOCART score systematically grades defect fill, border integration, surface, structure, and signal; early hypertrophic fill can occur and usually remodels.","topic":"Postoperative","joint":"knee"},
{"id":"d472","front":"How would you describe periprosthetic osteolysis on MRI with MARS protocol?","find":"Well-defined intermediate-signal soft-tissue intraosseous lesions adjacent to the prosthesis on MARS sequences, expanding the periprosthetic bone with scalloped endosteal margins, communicating with the joint via wear-particle synovitis. Best seen on STIR/MARS-corrected images that reduce metal susceptibility.","impr":"Periprosthetic osteolysis from particle-induced synovitis around the arthroplasty.","pearl":"MARS techniques (high bandwidth, view-angle tilting, SEMAC/MAVRIC, STIR over chemical fat-sat) are essential to reduce metal artifact and reveal osteolysis and soft-tissue reaction.","topic":"Postoperative","joint":"hip"},
{"id":"d473","front":"How would you describe an adverse local tissue reaction/pseudotumor (metal-on-metal hip)?","find":"Periprosthetic cystic or solid soft-tissue mass (pseudotumor) communicating with the joint, with variable T2 signal and characteristic low-signal synovial debris/deposits. Synovial thickening, fluid collections dissecting along tissue planes, and adjacent muscle/tendon (abductor) destruction. Classified by Anderson/Hauptfleisch type.","impr":"Adverse local tissue reaction with pseudotumor formation around a metal-on-metal arthroplasty.","pearl":"ALTR/metallosis from metal-on-metal or trunnion wear shows low-signal synovial deposits and abductor tendon destruction; correlate with serum cobalt/chromium levels.","topic":"Postoperative","joint":"hip"},
{"id":"d474","front":"How would you describe polyethylene wear and prosthetic loosening on MRI?","find":"Eccentric narrowing of the radiolucent polyethylene liner with asymmetric femoral head position within the cup indicating wear. Loosening shown by fluid-signal or fibrous tissue at the bone-implant/bone-cement interface, periprosthetic lucency, and osteolysis. Component migration or change in position over serial exams.","impr":"Polyethylene wear with particle disease and findings suggesting component loosening.","pearl":"Fluid/granulation signal interposed at the bone-implant interface is the imaging hallmark of loosening; eccentric head position signals poly wear.","topic":"Postoperative","joint":"hip"},
{"id":"d475","front":"How would you describe periprosthetic joint infection versus aseptic reaction on MRI?","find":"Infection: lamellated hyperintense synovitis with thick irregular enhancing synovium, periprosthetic fluid collections/abscess with rim enhancement, sinus tracts, edematous infiltration of fat planes, and reactive marrow edema. Aseptic particle disease: well-defined intermediate-signal osteolysis with bland synovitis and absence of soft-tissue edema/sinus tracts.","impr":"Findings favor periprosthetic [infection given lamellated synovitis, fluid collections, and sinus tracts / aseptic particle disease given bland osteolysis without soft-tissue edema].","pearl":"A lamellated (layered) hyperintense synovitis, extracapsular fluid/sinus tracts, and edema in adjacent soft tissues favor infection over bland aseptic osteolysis.","topic":"Postoperative","joint":"hip"},
{"id":"d476","front":"How would you describe fracture nonunion versus normal healing on MRI/imaging?","find":"Nonunion: persistent fracture gap with sclerotic or rounded fracture margins, absence of bridging trabeculae/callus, fluid or fibrous tissue within the fracture cleft (T2-bright), and in atrophic nonunion absence of marrow edema/vascularity at the ends. Normal healing: progressive bridging callus, resolving fracture line, and decreasing marrow edema.","impr":"Findings consistent with fracture nonunion [atrophic/hypertrophic] rather than expected healing.","pearl":"Hypertrophic nonunion shows abundant callus but a persistent cleft (mechanical/stability problem); atrophic nonunion shows sclerotic avascular ends (biologic problem).","topic":"Postoperative","joint":"ankle"},
{"id":"d477","front":"How would you describe hardware loosening on imaging?","find":"Lucent halo greater than 2 mm around screws or fixation with a sclerotic margin, progressive widening on serial exams, screw backout or change in angulation, and on MRI fluid/fibrous signal at the bone-hardware interface. Cortical resorption around the implant.","impr":"Hardware loosening with periimplant lucency and interface change.","pearl":"A progressive (rather than static) lucent zone greater than 2 mm or screw backout on serial radiographs is more reliable for loosening than a single exam.","topic":"Postoperative","joint":"ankle"},
{"id":"d478","front":"How would you describe infection around hardware on MRI?","find":"Periimplant marrow edema and enhancement with confluent T2-hyperintense signal, periosseous fluid collection or abscess with rim enhancement, sinus tract extending to the skin, and cortical destruction. MARS sequences used to reduce metal artifact. Distinguished from bland postoperative edema by abscess, sinus tract, and aggressive marrow involvement.","impr":"Hardware-associated osteomyelitis/soft-tissue infection.","pearl":"A sinus tract, drainable rim-enhancing collection, and confluent marrow edema/enhancement distinguish infection from expected early postoperative reactive change.","topic":"Postoperative","joint":"ankle"},
{"id":"d479","front":"How would you describe recurrent disc herniation versus epidural fibrosis on postoperative spine MRI?","find":"Recurrent herniation: focal, polypoid mass of disc material isointense to the parent disc, with smooth margins and only PERIPHERAL/rim enhancement, contiguous with the disc space, mass effect on the thecal sac/nerve root. Epidural fibrosis: ill-defined epidural soft tissue that enhances HOMOGENEOUSLY and immediately on early postcontrast images, retracts toward the dura, and lacks significant mass effect.","impr":"Findings favor [recurrent/residual disc herniation given peripheral enhancement and disc contiguity / epidural fibrosis given homogeneous immediate enhancement].","pearl":"Obtain immediate post-gadolinium images: scar enhances homogeneously and early, whereas disc material shows only peripheral enhancement (granulation tissue rim) early on.","topic":"Postoperative","joint":"spine"},
{"id":"d480","front":"How would you describe a postoperative pseudomeningocele?","find":"Well-defined CSF-signal (T2-bright, T1-hypointense) fluid collection in the posterior operative bed communicating with the thecal sac through a dural defect, following CSF signal on all sequences with a thin or imperceptible wall and no internal enhancement. May contain herniated nerve roots.","impr":"Postoperative pseudomeningocele communicating with the thecal sac.","pearl":"It follows CSF signal on all sequences and lacks a true epithelial lining (unlike a true meningocele); look for the dural defect and any entrapped nerve roots.","topic":"Postoperative","joint":"spine"},
{"id":"d481","front":"How would you describe a postoperative (repaired) Achilles tendon on MRI?","find":"Diffusely thickened tendon with heterogeneous intermediate signal at the repair site and low-signal suture material/susceptibility foci. Tendon in continuity with intact fibers spanning the prior tear. No fluid-filled gap. Mild peritendinous and Kager fat-pad scarring is expected.","impr":"Intact Achilles tendon repair with expected postoperative thickening and scarring.","pearl":"Repaired tendons remain thickened with heterogeneous signal for a long time; a discrete fluid-filled gap with fiber discontinuity indicates re-rupture, not the expected intermediate signal.","topic":"Postoperative","joint":"ankle"},
{"id":"d482","front":"How would you describe a distal biceps tendon repair (intact vs failed)?","find":"Intact: distal biceps tendon reattached to the radial tuberosity with low-to-intermediate signal and suture anchor/button artifact at the tuberosity, fibers in continuity, no fluid gap. Failed/re-tear: fluid-signal gap between the tendon stump and the tuberosity footprint with retraction (measure stump-to-footprint distance in cm), fluid undermining the repair, and anchor/cortical button displacement.","impr":"[Intact distal biceps repair / Distal biceps repair failure with re-tear and tendon retraction of X cm].","pearl":"FABS (flexion-abduction-supination) positioning best profiles the distal biceps footprint; measure the stump-to-footprint gap, which guides revision versus primary fixation.","topic":"Postoperative","joint":"elbow"},
{"id":"d483","front":"How would you describe carpal tunnel syndrome on MRI?","find":"Enlargement of the median nerve at the proximal carpal tunnel (pisiform level) with abrupt flattening within the tunnel at the level of the hook of the hamate; the nerve demonstrates increased T2 signal and loss of the normal fascicular pattern. The cross-sectional area of the median nerve at the pisiform measures > 10-12 mm2 (normal up to ~9-10 mm2), with a flattening ratio > 3 distally. Volar bowing of the flexor retinaculum is present. Look for an underlying cause: tenosynovitis of the flexor tendons, persistent median artery, anomalous lumbrical muscle, ganglion, or amyloid deposition. In advanced cases, denervation T2 edema/atrophy of the thenar muscles (abductor pollicis brevis).","impr":"Findings of median neuropathy at the carpal tunnel consistent with carpal tunnel syndrome.","pearl":"Median nerve CSA at the pisiform > 10-12 mm2 is the most reliable single marker; thenar denervation indicates more advanced disease.","topic":"Nerve entrapment","joint":"wrist"},
{"id":"d484","front":"How would you describe ulnar nerve entrapment at Guyon canal on MRI?","find":"The ulnar nerve is enlarged and demonstrates increased T2 signal as it traverses Guyon canal between the pisiform and hook of the hamate; the fascicular pattern is effaced. A space-occupying lesion is frequently the cause: a ganglion cyst arising from the pisotriquetral or triquetrohamate joint, an anomalous/accessory muscle (accessory abductor digiti minimi), ulnar artery thrombosis/aneurysm, or hook of hamate fracture. Denervation changes (acute T2 edema or chronic fatty atrophy) involve the hypothenar muscles and, depending on zone, the interossei and adductor pollicis. Spare the more proximally innervated FCU and FDP, which distinguishes this from cubital tunnel.","impr":"Ulnar neuropathy at Guyon canal, likely secondary to [ganglion/anomalous muscle/hamate fracture].","pearl":"Zone of compression matters: zone 1 (motor + sensory), zone 2 (deep motor only), zone 3 (superficial sensory only).","topic":"Nerve entrapment","joint":"wrist"},
{"id":"d485","front":"How would you describe cubital tunnel syndrome (ulnar neuropathy at the elbow) on MRI?","find":"The ulnar nerve is enlarged with increased T2 signal and loss of fascicular architecture within the cubital tunnel posterior to the medial epicondyle, beneath the cubital tunnel retinaculum (Osborne band). Causes include a thickened/accessory anconeus epitrochlearis muscle, nerve subluxation/dislocation over the medial epicondyle, ganglion, osteophytes from medial elbow osteoarthritis, or prior trauma. Secondary denervation manifests as T2 edema (subacute) or fatty atrophy (chronic) of the flexor carpi ulnaris, ulnar half of the flexor digitorum profundus, and the ulnar-innervated intrinsic hand muscles.","impr":"Ulnar neuropathy at the cubital tunnel with associated denervation changes.","pearl":"Involvement of FCU and ulnar FDP (forearm muscles) localizes the lesion to the elbow rather than to Guyon canal.","topic":"Nerve entrapment","joint":"elbow"},
{"id":"d486","front":"How would you describe posterior interosseous nerve (radial tunnel) syndrome on MRI?","find":"Increased T2 signal and mild enlargement of the posterior interosseous nerve (deep branch of the radial nerve) as it passes through the radial tunnel and the arcade of Frohse at the proximal margin of the supinator. A space-occupying lesion is often causative: lipoma, ganglion, or a thickened/hypertrophied arcade of Frohse. The hallmark is denervation of the supinator and the extensor compartment muscles innervated distal to the entrapment, with diffuse T2 hyperintensity (subacute) progressing to fatty atrophy (chronic) of the supinator, ECU, EDC, EDM, EPL, and abductor pollicis longus. The brachioradialis and ECRL are typically spared as they arise proximal to the bifurcation.","impr":"Posterior interosseous neuropathy at the arcade of Frohse with extensor compartment denervation.","pearl":"Selective denervation of the deep extensors with sparing of brachioradialis/ECRL is the imaging signature of PIN entrapment.","topic":"Nerve entrapment","joint":"elbow"},
{"id":"d487","front":"How would you describe pronator syndrome (proximal median nerve entrapment) on MRI?","find":"Increased T2 signal of the median nerve as it passes between the humeral and ulnar heads of the pronator teres, or beneath the lacertus fibrosus, sublimis bridge of the FDS, or a supracondylar process/ligament of Struthers. Unlike carpal tunnel syndrome, there is denervation T2 edema or fatty atrophy of the proximal median-innervated forearm muscles including the pronator teres (variably spared), FCR, palmaris longus, FDS, and the anterior interosseous-supplied FPL, FDP to digits 2-3, and pronator quadratus.","impr":"Proximal median neuropathy consistent with pronator syndrome.","pearl":"Forearm flexor denervation distinguishes pronator syndrome from carpal tunnel syndrome, which spares the forearm.","topic":"Nerve entrapment","joint":"elbow"},
{"id":"d488","front":"How would you describe anterior interosseous nerve syndrome on MRI?","find":"A pure motor neuropathy. The anterior interosseous nerve itself may show subtle T2 signal, but the diagnosis rests on the denervation pattern: T2 hyperintensity and enlargement (subacute) or fatty atrophy (chronic) selectively involving the flexor pollicis longus, the flexor digitorum profundus to the index and middle fingers, and the pronator quadratus. Sensory branches and other median-innervated muscles are spared. May be compressive (fibrous bands, vessels) or, frequently, a manifestation of Parsonage-Turner syndrome.","impr":"Anterior interosseous neuropathy with selective FPL/FDP/pronator quadratus denervation.","pearl":"Isolated AIN denervation is commonly neuralgic amyotrophy (Parsonage-Turner) rather than mechanical compression.","topic":"Nerve entrapment","joint":"elbow"},
{"id":"d489","front":"How would you describe suprascapular nerve entrapment at the suprascapular notch on MRI?","find":"Increased T2 signal of the suprascapular nerve at the suprascapular notch, often with a paralabral/ganglion cyst extending from a posterosuperior labral tear into the notch, or a thickened/ossified superior transverse scapular ligament. Because the entrapment is proximal to the branches to both muscles, denervation involves BOTH the supraspinatus and infraspinatus: diffuse T2 muscle edema with feathery hyperintensity (subacute) progressing to fatty atrophy and volume loss (chronic).","impr":"Suprascapular neuropathy at the suprascapular notch with supraspinatus and infraspinatus denervation.","pearl":"Suprascapular notch lesion = supraspinatus + infraspinatus; always search for an associated labral tear feeding the ganglion.","topic":"Nerve entrapment","joint":"shoulder"},
{"id":"d490","front":"How would you describe suprascapular nerve entrapment at the spinoglenoid notch on MRI?","find":"A paralabral/ganglion cyst at the spinoglenoid notch, typically arising from a posterior or posterosuperior labral tear, compressing the distal suprascapular nerve. Because the supraspinatus branch arises more proximally, denervation is ISOLATED to the infraspinatus: T2 edema and feathery hyperintensity in the subacute phase, with fatty atrophy and volume loss in the chronic phase, while the supraspinatus is preserved.","impr":"Distal suprascapular neuropathy at the spinoglenoid notch with isolated infraspinatus denervation.","pearl":"Isolated infraspinatus denervation localizes the lesion to the spinoglenoid notch; supraspinatus involvement implies a more proximal (notch) lesion.","topic":"Nerve entrapment","joint":"shoulder"},
{"id":"d491","front":"How would you describe quadrilateral space syndrome (axillary nerve) on MRI?","find":"Denervation changes of the teres minor (and variably the deltoid) from compression of the axillary nerve and posterior circumflex humeral artery within the quadrilateral space (bordered by teres minor, teres major, long head of triceps, and humeral shaft). Subacute denervation shows diffuse T2 edema of the teres minor; chronic disease shows fatty atrophy and volume loss. Causes include fibrous bands, paralabral cysts, hypertrophied muscle, or a humeral mass.","impr":"Axillary neuropathy in the quadrilateral space with teres minor denervation.","pearl":"Isolated teres minor fatty atrophy is a common incidental finding and does not always require a structural lesion; deltoid involvement supports true QSS.","topic":"Nerve entrapment","joint":"shoulder"},
{"id":"d492","front":"How would you describe Parsonage-Turner syndrome (neuralgic amyotrophy) on MRI?","find":"Multifocal, patchy T2/STIR hyperintensity (denervation edema) involving muscles of the shoulder girdle in a distribution that crosses single-nerve territories, most often the supraspinatus, infraspinatus, deltoid, and teres minor; the subscapularis and serratus anterior may also be involved. In the subacute phase muscles are edematous and mildly enlarged; in the chronic phase they show fatty atrophy. The nerves themselves may demonstrate focal T2 signal, hourglass-like constrictions, or fascicular thickening on high-resolution imaging. No mechanical compressive lesion is identified.","impr":"Multifocal denervation pattern consistent with Parsonage-Turner syndrome (acute brachial neuritis).","pearl":"A denervation pattern that does not respect a single peripheral nerve territory and lacks a compressive lesion is the key to diagnosing neuralgic amyotrophy.","topic":"Nerve entrapment","joint":"shoulder"},
{"id":"d493","front":"How would you describe tarsal tunnel syndrome (posterior tibial nerve) on MRI?","find":"Increased T2 signal and enlargement of the tibial nerve or its terminal branches deep to the flexor retinaculum behind the medial malleolus. A space-occupying lesion is frequently identified: ganglion cyst, varicosities/venous plexus, lipoma, accessory muscle, or a talocalcaneal coalition with associated osteophyte. Denervation of the plantar intrinsic muscles follows, with T2 edema (subacute) or fatty atrophy (chronic) of the abductor hallucis, flexor digitorum brevis, quadratus plantae, and abductor digiti minimi depending on which branches are involved.","impr":"Tibial neuropathy at the tarsal tunnel, likely due to [ganglion/varicosities/coalition].","pearl":"Always identify a structural cause; idiopathic tarsal tunnel syndrome is a diagnosis of exclusion. Branch-specific intrinsic muscle denervation maps the level of compression.","topic":"Nerve entrapment","joint":"ankle"},
{"id":"d494","front":"How would you describe Baxter neuropathy (inferior calcaneal/first branch of lateral plantar nerve) on MRI?","find":"Selective denervation of the abductor digiti minimi muscle of the foot, manifesting as T2/STIR edema in the subacute phase and, characteristically, fatty atrophy with volume loss in the chronic phase. The first branch of the lateral plantar nerve is entrapped between the deep fascia of the abductor hallucis and the medial head of the quadratus plantae, often in association with plantar fasciitis, a calcaneal enthesophyte, or biomechanical overload.","impr":"Baxter neuropathy with isolated fatty atrophy of the abductor digiti minimi.","pearl":"Isolated fatty atrophy/edema of the abductor digiti minimi (the most inferolateral plantar muscle) is pathognomonic for Baxter neuropathy and a common cause of chronic heel pain.","topic":"Nerve entrapment","joint":"foot"},
{"id":"d495","front":"How would you describe a Morton neuroma on MRI?","find":"An ovoid, teardrop-shaped mass in the intermetatarsal space at the level of the metatarsal heads, most commonly the second or third web space, that is iso- to hypointense to muscle on T1 and characteristically LOW signal on T2 (reflecting fibrosis/perineural fibrosis rather than a true neoplasm), with variable enhancement. The lesion is centered plantar to the deep transverse intermetatarsal ligament and typically measures > 5 mm in transverse diameter. An associated intermetatarsal bursitis with fluid signal is frequently present.","impr":"Morton neuroma of the [second/third] intermetatarsal web space.","pearl":"Low T2 signal distinguishes a Morton neuroma (fibrosis) from a fluid-filled intermetatarsal bursa, which is bright on T2; the two often coexist.","topic":"Nerve entrapment","joint":"foot"},
{"id":"d496","front":"How would you describe common peroneal (fibular) nerve entrapment at the fibular neck on MRI?","find":"Increased T2 signal and enlargement of the common peroneal nerve as it wraps around the fibular neck, often with a tibiofibular paralabral ganglion cyst tracking along the nerve, mass, or fibular head fracture/post-traumatic scar. Denervation involves the muscles of the anterior compartment (tibialis anterior, EHL, EDL) and lateral compartment (peroneus longus and brevis), with T2 edema (subacute) or fatty atrophy (chronic).","impr":"Common peroneal neuropathy at the fibular neck with anterior and lateral compartment denervation.","pearl":"A ganglion arising from the superior tibiofibular joint dissecting along the articular branch is a classic cause; track the cyst back to the joint.","topic":"Nerve entrapment","joint":"ankle"},
{"id":"d497","front":"How would you describe deep peroneal nerve entrapment (anterior tarsal tunnel syndrome) on MRI?","find":"Increased T2 signal of the deep peroneal nerve beneath the inferior extensor retinaculum at the anterior ankle/dorsum of the foot, often related to an osteophyte from the talonavicular or tarsometatarsal joints, ganglion, or ill-fitting footwear. Denervation, when present, selectively involves the extensor digitorum brevis and extensor hallucis brevis muscles (T2 edema acutely, fatty atrophy chronically).","impr":"Deep peroneal neuropathy at the anterior tarsal tunnel.","pearl":"Selective EDB/EHB denervation on the dorsum of the foot points to distal deep peroneal entrapment.","topic":"Nerve entrapment","joint":"ankle"},
{"id":"d498","front":"How would you describe superficial peroneal nerve entrapment on MRI?","find":"Focal T2 hyperintensity of the superficial peroneal nerve as it pierces the deep crural fascia in the distal third of the lateral leg (~10-12 cm above the lateral malleolus), sometimes associated with a fascial defect with muscle herniation, ganglion, or scar. Denervation pattern affects the lateral compartment muscles (peroneus longus and brevis) when entrapment is proximal; distal entrapment is purely sensory with no muscle changes.","impr":"Superficial peroneal neuropathy at the site of fascial penetration.","pearl":"A muscle herniation through a fascial defect at the point the nerve exits the deep fascia is a recognized cause of focal superficial peroneal neuropathy.","topic":"Nerve entrapment","joint":"ankle"},
{"id":"d499","front":"How would you describe piriformis syndrome (sciatic nerve) on MRI?","find":"Asymmetric hypertrophy of the piriformis muscle and/or increased T2 signal of the sciatic nerve as it courses at or through the piriformis at the greater sciatic foramen; an anatomic variant with the nerve (or its peroneal division) splitting/passing through the muscle may be present. The sciatic nerve shows increased caliber and T2 hyperintensity. In chronic cases, denervation edema or fatty atrophy of the hamstrings and distal sciatic-innervated leg muscles develops.","impr":"Sciatic neuropathy at the level of the piriformis (piriformis syndrome).","pearl":"Compare piriformis muscle bulk and sciatic nerve signal side-to-side; an anomalous nerve course through the muscle belly supports the diagnosis.","topic":"Nerve entrapment","joint":"hip"},
{"id":"d500","front":"How would you describe pudendal nerve entrapment on MRI?","find":"Increased T2 signal and/or enlargement of the pudendal nerve along its course through the greater sciatic foramen, between the sacrospinous and sacrotuberous ligaments, and within Alcock (pudendal) canal along the obturator internus. Look for a compressive cause: thickened/ossified sacrotuberous or sacrospinous ligament, perineural cyst, or scarring. Denervation may involve the levator ani and external anal/urethral sphincters and ischiocavernosus/bulbospongiosus muscles.","impr":"Pudendal neuropathy, possibly at the [interligamentous space/Alcock canal].","pearl":"The interligamentous segment between the sacrospinous and sacrotuberous ligaments and Alcock canal are the two classic entrapment points.","topic":"Nerve entrapment","joint":"hip"},
{"id":"d501","front":"How would you describe meralgia paresthetica (lateral femoral cutaneous nerve) on MRI?","find":"Focal T2 hyperintensity and/or enlargement of the lateral femoral cutaneous nerve as it passes beneath or through the inguinal ligament near the anterior superior iliac spine, sometimes with an acute angulation or compressive lesion. Because the nerve is purely sensory, there is NO muscle denervation; the diagnosis is supported by focal nerve signal/caliber change and exclusion of a mass.","impr":"Lateral femoral cutaneous neuropathy consistent with meralgia paresthetica.","pearl":"A purely sensory nerve, so the absence of any muscle denervation is expected and helps confirm the diagnosis.","topic":"Nerve entrapment","joint":"hip"},
{"id":"d502","front":"How would you describe the MRI appearance of acute/subacute muscle denervation?","find":"Diffuse, feathery T2/STIR hyperintensity throughout the affected muscle belly with preserved or mildly enlarged muscle volume and normal T1 signal (no fatty change yet). The edema-like signal reflects increased extracellular water and capillary bed enlargement and conforms strictly to a single nerve territory. Changes become detectable within days to a few weeks of denervation and are reversible if reinnervation occurs.","impr":"Subacute denervation edema in a [named nerve] distribution.","pearl":"Acute/subacute = bright T2/STIR with normal T1 and normal/increased volume; this phase is potentially reversible and signals recent or ongoing denervation.","topic":"Denervation","joint":"general"},
{"id":"d503","front":"How would you describe the MRI appearance of chronic muscle denervation?","find":"Fatty replacement of the muscle (T1 hyperintense streaks/global fatty infiltration that suppresses on fat-saturated sequences) with volume loss and atrophy of the affected muscle, again conforming to a single nerve territory. T2 edema-like signal has largely resolved. This represents irreversible end-stage denervation. Goutallier/fatty grading may be applied.","impr":"Chronic denervation with fatty atrophy in a [named nerve] distribution.","pearl":"Chronic = T1-bright fatty infiltration with volume loss; irreversible, in contrast to the reversible bright-T2 subacute phase.","topic":"Denervation","joint":"general"},
{"id":"d504","front":"How would you describe the value of muscle denervation pattern in localizing a peripheral nerve lesion?","find":"The constellation of involved muscles is read as a map: the set of denervated muscles (edema acutely, fatty atrophy chronically) is matched to the most proximal common nerve segment that innervates all of them, thereby localizing the lesion. Sparing of muscles innervated proximal to the lesion further refines the level. Reporting should name the involved muscles, the inferred nerve and level of involvement, and the chronicity (edema vs fatty atrophy).","impr":"Denervation pattern localizing the lesion to the [named nerve] at the [level].","pearl":"Think in terms of which branches arise above versus below the lesion: spared muscles are innervated proximal to the entrapment, denervated muscles distal to it.","topic":"Denervation","joint":"general"},
{"id":"d505","front":"How would you describe a normal TMJ disc position on MRI?","find":"On the closed-mouth sagittal oblique image, the biconcave disc is interposed between the condyle and the articular eminence with the posterior band positioned at the 12 o'clock position over the condylar apex (posterior band within ~10 degrees of vertical) and the thin intermediate zone between the condyle and eminence. On open-mouth imaging the disc translates anteriorly so the intermediate zone remains interposed between the translated condyle and the posterior slope of the eminence. The disc is uniformly low signal on all sequences.","impr":"Normal TMJ disc position and morphology, closed and open mouth.","pearl":"The posterior band should sit at the 12 o'clock position over the condyle in the closed-mouth position; this is the reference for diagnosing displacement.","topic":"TMJ","joint":"general"},
{"id":"d506","front":"How would you describe TMJ anterior disc displacement WITH reduction on MRI?","find":"On the closed-mouth image the posterior band of the disc is displaced anterior to the 12 o'clock position (anterior to the condylar apex), so the disc lies anterior to the condyle. On the open-mouth image the condyle translates beneath and recaptures the disc, with the intermediate zone returning to its normal interposed position between the condyle and eminence. The disc retains a relatively normal biconcave shape. A clicking joint is the clinical correlate.","impr":"Anterior disc displacement with reduction.","pearl":"Reduction = the disc is recaptured (normal disc-condyle relationship restored) on the open-mouth view; correlates clinically with a reciprocal click.","topic":"TMJ","joint":"general"},
{"id":"d507","front":"How would you describe TMJ anterior disc displacement WITHOUT reduction (closed lock) on MRI?","find":"On the closed-mouth image the disc is displaced anterior to the condyle, and on the open-mouth image the disc REMAINS anteriorly displaced and is NOT recaptured, often bunched/folded anterior to the condyle, with limited condylar translation. The disc frequently shows abnormal morphology with rounding, shortening, or deformation. Restricted mouth opening (closed lock) is the clinical correlate, and chronic cases develop degenerative change.","impr":"Anterior disc displacement without reduction (closed lock).","pearl":"No reduction = the disc stays anterior on open mouth and the condyle fails to translate normally; a deformed, balled-up disc and limited translation are supporting signs.","topic":"TMJ","joint":"general"},
{"id":"d508","front":"How would you describe a TMJ joint effusion on MRI?","find":"Abnormal increased T2/STIR fluid signal within the superior and/or inferior joint compartments, exceeding the small amount of normal joint fluid, distending the joint recesses. Effusion is frequently associated with internal derangement (disc displacement), synovitis, or degenerative change and may correlate with pain.","impr":"TMJ joint effusion.","pearl":"A T2-bright effusion is a nonspecific marker of joint inflammation/derangement; correlate with disc position and degenerative findings.","topic":"TMJ","joint":"general"},
{"id":"d509","front":"How would you describe degenerative TMJ disease (osteoarthritis) on MRI?","find":"Flattening of the condylar head and articular eminence with osteophyte formation, subchondral cysts and sclerosis, and erosions of the condyle. The disc is commonly displaced and deformed with loss of the normal biconcave shape, and a joint effusion may be present. Subchondral marrow edema-like signal may indicate active disease. Reduced joint space and condylar volume loss are seen in advanced cases.","impr":"Degenerative osteoarthritis of the TMJ.","pearl":"Condylar flattening, osteophytes, and subchondral cysts/erosions define TMJ osteoarthritis, typically accompanying chronic internal derangement.","topic":"TMJ","joint":"general"},
{"id":"d510","front":"How would you describe a TMJ disc perforation on MRI?","find":"Loss of disc continuity, typically in the posterior attachment (bilaminar zone) or the thin intermediate zone, with communication of fluid between the superior and inferior joint compartments. The disc is usually deformed and chronically displaced, often without reduction, and degenerative changes of the osseous structures are frequently present. Direct visualization of the perforation can be difficult; communicating effusion across both compartments is a supportive sign.","impr":"TMJ disc perforation with bicompartmental fluid communication.","pearl":"Perforation usually occurs at the posterior attachment in end-stage internal derangement; arthrography is more sensitive but communicating bicompartmental fluid on MRI is suggestive.","topic":"TMJ","joint":"general"},
{"id":"d511","front":"How would you describe radial (sensory) nerve entrapment (Wartenberg syndrome) on MRI?","find":"Focal increased T2 signal of the superficial (sensory) branch of the radial nerve as it emerges from beneath the brachioradialis tendon in the distal forearm, where it can be compressed between the brachioradialis and ECRL tendons (scissoring) or by external compression. Because the nerve is purely sensory, there is NO muscle denervation; diagnosis rests on focal nerve signal/caliber change and exclusion of a mass.","impr":"Superficial radial sensory neuropathy consistent with Wartenberg syndrome.","pearl":"Purely sensory, so no muscle denervation; distinguish from PIN syndrome, which is purely motor with extensor denervation.","topic":"Nerve entrapment","joint":"elbow"},
{"id":"d512","front":"How would you describe a peripheral nerve sheath tumor mimicking entrapment on MRI?","find":"A well-defined fusiform mass oriented along the expected course of a peripheral nerve, with entering and exiting nerve (the tail sign), the target sign (central low and peripheral high T2 signal), the split-fat sign (a rim of fat surrounding the lesion), and the fascicular sign. Schwannomas are eccentric to the nerve; neurofibromas are central/fusiform. Distal muscle denervation in the nerve territory may accompany a large lesion.","impr":"Benign peripheral nerve sheath tumor along the [named nerve].","pearl":"Split-fat, target, fascicular, and tail signs identify a lesion as neurogenic; rapid growth, ill-defined margins, and large size raise concern for malignant transformation.","topic":"Nerve entrapment","joint":"general"},
{"id":"d513","front":"How would you describe a Salter-Harris I fracture?","find":"There is widening of the [distal radial/distal fibular] physis with adjacent physeal and metaphyseal marrow edema. The fracture plane traverses the hypertrophic zone of the physis without extension into the metaphysis or epiphysis. There is mild [non-displaced/<2 mm] displacement of the epiphysis relative to the metaphysis. The physeal cartilage demonstrates intermediate signal with adjacent periosteal edema; no fracture line extends into bone.","impr":"Salter-Harris I physeal fracture with physeal widening and periphyseal edema.","pearl":"Often radiographically occult; physeal widening plus periphyseal marrow edema on MRI is the key sign.","topic":"Pediatric","joint":"general"},
{"id":"d514","front":"How would you describe a Salter-Harris II fracture?","find":"There is a fracture plane extending obliquely through the physis and exiting through the metaphysis, producing a triangular metaphyseal fragment (Thurston-Holland fragment) measuring [__] mm. The physis is widened with marrow edema spanning the metaphyseal fragment. There is [__] mm displacement and [__] degrees angulation of the epiphyseal segment; the epiphysis is uninvolved by fracture.","impr":"Salter-Harris II fracture through physis and metaphysis with Thurston-Holland fragment.","pearl":"Most common Salter-Harris type (~75%); the metaphyseal corner fragment defines it.","topic":"Pediatric","joint":"general"},
{"id":"d515","front":"How would you describe a Salter-Harris III fracture?","find":"A fracture plane extends through the physis and turns to exit through the epiphysis, crossing the articular surface. The intra-articular epiphyseal fragment is displaced by [__] mm with [__] mm articular step-off. There is physeal widening and marrow edema, and a [small/moderate] joint effusion with lipohemarthrosis. The metaphysis is intact.","impr":"Intra-articular Salter-Harris III fracture with articular step-off; risk of growth disturbance and post-traumatic OA.","pearl":"Intra-articular epiphyseal extension mandates reporting articular step-off; anatomic reduction required.","topic":"Pediatric","joint":"general"},
{"id":"d516","front":"How would you describe a Salter-Harris IV fracture?","find":"A vertically oriented fracture plane extends across the metaphysis, through the physis, and into the epiphysis, crossing the articular surface as a single contiguous fragment. There is [__] mm displacement with [__] mm articular incongruity. Physeal alignment is disrupted with marrow edema spanning all three regions, raising concern for premature physeal fusion.","impr":"Salter-Harris IV fracture spanning metaphysis, physis, and epiphysis with articular involvement; high risk of physeal bar formation.","pearl":"Transphyseal alignment must be restored to prevent bony bridging; classic at the distal tibia/medial malleolus.","topic":"Pediatric","joint":"ankle"},
{"id":"d517","front":"How would you describe a Salter-Harris V fracture?","find":"The physis demonstrates narrowing/compression with loss of the normal cartilage signal and abnormal marrow edema in the adjacent metaphysis and epiphysis without a discrete fracture line. There is an axial-loading injury pattern; no displaced fragment is identified. Findings raise concern for physeal crush injury.","impr":"Suspected Salter-Harris V physeal compression injury; high risk of growth arrest, often diagnosed retrospectively.","pearl":"Crush of the germinal physeal layer; frequently occult acutely and recognized only when growth arrest ensues.","topic":"Pediatric","joint":"general"},
{"id":"d518","front":"How would you describe a physeal bar (bridge)?","find":"There is a focal bony bridge traversing the [central/peripheral/linear] portion of the [distal femoral] physis, replacing the normal cartilaginous physeal signal with continuous marrow-equivalent bone spanning metaphysis to epiphysis. The bar involves approximately [__]% of the physeal cross-sectional area on the physeal map. There is [tethering/angular deformity/limb-length discrepancy] with adjacent physeal undulation.","impr":"Physeal bar involving ~[__]% of the physis; size and location determine candidacy for bar resection.","pearl":"Quantify percent involvement and map location (central vs peripheral) — bars <50% are resectable; fat interposition often used post-resection.","topic":"Pediatric","joint":"general"},
{"id":"d519","front":"How would you describe chronic physeal stress injury of the distal radius (gymnast wrist)?","find":"The distal radial physis is widened and irregular with metaphyseal sclerosis, cystic/cartilaginous extension of the physis into the metaphysis, and periphyseal marrow edema on fluid-sensitive sequences. There is loss of the normal sharp physeal margin with metaphyseal beaking. No discrete fracture line; findings reflect repetitive axial-loading microtrauma.","impr":"Chronic distal radial physeal stress injury (gymnast wrist); risk of premature fusion and positive ulnar variance.","pearl":"Widened, irregular physis with metaphyseal cystic change in a young gymnast; can lead to radial growth arrest and ulnar overgrowth.","topic":"Pediatric","joint":"general"},
{"id":"d520","front":"How would you describe Little League shoulder and elbow physeal stress?","find":"At the shoulder, the proximal humeral physis is widened and irregular with periphyseal marrow edema and metaphyseal demineralization from repetitive rotational/torsional stress. At the elbow, there is widening and fragmentation of the medial epicondyle apophysis with apophyseal marrow edema and adjacent common flexor origin edema; the apophysis may be [non-displaced/avulsed __ mm].","impr":"Chronic throwing-related physeal/apophyseal stress injury (Little League shoulder/elbow) from repetitive valgus and torsional overload.","pearl":"Proximal humeral physeal widening in a young thrower = Little League shoulder; medial epicondyle apophyseal widening/avulsion = Little League elbow.","topic":"Pediatric","joint":"elbow"},
{"id":"d521","front":"How would you describe an apophyseal avulsion of the pelvis (ASIS, AIIS, ischial, lesser trochanter)?","find":"There is displacement of the [ASIS sartorius / AIIS rectus femoris / ischial tuberosity hamstring / lesser trochanter iliopsoas] apophysis by [__] mm from its donor site, with a widened apophyseal cartilage cleft, marrow edema on both sides of the apophysis, and surrounding soft-tissue/myotendinous edema and hemorrhage. The avulsed osseous fragment measures [__] mm. No retraction of the parent muscle beyond the displaced apophysis.","impr":"Acute [site] apophyseal avulsion at the [muscle] origin; measure displacement to guide operative vs conservative management.","pearl":"In skeletally immature athletes the unfused apophysis fails before the tendon — sudden eccentric contraction avulses the apophysis rather than rupturing the tendon.","topic":"Pediatric","joint":"hip"},
{"id":"d522","front":"How would you describe Osgood-Schlatter disease?","find":"There is fragmentation and marrow edema of the tibial tubercle (secondary ossification center) with thickening, increased signal, and partial-thickness tearing of the distal patellar tendon insertion. There is infrapatellar deep bursal distension and obliteration of Hoffa fat pad signal with edema. Soft-tissue swelling anterior to the tubercle is present.","impr":"Osgood-Schlatter disease: traction apophysitis of the tibial tubercle with distal patellar tendinosis and deep infrapatellar bursitis.","pearl":"Distal patellar tendon (tibial tubercle) involvement distinguishes it from Sinding-Larsen-Johansson, which affects the proximal (inferior patellar pole) tendon.","topic":"Pediatric","joint":"knee"},
{"id":"d523","front":"How would you describe Sinding-Larsen-Johansson disease?","find":"There is fragmentation and marrow edema at the inferior pole of the patella with thickening and increased intrasubstance signal of the proximal patellar tendon at its origin. Adjacent soft-tissue edema and small partial-thickness fiber disruption are present. The tibial tubercle is normal.","impr":"Sinding-Larsen-Johansson syndrome: traction injury at the inferior patellar pole / proximal patellar tendon origin.","pearl":"Inferior patellar pole = SLJ (proximal tendon); tibial tubercle = Osgood-Schlatter (distal tendon).","topic":"Pediatric","joint":"knee"},
{"id":"d524","front":"How would you describe Sever disease (calcaneal apophysitis)?","find":"There is marrow edema within the calcaneal apophysis with fragmentation and sclerosis, accompanied by edema at the Achilles tendon insertion and within the adjacent retrocalcaneal/Kager fat. The apophyseal physis may appear widened. No discrete avulsion fragment.","impr":"Sever disease: calcaneal apophysitis from traction at the Achilles insertion in the active skeletally immature patient.","pearl":"Normal apophyses can be fragmented/sclerotic — diagnosis requires apophyseal and peri-insertional marrow/soft-tissue edema, not fragmentation alone.","topic":"Pediatric","joint":"ankle"},
{"id":"d525","front":"How would you describe an osteochondrosis in general terms?","find":"There is altered signal of a developing ossification center/apophysis with marrow edema, fragmentation, sclerosis, and irregular ossification, accompanied by adjacent soft-tissue edema at the tendon/ligament attachment. Findings reflect repetitive microtrauma and altered endochondral ossification at a site of high mechanical stress.","impr":"Osteochondrosis (traction/compression apophysitis) of the [site]; characterize marrow edema and any avulsion to gauge activity.","pearl":"Marrow edema and peri-attachment soft-tissue edema differentiate symptomatic osteochondrosis from normal developmental fragmentation.","topic":"Pediatric","joint":"general"},
{"id":"d526","front":"How would you describe Legg-Calve-Perthes disease (staging and features)?","find":"In the early stage there is decreased/absent enhancement of the femoral epiphysis on subtraction perfusion imaging with preserved epiphyseal marrow fat. Progressing to fragmentation, the epiphysis shows heterogeneous low T1 signal, subchondral fracture (crescent sign), and loss of height with flattening and lateral extrusion. There is physeal irregularity, metaphyseal cysts, and a joint effusion. In reossification/healing, marrow signal normalizes with residual coxa magna/plana and labral and acetabular remodeling.","impr":"Legg-Calve-Perthes disease, [avascular/fragmentation/reossification] stage; report epiphyseal coverage, lateral extrusion, and perfusion to guide containment.","pearl":"Perfusion (subtraction) MRI predicts extent of necrosis and outcome before plain-film changes; lateral pillar involvement and head-at-risk signs drive containment surgery.","topic":"Pediatric","joint":"hip"},
{"id":"d527","front":"How would you describe slipped capital femoral epiphysis (SCFE)?","find":"There is posteromedial slippage of the capital femoral epiphysis relative to the metaphysis with physeal widening, irregularity, and periphyseal marrow edema. A line along the superior femoral neck (Klein line) fails to intersect the epiphysis. There is metaphyseal blanch with remodeling; quantify slip angle [__] degrees. A reactive joint effusion is present. Assess the contralateral hip for prophylactic concern.","impr":"SCFE with [mild/moderate/severe] posteromedial epiphyseal slip and physeal widening; surgical pinning indicated, evaluate the opposite hip.","pearl":"Earliest MRI sign is physeal widening with periphyseal edema before frank slip; obese/adolescent males classically affected, bilateral in up to 1/3.","topic":"Pediatric","joint":"hip"},
{"id":"d528","front":"How would you describe developmental dysplasia of the hip (DDH)?","find":"There is a shallow, vertically oriented acetabulum with deficient superolateral coverage and increased acetabular index. The femoral head is [reduced/subluxated/dislocated] with [superolateral] displacement; the cartilaginous head sits eccentrically. There is hypertrophy and inversion of the labrum (neolimbus), a thickened pulvinar and ligamentum teres, and a stretched/inverted limbus impeding reduction. Assess for an interposed iliopsoas tendon.","impr":"Developmental dysplasia with acetabular undercoverage and [subluxation/dislocation]; identify obstacles to concentric reduction.","pearl":"MR/arthrography defines reducibility — inverted labrum, hypertrophied pulvinar/ligamentum teres, and transverse ligament are blocks to concentric reduction.","topic":"Pediatric","joint":"hip"},
{"id":"d529","front":"How would you describe transient synovitis versus septic arthritis of the pediatric hip?","find":"Transient synovitis shows a simple joint effusion with mild synovial thickening, no adjacent marrow edema, and preserved periarticular signal. Septic arthritis shows a complex/loculated effusion with thick enhancing synovium, periarticular soft-tissue edema, marrow edema of the femoral head/neck with possible decreased epiphyseal enhancement, and occasional bone erosion or adjacent osteomyelitis/abscess. Contralateral hip is normal.","impr":"Findings favor [transient synovitis/septic arthritis]; periarticular marrow/soft-tissue edema and abnormal epiphyseal perfusion favor infection.","pearl":"Marrow edema, soft-tissue edema, and reduced epiphyseal enhancement point to septic arthritis; an isolated simple effusion favors transient synovitis — but joint aspiration remains definitive.","topic":"Pediatric","joint":"hip"},
{"id":"d530","front":"How would you describe normal versus abnormal pediatric red marrow?","find":"Normal residual red (hematopoietic) marrow is mildly T1-hypointense but remains higher in signal than adjacent muscle and intervertebral disc, is symmetric, spares the epiphyses/apophyses, and shows no convexity or focal nodularity. Abnormal marrow is diffusely or focally T1-hypointense to muscle/disc, involves epiphyses/apophyses, demonstrates focal masslike or convex foci, and may enhance or restrict diffusion — concerning for infiltration or reconversion.","impr":"[Normal age-appropriate red marrow / Abnormal marrow signal] — signal lower than muscle and disc, epiphyseal involvement, and focal nodularity are red flags.","pearl":"The muscle/disc T1 comparison rule: red marrow brighter than muscle and disc is normal; marrow darker than muscle or disc is suspicious for infiltration.","topic":"Pediatric","joint":"general"},
{"id":"d531","front":"How would you describe the normal pattern of marrow conversion by age?","find":"At birth the marrow is predominantly red (hematopoietic) throughout. Conversion to yellow (fatty) marrow proceeds from peripheral to axial and distal to proximal, and from diaphysis outward toward metaphyses. Epiphyses/apophyses convert to fatty marrow within ~6 months of ossification. By the mid-20s the adult pattern is reached, with residual red marrow in the axial skeleton and proximal metaphyses of the femur/humerus.","impr":"Age-appropriate marrow conversion following the normal epiphysis-first, distal-to-proximal, diaphysis-to-metaphysis sequence.","pearl":"Epiphyses/apophyses convert to fat shortly after ossifying — persistent red marrow in an epiphysis is abnormal at any age and suggests reconversion or infiltration.","topic":"Pediatric","joint":"general"},
{"id":"d532","front":"How would you describe juvenile osteochondritis dissecans of the knee?","find":"There is a focal osteochondral lesion at the [lateral aspect of the medial femoral condyle] with subchondral marrow edema and a low-signal demarcating zone. In the stable juvenile lesion the overlying cartilage is intact and the interface lacks high T2 signal. Instability is suggested by a high-T2 rim/fluid undermining the fragment, cystic foci beneath the lesion (>5 mm), a full-thickness cartilage defect, or a displaced osteochondral fragment with a donor crater. Measure the lesion [__] x [__] mm.","impr":"Juvenile OCD of the [medial femoral condyle], [stable/unstable]; intact cartilage with open physes favors healing potential, while a high-T2 undermining interface indicates instability.","pearl":"In juveniles with open physes, a T2-bright rim can represent vascular granulation tissue rather than instability — correlate with cartilage integrity and subchondral cysts before calling unstable.","topic":"Pediatric","joint":"knee"},
{"id":"d533","front":"How would you describe a juvenile Tillaux fracture?","find":"There is a Salter-Harris III fracture of the anterolateral distal tibial epiphysis, with the fragment avulsed by the anterior tibiofibular ligament. The vertical epiphyseal fracture line extends to the articular surface with [__] mm of articular displacement, and the fracture plane exits through the partially fused (laterally open) physis. Anteromedial physis is already closed. Marrow edema and a joint effusion are present.","impr":"Juvenile Tillaux fracture (SH III) of the anterolateral distal tibial epiphysis; report articular step-off as >2 mm warrants fixation.","pearl":"Occurs during the ~18-month window of asymmetric physeal closure (central/medial closed, lateral open) — the anterolateral fragment is avulsed by the AITFL.","topic":"Pediatric","joint":"ankle"},
{"id":"d534","front":"How would you describe a triplane fracture?","find":"There is a multiplanar distal tibial fracture combining a Salter-Harris III/IV pattern: a sagittal fracture through the epiphysis, an axial fracture through the physis, and a coronal/oblique fracture through the posterior metaphysis (Thurston-Holland fragment). On CT the [two- vs three-part] configuration is defined; articular displacement measures [__] mm. There is associated marrow edema and effusion.","impr":"Triplane distal tibial fracture, [two-part/three-part]; CT best defines fragment number and articular step-off for fixation planning.","pearl":"Looks like SH III on the AP and SH II on the lateral — the multiplanar geometry mandates CT to count fragments and measure intra-articular step-off.","topic":"Pediatric","joint":"ankle"},
{"id":"d535","front":"How would you describe a bipartite patella?","find":"There is an accessory ossification center at the superolateral patella (type III) separated by a smooth, corticated, fluid-bright synchondrosis. When symptomatic there is marrow edema spanning both sides of the synchondrosis with fluid signal and widening of the cleft, indicating motion/stress. The remaining patella is normal and articular cartilage is intact.","impr":"[Asymptomatic / Symptomatic] superolateral bipartite patella; bridging marrow edema across the synchondrosis indicates a painful unstable fragment.","pearl":"Superolateral location and a smooth corticated margin distinguish bipartite patella from an acute fracture; marrow edema on both sides of the synchondrosis indicates symptomatic stress.","topic":"Pediatric","joint":"knee"},
{"id":"d536","front":"How would you describe a grade 2 muscle strain (partial tear)?","find":"There is partial-thickness disruption of muscle fibers at the [myotendinous junction] with a focal fluid-signal cleft and surrounding feathery edema and perifascial fluid/hematoma. Fiber disruption involves approximately [__]% of the muscle cross-sectional area over a [__] cm craniocaudal extent, with mild fiber wave/retraction but maintained gross continuity. The intramuscular tendon shows [intact/partial-thickness] involvement.","impr":"Grade 2 (partial-thickness) myotendinous tear involving ~[__]% of cross-section over [__] cm; intramuscular tendon involvement prolongs recovery.","pearl":"Always report percent cross-sectional involvement, craniocaudal length, and whether the intramuscular tendon is torn — tendon involvement predicts longer rehabilitation and re-injury risk.","topic":"Muscle/Tendon","joint":"general"},
{"id":"d537","front":"How would you describe a grade 3 muscle strain (complete rupture with retraction)?","find":"There is complete (full-thickness) discontinuity of the [muscle/myotendinous unit] with a fluid- and hemorrhage-filled gap and retraction of the torn ends by [__] cm. The torn muscle stump is balled-up/wavy with extensive surrounding hematoma and perifascial fluid. There is loss of the normal myotendinous transition with adjacent fatty stranding. Quantify the retraction gap for surgical planning.","impr":"Grade 3 complete myotendinous rupture with [__] cm retraction gap and hematoma; surgical repair considered when retraction is significant.","pearl":"The retraction gap distance is the surgically actionable measurement — report it explicitly, along with stump morphology and hematoma extent.","topic":"Muscle/Tendon","joint":"general"},
{"id":"d538","front":"How would you describe the location of a muscle injury (myotendinous junction vs intramuscular tendon vs musculotendinous)?","find":"The injury centers at the [myotendinous junction], the transition zone between contractile muscle fibers and the tendon where strains preferentially occur. Specify whether disruption involves the proximal/distal MTJ, the central intramuscular (intratendinous) tendon, or the peripheral aponeurosis/musculotendinous junction. Note the proportion of the aponeurotic surface involved and any fluid undercutting the aponeurosis.","impr":"Injury localized to the [proximal/distal MTJ / central intramuscular tendon / aponeurosis]; precise localization predicts healing time.","pearl":"Strains preferentially occur at the myotendinous junction; central intramuscular tendon tears heal more slowly than peripheral aponeurotic injuries — localize precisely.","topic":"Muscle/Tendon","joint":"general"},
{"id":"d539","front":"How would you describe the signal evolution of an intramuscular hematoma?","find":"Hyperacute (<24 h, oxyhemoglobin) hematoma is iso/hyperintense on T1 and hyperintense on T2. Acute (1-3 d, deoxyhemoglobin) is iso/hypointense on T1 and markedly hypointense on T2. Early subacute (3-7 d, intracellular methemoglobin) is hyperintense on T1 and hypointense on T2; late subacute (1-4 wk, extracellular methemoglobin) is hyperintense on both T1 and T2. Chronic (>weeks) shows a hypointense hemosiderin rim with central fluid and possible fluid-fluid levels.","impr":"Intramuscular hematoma, [hyperacute/acute/subacute/chronic] stage by signal; correlate with timing of injury.","pearl":"T1-bright signal (methemoglobin) appears in the subacute phase; a peripheral hypointense hemosiderin rim with fluid-fluid levels indicates chronicity.","topic":"Muscle/Tendon","joint":"general"},
{"id":"d540","front":"How would you describe muscle (fascial) herniation?","find":"There is a focal defect in the investing [crural] fascia through which muscle tissue protrudes, best seen as a mushroom-shaped extrusion of normal-signal muscle through the fascial gap; the herniation enlarges on dynamic/standing or muscle-contracted imaging. The defect measures [__] mm. The underlying muscle signal is normal without strain or denervation; a perforating neurovascular bundle may mark the defect site.","impr":"Muscle herniation through a focal fascial defect [__] mm, classically at the anterolateral leg; dynamic imaging accentuates the protrusion.","pearl":"Most common in the anterolateral leg at the site of a perforating vessel; dynamic or contracted imaging best demonstrates the reducible mushroom-shaped herniation.","topic":"Muscle/Tendon","joint":"general"},
{"id":"d541","front":"How would you describe chronic myotendinous scarring?","find":"There is a focal low-signal (T1 and T2) band/nodule at the prior site of injury within the [myotendinous junction], representing mature fibrous scar with loss of normal muscle striation and architectural distortion. There may be associated focal fatty atrophy of the muscle, tethering/retraction, and thickening of the intramuscular tendon. No active edema to suggest re-injury.","impr":"Chronic myotendinous fibrotic scarring with architectural distortion and focal fatty change; a re-injury risk factor.","pearl":"Mature scar is dark on all sequences (unlike active edema) — superimposed bright T2 edema within or adjacent to scar suggests acute re-injury.","topic":"Muscle/Tendon","joint":"general"},
{"id":"d542","front":"How would you describe an accessory muscle?","find":"There is a supernumerary muscle [accessory soleus / peroneus quartus / accessory flexor digitorum longus] occupying [Kager fat pad / retromalleolar groove] with signal isointense to adjacent skeletal muscle on all sequences and continuity with its expected tendon. The mass demonstrates normal muscle striation, no abnormal enhancement, and exerts [mass effect/no mass effect] on the [tarsal tunnel/neurovascular bundle].","impr":"Accessory [muscle] — a normal-variant supernumerary muscle following muscle signal on all sequences; report any compressive/neurovascular effect.","pearl":"Following muscle signal on every sequence is the key to confidently calling it an accessory muscle rather than a soft-tissue mass.","topic":"Muscle/Tendon","joint":"ankle"},
{"id":"d543","front":"How would you describe rhabdomyolysis on MRI?","find":"There is diffuse, often symmetric T2/STIR hyperintense edema of the involved muscle groups with muscle enlargement/swelling and preserved-to-mildly-disrupted architecture. Necrotic muscle may show a rim or stipple enhancement pattern with non-enhancing necrotic core; subacutely there can be hemorrhage and patchy enhancement. There is perifascial fluid; subcutaneous fat is relatively spared.","impr":"Rhabdomyolysis with extensive intramuscular edema [and necrosis]; correlate with serum CK and exclude compartment syndrome.","pearl":"Diffuse symmetric muscle edema with possible necrotic non-enhancing zones and stipple/rim enhancement — always correlate with CK and assess for evolving compartment syndrome.","topic":"Muscle/Tendon","joint":"general"},
{"id":"d544","front":"How would you describe the edema pattern of inflammatory myositis?","find":"There is symmetric, bilateral T2/STIR hyperintense edema involving the [proximal thigh] musculature in a [diffuse/patchy] distribution, often with perifascial and subcutaneous edema. Chronic disease shows muscle atrophy with fatty infiltration (T1-bright streaks) and calcifications. The distribution is typically symmetric and proximal, distinguishing it from focal traumatic or infectious edema.","impr":"Inflammatory myositis with symmetric proximal muscle edema [and chronic fatty atrophy]; characterize active edema vs chronic fatty replacement for therapy guidance.","pearl":"Symmetric, proximal, bilateral edema with perifascial involvement favors inflammatory myopathy; STIR shows active disease while T1 fatty atrophy reflects chronic/irreversible change.","topic":"Muscle/Tendon","joint":"general"},
{"id":"d545","front":"How would you describe diabetic muscle infarction?","find":"There is focal enlargement and T2/STIR hyperintense edema of an involved muscle (commonly the thigh — quadriceps/thigh adductors) with feathery intramuscular and perifascial edema. There may be a non-enhancing infarcted core with surrounding rim/peripheral enhancement and subcutaneous/fascial edema. No drainable abscess or gas; the patient has long-standing poorly controlled diabetes.","impr":"Diabetic muscle infarction of the [thigh] with intramuscular edema and a non-enhancing infarct core; clinical correlation with poorly controlled diabetes.","pearl":"Acutely painful swollen thigh in long-standing diabetes with intramuscular edema and a non-enhancing core — biopsy is usually avoided as it can worsen the course; manage conservatively.","topic":"Muscle/Tendon","joint":"general"},
{"id":"d546","front":"How would you describe the muscle edema of compartment syndrome?","find":"There is diffuse T2/STIR hyperintense edema and swelling of the muscles within a single fascial compartment ([anterior compartment of the leg]) with taut bulging fascia and effacement of intermuscular fat planes. Findings are confined to the compartment boundaries. Late/ischemic change shows non-enhancing necrotic muscle. Perifascial fluid and subfascial pressure effect are present; correlate with clinical compartment pressures.","impr":"Imaging findings compatible with [anterior] compartment syndrome — compartment-confined muscle edema with tense fascia; this is a clinical/pressure-measurement diagnosis requiring urgent correlation.","pearl":"Edema respecting compartmental fascial boundaries with taut bulging fascia suggests compartment syndrome, but the diagnosis is clinical/manometric — flag urgently rather than relying on MRI alone.","topic":"Muscle/Tendon","joint":"general"},
{"id":"d547","front":"How would you report and threshold the alpha angle for cam-type FAI?","find":"The alpha angle measures __ degrees on the oblique axial (Dunn) view (normal <55 degrees); a value >55 degrees indicates cam morphology with an aspherical femoral head-neck junction.","impr":"Cam morphology, alpha angle __ degrees.","pearl":"Drawn from femoral head center to the point where the head-neck contour exceeds the radius of the head; values >60 degrees are more specific for symptomatic cam FAI.","topic":"Measurements","joint":"hip"},
{"id":"d548","front":"How would you report and threshold the lateral center-edge angle (LCEA) of the hip?","find":"The lateral center-edge angle measures __ degrees (normal 25-39 degrees); <20 degrees indicates acetabular dysplasia/undercoverage and >40 degrees indicates pincer-type overcoverage.","impr":"Acetabular [dysplasia/overcoverage], LCEA __ degrees.","pearl":"Angle of Wiberg: between a vertical line through the femoral head center and a line to the lateral acetabular edge; borderline dysplasia 20-25 degrees.","topic":"Measurements","joint":"hip"},
{"id":"d549","front":"How would you report and threshold the acetabular index (Tonnis angle)?","find":"The acetabular index (Tonnis angle) measures __ degrees (normal 0-10 degrees); >10 degrees suggests lateral instability/dysplasia and <0 degrees suggests overcoverage/pincer.","impr":"[Increased/decreased] acetabular index __ degrees.","pearl":"Angle between a horizontal line and the sclerotic weight-bearing sourcil of the acetabular roof.","topic":"Measurements","joint":"hip"},
{"id":"d550","front":"How would you report and threshold femoral version on MRI?","find":"Femoral anteversion measures __ degrees (normal 10-20 degrees); >20-25 degrees indicates excessive anteversion and <10 degrees (or retroversion) predisposes to anterior impingement.","impr":"[Increased/decreased] femoral version __ degrees.","pearl":"Measured between the femoral neck axis and the posterior condylar axis on axial images.","topic":"Measurements","joint":"hip"},
{"id":"d551","front":"How would you report and threshold the TT-TG distance for patellar instability?","find":"The tibial tubercle-trochlear groove (TT-TG) distance measures __ mm (normal <15 mm); >20 mm is abnormal and supports lateralized extensor mechanism contributing to patellar instability.","impr":"[Normal/elevated] TT-TG distance __ mm.","pearl":"Measured on superimposed axial images as the mediolateral offset between the deepest trochlear groove and the tibial tubercle; 15-20 mm is borderline.","topic":"Measurements","joint":"knee"},
{"id":"d552","front":"How would you report and threshold the Insall-Salvati ratio?","find":"The Insall-Salvati ratio measures __ (normal 0.8-1.2); >1.2 indicates patella alta and <0.8 indicates patella baja.","impr":"Patella [alta/baja], Insall-Salvati ratio __.","pearl":"Ratio of patellar tendon length to patellar bone length on sagittal images.","topic":"Measurements","joint":"knee"},
{"id":"d553","front":"How would you report and threshold the Caton-Deschamps index?","find":"The Caton-Deschamps index measures __ (normal 0.6-1.2); >1.2 indicates patella alta, a risk factor for patellar instability.","impr":"Patella alta, Caton-Deschamps index __.","pearl":"Ratio of the distance from the inferior patellar articular surface to the anterosuperior tibial margin, divided by the length of the patellar articular surface.","topic":"Measurements","joint":"knee"},
{"id":"d554","front":"How would you report and threshold the trochlear sulcus angle for dysplasia?","find":"The trochlear sulcus angle measures __ degrees (normal <145 degrees); >145 degrees indicates trochlear dysplasia with a shallow/flat groove.","impr":"Trochlear dysplasia, sulcus angle __ degrees.","pearl":"Measured on axial images at the proximal trochlea between the medial and lateral facets; trochlear depth <3 mm also indicates dysplasia.","topic":"Measurements","joint":"knee"},
{"id":"d555","front":"How would you report and threshold meniscal extrusion?","find":"The medial meniscal body is extruded __ mm beyond the tibial margin (normal <3 mm); extrusion >=3 mm is considered major/significant and associated with meniscal root tear and accelerated osteoarthritis.","impr":"Significant meniscal extrusion __ mm.","pearl":"Measured on the mid-coronal image from the peripheral meniscal margin to the tibial plateau edge, excluding osteophytes.","topic":"Measurements","joint":"knee"},
{"id":"d556","front":"How would you report and use the Blumensaat line for patellar height?","find":"On the lateral/sagittal image in extension the inferior pole of the patella projects at the level of Blumensaat line (the roof of the intercondylar notch); the patella lying well above this line indicates patella alta.","impr":"Patella alta relative to Blumensaat line.","pearl":"Blumensaat line is the linear sclerosis of the intercondylar notch roof; a qualitative adjunct to ratio-based patellar height measures.","topic":"Measurements","joint":"knee"},
{"id":"d557","front":"How would you report and threshold the critical shoulder angle (CSA)?","find":"The critical shoulder angle measures __ degrees (normal 30-35 degrees); >35 degrees is associated with rotator cuff tears and <30 degrees with glenohumeral osteoarthritis.","impr":"[Elevated/low] critical shoulder angle __ degrees.","pearl":"Angle between a line connecting superior and inferior glenoid margins and a line from the inferior glenoid to the lateral acromion, on a true AP view.","topic":"Measurements","joint":"shoulder"},
{"id":"d558","front":"How would you report and threshold the acromiohumeral interval (AHI)?","find":"The acromiohumeral interval measures __ mm (normal 7-14 mm); <7 mm indicates superior migration of the humeral head from a large/chronic rotator cuff tear (cuff tear arthropathy).","impr":"Narrowed acromiohumeral interval __ mm.","pearl":"Measured as the shortest distance between the undersurface of the acromion and the humeral head on AP/coronal images.","topic":"Measurements","joint":"shoulder"},
{"id":"d559","front":"How would you report and threshold glenoid version?","find":"The glenoid version measures __ degrees (normal -2 to -9 degrees, i.e. slight retroversion); retroversion >10-15 degrees is associated with posterior instability and dysplasia.","impr":"Excessive glenoid retroversion __ degrees.","pearl":"Measured on axial images between the glenoid face and a line perpendicular to the scapular body (Friedman method); negative values denote retroversion.","topic":"Measurements","joint":"shoulder"},
{"id":"d560","front":"How would you report and threshold glenoid bone loss for instability?","find":"There is __ % anteroinferior glenoid bone loss measured on the en-face sagittal oblique view; loss >20-25 % is considered critical and typically requires bony (Latarjet/bone block) rather than soft-tissue repair.","impr":"Critical glenoid bone loss __ %.","pearl":"Assessed using the best-fit circle (Pico) method on the inferior glenoid; 13-20 % is subcritical.","topic":"Measurements","joint":"shoulder"},
{"id":"d561","front":"How would you report an off-track Hill-Sachs lesion?","find":"The Hill-Sachs interval exceeds the glenoid track (glenoid track = 0.83 x glenoid diameter minus bone loss), making the lesion off-track and at high risk for engagement and recurrent instability.","impr":"Off-track (engaging) Hill-Sachs lesion.","pearl":"On-track lesions stay within the glenoid track; off-track lesions extend medial to it and favor bony augmentation/remplissage.","topic":"Measurements","joint":"shoulder"},
{"id":"d562","front":"How would you report and threshold the tibiofibular clear space at the ankle?","find":"The tibiofibular clear space measures __ mm (normal <6 mm) measured 1 cm above the plafond; >6 mm indicates syndesmotic widening/injury.","impr":"Syndesmotic diastasis, tibiofibular clear space __ mm.","pearl":"The clear space (distance between the incisural fibular margin and posterior tibia) is the most reliable plain radiographic/CT sign of syndesmotic injury.","topic":"Measurements","joint":"ankle"},
{"id":"d563","front":"How would you report and threshold the Bohler angle of the calcaneus?","find":"The Bohler (tuber-joint) angle measures __ degrees (normal 20-40 degrees); <20 degrees indicates a depressed calcaneal fracture of the posterior facet.","impr":"Decreased Bohler angle __ degrees, consistent with calcaneal compression fracture.","pearl":"Angle between a line from the posterior tuberosity to the posterior facet apex and a line to the anterior process.","topic":"Measurements","joint":"ankle"},
{"id":"d564","front":"How would you report and threshold the Meary angle (talo-first metatarsal angle)?","find":"The Meary angle measures __ degrees (normal 0 degrees, i.e. colinear talus and first metatarsal); a plantar/convex apex indicates pes planus and a dorsal apex indicates pes cavus, with abnormal generally >4 degrees.","impr":"Pes [planus/cavus], Meary angle __ degrees.","pearl":"Measured on the lateral weight-bearing view along the long axes of the talus and first metatarsal.","topic":"Measurements","joint":"foot"},
{"id":"d565","front":"How would you report and threshold the calcaneal pitch angle?","find":"The calcaneal pitch (inclination) angle measures __ degrees (normal 20-30 degrees); <20 degrees indicates pes planus (flatfoot) and >30 degrees indicates pes cavus.","impr":"[Decreased/increased] calcaneal pitch __ degrees.","pearl":"Angle between the inferior calcaneal cortex and the supporting horizontal surface on the lateral weight-bearing view.","topic":"Measurements","joint":"foot"},
{"id":"d566","front":"How would you report and threshold the hallux valgus angle?","find":"The hallux valgus angle measures __ degrees (normal <15 degrees); >15 degrees indicates hallux valgus (mild 15-20, moderate 20-40, severe >40 degrees).","impr":"Hallux valgus, HV angle __ degrees.","pearl":"Angle between the long axes of the first metatarsal and proximal phalanx of the great toe.","topic":"Measurements","joint":"foot"},
{"id":"d567","front":"How would you report and threshold the first-second intermetatarsal angle?","find":"The intermetatarsal angle (IMA) measures __ degrees (normal <9 degrees); >9 degrees indicates metatarsus primus varus contributing to hallux valgus (moderate 11-16, severe >16 degrees).","impr":"Increased intermetatarsal angle __ degrees.","pearl":"Angle between the long axes of the first and second metatarsals.","topic":"Measurements","joint":"foot"},
{"id":"d568","front":"How would you report and threshold cervical spinal canal stenosis by AP diameter?","find":"The cervical canal AP diameter measures __ mm (normal >12 mm); <13 mm indicates relative stenosis and <10 mm indicates absolute stenosis with cord compromise risk.","impr":"Absolute cervical canal stenosis, AP diameter __ mm.","pearl":"Measured from the posterior vertebral body to the spinolaminar line; the cord itself is ~10 mm AP.","topic":"Measurements","joint":"spine"},
{"id":"d569","front":"How would you report and threshold the Torg-Pavlov ratio?","find":"The Torg-Pavlov ratio measures __ (normal ~1.0); <0.8 indicates developmental cervical canal stenosis and increased risk of transient cord neurapraxia.","impr":"Developmental cervical stenosis, Torg ratio __.","pearl":"Ratio of the canal AP diameter (body to spinolaminar line) to the vertebral body AP diameter; corrects for magnification.","topic":"Measurements","joint":"spine"},
{"id":"d570","front":"How would you report and grade spondylolisthesis using the Meyerding grade?","find":"There is anterolisthesis with __ % slip (Meyerding grade [I-V]): grade I <25 %, II 25-50 %, III 50-75 %, IV 75-100 %, V (spondyloptosis) >100 %.","impr":"Grade [I-V] anterolisthesis, __ % slip.","pearl":"Percentage of anteroposterior slip of the superior vertebral body relative to the one below.","topic":"Measurements","joint":"spine"},
{"id":"d571","front":"How would you report and threshold the Cobb angle for scoliosis?","find":"The Cobb angle measures __ degrees; a curve >10 degrees defines scoliosis, with surgical consideration generally for curves >40-50 degrees.","impr":"Scoliosis, Cobb angle __ degrees.","pearl":"Measured between lines along the endplates of the most-tilted upper and lower end vertebrae of the curve.","topic":"Measurements","joint":"spine"},
{"id":"d572","front":"How would you report and threshold the cartilage cap thickness of an osteochondroma?","find":"The hyaline cartilage cap measures __ cm (normal <1.5 cm in adults); a cap >1.5-2 cm is worrisome for malignant transformation to secondary chondrosarcoma.","impr":"Thickened cartilage cap __ cm, concerning for chondrosarcomatous transformation.","pearl":"Best measured on fluid-sensitive (T2/PD fat-sat) sequences; growth after skeletal maturity is also a red flag.","topic":"Measurements","joint":"general"},
{"id":"d573","front":"How would you report a soft-tissue mass size threshold of concern?","find":"The soft-tissue mass measures __ cm; a deep mass >5 cm raises concern for sarcoma and warrants further workup/biopsy regardless of imaging characteristics.","impr":"Indeterminate soft-tissue mass __ cm, exceeds size threshold of concern.","pearl":"Enright criteria: size >5 cm, deep location, rapid growth, and heterogeneity increase suspicion for malignancy.","topic":"Measurements","joint":"general"},
{"id":"d574","front":"How would you report and threshold lymph node short-axis diameter?","find":"The lymph node measures __ mm in short axis (normal <10 mm for most regions); >10 mm short-axis (or loss of fatty hilum/rounded shape) is suspicious for pathologic involvement.","impr":"Enlarged lymph node, __ mm short axis.","pearl":"Short axis is more reliable than long axis; inguinal nodes can normally be up to ~15 mm.","topic":"Measurements","joint":"general"},
{"id":"d575","front":"How would you report and threshold Achilles tendon thickness?","find":"The Achilles tendon measures __ mm in AP thickness (normal <6-7 mm); >7-8 mm with intrasubstance signal indicates tendinosis.","impr":"Achilles tendinosis with fusiform thickening to __ mm.","pearl":"Best measured on sagittal/axial images a few cm above the calcaneal insertion; the normal tendon has a flat or concave anterior margin.","topic":"Measurements","joint":"ankle"},
{"id":"d576","front":"How would you report and threshold the scapholunate angle?","find":"The scapholunate angle measures __ degrees (normal 30-60 degrees); >60-70 degrees indicates DISI (dorsal intercalated segment instability) and <30 degrees indicates VISI.","impr":"DISI deformity, scapholunate angle __ degrees.","pearl":"Angle between the long axes of the scaphoid and lunate on the lateral/sagittal view.","topic":"Measurements","joint":"wrist"},
{"id":"d577","front":"How would you report and threshold the scapholunate interval (Terry Thomas sign)?","find":"The scapholunate interval measures __ mm (normal <3 mm); >3 mm (Terry Thomas sign) indicates scapholunate ligament disruption.","impr":"Scapholunate dissociation, SL interval __ mm.","pearl":"Best assessed on the PA view, ideally with a clenched-fist stress view; should be symmetric with the contralateral side.","topic":"Measurements","joint":"wrist"},
{"id":"d578","front":"How would you report and threshold ulnar variance?","find":"The ulnar variance measures __ mm (neutral approximately 0 mm); positive variance >2 mm predisposes to ulnar impaction syndrome and negative variance to Kienbock disease.","impr":"Positive ulnar variance __ mm.","pearl":"Difference in length between the distal ulnar and radial articular surfaces on a neutral-rotation PA view.","topic":"Measurements","joint":"wrist"},
{"id":"d579","front":"How would you report and threshold normal volar tilt of the distal radius?","find":"The volar (palmar) tilt of the distal radius measures __ degrees (normal 10-15 degrees volar); loss of volar tilt or dorsal tilt indicates malalignment, commonly post-fracture.","impr":"Dorsal tilt of the distal radius, __ degrees (abnormal).","pearl":"Measured on the lateral view between a line perpendicular to the radial shaft and the distal articular surface; normal radial inclination is 21-25 degrees.","topic":"Measurements","joint":"wrist"},
{"id":"d580","front":"How would you describe internal (posterosuperior) impingement in an overhead throwing athlete?","find":"Articular-surface partial-thickness tearing/fraying of the posterior supraspinatus and anterior infraspinatus footprint with intrasubstance signal, contacting the posterosuperior glenoid labrum in abduction-external rotation. Posterosuperior labral fraying/tear and adjacent posterosuperior humeral head and greater tuberosity subcortical cystic change and marrow edema. Mild posterior capsular thickening.","impr":"Posterosuperior internal impingement of the throwing shoulder with articular-sided posterior cuff undersurface tearing and posterosuperior labral injury.","pearl":"Classic kissing lesions: posterosuperior humeral head cysts + posterosuperior labral fraying in the late-cocking phase.","topic":"Sports injury","joint":"shoulder"},
{"id":"d581","front":"How would you describe a Bennett lesion in a throwing athlete?","find":"Curvilinear mineralization along the posteroinferior glenoid rim, extra-articular, paralleling the posterior band of the inferior glenohumeral ligament, with adjacent posteroinferior labral and capsular thickening. Low signal on all sequences with susceptibility blooming on gradient images.","impr":"Bennett lesion (posteroinferior glenoid extra-articular ossification) of the throwing shoulder.","pearl":"Associated with posterior labral injury and posterosuperior internal impingement in pitchers.","topic":"Sports injury","joint":"shoulder"},
{"id":"d582","front":"How would you describe glenohumeral internal rotation deficit (GIRD) changes in a pitcher?","find":"Posteroinferior capsular thickening and contracture with associated posterosuperior labral fraying and articular-sided posterior cuff partial tearing. Findings of internal impingement with posterosuperior humeral head cystic change. No discrete full-thickness cuff tear.","impr":"Posteroinferior capsular contracture (GIRD) with secondary internal impingement changes.","pearl":"GIRD shifts the glenohumeral contact point posterosuperiorly, driving the internal impingement cascade.","topic":"Sports injury","joint":"shoulder"},
{"id":"d583","front":"How would you describe Little League shoulder (proximal humeral epiphysiolysis)?","find":"Widening and irregularity of the proximal humeral physis with adjacent metaphyseal marrow edema and periphyseal signal on fluid-sensitive sequences. No discrete fracture line or displacement.","impr":"Little League shoulder: chronic stress-related proximal humeral physeal injury (epiphysiolysis).","pearl":"Seen in adolescent throwers; radiographs show physeal widening, MRI shows physeal/metaphyseal edema.","topic":"Sports injury","joint":"shoulder"},
{"id":"d584","front":"How would you describe Little League elbow (medial epicondyle apophysitis)?","find":"Widening and increased signal of the medial epicondyle apophysis with adjacent marrow and soft-tissue edema along the common flexor-pronator origin and UCL. No avulsion fragment displacement.","impr":"Little League elbow: medial epicondyle apophyseal stress injury (medial apophysitis).","pearl":"Valgus traction stress in adolescent throwers; can progress to medial epicondyle avulsion.","topic":"Sports injury","joint":"elbow"},
{"id":"d585","front":"How would you describe valgus extension overload of the elbow in a pitcher?","find":"Posteromedial olecranon osteophytosis with chondral wear and subchondral marrow edema along the posteromedial olecranon and olecranon fossa. Loose intra-articular bodies in the posterior compartment. Associated UCL thickening and chondromalacia.","impr":"Valgus extension overload with posteromedial olecranon osteophyte and chondral injury.","pearl":"Repetitive valgus + extension drives posteromedial olecranon abutment against the trochlea/fossa.","topic":"Sports injury","joint":"elbow"},
{"id":"d586","front":"How would you describe a chronic UCL tear in a pitcher?","find":"Thickening and intermediate intrasubstance signal of the anterior bundle of the UCL with partial undersurface fiber detachment from the sublime tubercle producing the T-sign on arthrography (contrast tracking distally along the medial coronoid). Adjacent sublime tubercle marrow edema and traction osteophyte.","impr":"Chronic UCL injury with distal undersurface (T-sign) partial tear at the sublime tubercle.","pearl":"The T-sign indicates undersurface detachment of an otherwise intact UCL at its distal insertion.","topic":"Sports injury","joint":"elbow"},
{"id":"d587","front":"How would you describe a tibial bone stress injury using the Fredericson grading system?","find":"Grade 1: periosteal edema only. Grade 2: marrow edema on T2/STIR only. Grade 3: marrow edema on both T1 and T2/STIR. Grade 4a: multiple discrete intracortical signal foci; 4b: linear T1/T2 hypointense fracture line through the cortex. Posteromedial tibial location typical of running.","impr":"Tibial bone stress injury, Fredericson grade [1-4b].","pearl":"Higher Fredericson grade correlates with longer return-to-play; grade 4b is a true cortical stress fracture.","topic":"Sports injury","joint":"ankle"},
{"id":"d588","front":"How would you describe medial tibial stress syndrome (shin splints) on MRI?","find":"Periosteal edema along the posteromedial tibial cortex over a long longitudinal segment with adjacent soft-tissue edema along the soleus/posterior tibialis origin. No or only mild marrow edema and no cortical fracture line, distinguishing it from a tibial stress fracture.","impr":"Medial tibial stress syndrome (periostitis) without stress fracture.","pearl":"MTSS = diffuse periosteal edema; a focal marrow/cortical line signals progression to stress fracture.","topic":"Sports injury","joint":"ankle"},
{"id":"d589","front":"How would you describe an anterior tibial cortex stress fracture (the dreaded black line)?","find":"Focal transverse lucency/low-signal line through the anterior mid-tibial cortex on the tension side with surrounding cortical thickening and minimal marrow edema, the dreaded black line. Wedge-shaped or fanned configuration.","impr":"Anterior tibial cortex (tension-side) high-risk stress fracture, dreaded black line.","pearl":"Tension-side anterior tibial location is high risk for nonunion/completion; prolonged restriction or surgery often needed.","topic":"Sports injury","joint":"ankle"},
{"id":"d590","front":"How would you describe a navicular stress fracture in an athlete?","find":"Sagittal/oblique low-signal fracture line through the central third of the tarsal navicular (the relatively avascular sagittal watershed) with surrounding marrow edema. Best seen on CT; MRI shows marrow edema before a discrete line appears.","impr":"Tarsal navicular stress fracture (high-risk) of the central third.","pearl":"Central-third navicular is a high-risk site due to its watershed blood supply; CT defines fracture extent.","topic":"Sports injury","joint":"foot"},
{"id":"d591","front":"How would you describe a fifth metatarsal proximal diaphyseal (Jones) stress fracture?","find":"Transverse fracture line at the proximal fifth metatarsal metaphyseal-diaphyseal junction (Zone 2/3) with periosteal and marrow reaction. Sclerotic margins and intramedullary sclerosis indicate chronicity and impaired healing.","impr":"Proximal fifth metatarsal (Jones-zone) stress fracture, high-risk for nonunion.","pearl":"The metaphyseal-diaphyseal watershed makes the Jones zone prone to delayed union; screw fixation often favored in athletes.","topic":"Sports injury","joint":"foot"},
{"id":"d592","front":"How would you describe a femoral neck stress fracture (tension side vs compression side)?","find":"Compression-side: marrow edema and a low-signal line along the inferomedial femoral neck, lower risk. Tension-side: edema and fracture line along the superolateral femoral neck, high risk for displacement and completion. Assess for any cortical break and percentage of neck width involved.","impr":"Femoral neck stress fracture, [compression-side / tension-side, high-risk].","pearl":"Superolateral (tension-side) femoral neck stress fractures are high-risk and often warrant prophylactic fixation.","topic":"Sports injury","joint":"hip"},
{"id":"d593","front":"How would you describe a metatarsal shaft stress fracture (march fracture)?","find":"Periosteal new bone and marrow edema along a second or third metatarsal diaphysis with a faint transverse low-signal line and surrounding soft-tissue edema. Callus and cortical thickening in subacute stages.","impr":"Metatarsal shaft stress fracture (march fracture), low-risk.","pearl":"Second/third metatarsal shafts are the classic low-risk march fracture sites in runners and military recruits.","topic":"Sports injury","joint":"foot"},
{"id":"d594","front":"How would you describe patellar tendinopathy (jumper's knee)?","find":"Focal fusiform thickening and intrasubstance intermediate T2 signal of the proximal patellar tendon at its inferior patellar pole attachment, predominantly posterior/central fibers, over a [length] mm segment. Adjacent Hoffa fat-pad edema and inferior pole marrow edema. No full-thickness fiber discontinuity.","impr":"Proximal patellar tendinosis (jumper's knee) at the inferior patellar pole.","pearl":"Posterior-central proximal fibers at the inferior pole are the classic site of jumper's knee.","topic":"Sports injury","joint":"knee"},
{"id":"d595","front":"How would you describe quadriceps tendinopathy at the patellar insertion?","find":"Thickening and intrasubstance signal of the distal quadriceps tendon at the superior patellar pole with partial-thickness fiber irregularity involving the [rectus femoris / vastus] layer and adjacent superior pole marrow edema. No complete tendon discontinuity or retraction.","impr":"Distal quadriceps tendinosis with partial-thickness tearing at the superior patellar pole.","pearl":"The quadriceps tendon is trilaminar; specify which layer is involved for surgical planning.","topic":"Sports injury","joint":"knee"},
{"id":"d596","front":"How would you describe a proximal hamstring origin avulsion at the ischial tuberosity?","find":"Full-thickness avulsion of the conjoint hamstring origin (semitendinosus/long head biceps femoris and semimembranosus) from the ischial tuberosity with [X] cm of tendon retraction, intervening fluid/hematoma, and ischial marrow edema. Stripping of the periosteal sleeve.","impr":"Proximal hamstring origin avulsion from the ischial tuberosity with [X] cm retraction.","pearl":"Retraction over ~2 cm and multi-tendon involvement favor surgical repair; report retraction distance.","topic":"Sports injury","joint":"hip"},
{"id":"d597","front":"How would you describe a rectus femoris central (intramuscular) tendon strain in a kicker?","find":"High T2 signal feathery edema surrounding the central intramuscular tendon of the rectus femoris with intrasubstance tendon thickening/disruption and adjacent muscle fiber tearing. Bull's-eye appearance of fluid around the central tendon on axial images. Estimate percentage cross-sectional involvement.","impr":"Rectus femoris central tendon (intramuscular) strain, grade [1-3].","pearl":"Central-tendon (intramuscular) strains heal slower and re-tear more than peripheral myofascial strains.","topic":"Sports injury","joint":"hip"},
{"id":"d598","front":"How would you describe adductor longus origin strain / athletic pubalgia?","find":"Edema and partial tearing at the adductor longus origin off the pubis with a secondary cleft sign (contrast/fluid extending along the inferior pubic margin between the adductor and rectus abdominis aponeurosis). Pubic bone marrow edema and disruption of the rectus abdominis-adductor aponeurotic plate at the pubic symphysis.","impr":"Athletic pubalgia with adductor longus origin injury and rectus abdominis-adductor aponeurotic plate disruption.","pearl":"The secondary cleft sign indicates microtearing at the adductor-rectus aponeurosis; central to the core-muscle injury complex.","topic":"Sports injury","joint":"hip"},
{"id":"d599","front":"How would you describe a sports hernia (inguinal disruption)?","find":"Disruption/attenuation of the posterior inguinal wall (transversalis fascia) with bulging at the deep inguinal ring and edema/tearing of the conjoint tendon and rectus abdominis insertion at the pubic tubercle. No discrete fascial defect with bowel herniation. Associated pubic and adductor changes.","impr":"Sports hernia (athletic inguinal disruption) without a true hernia sac.","pearl":"Sports hernia is a posterior inguinal wall weakness without a palpable hernia; part of the core-muscle injury spectrum.","topic":"Sports injury","joint":"hip"},
{"id":"d600","front":"How would you describe osteitis pubis in an athlete?","find":"Symmetric subchondral marrow edema and sclerosis flanking the pubic symphysis with subchondral cystic change, irregularity and widening of the symphyseal articular margins, and fluid within the symphyseal cleft. Often bilateral.","impr":"Osteitis pubis with symmetric periarticular pubic marrow edema.","pearl":"Bilateral symmetric symphyseal edema favors osteitis pubis over a unilateral traumatic injury.","topic":"Sports injury","joint":"hip"},
{"id":"d601","front":"How would you describe the ACL tear bone-contusion (pivot-shift) pattern?","find":"Complete discontinuity of the ACL fibers with abnormal horizontal fiber orientation and empty notch. Pivot-shift bone contusions: marrow edema at the lateral femoral condyle sulcus terminalis and the posterolateral tibial plateau. Anterior tibial translation, deep lateral femoral notch sign, and Segond fracture of the lateral tibial rim.","impr":"Complete ACL tear with classic pivot-shift bone-contusion pattern.","pearl":"Lateral femoral condyle (sulcus terminalis) + posterolateral tibial plateau contusions are the ACL kissing lesions.","topic":"Sports injury","joint":"knee"},
{"id":"d602","front":"How would you describe an MCL sprain graded on MRI?","find":"Grade 1: periligamentous edema with an intact MCL. Grade 2: partial-thickness fiber tearing with ligament thickening and surrounding edema. Grade 3: complete fiber discontinuity with wavy/lax fibers and adjacent fluid. Specify femoral-sided, mid-substance, or tibial-sided location.","impr":"Medial collateral ligament sprain, grade [1-3].","pearl":"A distally avulsed deep MCL displaced over the pes (Stener-like) impairs healing; note femoral vs tibial location.","topic":"Sports injury","joint":"knee"},
{"id":"d603","front":"How would you describe a high ankle (syndesmotic) sprain?","find":"Edema and partial-to-complete disruption of the anterior inferior tibiofibular ligament and interosseous membrane with widening of the tibiofibular clear space and syndesmotic recess fluid extending >1 cm above the plafond. Associated posterior malleolar and deltoid involvement; assess for tibiofibular diastasis.","impr":"Syndesmotic (high ankle) sprain with AITFL injury.","pearl":"Syndesmotic fluid extending more than ~1 cm above the plafond and clear-space widening suggest an unstable high ankle sprain.","topic":"Sports injury","joint":"ankle"},
{"id":"d604","front":"How would you describe a turf toe (plantar plate / first MTP capsuloligamentous) injury?","find":"Disruption of the plantar plate and plantar capsule of the first MTP joint with edema and partial/complete tearing of the medial or lateral sesamoid-phalangeal ligament. Proximal retraction of a sesamoid, MTP joint effusion, and capsular avulsion at the metatarsal head plantar margin.","impr":"Turf toe: first MTP plantar plate/capsuloligamentous injury.","pearl":"Proximal sesamoid migration indicates plantar plate disruption; grade dictates conservative vs surgical management.","topic":"Sports injury","joint":"foot"},
{"id":"d605","front":"How would you describe a Lisfranc injury in an athlete?","find":"Disruption of the Lisfranc ligament (plantar C1-M2 component) with diastasis between the first and second tarsometatarsal bases >2 mm, marrow edema at the medial cuneiform and second metatarsal base, and a fleck (avulsion) fragment in the interval. Malalignment of the medial M2 border with the medial middle cuneiform.","impr":"Lisfranc ligamentous injury with tarsometatarsal malalignment.","pearl":"The fleck sign and C1-M2 diastasis on weight-bearing/MRI signal an unstable Lisfranc injury often needing fixation.","topic":"Sports injury","joint":"foot"},
{"id":"d606","front":"How would you describe a hook of hamate fracture in a golfer or batter?","find":"Fracture line through the hook of the hamate with surrounding marrow edema, best seen on axial and coronal images and confirmed on CT. Assess for ulnar nerve (Guyon canal) proximity and flexor tendon (small finger FDP) attrition along the fracture.","impr":"Hook of hamate fracture with adjacent marrow edema.","pearl":"Watch for ulnar neurovascular bundle injury and flexor tendon attrition rupture adjacent to the hamate hook.","topic":"Sports injury","joint":"wrist"},
{"id":"d607","front":"How would you describe ECU tendinopathy/subluxation in a racquet/tennis athlete?","find":"Thickening and intrasubstance T2 signal of the extensor carpi ulnaris with tenosynovial fluid within the sixth dorsal compartment and edema at the ulnar groove. Subsheath disruption with subluxation of the ECU tendon medial to the ulnar styloid groove in supination. Partial longitudinal split tearing.","impr":"ECU tendinopathy with subsheath injury and subluxation.","pearl":"Dynamic supination unmasks ECU subluxation; subsheath tear is the lesion permitting instability.","topic":"Sports injury","joint":"wrist"},
{"id":"d608","front":"How would you describe gymnast wrist (distal radial physeal stress injury)?","find":"Widening, irregularity, and increased fluid signal of the distal radial physis with adjacent metaphyseal marrow edema and physeal extension of cartilage. No discrete fracture. Chronic cases show physeal bar formation and positive ulnar variance.","impr":"Gymnast wrist: chronic distal radial physeal stress injury (Salter-Harris-type stress reaction).","pearl":"Repetitive axial loading injures the distal radial physis; chronic injury causes growth arrest and ulnar positive variance.","topic":"Sports injury","joint":"wrist"},
{"id":"d609","front":"How would you describe a peripheral (Palmer 1B) traumatic TFCC tear in an athlete?","find":"High T2 signal disruption of the ulnar (peripheral) attachment of the triangular fibrocartilage at the fovea/ulnar styloid with fluid undercutting the ligamentous attachment. Distal radioulnar joint effusion and possible DRUJ instability. Foveal versus styloid component specified.","impr":"Peripheral (Palmer class 1B) traumatic TFCC tear with foveal involvement.","pearl":"Peripheral foveal tears are vascularized and reparable, unlike central (1A) degenerative-type defects.","topic":"Sports injury","joint":"wrist"},
{"id":"d610","front":"How would you describe a muscle strain graded by MRI (grade 1 to 3)?","find":"Grade 1: feathery interstitial/perifascial T2 edema, <5% fiber involvement, no architectural disruption. Grade 2: partial macroscopic tear with fiber discontinuity, intramuscular hematoma, and partial myotendinous detachment, estimate percentage cross-section. Grade 3: complete muscle/myotendinous rupture with retraction and a gap filled by hematoma.","impr":"Muscle strain, grade [1-3], at the [muscle] myotendinous junction.","pearl":"Most strains occur at the myotendinous junction; quantify percentage cross-section and any retraction distance.","topic":"Sports injury","joint":"hip"},
{"id":"d611","front":"How would you describe a hamstring myotendinous strain in a sprinter?","find":"Feathery T2 hyperintense edema tracking along the long head of biceps femoris myotendinous junction with partial fiber disruption involving approximately [X]% of the cross-section over a [length] cm craniocaudal segment. Minimal intramuscular hematoma; the central tendon remains in continuity without retraction.","impr":"Biceps femoris myotendinous strain, grade 2, without tendon retraction.","pearl":"Central tendon involvement and longer craniocaudal extent of edema predict longer return-to-play in sprinters.","topic":"Sports injury","joint":"hip"},
{"id":"d612","front":"How would you describe tennis leg (medial gastrocnemius / plantaris injury)?","find":"Fluid and hematoma dissecting along the aponeurotic interface between the medial gastrocnemius and soleus with partial tearing at the distal medial gastrocnemius myotendinous junction. Possible discontinuity of the plantaris tendon. Feathery muscle edema and a fluid collection in the intermuscular plane.","impr":"Tennis leg: distal medial gastrocnemius myotendinous tear with intermuscular hematoma.","pearl":"Fluid in the gastroc-soleus aponeurotic plane is the hallmark; plantaris rupture may coexist.","topic":"Sports injury","joint":"ankle"},
{"id":"d613","front":"How would you describe a quadriceps (rectus femoris) tear in a sprinter?","find":"Partial-thickness tearing at the rectus femoris myotendinous junction with feathery T2 edema, intramuscular hematoma, and disruption of approximately [X]% of the muscle cross-section. Distal quadriceps tendon remains in continuity. No complete retraction.","impr":"Rectus femoris strain, grade 2, at the myotendinous junction.","pearl":"The rectus femoris, a two-joint muscle, is most susceptible to strain among the quadriceps group.","topic":"Sports injury","joint":"hip"},
{"id":"d614","front":"How would you describe iliotibial band friction syndrome in a runner/cyclist?","find":"Ill-defined T2 hyperintense fluid and edema deep to the iliotibial band overlying the lateral femoral epicondyle, within the potential space between the ITB and lateral condyle. Mild thickening of the distal iliotibial band. No intra-articular communication.","impr":"Iliotibial band friction syndrome with fluid deep to the ITB at the lateral femoral epicondyle.","pearl":"Edema is lateral to the joint and deep to the ITB, distinguishing it from a lateral meniscal or intra-articular cause.","topic":"Sports injury","joint":"knee"},
{"id":"d615","front":"How would you describe pes anserine bursitis?","find":"Fluid distension of the pes anserine bursa along the anteromedial proximal tibia, deep to the conjoined sartorius, gracilis, and semitendinosus tendons and superficial to the tibial insertion of the MCL. Adjacent soft-tissue edema; no communication with the joint.","impr":"Pes anserine bursitis.","pearl":"Located between the pes tendons and the tibial MCL insertion, anteromedial and inferior to the joint line.","topic":"Sports injury","joint":"knee"},
{"id":"d616","front":"How would you describe a Morton neuroma in a runner?","find":"Well-defined teardrop-shaped mass at the plantar intermetatarsal space (commonly third webspace) that is low-to-intermediate signal on T1 and T2, located plantar to the intermetatarsal ligament, enhancing after contrast. Associated intermetatarsal bursal fluid.","impr":"Morton neuroma of the [third] intermetatarsal space.","pearl":"Low T2 signal (fibrous tissue) and plantar location distinguish a Morton neuroma from a fluid intermetatarsal bursitis.","topic":"Sports injury","joint":"foot"},
{"id":"d617","front":"How would you describe plantar fasciitis in a runner?","find":"Fusiform thickening of the proximal plantar fascia >4 mm at the calcaneal origin with intrasubstance and perifascial T2 hyperintense edema. Adjacent calcaneal enthesophyte and subcortical marrow edema at the medial calcaneal tubercle. No discrete plantar fascia tear.","impr":"Plantar fasciitis with proximal plantar fascia thickening and perifascial edema.","pearl":"Proximal fascia thickness over ~4 mm with perifascial edema supports plantar fasciitis; look for a coexisting tear.","topic":"Sports injury","joint":"foot"},
{"id":"d618","front":"How would you describe normal age-related red and yellow marrow distribution?","find":"Marrow signal follows expected age-related conversion. In the adult, the axial skeleton and proximal metaphyses of the femur and humerus retain hematopoietic (red) marrow, which is mildly hyperintense to skeletal muscle and hypointense to fat on T1; the epiphyses, apophyses, and distal appendicular skeleton show fatty (yellow) marrow that is isointense to subcutaneous fat on all sequences. Red marrow remains higher in signal than adjacent intervertebral disc and muscle on T1. No focal lesion, no T1 signal lower than muscle, and no abnormal STIR hyperintensity.","impr":"Normal age-appropriate red and yellow marrow distribution.","pearl":"Conversion proceeds from distal to proximal and from epiphysis/diaphysis to metaphysis; epiphyses fattly convert shortly after ossification. The cardinal rule: normal/benign red marrow stays HIGHER than skeletal muscle and disc on T1.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d619","front":"How would you describe red marrow reconversion?","find":"Symmetric, fairly homogeneous reconverted hematopoietic marrow re-expanding from the axial skeleton into the proximal metaphyses and, when severe, the diaphyses of the long bones, in reverse order of normal conversion. The marrow is mildly hyperintense to muscle and hypointense to fat on T1 and mildly hyperintense on STIR/fluid-sensitive sequences, with islands of preserved fat and sparing of the epiphyses/apophyses. Signal remains > muscle and > disc on T1 with no focal mass.","impr":"Red marrow reconversion, likely physiologic/reactive (anemia, smoker, endurance athlete, marrow-stimulating agents).","pearl":"Distinguishing feature from malignancy: reconversion is symmetric, spares epiphyses, contains residual fat islands, and stays HIGHER than muscle on T1. Epiphyseal red marrow should raise concern for pathologic infiltration.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d620","front":"How would you describe diffuse marrow replacement suspicious for malignancy (leukemia/myeloma/diffuse mets)?","find":"Diffuse, near-homogeneous marrow infiltration that is hypointense to skeletal muscle and intervertebral disc on T1-weighted images, with diffusely increased STIR/fat-suppressed T2 signal and avid post-contrast enhancement. The normal fatty marrow signal of the epiphyses and subcortical bone is effaced. On Dixon, the fat fraction is markedly reduced. Often described with the 'flip' of normal disc-to-marrow signal so that the disc appears brighter than the vertebral body on T1.","impr":"Diffuse marrow replacement; concerning for hematologic malignancy or diffuse metastatic disease.","pearl":"Key malignancy rule: marrow T1 signal LOWER than adjacent muscle or disc is the most reliable sign of pathologic infiltration. Reconversion never drops below muscle.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d621","front":"How would you describe focal marrow lesions on the T1 signal rule for malignancy?","find":"Focal marrow lesion(s) that are hypointense to skeletal muscle and to adjacent intervertebral disc on T1, measuring [size] cm, with corresponding STIR/fat-suppressed hyperintensity and enhancement. Lesions lack a fatty halo. Contrast this with benign focal red marrow, which remains isointense or hyperintense to muscle on T1 and shows interspersed fat.","impr":"Focal marrow lesion with T1 signal below muscle/disc; suspicious for metastasis or focal myeloma.","pearl":"A lesion smaller than ~1 cm that is hyperintense to muscle on T1 is almost always benign focal red marrow. Out-of-phase signal drop (>20%) on Dixon/chemical-shift favors benign marrow over tumor.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d622","front":"How would you describe Dixon fat-fraction quantification of marrow?","find":"Two-point/multi-point Dixon yields water-only, fat-only, in-phase and out-of-phase reconstructions allowing calculation of proton-density fat fraction. Normal/benign marrow shows preserved fat fraction (typically >20%) with signal drop on opposed-phase images. Malignant marrow infiltration shows markedly reduced fat fraction (often <20%) and absence of opposed-phase signal loss because tumor cells displace marrow fat.","impr":"Dixon fat-fraction technique; reduced fat fraction favors marrow-replacing process.","pearl":"Chemical-shift opposed-phase signal drop of >20% indicates intravoxel fat (benign); failure to drop suggests tumor. Sclerotic/treated mets and hemosiderin can confound chemical-shift assessment.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d623","front":"How would you describe osteoporosis with an insufficiency fracture?","find":"Diffusely diminished trabecular density with relative cortical prominence. Superimposed insufficiency fracture demonstrates a linear or band-like region of marrow edema with a low-signal fracture line on T1, surrounding STIR/fat-suppressed hyperintensity, and no soft-tissue mass. Common sites include the sacral ala (vertical components paralleling the SI joints, the 'Honda sign' when combined with a horizontal component), pubic rami, supra-acetabular region, and medial proximal tibia.","impr":"Insufficiency fracture on a background of osteoporosis.","pearl":"Insufficiency fractures occur with normal stress on abnormal (weak) bone; the marrow edema can mimic neoplasm, but a low-signal fracture line and characteristic location are key. Bilateral symmetric sacral ala edema = Honda/H sign.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d624","front":"How would you describe osteomalacia with a Looser zone (pseudofracture)?","find":"Generalized osteopenia with coarsened, indistinct trabeculae. A Looser zone appears as a focal transverse lucent band perpendicular to the cortex with sclerotic margins, classically on the compression (concave/medial) side of the femoral neck, pubic rami, scapula, and ribs. On MRI the pseudofracture shows a linear low-signal cortical defect with surrounding marrow and periosteal edema, bilateral and often symmetric.","impr":"Looser zone (pseudofracture) consistent with osteomalacia.","pearl":"Looser zones are bilateral, symmetric, and occur at characteristic stress sites; they reflect unmineralized osteoid. Search for an underlying cause (vitamin D deficiency, renal disease, tumor-induced osteomalacia).","topic":"Marrow/metabolic","joint":"general"},
{"id":"d625","front":"How would you describe renal osteodystrophy?","find":"Combination of findings reflecting secondary hyperparathyroidism and osteomalacia in chronic kidney disease: subperiosteal bone resorption (radial aspects of the middle phalanges), the 'rugger jersey spine' with sclerotic vertebral endplate bands alternating with lucent central bodies, soft-tissue and vascular calcification, brown tumors, and insufficiency fractures. MRI shows heterogeneous marrow, endplate edema, and amyloid-related joint changes in long-standing dialysis.","impr":"Renal osteodystrophy with mixed hyperparathyroid and osteomalacic features.","pearl":"Rugger-jersey spine (sclerotic endplate bands) is essentially pathognomonic for renal osteodystrophy and distinguishes it from the sharply marginated central bands of osteopetrosis.","topic":"Marrow/metabolic","joint":"spine"},
{"id":"d626","front":"How would you describe hyperparathyroidism with subperiosteal resorption and brown tumors?","find":"Subperiosteal bone resorption along the radial margins of the middle phalanges of the index and middle fingers, terminal tuft resorption (acro-osteolysis), and a salt-and-pepper skull. Brown tumors appear as expansile, lytic, well-defined lesions; on MRI they are T1 hypointense and heterogeneously T2 hyper/hypointense with fluid-fluid levels and blooming from hemosiderin, and may enhance. Generalized osteopenia and chondrocalcinosis are associated.","impr":"Hyperparathyroidism with subperiosteal resorption and brown tumor(s).","pearl":"Subperiosteal resorption along the radial middle phalanges is the most specific radiographic sign of hyperparathyroidism. Brown tumors are osteoclastic giant-cell lesions ('osteitis fibrosa cystica') that can blooming on GRE due to hemorrhage.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d627","front":"How would you describe Paget disease of bone (phases and MRI appearance)?","find":"Bone enlargement with cortical thickening and coarse, thickened trabeculae. Lytic phase: advancing 'blade of grass'/flame-shaped lucent front in a long bone or 'osteoporosis circumscripta' in the skull. Mixed and sclerotic phases: cortical thickening, trabecular coarsening, and 'cotton wool' skull. On MRI, preserved or fatty marrow signal with coarsened trabeculae in inactive disease; active disease shows marrow edema-like and granular T2 signal with enhancement. Bone expansion with maintained corticomedullary architecture is characteristic.","impr":"Paget disease, [lytic/mixed/sclerotic] phase.","pearl":"Preserved fatty marrow signal between coarsened trabeculae favors uncomplicated Paget over malignancy. New marrow-replacing soft-tissue mass, cortical destruction, or T1-hypointense marrow should raise concern for sarcomatous degeneration (Paget sarcoma).","topic":"Marrow/metabolic","joint":"general"},
{"id":"d628","front":"How would you describe osteopetrosis?","find":"Diffusely increased bone density with loss of corticomedullary differentiation and obliteration of the medullary marrow space. Characteristic 'bone-in-bone' (endobone) appearance, sandwich/rugger-jersey-like sclerotic vertebral endplate bands, and 'Erlenmeyer flask' metaphyseal undertubulation. MRI shows markedly low marrow signal on all sequences from dense bone and reduced/absent hematopoietic marrow. Pathologic and transverse fractures are common.","impr":"Osteopetrosis with diffuse osteosclerosis and bone-in-bone appearance.","pearl":"Despite the dense bone, the bone is brittle and fracture-prone ('marble bone disease'). Marrow obliteration leads to extramedullary hematopoiesis and anemia.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d629","front":"How would you describe Gaucher disease in the skeleton?","find":"Diffuse marrow infiltration by Gaucher cells producing low T1 and low-to-intermediate T2 marrow signal that replaces normal fat, with proximal-to-distal extension. Erlenmeyer flask deformity of the distal femur from failure of metaphyseal remodeling, focal lytic lesions, and complications including avascular necrosis (femoral head, humeral head), bone infarcts, and pathologic fractures. Marrow burden scoring may be reported.","impr":"Skeletal Gaucher disease with marrow infiltration, Erlenmeyer flask deformity, and risk of osteonecrosis.","pearl":"Distinguish a painful bone 'crisis' (acute infarct with marrow edema, periostitis) from indolent infiltration. Erlenmeyer flask is classic but nonspecific (also Pyle disease, thalassemia, osteopetrosis).","topic":"Marrow/metabolic","joint":"general"},
{"id":"d630","front":"How would you describe marrow iron overload / hemochromatosis on MRI?","find":"Diffusely decreased marrow (and hepatic/splenic) signal on all sequences, most pronounced with marked T2 and T2* signal loss (blooming) from paramagnetic iron, becoming progressively darker on longer-TE gradient-echo images. The marrow may appear abnormally low on T1 as well. Associated arthropathy shows hook-like osteophytes at the metacarpal heads (2nd and 3rd MCP) and chondrocalcinosis.","impr":"Iron deposition in marrow consistent with hemochromatosis/transfusional iron overload.","pearl":"Iron causes signal loss that worsens with increasing TE and on gradient-echo (T2*) sequences. Hook osteophytes at the 2nd/3rd MCP joints are a classic associated arthropathy.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d631","front":"How would you describe systemic mastocytosis in bone?","find":"Diffuse or multifocal sclerotic and/or lytic marrow lesions with a heterogeneous, 'moth-eaten' or coarsely trabeculated appearance. On MRI, multifocal marrow infiltration shows low T1 and variable T2 signal with patchy enhancement, frequently involving the axial skeleton and proximal long bones. Osteopenia or paradoxical osteosclerosis and insufficiency fractures may coexist.","impr":"Marrow involvement by systemic mastocytosis.","pearl":"Mastocytosis can produce both osteopenia and osteosclerosis; multifocal sclerotic marrow lesions in a patient with urticaria pigmentosa or flushing should suggest the diagnosis.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d632","front":"How would you describe sickle cell disease in the marrow and bones?","find":"Diffuse low T1 marrow signal from red marrow hyperplasia/reconversion. Acute bone infarcts show geographic marrow edema with a serpentine low-signal rim, and chronic infarcts demonstrate a serpiginous double-line/sclerotic margin with central fatty signal. Vertebrae show central endplate depressions producing the 'H-shaped' (Lincoln-log) vertebra. Avascular necrosis of the femoral and humeral heads and dactylitis (hand-foot syndrome) in children are common. Superimposed osteomyelitis must be excluded.","impr":"Sickle cell disease with marrow reconversion, bone infarcts, and H-shaped vertebrae.","pearl":"H-shaped vertebrae (central squared-off endplate depressions) result from microvascular occlusion of the central endplate. Differentiating acute infarct from osteomyelitis is challenging; rim enhancement, sequestrum, and soft-tissue abscess favor infection.","topic":"Marrow/metabolic","joint":"spine"},
{"id":"d633","front":"How would you describe avascular necrosis of the femoral head with the double-line sign?","find":"Subchondral geographic lesion in the anterosuperior femoral head with a serpentine, well-defined reactive interface. On T2/STIR there is a 'double-line sign' — an inner bright (hyperemic granulation) line and an outer dark (sclerotic) line. The enclosed segment retains fatty (early) or progressively edematous signal. Subchondral fracture (crescent sign) and articular surface flattening indicate later, post-collapse stages.","impr":"Avascular necrosis of the femoral head with double-line sign; specify pre- vs post-collapse.","pearl":"The double-line sign on T2 is nearly pathognomonic for osteonecrosis. The single most important staging distinction is presence of subchondral fracture/collapse (crescent sign), which changes management toward joint-preserving vs arthroplasty.","topic":"Marrow/metabolic","joint":"hip"},
{"id":"d634","front":"How would you stage femoral head avascular necrosis (ARCO/Ficat-Arlet)?","find":"Stage 0: normal imaging, at-risk. Stage I: normal radiograph, abnormal MRI (marrow edema and/or geographic lesion with double-line sign). Stage II: radiographic sclerosis/lucency without subchondral fracture or contour change. Stage III: subchondral fracture (crescent sign) and/or femoral head flattening, joint space preserved. Stage IV: secondary osteoarthritis with joint-space loss and acetabular involvement. Percentage of weight-bearing surface involved and presence of collapse are reported.","impr":"Femoral head osteonecrosis, ARCO/Ficat-Arlet stage [I-IV].","pearl":"The pivotal prognostic threshold is the subchondral fracture (crescent sign) marking transition to collapse (stage III). Larger lesions involving >30% of the weight-bearing surface portend collapse.","topic":"Marrow/metabolic","joint":"hip"},
{"id":"d635","front":"How would you distinguish subchondral insufficiency fracture of the knee (SIFK) from osteonecrosis?","find":"SIFK (formerly SONK/spontaneous osteonecrosis): focal subchondral marrow edema in the medial femoral condyle (or medial tibial plateau) with a subchondral low-signal fracture line paralleling the articular surface, often with an associated meniscal root tear or extrusion. Primary osteonecrosis shows a serpentine double-line demarcating a necrotic segment, frequently bilateral and steroid/alcohol associated, with a fatty or epiphyseal-based necrotic zone rather than a simple subchondral edema-fracture complex.","impr":"Subchondral insufficiency fracture of the knee (SIFK) versus avascular necrosis; favor [diagnosis].","pearl":"SIFK is an insufficiency fracture (often after meniscal root tear in older patients), not true primary osteonecrosis. A low-signal subchondral fracture line with overlying edema and intact cartilage, plus a meniscal root tear, points to SIFK; epiphyseal serpentine double-line favors AVN.","topic":"Marrow/metabolic","joint":"knee"},
{"id":"d636","front":"How would you describe avascular necrosis of the talus?","find":"Geographic subchondral signal abnormality in the talar dome/body, typically after a talar neck fracture (Hawkins classification risk). Acutely, MRI shows marrow edema; subacutely a serpentine double-line sign demarcates the necrotic segment. Late findings include subchondral collapse and articular incongruity. On radiographs, the Hawkins sign (subchondral lucency of the talar dome at 6-8 weeks) indicates preserved vascularity and argues against AVN.","impr":"Talar avascular necrosis; correlate with prior talar neck fracture.","pearl":"A POSITIVE Hawkins sign (subchondral lucency) is a good prognostic indicator of intact blood supply; its ABSENCE (sclerosis/relative density) suggests osteonecrosis. The talus has a tenuous retrograde blood supply.","topic":"Marrow/metabolic","joint":"ankle"},
{"id":"d637","front":"How would you describe humeral head avascular necrosis?","find":"Geographic subchondral lesion in the superior central humeral head (the weight/contact-bearing zone) with a serpentine double-line sign on T2/STIR, demarcating a wedge of necrotic marrow. Progression to subchondral fracture (crescent sign) and articular collapse parallels the femoral head. Often bilateral and associated with corticosteroids, alcohol, sickle cell, or prior trauma.","impr":"Avascular necrosis of the humeral head; stage by presence of collapse.","pearl":"The humeral head is the second most common site of osteonecrosis after the femoral head. Staging mirrors the hip (Cruess/Ficat-like): pre- versus post-collapse is the key surgical determinant.","topic":"Marrow/metabolic","joint":"shoulder"},
{"id":"d638","front":"How would you describe regional migratory osteoporosis?","find":"Transient bone marrow edema syndrome that sequentially involves different joints of the lower extremity over time (e.g., progressing from hip to knee to ankle/foot). Each episode shows diffuse subchondral and metaphyseal marrow edema (low T1, high STIR) with joint effusion but no fracture line, double-line sign, or articular collapse, with spontaneous resolution and subsequent 'migration' to an adjacent region.","impr":"Regional migratory osteoporosis; self-limited migratory marrow edema.","pearl":"It is the migratory counterpart of transient osteoporosis; the key is the sequential, shifting joint involvement over months and the absence of structural osteonecrotic features.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d639","front":"How would you describe complex regional pain syndrome (CRPS/RSD) on imaging?","find":"Patchy, periarticular regional osteopenia on radiographs out of proportion to disuse. MRI may show skin thickening, soft-tissue and periarticular marrow edema, and joint effusions. Three-phase bone scintigraphy classically shows increased periarticular juxta-articular uptake on delayed images. Findings are regional, crossing joint boundaries, following an inciting injury.","impr":"Findings compatible with complex regional pain syndrome (CRPS type I).","pearl":"CRPS is a clinical diagnosis; imaging is supportive. Aggressive-appearing patchy regional osteopenia and increased delayed periarticular uptake on bone scan support it. Marrow edema is variable and nonspecific.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d640","front":"How would you describe acromegaly in the musculoskeletal system?","find":"Generalized bone and soft-tissue overgrowth: heel-pad thickening (>23 mm), spade-shaped distal phalangeal tufts, widened joint spaces from cartilage hypertrophy progressing to premature osteoarthritis, increased intervertebral disc spaces, posterior vertebral scalloping, and prominent frontal sinuses with prognathism. Soft-tissue thickening of the hands and feet is characteristic.","impr":"Musculoskeletal manifestations of acromegaly.","pearl":"Early on, cartilage hypertrophy WIDENS joint spaces (a clue distinguishing it from ordinary OA), but degeneration later supervenes. Heel-pad thickness >23 mm and spade-like tufts are classic.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d641","front":"How would you describe hypothyroid myxedematous soft-tissue and joint changes?","find":"Non-pitting soft-tissue thickening from mucopolysaccharide (myxedema) deposition, joint effusions with relatively viscous fluid, and slow-relaxing reflexes. In congenital/juvenile hypothyroidism, delayed and fragmented epiphyseal ossification (epiphyseal dysgenesis), delayed bone age, and dense metaphyseal bands are seen.","impr":"Soft-tissue and skeletal changes consistent with hypothyroidism/myxedema.","pearl":"Fragmented, stippled epiphyses (epiphyseal dysgenesis) and markedly delayed bone age are hallmarks of cretinism/juvenile hypothyroidism and can mimic avascular necrosis or a dysplasia.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d642","front":"How would you describe amyloid arthropathy (dialysis-related)?","find":"Bilateral, symmetric soft-tissue masses and synovial thickening that is characteristically LOW signal on both T1 and T2 (mimicking PVNS but without blooming as prominent), with multiple well-defined subchondral cysts/erosions and preserved or only mildly narrowed joint spaces. Common at the shoulders, hips, wrists (carpal tunnel), and spine (destructive spondyloarthropathy). Seen in long-term hemodialysis patients (beta-2 microglobulin amyloid).","impr":"Amyloid arthropathy, likely dialysis-related (beta-2 microglobulin).","pearl":"Low T1 AND low T2 synovial/soft-tissue signal with large subchondral cysts and relatively preserved joint space in a dialysis patient is the classic combination. Distinguish from PVNS (more blooming, monoarticular) and infection (more aggressive).","topic":"Marrow/metabolic","joint":"general"},
{"id":"d643","front":"How would you describe hemophilic arthropathy?","find":"Recurrent hemarthrosis leading to synovial hypertrophy and hemosiderin deposition that is LOW signal on T1 and T2 with prominent BLOOMING/susceptibility artifact on gradient-echo. Findings include effusions, dense or low-signal synovium, subchondral cysts, cartilage loss with secondary osteoarthritis, and characteristic enlarged epiphyses with a widened intercondylar notch of the knee and squared patella. Typically affects the knees, elbows, and ankles.","impr":"Hemophilic arthropathy with hemosiderin-laden synovium.","pearl":"Hemosiderin blooming on GRE is the imaging signature, shared with PVNS — but hemophilic arthropathy is polyarticular and symmetric in a hemophiliac, whereas PVNS is typically monoarticular. Widened intercondylar notch is classic at the knee.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d644","front":"How would you describe pigmented villonodular synovitis (diffuse PVNS/TGCT)?","find":"Diffuse villonodular synovial proliferation filling the joint with frondlike masses that are LOW signal on T1 and T2 and demonstrate characteristic BLOOMING on gradient-echo sequences due to hemosiderin. Associated hemorrhagic effusion, pressure erosions on both sides of the joint with preserved joint space until late, and avid enhancement of the synovium. Most common in the knee; localized form (TGCT) presents as a focal nodule.","impr":"Diffuse pigmented villonodular synovitis (diffuse-type tenosynovial giant cell tumor).","pearl":"GRE blooming from hemosiderin is the key feature; preserved joint space with pressure erosions on both sides of the joint helps distinguish from inflammatory/infectious arthritis. Use GRE to confirm susceptibility.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d645","front":"How would you describe osseous sarcoidosis?","find":"Most commonly small tubular bones of the hands and feet: lacy, reticulated trabecular pattern with well-defined lytic 'punched-out' lesions and a coarsened/honeycomb appearance, often with overlying soft-tissue swelling (dactylitis). On MRI, marrow lesions are T1 hypointense, T2 hyperintense and enhance; they may be multifocal in the axial skeleton mimicking metastases. Pulmonary/hilar findings support the diagnosis.","impr":"Osseous sarcoidosis; correlate with pulmonary disease.","pearl":"Lacy/reticulated lytic lesions in the phalanges are the classic radiographic pattern. Axial marrow sarcoid lesions can closely mimic metastatic disease on MRI — clinical and pulmonary correlation is essential.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d646","front":"How would you describe marrow rebound hyperplasia after chemotherapy or G-CSF?","find":"Diffuse, symmetric increase in hematopoietic marrow with mild T1 signal that remains hyperintense to skeletal muscle, mild STIR hyperintensity, and a homogeneous pattern that spares the epiphyses, occurring after cytotoxic therapy or marrow-stimulating factors. Residual fat islands are preserved and there is no focal T1-hypointense mass.","impr":"Treatment-related marrow rebound (red marrow) hyperplasia; no focal marrow-replacing lesion.","pearl":"Rebound hyperplasia can mimic diffuse malignant infiltration, but the marrow stays > muscle on T1, is symmetric, and correlates with recent chemotherapy/G-CSF. Compare with prior exams and use Dixon/chemical shift to confirm preserved fat.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d647","front":"How would you describe serous atrophy of marrow (gelatinous transformation)?","find":"Diffusely abnormal marrow that is LOW on T1 and notably HIGH on STIR/T2 with a fluid-like quality, reflecting replacement of marrow fat and hematopoietic cells by gelatinous mucopolysaccharide. Seen in severe cachexia, anorexia nervosa, and end-stage illness. The signal change is diffuse and reverses with nutritional recovery.","impr":"Serous (gelatinous) atrophy of marrow, consistent with cachexia/anorexia.","pearl":"Diffuse low T1/high T2 marrow in an emaciated patient should suggest serous atrophy rather than infiltrative malignancy; the clinical context of severe weight loss is the key.","topic":"Marrow/metabolic","joint":"general"},
{"id":"d648","front":"How would you describe a reverse Bankart lesion (posterior labral tear)?","find":"Detachment and tearing of the posteroinferior labrum from the glenoid rim along the 7-9 o'clock position, with abnormal increased intrasubstance signal and fluid/contrast undercutting the labral base. Associated posterior capsuloperiosteal stripping and mild posterior glenoid rim marrow edema. No appreciable bony fragment.","impr":"Reverse Bankart (posteroinferior labral tear) consistent with prior posterior glenohumeral subluxation.","pearl":"Suspect after seizure, electrocution, or fall on a flexed adducted arm; pair with reverse Hill-Sachs.","topic":"Instability","joint":"shoulder"},
{"id":"d649","front":"How would you describe a reverse Hill-Sachs lesion?","find":"Impaction deformity of the anteromedial humeral head with subcortical marrow edema and flattening, located ABOVE the level of the coracoid on axial images, measuring approximately 12 x 8 mm. The defect engages the posterior glenoid rim in external rotation.","impr":"Reverse Hill-Sachs deformity indicating prior posterior glenohumeral dislocation.","pearl":"Anteromedial location distinguishes it from a normal bare area; located cephalad to the coracoid tip.","topic":"Instability","joint":"shoulder"},
{"id":"d650","front":"How would you describe a POLPSA (posterior labrocapsular periosteal sleeve avulsion)?","find":"Avulsion of the posterior labrum together with an intact but stripped and redundant posterior scapular periosteum, forming a recess that communicates with the joint and fills with fluid. The labrum remains attached to the lifted periosteal sleeve rather than displaced.","impr":"POLPSA lesion — posterior periosteal sleeve avulsion, the posterior analog of an ALPSA.","pearl":"Periosteum remains intact (unlike reverse Bankart) creating a patulous posterior recess.","topic":"Instability","joint":"shoulder"},
{"id":"d651","front":"How would you describe a Buford complex?","find":"Congenital absence of the anterosuperior labrum (1-3 o'clock) with a cord-like thickened middle glenohumeral ligament arising directly from the superior labrum at the base of the biceps anchor. The anterosuperior glenoid rim is smooth without fraying or contrast undercutting.","impr":"Buford complex — normal anatomic variant; do NOT mistake for a labral tear.","pearl":"Pitfall: the cord-like MGHL must insert into the superior labrum; tracing it confirms the variant.","topic":"Variants","joint":"shoulder"},
{"id":"d652","front":"How would you describe a sublabral foramen?","find":"Smooth unattachment of the anterosuperior labrum from the glenoid rim confined to the 1-3 o'clock position, with smooth subjacent cartilage and no extension below the equator. The labral margins are smooth without fraying or displacement.","impr":"Sublabral foramen — normal variant of the anterosuperior labrum.","pearl":"Becomes pathologic only if it extends below the 3 o'clock position (then consider a tear).","topic":"Variants","joint":"shoulder"},
{"id":"d653","front":"How would you describe glenoid hypoplasia (dysplasia)?","find":"Hypoplasia of the posteroinferior glenoid with rounding and deficiency of the posterior osseous rim, retroversion, and a thickened/hypertrophied posterior labrum and posterior capsule filling the dysplastic notch. Mild posterior humeral head subluxation.","impr":"Glenoid hypoplasia/dysplasia with compensatory posterior labral hypertrophy.","pearl":"Hypertrophied posterior labrum is a normal adaptation here — do not call it a tear.","topic":"Variants","joint":"shoulder"},
{"id":"d654","front":"How would you describe a SLAP type III lesion?","find":"Bucket-handle tear of the superior labrum with a displaced labral fragment into the joint, while the biceps tendon anchor remains intact and attached to the residual labrum. Fluid signal undercuts the displaced meniscoid fragment.","impr":"SLAP type III — bucket-handle superior labral tear with intact biceps anchor.","pearl":"Biceps anchor stays attached (vs type IV where the tear extends into the biceps tendon).","topic":"Labrum","joint":"shoulder"},
{"id":"d655","front":"How would you describe a SLAP type IV lesion?","find":"Bucket-handle tear of the superior labrum with longitudinal extension of the tear into the biceps tendon itself, demonstrating intrasubstance signal and partial splitting of the biceps fibers, with a displaced labral-biceps fragment.","impr":"SLAP type IV — superior labral tear propagating into the biceps tendon.","pearl":"Key differentiator from type III is biceps tendon involvement.","topic":"Labrum","joint":"shoulder"},
{"id":"d656","front":"How would you describe a biceps pulley (Habermeyer) lesion?","find":"Disruption of the biceps reflection pulley with insufficiency of the superior glenohumeral ligament and coracohumeral ligament, allowing medial subluxation of the long head biceps tendon over the lesser tuberosity and toward/under the subscapularis. Associated articular-sided fraying of the anterior supraspinatus.","impr":"Biceps pulley lesion with medial subluxation of the long head of biceps.","pearl":"Look for the biceps perched on or medial to the lesser tuberosity; often coexists with a hidden subscapularis tear.","topic":"Biceps","joint":"shoulder"},
{"id":"d657","front":"How would you describe a suprascapular/spinoglenoid notch cyst with denervation?","find":"Lobulated T2-hyperintense paralabral cyst in the spinoglenoid notch measuring approximately 18 x 12 mm, arising from an adjacent posterosuperior labral tear, compressing the suprascapular nerve. Diffuse T2 hyperintensity (edema-like denervation) of the infraspinatus muscle with preserved bulk.","impr":"Spinoglenoid notch paralabral cyst with isolated infraspinatus denervation.","pearl":"Spinoglenoid location spares supraspinatus (infraspinatus only); suprascapular notch location affects both muscles.","topic":"Nerve","joint":"shoulder"},
{"id":"d658","front":"How would you describe isolated teres minor denervation?","find":"Diffuse T2 edema-like hyperintensity of the teres minor muscle without fatty atrophy in the acute phase, or fatty infiltration and volume loss in the chronic phase, with normal infraspinatus signal. No mass in the quadrilateral space identified.","impr":"Isolated teres minor denervation, likely quadrilateral space involvement of the axillary nerve teres minor branch.","pearl":"Often an incidental, frequently idiopathic finding; isolated pattern points to the axillary nerve branch.","topic":"Nerve","joint":"shoulder"},
{"id":"d659","front":"How would you describe calcific tendinitis in the resorptive phase?","find":"Amorphous calcific deposit within the supraspinatus tendon footprint measuring approximately 9 mm, now ill-defined and fluffy with surrounding tendon and peritendinous T2 hyperintensity and adjacent subacromial-subdeltoid bursal fluid. Adjacent intraosseous migration with humeral head marrow edema may be present.","impr":"Calcific tendinitis, resorptive (acute) phase with peritendinous inflammation.","pearl":"Ill-defined fluffy calcium with surrounding edema = symptomatic resorptive phase; dense well-defined = quiescent formative phase.","topic":"Tendon","joint":"shoulder"},
{"id":"d660","front":"How would you describe hydroxyapatite deposition with intraosseous migration?","find":"Hydroxyapatite calcific deposit at the rotator cuff footprint with adjacent cortical erosion and a tract of intraosseous migration into the greater tuberosity, surrounded by marrow edema and a sclerotic rim. Hypointense on all sequences with surrounding T2 hyperintensity.","impr":"Calcific tendinitis with intraosseous migration of hydroxyapatite.","pearl":"Marrow edema with a calcific tract can mimic aggressive lesion or infection — recognize the cuff footprint origin.","topic":"Tendon","joint":"shoulder"},
{"id":"d661","front":"How would you describe adhesive capsulitis (frozen shoulder) on MRI?","find":"Thickening and T2 hyperintensity of the rotator interval soft tissues and coracohumeral ligament, thickening of the axillary recess capsule and inferior glenohumeral ligament beyond 4 mm, with obliteration of the subcoracoid fat triangle and enhancement of the capsule on post-contrast images.","impr":"Findings consistent with adhesive capsulitis (frozen shoulder).","pearl":"Axillary pouch capsular thickness over 4 mm and obliterated subcoracoid fat are the most reliable signs.","topic":"Capsule","joint":"shoulder"},
{"id":"d662","front":"How would you describe a symptomatic os acromiale with instability?","find":"Unfused mesoacromial ossification center with a smooth synchondrosis demonstrating subchondral marrow edema on both sides and fluid signal across the synchondrosis, with downward tilt and overlying supraspinatus tendinosis/partial tearing indicating dynamic instability.","impr":"Os acromiale (mesoacromion) with unstable, edematous synchondrosis contributing to impingement.","pearl":"Edema across the synchondrosis and cuff changes indicate symptomatic instability rather than an incidental os.","topic":"Variants","joint":"shoulder"},
{"id":"d663","front":"How would you describe coracoclavicular ligament injury in AC separation?","find":"Edema and discontinuity of the conoid and trapezoid components of the coracoclavicular ligament with increased coracoclavicular distance, superior displacement of the distal clavicle, and disruption of the acromioclavicular capsule and ligaments. Associated deltotrapezial fascia injury.","impr":"High-grade acromioclavicular separation with coracoclavicular ligament disruption (Rockwood III or higher).","pearl":"Increased CC distance and torn conoid/trapezoid indicate a surgical-grade (type III+) separation.","topic":"AC Joint","joint":"shoulder"},
{"id":"d664","front":"How would you describe subcoracoid impingement?","find":"Narrowing of the coracohumeral interval below 6 mm with edema and tendinosis/partial tearing of the upper subscapularis at its insertion, effacement of the subcoracoid fat, and possible medial subluxation of the biceps. The lesser tuberosity abuts the coracoid tip.","impr":"Subcoracoid impingement with associated subscapularis tendinopathy.","pearl":"Coracohumeral distance under 6 mm with subscapularis changes supports the diagnosis.","topic":"Impingement","joint":"shoulder"},
{"id":"d665","front":"How would you describe meniscocapsular separation of the medial meniscus?","find":"Fluid signal interposed between the peripheral margin of the posterior horn medial meniscus and the joint capsule, with disruption of the meniscotibial (coronary) ligament and uncovering of the meniscal periphery. Perimeniscal edema and possible mild medial meniscal displacement.","impr":"Meniscocapsular separation at the posterior horn medial meniscus.","pearl":"Often associated with ACL injury; fluid between meniscus and capsule is the key sign.","topic":"Meniscus","joint":"knee"},
{"id":"d666","front":"How would you describe a ramp lesion?","find":"Longitudinal tear at the meniscocapsular junction of the posterior horn medial meniscus with disruption of the meniscotibial ligament, demonstrating fluid signal and irregularity along the inferior peripheral red zone. Associated posteromedial tibial marrow edema in the setting of an ACL tear.","impr":"Ramp lesion of the posteromedial meniscocapsular junction.","pearl":"Highly associated with ACL tears; posteromedial tibial edema is a strong secondary sign — examine the red zone closely.","topic":"Meniscus","joint":"knee"},
{"id":"d667","front":"How would you describe meniscal flounce?","find":"Smooth undulating wave-like folding of the free edge of the medial meniscus on sagittal images, with otherwise normal meniscal signal and no surface-reaching line. The contour is smooth and the meniscus is intact.","impr":"Meniscal flounce — a normal redundancy of the meniscal free margin; no tear.","pearl":"A normal/incidental finding that should not be confused with a tear; smooth and signal-normal.","topic":"Meniscus","joint":"knee"},
{"id":"d668","front":"How would you describe a meniscal ossicle?","find":"Focus of marrow-signal ossification within the posterior horn medial meniscus, isointense to fatty marrow on all sequences with a peripheral cortical rim, often associated with adjacent radial or complex meniscal tearing.","impr":"Meniscal ossicle in the posterior horn medial meniscus.","pearl":"Follows marrow signal (not low signal like loose body/chondrocalcinosis); commonly linked to root or radial tears.","topic":"Meniscus","joint":"knee"},
{"id":"d669","front":"How would you describe a flipped meniscus / double delta sign?","find":"Displaced meniscal fragment from a bucket-handle tear lying anteriorly, creating two triangular meniscal structures in the anterior horn (double anterior horn / double delta), with a diminutive or absent posterior horn (absent bow-tie sign).","impr":"Displaced bucket-handle meniscal tear with a flipped fragment (double delta sign).","pearl":"Double anterior horn plus too-few bow-ties on sagittal slices indicates a flipped/displaced bucket-handle fragment.","topic":"Meniscus","joint":"knee"},
{"id":"d670","front":"How would you describe a posterior medial meniscal root tear?","find":"Radial/vertical tear at the posterior root attachment of the medial meniscus with a fluid-filled cleft, a truncated/absent root on coronal and axial images, and meniscal extrusion beyond the tibial margin exceeding 3 mm. Associated medial compartment subchondral edema.","impr":"Posterior medial meniscal root tear with meniscal extrusion (functionally meniscectomy-equivalent).","pearl":"Ghost sign on sagittal plus extrusion over 3 mm; loss of hoop stress accelerates compartment degeneration.","topic":"Meniscus","joint":"knee"},
{"id":"d671","front":"How would you describe the transverse (intermeniscal) ligament pitfall?","find":"A linear low-signal band coursing through Hoffa fat pad connecting the anterior horns of the medial and lateral menisci, creating apparent pseudo-tear signal at its junction with the anterior horn of the lateral meniscus on sagittal images.","impr":"Transverse intermeniscal ligament — normal structure mimicking an anterior horn lateral meniscal tear.","pearl":"Trace the ligament across Hoffa fat on adjacent slices to avoid calling a pseudo-tear at the anterior horn.","topic":"Pitfalls","joint":"knee"},
{"id":"d672","front":"How would you describe the popliteomeniscal fascicle pitfall vs tear?","find":"Normal popliteus tendon coursing through the popliteal hiatus with fluid in the hiatus and intact superior and inferior popliteomeniscal fascicles. A tear is suggested when the fascicles are disrupted with abnormal fluid extending vertically and posterolateral corner instability.","impr":"Normal popliteal hiatus fluid; intact popliteomeniscal fascicles (no tear).","pearl":"Fluid in the hiatus is normal; only disrupted fascicles with vertical fluid indicate a true posterior horn lateral meniscus tear.","topic":"Pitfalls","joint":"knee"},
{"id":"d673","front":"How would you describe ACL mucoid degeneration vs intrasubstance ganglion?","find":"Diffuse increased T2 signal interspersed between intact, taut ACL fibers giving a celery-stalk appearance with thickening of the ligament but preserved fiber continuity. A ganglion instead appears as a well-defined fluid collection along or within the ACL.","impr":"Mucoid degeneration of the ACL (celery-stalk appearance) with intact fibers — not a tear.","pearl":"Fibers remain continuous and taut; may be associated with intercondylar notch tibial cysts; can cause loss of extension.","topic":"Ligament","joint":"knee"},
{"id":"d674","front":"How would you describe a cyclops lesion?","find":"Focal nodular fibrous mass of low-to-intermediate signal in the anterior intercondylar notch anterior to the ACL graft/native ligament, measuring approximately 12 mm, sometimes with low-signal hemosiderin, limiting terminal extension.","impr":"Cyclops lesion (localized anterior arthrofibrosis) post ACL reconstruction.","pearl":"Anterior notch fibrous nodule causing an extension block; typically post-ACL reconstruction.","topic":"Postoperative","joint":"knee"},
{"id":"d675","front":"How would you describe a PCL ganglion cyst?","find":"Well-defined multiloculated T2-hyperintense cystic lesion arising along and splaying the fibers of the posterior cruciate ligament, with the PCL fibers themselves intact and of normal signal. No mass effect on adjacent neurovascular structures.","impr":"Ganglion cyst of the posterior cruciate ligament.","pearl":"Cyst conforms to and splays the PCL fibers while fibers remain intact — not a tear.","topic":"Ligament","joint":"knee"},
{"id":"d676","front":"How would you describe a Wrisberg ligament pseudo-tear?","find":"The posterior meniscofemoral ligament of Wrisberg coursing posterior to the PCL toward the medial femoral condyle, creating apparent cleft-like signal at its origin from the posterior horn lateral meniscus on sagittal images.","impr":"Ligament of Wrisberg — normal meniscofemoral ligament mimicking a posterior horn lateral meniscal tear.","pearl":"Trace the obliquely coursing ligament toward the medial condyle to avoid a pseudo-tear at the lateral meniscus posterior horn.","topic":"Pitfalls","joint":"knee"},
{"id":"d677","front":"How would you describe a medial (mediopatellar) plica syndrome?","find":"Thickened low-signal medial synovial plica extending from the medial wall to the infrapatellar fat, measuring over 3 mm, with adjacent chondral wear of the medial patellar facet and medial femoral condyle and surrounding synovitis/effusion.","impr":"Symptomatic mediopatellar plica with associated chondromalacia.","pearl":"Thickening over 3 mm plus adjacent medial facet chondral wear suggests symptomatic plica syndrome.","topic":"Synovium","joint":"knee"},
{"id":"d678","front":"How would you describe a bipartite patella vs acute fracture?","find":"Well-corticated synchondrosis at the superolateral patella (most common type) with smooth rounded margins and no surrounding marrow edema. An acute fracture instead shows sharp non-corticated margins with adjacent marrow edema.","impr":"Bipartite patella (superolateral) — normal variant; no acute fracture.","pearl":"Corticated smooth margins without marrow edema = bipartite; sharp margins with edema = fracture.","topic":"Variants","joint":"knee"},
{"id":"d679","front":"How would you describe a dorsal defect of the patella?","find":"Well-defined rounded lucency/defect in the superolateral aspect of the patella with intact overlying articular cartilage, smooth sclerotic margins, and no surrounding marrow edema or soft tissue mass.","impr":"Dorsal defect of the patella — benign normal variant.","pearl":"Intact overlying cartilage and lack of aggressive features distinguish it from osteochondral lesion or tumor.","topic":"Variants","joint":"knee"},
{"id":"d680","front":"How would you describe Pellegrini-Stieda lesion?","find":"Curvilinear ossification paralleling the medial femoral condyle at the proximal MCL origin, with adjacent MCL thickening and chronic post-traumatic changes. No acute marrow edema in the chronic phase.","impr":"Pellegrini-Stieda lesion — chronic post-traumatic ossification of the proximal MCL.","pearl":"Reflects prior MCL injury at its femoral origin; ossification parallels the medial condyle.","topic":"Ligament","joint":"knee"},
{"id":"d681","front":"How would you describe fabella / fabella syndrome?","find":"Well-corticated ossicle within the lateral head of gastrocnemius tendon posterolaterally, with adjacent marrow-equivalent signal. In fabella syndrome, posterolateral pain with edema at the fabellofemoral articulation and adjacent chondral wear of the posterolateral femoral condyle.","impr":"Fabella with fabellofemoral changes (fabella syndrome).","pearl":"Sesamoid in lateral gastrocnemius; can cause posterolateral pain or peroneal nerve symptoms.","topic":"Variants","joint":"knee"},
{"id":"d682","front":"How would you describe a jersey finger (FDP avulsion)?","find":"Discontinuity of the flexor digitorum profundus tendon at its insertion on the volar base of the distal phalanx, with a fluid-filled gap and proximal tendon retraction. Leddy-Packer classification: Type I — tendon retracts to the palm with disruption of both vincula (retracted level documented); Type II — retracts to the level of the PIP joint, held by the long vincula; Type III — large bony avulsion fragment from the distal phalanx base caught at the A4 pulley. Measure the tendon gap and the level of the retracted stump relative to the A-pulleys. Adjacent flexor sheath fluid and soft-tissue edema.","impr":"FDP avulsion (jersey finger), Leddy-Packer type [I/II/III], with proximal retraction to [palm/PIP/A4 pulley].","pearl":"The retraction level drives surgical urgency — Type I (palm, no vincular blood supply) must be repaired within ~7-10 days before the tendon scars and the muscle contracts.","topic":"Finger","joint":"hand"},
{"id":"d683","front":"How would you describe a mallet finger (terminal extensor tendon injury)?","find":"Disruption of the terminal extensor tendon at its insertion on the dorsal base of the distal phalanx, with fluid in the tendon gap and flexion deformity of the DIP joint. Bony mallet variant shows a dorsal avulsion fragment from the distal phalanx base; quantify fragment size and the percentage of the articular surface involved, and assess for volar subluxation of the distal phalanx when the fragment exceeds ~30-50% of the joint.","impr":"Terminal extensor tendon injury (mallet finger), [tendinous/bony], with DIP extensor lag.","pearl":"Volar subluxation of the distal phalanx with a large articular fragment favors operative fixation over splinting.","topic":"Finger","joint":"hand"},
{"id":"d684","front":"How would you describe a central slip rupture / boutonniere injury?","find":"Disruption of the central slip of the extensor mechanism at its insertion on the dorsal base of the middle phalanx, with fluid in the gap and PIP flexion deformity. Volar migration of the lateral bands converts them to PIP flexors and MCP/DIP extenders, producing the boutonniere configuration. Assess for an avulsion fragment from the dorsal middle phalanx base and for triangular ligament attenuation permitting lateral band subluxation.","impr":"Central slip disruption with developing boutonniere deformity.","pearl":"Boutonniere = PIP flexion + DIP hyperextension; it is the mechanical opposite of the swan-neck deformity.","topic":"Finger","joint":"hand"},
{"id":"d685","front":"How would you describe a sagittal band rupture with extensor tendon subluxation?","find":"Disruption of the sagittal band at the metacarpophalangeal joint (most commonly the radial sagittal band of the long finger), with the extensor digitorum communis tendon subluxed/dislocated ulnarly into the intermetacarpal groove, best seen on axial images with the MCP in flexion. Surrounding soft-tissue edema; the contralateral sagittal band may be attenuated.","impr":"Sagittal band rupture with ulnar subluxation of the extensor tendon at the MCP joint.","pearl":"Radial sagittal band tears predominate, so the extensor tendon typically subluxes ulnarly; dynamic/flexed-MCP imaging unmasks reducible subluxation.","topic":"Finger","joint":"hand"},
{"id":"d686","front":"How would you describe a volar plate injury of the PIP joint?","find":"Thickening, increased signal, or discontinuity of the volar plate at its insertion on the volar base of the middle phalanx, often with a small avulsion fragment from the volar base. Associated joint effusion and dorsal dislocation/subluxation tendency. Assess collateral ligaments for concomitant injury.","impr":"Volar plate injury at the PIP joint with [small volar avulsion fragment].","pearl":"Volar plate avulsions arise from hyperextension and accompany dorsal PIP dislocations; a large fragment with joint incongruity needs fixation.","topic":"Finger","joint":"hand"},
{"id":"d687","front":"How would you describe a collateral ligament tear of the PIP or MCP joint?","find":"Discontinuity or high signal of the radial or ulnar collateral ligament with surrounding edema; document complete versus partial tear, avulsion fragment, and joint-space widening on the affected side with stress. The proper and accessory collateral ligaments may be involved.","impr":"[Radial/ulnar] collateral ligament tear of the [PIP/MCP] joint.","topic":"Finger","joint":"hand"},
{"id":"d688","front":"How would you describe a gamekeeper/skier thumb (UCL tear) with a Stener lesion?","find":"Disruption of the ulnar collateral ligament of the thumb MCP joint at its distal insertion on the proximal phalanx base, with edema. A Stener lesion is present when the torn, retracted UCL is displaced proximal and superficial to the adductor aponeurosis, appearing as a balled-up 'yo-yo on a string' mass at the proximal/dorsal MCP. Document any avulsion fragment and the degree of MCP instability.","impr":"Complete UCL tear of the thumb MCP joint with a Stener lesion.","pearl":"A Stener lesion mandates surgery because the interposed adductor aponeurosis prevents the ligament ends from healing.","topic":"Thumb","joint":"hand"},
{"id":"d689","front":"How would you describe trigger finger (A1 pulley)?","find":"Thickening of the A1 pulley with peritendinous edema and tenosynovial fluid around the flexor tendons at the metacarpal head, sometimes with a focal nodular thickening of the flexor tendon (notch sign) impeding gliding through the pulley.","impr":"Stenosing flexor tenosynovitis (trigger finger) at the A1 pulley.","topic":"Finger","joint":"hand"},
{"id":"d690","front":"How would you describe a Dupuytren cord?","find":"Nodular and cord-like soft-tissue thickening of the palmar aponeurosis, low-to-intermediate signal on all sequences, extending longitudinally from the distal palm toward the proximal phalanx along the flexor surface, causing flexion contracture at the MCP and/or PIP joints. Cellular/active cords show higher T2 signal and enhancement.","impr":"Dupuytren contracture with palmar fascial cord.","pearl":"Higher T2 signal/enhancement indicates a cellular, proliferative (active) lesion more prone to recurrence after fasciectomy.","topic":"Hand","joint":"hand"},
{"id":"d691","front":"How would you describe a glomus tumor of the finger?","find":"Small (often <1 cm) well-circumscribed subungual mass, markedly T2 hyperintense and T1 iso/hypointense, with intense avid enhancement; may scallop the dorsal cortex of the distal phalanx. Measure precisely given the small size.","impr":"Subungual glomus tumor.","pearl":"Classic triad: pinpoint pain, cold sensitivity, and point tenderness — an avidly enhancing subungual nodule confirms it.","topic":"Finger","joint":"hand"},
{"id":"d692","front":"How would you describe a mucous cyst of the finger?","find":"Well-defined T2-hyperintense cystic lesion at the dorsal DIP joint, arising from an osteoarthritic (Heberden) joint, often with a stalk to the joint and adjacent dorsal osteophytes; may cause nail-plate grooving from pressure on the germinal matrix.","impr":"Dorsal DIP mucous cyst associated with interphalangeal osteoarthritis.","topic":"Finger","joint":"hand"},
{"id":"d693","front":"How would you describe infectious flexor tenosynovitis (Kanavel)?","find":"Complex/heterogeneous fluid distending the flexor tendon sheath with synovial thickening, peritendinous and subcutaneous edema, and avid synovial enhancement; the tendon may show intrasubstance signal. Assess for rim-enhancing abscess and adjacent osteomyelitis or septic arthritis.","impr":"Suppurative flexor tenosynovitis, concerning for pyogenic infection.","pearl":"Kanavel's four cardinal signs: fusiform digit swelling, semi-flexed resting posture, tenderness along the sheath, and pain on passive extension — a surgical emergency.","topic":"Finger","joint":"hand"},
{"id":"d694","front":"How would you describe midcarpal instability?","find":"Nonspecific findings on static MRI; look for attenuation/laxity of the volar extrinsic ligaments (especially the ulnar arm of the arcuate/triquetrohamate-capitate) and the dorsal radiocarpal ligament. Dynamic clunk on stress is the clinical hallmark; document any associated carpal malalignment (CIND - capitolunate angle abnormality).","impr":"Findings suggestive of (palmar) midcarpal instability — correlate with dynamic clinical exam.","topic":"Carpal instability","joint":"wrist"},
{"id":"d695","front":"How would you describe ulnar impaction syndrome versus ulnar impingement?","find":"Ulnar impaction (abutment): positive ulnar variance with subchondral marrow edema, sclerosis, and subchondral cysts in the ulnar-sided lunate and proximal ulnar triquetrum, degenerative central TFCC perforation, and lunotriquetral ligament degeneration. Ulnar impingement is a distinct entity: a short/hypoplastic ulna (often post-Darrach or congenital) whose distal end abuts and erodes the distal radius metaphysis with a painful pseudarthrosis-like notch.","impr":"Ulnar impaction syndrome (positive variance) — distinct from ulnar impingement of a foreshortened ulna against the radius.","pearl":"Impaction = too-long ulna hitting the carpus; impingement = too-short ulna hitting the radius.","topic":"Ulnar wrist","joint":"wrist"},
{"id":"d696","front":"How would you describe scaphoid nonunion advanced collapse (SNAC)?","find":"Established scaphoid nonunion (sclerotic/cystic margins, no bridging trabeculae) with progressive osteoarthritis: Stage I — radioscaphoid (radial styloid) arthrosis; Stage II — adds scaphocapitate arthrosis; Stage III — adds capitolunate/midcarpal arthrosis with proximal capitate migration; the radiolunate joint is characteristically preserved. Assess proximal pole vascularity/marrow signal.","impr":"Scaphoid nonunion advanced collapse (SNAC) stage [I/II/III].","pearl":"Like SLAC, the radiolunate articulation is spared until the end stages — preserved radiolunate cartilage enables motion-sparing salvage (e.g., PRC).","topic":"Carpal arthrosis","joint":"wrist"},
{"id":"d697","front":"How would you describe scapholunate advanced collapse (SLAC)?","find":"Sequela of chronic scapholunate dissociation: widened SL interval with DISI. Stage I — arthrosis at the radial styloid-distal scaphoid; Stage II — extends along the entire radioscaphoid joint; Stage III — capitolunate (midcarpal) arthrosis with proximal capitate migration into the SL gap; the radiolunate joint remains preserved.","impr":"Scapholunate advanced collapse (SLAC) stage [I/II/III].","pearl":"SLAC is the most common pattern of degenerative wrist arthritis; radiolunate sparing is the rule.","topic":"Carpal arthrosis","joint":"wrist"},
{"id":"d698","front":"How would you describe a dorsal versus volar wrist ganglion?","find":"Well-defined unilocular or multilocular T2-markedly-hyperintense, T1-hypointense cystic lesion with a thin non-enhancing wall and an enhancing rim only. Dorsal ganglion arises from the scapholunate interval/dorsal capsule; volar ganglion arises from the radioscaphoid or scaphotrapezial joint, often abutting the radial artery and FCR. Trace the stalk to the joint of origin.","impr":"[Dorsal/volar] wrist ganglion cyst arising from the [scapholunate/radioscaphoid] joint.","topic":"Cystic","joint":"wrist"},
{"id":"d699","front":"How would you describe an ECU subsheath tear with tendon instability?","find":"Disruption of the fibro-osseous subsheath at the ulnar groove with the extensor carpi ulnaris tendon subluxed/dislocated medially over the ulnar styloid, best demonstrated with the forearm supinated. Tendon shows tendinosis or longitudinal split, and fluid distends the sheath; an empty or shallow ulnar groove may be present.","impr":"ECU subsheath disruption with tendon subluxation/instability.","pearl":"Supination provokes the subluxation; an empty ECU groove on a single static image should prompt dynamic correlation.","topic":"Ulnar wrist","joint":"wrist"},
{"id":"d700","front":"How would you describe FCR tendinopathy, de Quervain tenosynovitis, and intersection syndrome?","find":"FCR tendinopathy: thickening/high signal of the flexor carpi radialis as it passes the scaphoid/trapezial ridge with peritendinous fluid, often with adjacent STT osteoarthritis. De Quervain: thickening and edema of the first dorsal extensor compartment (APL and EPB) at the radial styloid with sheath fluid; assess for an intracompartmental septum separating EPB. Intersection syndrome: peritendinous edema where the first compartment crosses over the second (ECRL/ECRB) ~4-6 cm proximal to Lister tubercle.","impr":"[FCR tendinopathy / de Quervain tenosynovitis / intersection syndrome].","pearl":"De Quervain occurs at the radial styloid; intersection syndrome occurs more proximally at the first-second compartment crossover.","topic":"Radial wrist","joint":"wrist"},
{"id":"d701","front":"How would you describe distal radioulnar joint (DRUJ) instability?","find":"Disruption of the foveal (deep) attachment of the radioulnar ligaments / TFCC at the ulnar fovea (Palmer 1B / ulnar-sided peripheral tear), with dorsal or volar displacement of the ulnar head relative to the sigmoid notch on axial images. Assess sigmoid notch morphology, ECU subsheath integrity, and ulnar styloid base fracture.","impr":"DRUJ instability from foveal TFCC disruption.","pearl":"The deep (ligamentum subcruentum/foveal) fibers are the principal DRUJ stabilizer — superficial-only tears may be stable.","topic":"DRUJ","joint":"wrist"},
{"id":"d702","front":"How would you describe pisotriquetral osteoarthritis?","find":"Joint-space narrowing, subchondral sclerosis, osteophytes, and subchondral cysts at the pisotriquetral articulation with a joint effusion; cartilage thinning of the pisiform articular surface. Adjacent FCU tendinopathy may coexist.","impr":"Pisotriquetral osteoarthritis.","topic":"Ulnar wrist","joint":"wrist"},
{"id":"d703","front":"How would you describe a carpal coalition?","find":"Osseous (smooth bridging trabeculae) or non-osseous/fibrocartilaginous (irregular pseudarthrosis-like cleft with cystic change and edema) union between adjacent carpal bones, most commonly lunotriquetral. Classify by completeness; symptomatic incomplete coalitions may show edema across the fibrous junction.","impr":"[Lunotriquetral] carpal coalition, [complete osseous / incomplete fibrocartilaginous].","pearl":"Lunotriquetral coalition is the most common carpal coalition; incomplete fibrous types can be symptomatic.","topic":"Carpal anomaly","joint":"wrist"},
{"id":"d704","front":"How would you describe capitellar osteochondritis dissecans (OCD)?","find":"Focal subchondral lesion of the anterolateral capitellum with marrow edema. Staging of stability: Stage I — intact overlying cartilage, stable; Stage II — partial detachment with fluid/high signal undermining part of the fragment; Stage III — completely detached but in situ; Stage IV — displaced intra-articular loose body. A T2-hyperintense rim or cyst beneath the fragment signals instability. Survey the joint for loose bodies.","impr":"Capitellar osteochondritis dissecans, [stable / unstable], stage [I-IV].","pearl":"A high-signal line or cysts fully surrounding the fragment, or fluid undercutting it, indicates an unstable lesion that will not heal with rest.","topic":"Elbow OCD","joint":"elbow"},
{"id":"d705","front":"How would you describe a radial head fracture with marrow edema?","find":"Fracture line through the radial head/neck with surrounding marrow edema; document articular involvement, step-off, displacement, and angulation. Associated lipohemarthrosis with a fat-fluid level distending the joint. Survey for occult coronoid fracture and ligament injury.","impr":"Radial head fracture with marrow edema and lipohemarthrosis.","pearl":"A fat-fluid level (lipohemarthrosis) on a tightly windowed image is a clue to an occult intra-articular fracture even when the line is inconspicuous.","topic":"Elbow fracture","joint":"elbow"},
{"id":"d706","front":"How would you describe a common extensor tendon full-thickness tear versus tendinosis?","find":"Tendinosis (lateral epicondylitis): thickening and intermediate-to-high T1/PD signal within the common extensor origin without a fluid-signal cleft, centered on the ECRB component, lower T2 than fluid. Full-thickness tear: a fluid-signal gap completely traversing the tendon with retraction and a bare lateral epicondyle. Assess the underlying lateral collateral ligament/LUCL for concomitant injury.","impr":"Common extensor [tendinosis / full-thickness tear].","pearl":"Look for LUCL involvement with high-grade common extensor tears — combined injury risks posterolateral rotatory instability.","topic":"Elbow tendon","joint":"elbow"},
{"id":"d707","front":"How would you describe a distal biceps tendon partial versus complete tear?","find":"Use the FABS (flexion-abduction-supination) view through the cubital window for the distal insertion. Partial tear: fluid/high signal within a thinned tendon, often involving the radial-tuberosity footprint, with the tendon still in continuity. Complete tear: full discontinuity with proximal retraction; an intact lacertus fibrosus limits retraction. Distended bicipitoradial bursa. Measure the retraction gap from the radial tuberosity.","impr":"Distal biceps tendon [partial-thickness / complete] tear, retracted [measurement].","pearl":"The FABS position best profiles the distal biceps tendon and footprint; an intact lacertus fibrosus tethers the stump and can mask the degree of retraction.","topic":"Elbow tendon","joint":"elbow"},
{"id":"d708","front":"How would you describe a triceps tendon avulsion?","find":"Disruption of the triceps tendon at its olecranon insertion with a fluid gap, retraction, and surrounding edema; frequently an avulsed osseous fleck from the olecranon (flake sign). Quantify the gap and percentage of tendon torn (partial deep-fiber tears are common).","impr":"Triceps tendon avulsion at the olecranon, [partial / complete].","pearl":"An olecranon flake avulsion fragment is the radiographic clue to triceps rupture; partial deep-fiber tears are easily underestimated.","topic":"Elbow tendon","joint":"elbow"},
{"id":"d709","front":"How would you describe snapping triceps with ulnar nerve instability?","find":"Dynamic medial dislocation of the ulnar nerve out of the cubital tunnel over the medial epicondyle during flexion, often accompanied by a dislocating medial head of the triceps; on static images note an anteriorly displaced/enlarged signal-abnormal ulnar nerve and cubital tunnel changes. Assess for nerve edema and denervation in the FCU/FDP.","impr":"Snapping triceps syndrome with ulnar nerve subluxation/instability.","pearl":"The medial triceps and ulnar nerve can snap together over the epicondyle in flexion, mimicking ulnar nerve subluxation alone.","topic":"Elbow nerve","joint":"elbow"},
{"id":"d710","front":"How would you describe valgus extension overload (posteromedial impingement)?","find":"Posteromedial olecranon osteophyte at the olecranon tip/posteromedial facet with subchondral edema, chondral wear of the posteromedial trochlea, and a posterior loose body; associated chronic attenuation/tearing of the anterior bundle of the medial UCL from repetitive valgus throwing stress.","impr":"Valgus extension overload with posteromedial olecranon osteophyte and UCL attrition.","pearl":"This is the throwing-athlete triad: UCL insufficiency, posteromedial olecranon osteophyte, and posteromedial chondral wear.","topic":"Elbow impingement","joint":"elbow"},
{"id":"d711","front":"How would you describe an annular ligament injury / nursemaid elbow?","find":"In nursemaid's (radial head subluxation), the annular ligament is interposed/displaced over the radial head following axial traction in a young child, usually with a normal-appearing radial head and minimal effusion. Annular ligament tear in adults shows discontinuity/edema of the ligament encircling the radial neck with radiocapitellar instability.","impr":"[Annular ligament displacement (nursemaid's elbow) / annular ligament tear].","pearl":"Nursemaid's elbow is a clinical/reduction diagnosis in toddlers; imaging is usually reserved to exclude fracture.","topic":"Elbow ligament","joint":"elbow"},
{"id":"d712","front":"How would you describe a deep vein thrombosis on MRI?","find":"Distended deep vein (e.g., popliteal/femoral) with absent normal flow void and intraluminal filling defect that is T1 isointense to mildly hyperintense and T2 variable depending on clot age, expanding the vessel caliber. No central enhancement of the clot on post-contrast images, with surrounding perivenous edema and rim/wall enhancement of the vessel. Acute thrombus expands the vein; chronic thrombus shows retracted, eccentric webs with a smaller, recanalized lumen.","impr":"Acute deep venous thrombosis of the [vessel].","pearl":"Flow-related artifact and slow flow can mimic thrombus; confirm with absence of enhancement on subtraction or time-of-flight MRV.","topic":"Vascular","joint":"general"},
{"id":"d713","front":"How would you describe an intramuscular hemangioma on MRI?","find":"Lobulated, infiltrative intramuscular mass that is T2 markedly hypervascular/hyperintense (>fat) with serpentine high-signal vascular channels, interspersed macroscopic fat that follows fat signal on all sequences and suppresses on fat-sat, and rounded T2-hypointense foci with blooming on GRE representing phleboliths. Avid heterogeneous enhancement of the vascular channels. Fluid-fluid levels may be present.","impr":"Intramuscular hemangioma (venous-predominant vascular malformation) of the [muscle].","pearl":"Phleboliths (low-signal, blooming) plus interspersed fat are the discriminators from a soft-tissue sarcoma.","topic":"Vascular","joint":"general"},
{"id":"d714","front":"How would you describe a venous malformation on MRI?","find":"Trans-spatial, lobulated, T2 markedly hyperintense lesion composed of dilated venous channels and lakes, with fluid-fluid levels from stasis/sedimentation and rounded blooming phleboliths on GRE. Slow, gradual peripheral and progressive fill-in enhancement on delayed post-contrast images, without arterial flow voids or early arterial enhancement.","impr":"Low-flow venous malformation.","pearl":"Phleboliths and slow fill-in distinguish a low-flow venous malformation from a high-flow AVM, which has flow voids and no phleboliths.","topic":"Vascular","joint":"general"},
{"id":"d715","front":"How would you describe an arteriovenous malformation on MRI?","find":"High-flow vascular lesion comprising a tangle (nidus) of numerous serpentine signal voids on T1/T2 representing enlarged feeding arteries and dilated draining veins, with no discrete soft-tissue mass. Early arterial enhancement with rapid arteriovenous shunting and enlarged early-draining veins on dynamic post-contrast/time-resolved MRA. No phleboliths and minimal interspersed soft tissue.","impr":"High-flow arteriovenous malformation.","pearl":"Absence of a soft-tissue mass plus flow voids and early venous filling separate AVM from venous malformation (phleboliths, slow fill-in).","topic":"Vascular","joint":"general"},
{"id":"d716","front":"How would you describe a lymphatic malformation on MRI?","find":"Trans-spatial, multiloculated cystic lesion that is T1 hypointense and T2 markedly hyperintense with thin internal septations and fluid-fluid levels (hemorrhage/proteinaceous debris). Macrocystic type shows only thin septal and rim enhancement with no enhancing solid component; microcystic type shows more diffuse enhancement of the interstitium. No flow voids or phleboliths.","impr":"Lymphatic (macrocystic or microcystic) malformation.","pearl":"Lack of phleboliths and lack of solid enhancement separate it from a venous malformation; fluid-fluid levels are common to both.","topic":"Vascular","joint":"general"},
{"id":"d717","front":"How would you describe popliteal artery entrapment syndrome on MRI?","find":"Medial deviation of the popliteal artery around an aberrant or accessory medial head of gastrocnemius (or a fibrous band), with the artery coursing medial to or between abnormal muscle slips. Provocative imaging (active plantarflexion) shows dynamic compression and flow reduction or occlusion of the popliteal artery. Chronic injury may show arterial wall thickening, post-stenotic aneurysmal dilatation, or mural thrombus.","impr":"Popliteal artery entrapment from an anomalous gastrocnemius relationship.","pearl":"Functional (type VI) entrapment may have normal anatomy with positional occlusion only on provocative maneuvers.","topic":"Vascular","joint":"knee"},
{"id":"d718","front":"How would you describe cystic adventitial disease on MRI?","find":"Well-defined, T2 hyperintense, mucin-filled cyst within the adventitia of the popliteal artery, conforming to the vessel wall in a curvilinear (scimitar) or hourglass configuration and eccentrically compressing the lumen. Thin peripheral enhancement without solid enhancement. The arterial lumen is narrowed/crescentic; the rest of the vessel is normal.","impr":"Cystic adventitial disease of the popliteal artery.","pearl":"Younger patient with claudication and no atherosclerosis; the cyst is intramural (adventitial), distinguishing it from a periarterial ganglion.","topic":"Vascular","joint":"knee"},
{"id":"d719","front":"How would you describe a pseudoaneurysm on MRI?","find":"Round perivascular collection in continuity with an artery via a narrow neck, demonstrating a swirling yin-yang flow pattern with central enhancement that follows the arterial lumen and a peripheral mural thrombus of layered/laminated signal. Pulsation artifact in the phase-encoding direction. No complete vessel wall surrounding the sac.","impr":"Pseudoaneurysm arising from the [artery].","pearl":"A true aneurysm contains all vessel-wall layers and is fusiform; a pseudoaneurysm is contained by adventitia/clot only and has a neck.","topic":"Vascular","joint":"general"},
{"id":"d720","front":"How would you describe aneurysmal change of an artery on MRI?","find":"Fusiform or saccular focal dilatation of the artery exceeding 1.5x the normal adjacent caliber, with a patent central flow void/enhancing lumen and concentric or eccentric laminated mural thrombus of intermediate T1/low T2 signal. Possible perivascular edema or hematoma if leaking.","impr":"Arterial aneurysm of the [vessel] with mural thrombus.","pearl":"Popliteal aneurysm is the most common peripheral aneurysm and is frequently bilateral and associated with AAA.","topic":"Vascular","joint":"general"},
{"id":"d721","front":"How would you describe Klippel-Trenaunay syndrome on MRI?","find":"Combined slow-flow malformation with limb (usually lower-extremity) overgrowth: extensive subcutaneous and intramuscular venous and lymphatic malformations (T2 hyperintense channels, phleboliths, fluid-fluid levels), a persistent lateral marginal (embryonic) vein, hypertrophy of bone and soft tissues, and overlying capillary malformation. No high-flow arteriovenous shunting.","impr":"Klippel-Trenaunay syndrome (capillary-lymphatic-venous malformation with limb overgrowth).","pearl":"Presence of arteriovenous shunting indicates Parkes-Weber syndrome (high-flow) rather than Klippel-Trenaunay.","topic":"Vascular","joint":"general"},
{"id":"d722","front":"How would you describe myositis ossificans on MRI?","find":"Intramuscular mass with zonal organization: in the early/active phase, an ill-defined T2-hyperintense central mass with extensive surrounding muscle and soft-tissue edema and heterogeneous enhancement, mimicking a tumor. As it matures, a peripheral rim of low-signal mineralization develops (zonal phenomenon, mature ossification at the periphery, immature center) with a low-signal ossified shell on all sequences. Lesion decreases in size and edema resolves over weeks.","impr":"Myositis ossificans (heterotopic ossification), maturing.","pearl":"The peripheral (centripetal) maturation pattern is opposite that of an osteosarcoma; correlate with serial radiographs/CT showing peripheral rim calcification.","topic":"Muscle","joint":"general"},
{"id":"d723","front":"How would you describe diabetic muscle infarction on MRI?","find":"Diffuse muscle enlargement and T2/STIR hyperintense edema involving one or more muscles (typically thigh/calf) in a long-standing diabetic, with intramuscular and perifascial/subcutaneous edema. Geographic non-enhancing necrotic areas with surrounding enhancement (rim or feathery), often with a serpentine non-enhancing central focus. No drainable abscess or gas.","impr":"Diabetic muscle infarction.","pearl":"Clinical context (poorly controlled diabetes, atraumatic painful swelling) and absence of a rim-enhancing pus collection distinguish it from pyomyositis.","topic":"Muscle","joint":"general"},
{"id":"d724","front":"How would you describe pyomyositis and intramuscular abscess on MRI?","find":"Enlarged muscle with diffuse T2-hyperintense edema (early phase), progressing to a rim-enhancing fluid collection that is T2 hyperintense centrally with restricted diffusion of the purulent contents and a thick enhancing wall. Surrounding myofascial edema and reactive subcutaneous changes. Foci of gas (signal void/blooming) may be present.","impr":"Pyomyositis with intramuscular abscess.","pearl":"Restricted diffusion and a thick rim-enhancing collection differentiate abscess from non-enhancing necrosis of muscle infarction or a cystic tumor.","topic":"Muscle","joint":"general"},
{"id":"d725","front":"How would you describe inflammatory myositis (dermatomyositis/polymyositis) on MRI?","find":"Symmetric, bilateral T2/STIR-hyperintense edema of proximal muscles with relative preservation of muscle bulk in the acute phase, perifascial and subcutaneous edema, and in dermatomyositis subcutaneous/fascial calcifications (low signal, blooming). Chronic disease shows fatty atrophy/replacement (T1 hyperintense) and decreased muscle volume. Patchy enhancement of active inflammation.","impr":"Active inflammatory myopathy (consistent with dermatomyositis/polymyositis).","pearl":"Symmetric proximal distribution with perifascial edema; chronic fatty infiltration indicates burnt-out disease and guides biopsy away from inactive sites.","topic":"Muscle","joint":"general"},
{"id":"d726","front":"How would you describe compartment syndrome on MRI?","find":"Tense enlargement of the involved fascial compartment with diffuse T2/STIR-hyperintense muscle edema, convex bulging of the compartment, and effacement of intermuscular fat planes. Necrotic muscle shows non-enhancement; perifascial fluid may be present. Fascia is taut/bowed outward.","impr":"Findings compatible with compartment syndrome.","pearl":"This is a clinical/compartment-pressure diagnosis; MRI is supportive (tense edematous compartment, non-enhancing necrosis), not definitive.","topic":"Muscle","joint":"general"},
{"id":"d727","front":"How would you describe a fascial herniation of muscle on MRI?","find":"Focal mushroom-shaped protrusion of muscle (commonly tibialis anterior/anterior compartment) through a defect in the overlying deep fascia, best seen with the muscle contracted/standing or on dynamic imaging, with a visible discontinuity of the low-signal fascial line and the herniated muscle isointense to its parent muscle.","impr":"Muscle (fascial) herniation through a deep fascial defect.","pearl":"May only be apparent with provocative/dynamic imaging or muscle contraction; the herniated portion follows normal muscle signal.","topic":"Muscle","joint":"general"},
{"id":"d728","front":"How would you describe an accessory soleus muscle on MRI?","find":"Well-defined accessory muscle anteromedial to the Achilles tendon within Kager fat pad, isointense to and paralleling normal skeletal muscle on all sequences, arising from the soleus/tibia and inserting on the calcaneus or Achilles. Fills/obliterates the pre-Achilles fat triangle. No abnormal signal unless symptomatic (edema with exertion).","impr":"Accessory soleus muscle.","pearl":"Muscle signal identical to normal muscle differentiates it from a soft-tissue mass occupying Kager fat; may cause exertional pain or pseudomass.","topic":"Muscle","joint":"ankle"},
{"id":"d729","front":"How would you describe an anconeus epitrochlearis on MRI?","find":"Accessory muscle bridging the medial epicondyle to the olecranon, replacing the normal Osborne fascial retinaculum and forming the roof of the cubital tunnel, isointense to muscle on all sequences. May compress the ulnar nerve, with associated nerve T2 hyperintensity/enlargement.","impr":"Anconeus epitrochlearis (accessory muscle), a cause of cubital tunnel syndrome.","pearl":"Distinguish from the normal arcuate ligament; this accessory muscle can compress the ulnar nerve, so assess for ulnar neuritis.","topic":"Muscle","joint":"elbow"},
{"id":"d730","front":"How would you describe acute versus chronic muscle denervation on MRI?","find":"Acute/subacute denervation: diffuse T2/STIR-hyperintense edema-like signal throughout the muscle(s) supplied by a single nerve, with preserved bulk and normal T1 signal. Chronic denervation: fatty atrophy with T1-hyperintense fatty infiltration and decreased muscle volume. The distribution follows a specific nerve territory.","impr":"Denervation change (acute edematous vs chronic fatty) in the [nerve] distribution.","pearl":"Nerve-territory distribution distinguishes denervation edema from myositis (which is multifocal/symmetric and not nerve-mapped).","topic":"Muscle","joint":"general"},
{"id":"d731","front":"How would you describe a muscle contusion on MRI?","find":"Ill-defined, feathery interstitial T2/STIR-hyperintense edema and hemorrhage within the muscle belly at the site of direct impact, often subfascial, without architectural disruption or a discrete gap. Edema crosses muscle planes superficially under the point of impact. No retraction or tendon involvement.","impr":"Muscle contusion.","pearl":"Contusion edema is at the impact site without fiber discontinuity, unlike a strain, which centers at the myotendinous junction with possible gap/retraction.","topic":"Muscle","joint":"general"},
{"id":"d732","front":"How would you describe a Morel-Lavallee lesion on MRI?","find":"Closed degloving fluid collection in the subcutaneous plane overlying the deep fascia (classically lateral thigh/greater trochanter or knee), fusiform/lenticular and elongated along the fascia, with variable signal depending on age of blood/lymph and chronicity. Mature lesions have a low-signal fibrous capsule, fluid-fluid levels, internal fat globules, and no significant central enhancement (only capsular).","impr":"Morel-Lavallee lesion (post-traumatic closed degloving collection).","pearl":"Mellado-Bencardino classification by signal/capsule; a thick capsule indicates chronicity and predicts need for surgical management over aspiration.","topic":"Soft tissue","joint":"general"},
{"id":"d733","front":"How would you describe a seroma on MRI?","find":"Well-circumscribed, simple fluid collection at a surgical/operative bed following the signal of fluid (T1 hypointense, T2 hyperintense) with a thin pseudocapsule, no internal solid nodularity, and only thin peripheral capsular enhancement. No restricted diffusion or thick irregular wall.","impr":"Postoperative seroma.","pearl":"Thin smooth wall and lack of restricted diffusion separate a seroma from an abscess (thick rim, restricted diffusion) or recurrent/residual tumor (enhancing nodularity).","topic":"Soft tissue","joint":"general"},
{"id":"d734","front":"How would you describe soft-tissue fat necrosis on MRI?","find":"Subcutaneous lesion centered in fat with a central focus that follows fat signal (T1/T2 hyperintense, suppresses on fat-sat) surrounded by a variable T2-hyperintense rim of edema/fibrosis and a low-signal capsule; chronic lesions show calcification (blooming) and decreasing edema. Mild rim enhancement only.","impr":"Fat necrosis.","pearl":"A central fat-signal core that suppresses with fat-sat is the key clue, preventing misdiagnosis as a malignant soft-tissue mass.","topic":"Soft tissue","joint":"general"},
{"id":"d735","front":"How would you describe a foreign body granuloma on MRI?","find":"Focal soft-tissue mass surrounding a low-signal foreign body (wood, glass, metal causing susceptibility/blooming), with a T2-hyperintense rim of granulation tissue and surrounding edema, and a rim of enhancement. Sinus tract or adjacent abscess may be present.","impr":"Foreign body granuloma.","pearl":"The central signal-void foreign body with surrounding inflammation is the clue; correlate with radiographs/CT for radiopaque material and history.","topic":"Soft tissue","joint":"general"},
{"id":"d736","front":"How would you describe an epidermal inclusion cyst on MRI?","find":"Well-defined subcutaneous/cutaneous cystic lesion that is T1 iso- to hyperintense and T2 hyperintense with heterogeneous keratin debris, often showing restricted diffusion, with thin wall enhancement only and no solid enhancing component. May rupture causing surrounding inflammatory change.","impr":"Epidermal inclusion cyst.","pearl":"Restricted diffusion from keratin can mimic abscess; the superficial dermal location and history of slow growth favor an inclusion cyst.","topic":"Soft tissue","joint":"general"},
{"id":"d737","front":"How would you describe a ganglion cyst versus a bursa on MRI?","find":"Ganglion: well-defined, lobulated, T1-hypointense and T2-markedly-hyperintense cyst with thin internal septations, arising adjacent to a joint or tendon sheath, frequently with a stalk/neck connecting to the joint, and thin peripheral enhancement only. A bursa is a thin-walled fluid collection at a constant anatomic location between tendons/bone, distending only when inflamed.","impr":"Ganglion cyst (vs distended bursa at an anatomic site).","pearl":"A communicating stalk to the joint and lobulated morphology favor a ganglion; a constant anatomic location favors a bursa.","topic":"Soft tissue","joint":"general"},
{"id":"d738","front":"How would you describe plantar fibromatosis on MRI?","find":"Ill-defined or nodular masses arising from the plantar aponeurosis, typically along the medial/central cord, that are T1 and T2 hypointense to isointense to muscle (reflecting dense collagen) with variable enhancement, blending superficially into the fascia. Lesions are infiltrative along the aponeurosis without bone destruction.","impr":"Plantar fibromatosis (Ledderhose disease).","pearl":"Low T2 signal reflects fibrous (collagenous) content; multiplicity and aponeurotic origin are characteristic, and lesions may be bilateral.","topic":"Soft tissue","joint":"foot"},
{"id":"d739","front":"How would you describe palmar fibromatosis on MRI?","find":"Nodular and cord-like soft-tissue thickening superficial to the flexor tendons along the palmar aponeurosis, predominantly ulnar-sided (ring/little fingers), with low to intermediate T1 and T2 signal from fibrous tissue and variable enhancement. Tethering of the overlying skin and digital flexion contracture in advanced disease.","impr":"Palmar fibromatosis (Dupuytren disease).","pearl":"Superficial palmar location and low T2 signal distinguish it from a flexor sheath tumor; often associated with plantar fibromatosis.","topic":"Soft tissue","joint":"hand"},
{"id":"d740","front":"How would you describe nodular fasciitis on MRI?","find":"Small (typically <3-4 cm), well-defined or mildly infiltrative soft-tissue mass arising along fascia, often with a fascial tail, T1 isointense to muscle and T2 iso- to hyperintense, with avid heterogeneous enhancement; rapid growth and superficial location (forearm common). May show a low-signal myxoid-to-cellular gradient.","impr":"Nodular fasciitis.","pearl":"A rapidly growing, painful small superficial mass with a fascial tail in a young adult; a self-limited benign lesion that mimics sarcoma.","topic":"Soft tissue","joint":"general"},
{"id":"d741","front":"How would you describe elastofibroma dorsi on MRI?","find":"Ill-defined, non-encapsulated soft-tissue mass deep to the inferomedial scapula between serratus anterior/latissimus and the chest wall, with a characteristic lamellated/striated pattern of soft-tissue signal interlaced with strands of entrapped fat (fat signal on all sequences). Minimal enhancement; frequently bilateral.","impr":"Elastofibroma dorsi.","pearl":"Characteristic subscapular location with interlacing fat strands and frequent bilaterality; no aggressive features, so no biopsy needed.","topic":"Soft tissue","joint":"shoulder"},
{"id":"d742","front":"How would you describe a lipoma versus a well-differentiated liposarcoma on MRI?","find":"Lipoma: homogeneous mass following subcutaneous fat signal on all sequences, suppressing completely on fat-sat, with no more than a few thin (<2 mm) septa, no nodular non-fatty tissue, and no enhancement. Features favoring atypical lipomatous tumor/well-differentiated liposarcoma: large size (>10 cm), thick (>2 mm) or nodular septa, prominent enhancing non-adipose nodular tissue, and <75% fat composition.","impr":"Lipoma (vs atypical lipomatous tumor/well-differentiated liposarcoma if aggressive features present).","pearl":"Thick/nodular septa, enhancing soft-tissue nodules, and large size raise concern for liposarcoma and warrant biopsy.","topic":"Soft tissue","joint":"general"},
{"id":"d743","front":"How would you describe a hibernoma on MRI?","find":"Well-defined mass of brown fat that is slightly hypointense to subcutaneous fat on T1 and intermediate-to-high on T2, with intervening low-signal septa, prominent serpentine internal flow voids (vascularity), and avid heterogeneous enhancement; does not fully suppress as cleanly as ordinary fat on fat-sat.","impr":"Hibernoma (benign brown-fat tumor).","pearl":"Marked internal vascularity and avid enhancement of a fat-containing mass that is not pure white fat suggest hibernoma over a simple lipoma.","topic":"Soft tissue","joint":"general"},
{"id":"d744","front":"How would you describe olecranon bursitis on MRI?","find":"Distended fluid collection in the subcutaneous bursa superficial to the olecranon process, T2 hyperintense with variable T1 signal, with wall thickening and synovial/rim enhancement if inflamed/infected; internal debris, septations, or rice bodies in chronic/inflammatory cases. Surrounding subcutaneous edema.","impr":"Olecranon bursitis.","pearl":"Thick irregular enhancing wall, internal debris, and restricted diffusion raise concern for septic bursitis.","topic":"Synovial","joint":"elbow"},
{"id":"d745","front":"How would you describe prepatellar bursitis on MRI?","find":"Distended fluid signal in the prepatellar subcutaneous bursa anterior to the patella, T2 hyperintense, with possible internal septations, debris, or hemorrhage and rim/synovial enhancement when inflamed. Associated subcutaneous soft-tissue edema (housemaid's knee).","impr":"Prepatellar bursitis.","pearl":"Look for thick enhancing wall and restricted diffusion suggesting septic bursitis, especially with overlying skin breakdown.","topic":"Synovial","joint":"knee"},
{"id":"d746","front":"How would you describe retrocalcaneal bursitis on MRI?","find":"Fluid distension of the retrocalcaneal bursa between the posterosuperior calcaneus (Haglund prominence) and the Achilles tendon, T2 hyperintense, often with adjacent Achilles tendinosis, calcaneal posterosuperior marrow edema, and a Haglund deformity. Wall enhancement when inflamed.","impr":"Retrocalcaneal bursitis (often with Haglund deformity).","pearl":"Part of the Haglund syndrome triad with insertional Achilles tendinosis and posterosuperior calcaneal prominence.","topic":"Synovial","joint":"ankle"},
{"id":"d747","front":"How would you describe trochanteric bursitis on MRI?","find":"T2-hyperintense fluid and edema in the peritrochanteric region within the subgluteus maximus/medius bursae lateral to the greater trochanter, with adjacent gluteus medius/minimus tendinopathy or tearing and reactive marrow edema. Variable rim enhancement.","impr":"Greater trochanteric pain syndrome with trochanteric bursitis and gluteal tendinopathy.","pearl":"Frequently coexists with gluteus medius/minimus tendinopathy (the rotator cuff of the hip); assess the tendons, not just the bursa.","topic":"Synovial","joint":"hip"},
{"id":"d748","front":"How would you describe iliopsoas bursitis on MRI?","find":"Distended fluid collection along the iliopsoas tendon anterior to the hip joint, conforming to a teardrop/comma shape that extends cephalad along the iliopsoas muscle, T2 hyperintense, often communicating with the hip joint through a defect in the anterior capsule. Mass effect on adjacent femoral vessels possible.","impr":"Iliopsoas bursitis.","pearl":"Communication with the hip joint (in ~15%) means an underlying hip arthropathy/effusion may be the source; evaluate the joint.","topic":"Synovial","joint":"hip"},
{"id":"d749","front":"How would you describe an adventitial bursa on MRI?","find":"An acquired (non-anatomic) fluid collection that develops at sites of chronic friction or pressure (e.g., over a bunion, amputation stump, or bony prominence), T2 hyperintense with a thin wall, no epithelial lining, located within subcutaneous tissues at the friction point.","impr":"Adventitial (adventitious) bursa from chronic friction.","pearl":"Unlike a true bursa, it has no constant anatomic location and forms secondary to repetitive mechanical stress.","topic":"Synovial","joint":"general"},
{"id":"d750","front":"How would you describe synovial chondromatosis on MRI?","find":"Multiple similar-sized intra-articular bodies within a distended joint, classically isointense to muscle with low-signal foci when calcified/ossified; ossified bodies contain central fatty marrow (T1 hyperintense) with a low-signal rim, while non-calcified cartilaginous bodies are T2 hyperintense. Lobulated synovial proliferation may erode adjacent bone (pressure erosions).","impr":"Primary synovial (osteo)chondromatosis.","pearl":"Multiple uniformly sized loose bodies distinguish primary synovial chondromatosis from a few variably sized osteochondral fragments in secondary OA.","topic":"Synovial","joint":"general"},
{"id":"d751","front":"How would you describe lipoma arborescens on MRI?","find":"Frond-like, villous synovial proliferation with the fronds following fat signal on all sequences (T1 hyperintense, suppressing on fat-sat), arising from the synovium and projecting into a joint effusion (classically the suprapatellar recess of the knee). No enhancement of the fatty fronds. Associated effusion and underlying degenerative joint disease.","impr":"Lipoma arborescens.","pearl":"Fat-suppression confirms the frondlike fatty synovium; typically a reactive process associated with chronic arthropathy.","topic":"Synovial","joint":"knee"},
{"id":"d752","front":"How would you describe amyloid arthropathy on MRI?","find":"Bilateral, symmetric soft-tissue and synovial deposits that are characteristically LOW signal on both T1 and T2 (intermediate-to-low), filling and distending the joint with preserved bone density, periarticular and subchondral cystic erosions, and relatively mild enhancement. Common in dialysis patients (shoulders, hips, wrists).","impr":"Amyloid (dialysis-related/beta-2-microglobulin) arthropathy.","pearl":"Low T2 signal of the synovial deposits with multiple subchondral cysts in a chronic dialysis patient is the clue; mimics infection or PVNS.","topic":"Synovial","joint":"general"},
{"id":"d753","front":"How would you describe hemophilic arthropathy on MRI?","find":"Joint with low-signal (blooming on GRE) hemosiderin-laden synovial hypertrophy from recurrent hemarthrosis, dark on T1 and T2, with effusion, cartilage loss, subchondral cysts/erosions, and epiphyseal overgrowth/squaring (e.g., widened intercondylar notch). Susceptibility blooming reflects iron deposition.","impr":"Hemophilic arthropathy.","pearl":"Blooming hemosiderin resembles PVNS, but hemophilic arthropathy is bilateral/polyarticular with characteristic epiphyseal changes and clinical history.","topic":"Synovial","joint":"general"},
{"id":"d754","front":"How would you describe diffuse tenosynovial giant cell tumor (PVNS) on MRI?","find":"Lobulated, frond-like synovial proliferative mass distending the joint with characteristic low T1 and low T2 signal and prominent blooming/susceptibility artifact on GRE from hemosiderin, with hemorrhagic effusion, pressure erosions on both sides of the joint, and heterogeneous enhancement of the solid synovial component.","impr":"Diffuse-type tenosynovial giant cell tumor (pigmented villonodular synovitis).","pearl":"Blooming on gradient-echo from hemosiderin is the hallmark; the localized (nodular) form is a focal mass, often in the knee (Hoffa fat pad) or along a tendon sheath.","topic":"Synovial","joint":"general"},
{"id":"d755","front":"How would you describe a sublabral recess (and distinguish it from a SLAP tear)?","find":"At the superior labral-biceps anchor there is a smooth, linear high-signal cleft oriented medially (toward the head) and paralleling the glenoid articular surface, measuring <2 mm, without lateral or posterior extension and without contrast extension on arthrography.","impr":"Sublabral recess (normal superior labral variant); no SLAP tear.","pearl":"A recess is smooth, <2 mm, medially oriented and follows the glenoid contour; a SLAP tear is irregular, >2-3 mm wide, laterally/posteriorly directed, and often shows a paralabral cyst.","topic":"Variant/pitfall","joint":"shoulder"},
{"id":"d756","front":"How would you describe the normal biceps-labral sulcus?","find":"A shallow, smooth recess of fluid signal is seen between the superior labrum and the glenoid articular cartilage at the biceps anchor, <1-2 mm, oriented parallel to the glenoid and without extension into the labral substance.","impr":"Normal biceps-labral sulcus; no superior labral tear.","topic":"Variant/pitfall","joint":"shoulder"},
{"id":"d757","front":"How would you describe an os acromiale?","find":"There is an unfused accessory acromial ossification center (most commonly the meso-acromion) with a smooth, corticated synchondrosis oriented in the axial/coronal plane, best seen on axial images, without marrow edema across the cleft.","impr":"Os acromiale (unfused acromial apophysis); a normal variant that may contribute to impingement.","pearl":"A corticated, smooth cleft on axial images at the expected synchondrosis distinguishes os acromiale from an acromial fracture, which has sharp noncorticated margins and surrounding marrow edema.","topic":"Variant/pitfall","joint":"shoulder"},
{"id":"d758","front":"How would you describe the rotator cable (and avoid calling it a tear)?","find":"A low-signal band coursing perpendicular to the supraspinatus and infraspinatus fibers is seen on coronal images near the articular footprint, representing the thickened reflection of the coracohumeral ligament, with intact overlying tendon.","impr":"Normal rotator cable; no rotator cuff tear.","pearl":"The cable is a smooth low-signal band oriented perpendicular to the cuff fibers with intact tendon on both sides; a tear shows fluid signal traversing the tendon with fiber discontinuity.","topic":"Variant/pitfall","joint":"shoulder"},
{"id":"d759","front":"How would you describe a meniscal flounce?","find":"There is a smooth, single, wave-like undulation of the free edge of the medial meniscus on a sagittal image, with normal internal meniscal signal and no surface-reaching line.","impr":"Meniscal flounce, a normal variant of meniscal morphology; no meniscal tear.","pearl":"A flounce is a smooth single fold with normal internal signal and is highly specific for an intact meniscus; a tear shows surface-reaching high signal or displaced fragment.","topic":"Variant/pitfall","joint":"knee"},
{"id":"d760","front":"How would you describe a transverse (intermeniscal) ligament pseudotear at the anterior horn?","find":"At the junction of the transverse intermeniscal ligament and the anterior horn of the lateral (or medial) meniscus there is an oblique linear high signal that follows the expected course of the ligament insertion, without surface-reaching extension on adjacent images.","impr":"Pseudotear from the transverse intermeniscal ligament insertion; no true anterior horn tear.","pearl":"Trace the linear signal to the cord-like transverse ligament on sequential sagittal images; a real tear does not connect to the ligament and reaches the meniscal surface.","topic":"Variant/pitfall","joint":"knee"},
{"id":"d761","front":"How would you describe a popliteus hiatus pseudotear?","find":"At the posterior horn of the lateral meniscus there is high signal at the popliteomeniscal fascicles and popliteus tendon hiatus, oriented obliquely and following the expected course of the popliteus tendon sheath, without a displaced fragment.","impr":"Popliteus hiatus pseudotear; no posterior horn tear.","pearl":"Fluid in the popliteus hiatus and the obliquely oriented fascicles mimic a tear; a true tear is vertically/horizontally oriented and reaches the meniscal surface away from the hiatus.","topic":"Variant/pitfall","joint":"knee"},
{"id":"d762","front":"How would you describe an oblique meniscomeniscal ligament (and the pseudotear it creates)?","find":"A linear low-signal band traverses the intercondylar notch between the anterior horn of one meniscus and the posterior horn of the contralateral meniscus, mimicking a flipped meniscal fragment or a displaced ACL-region structure on sagittal images.","impr":"Oblique meniscomeniscal ligament, a normal variant; the menisci are otherwise intact.","pearl":"The band is smooth and crosses the notch between opposite horns; both menisci should be morphologically intact, distinguishing it from a displaced bucket-handle fragment.","topic":"Variant/pitfall","joint":"knee"},
{"id":"d763","front":"How would you describe a normal meniscofemoral ligament (Wrisberg/Humphrey) and avoid calling it a tear?","find":"A discrete low-signal band arises from the posterior horn of the lateral meniscus and courses to the medial femoral condyle, passing posterior (ligament of Wrisberg) or anterior (ligament of Humphrey) to the PCL, with adjacent fluid creating a pseudotear at its meniscal origin.","impr":"Normal meniscofemoral ligament; pseudotear at the posterior horn lateral meniscus attachment, not a true tear.","pearl":"Follow the ligament to its femoral attachment; the high signal at the meniscal origin is a pseudotear, whereas a real tear extends into the meniscal body away from the ligament.","topic":"Variant/pitfall","joint":"knee"},
{"id":"d764","front":"How would you describe the magic angle effect in the patellar tendon?","find":"On short-TE sequences (T1/PD/GRE) there is intermediate signal in the proximal patellar tendon where its fibers approach 55 degrees to the main magnetic field, which resolves (becomes low signal) on the long-TE T2-weighted images.","impr":"Magic angle artifact in the patellar tendon; no tendinosis or tear.","pearl":"Magic angle signal appears only on short-TE sequences and disappears on T2; true tendinopathy persists as intermediate-to-high signal on long-TE images with tendon thickening.","topic":"Variant/pitfall","joint":"knee"},
{"id":"d765","front":"How would you describe a vacuum phenomenon in the knee joint?","find":"There is a focus of signal void (gas) within the joint, typically along the tibiofemoral articulation or within the menisci, with associated blooming on gradient-echo images and no fluid signal.","impr":"Vacuum phenomenon (intra-articular gas), a benign degenerative/positional finding.","pearl":"Gas blooms on GRE and is signal-void on all sequences, distinguishing it from a loose body (which has marrow/cartilage signal) or fluid.","topic":"Variant/pitfall","joint":"knee"},
{"id":"d766","front":"How would you describe a normal infrapatellar (ligamentum mucosum) plica?","find":"A thin linear low-signal band extends from the intercondylar notch through Hoffa fat pad toward the inferior pole of the patella on sagittal images, of uniform thickness and without surrounding edema.","impr":"Normal infrapatellar plica (ligamentum mucosum); not an ACL tear fragment or loose body.","pearl":"The plica is a smooth midline band in Hoffa fat; do not mistake it for a torn ACL bundle or an intra-articular body.","topic":"Variant/pitfall","joint":"knee"},
{"id":"d767","front":"How would you describe a normal acetabular sublabral sulcus?","find":"There is a smooth, shallow cleft of fluid/contrast signal between the acetabular labrum and the articular cartilage, typically posteroinferior or anterosuperior, paralleling the labral base without extending into the labral substance.","impr":"Sublabral sulcus, a normal acetabular labral variant; no labral tear.","pearl":"A sulcus is smooth, shallow, and follows the cartilage-labral junction without intrasubstance signal; a true tear extends into or detaches the labrum and is often anterosuperior with a paralabral cyst.","topic":"Variant/pitfall","joint":"hip"},
{"id":"d768","front":"How would you describe a stellate lesion / supra-acetabular fossa?","find":"At the acetabular dome (superomedial, weight-bearing zone) there is a focal cartilage-covered bare area without subchondral cartilage, of geographic configuration, without subchondral edema or aggressive features.","impr":"Stellate lesion / supra-acetabular fossa, a normal cartilage variant of the acetabular dome; not a chondral defect.","pearl":"Its constant superomedial location and absence of subchondral marrow edema distinguish it from a true chondral lesion or osteoarthritic defect.","topic":"Variant/pitfall","joint":"hip"},
{"id":"d769","front":"How would you describe an os acetabuli?","find":"There is a well-corticated ossicle along the anterosuperior acetabular rim with smooth margins and no surrounding marrow edema, representing an unfused secondary ossification center or a chronic rim apophysis.","impr":"Os acetabuli (acetabular rim ossicle), a developmental variant; no acute rim fracture.","pearl":"Smooth corticated margins favor os acetabuli; sharp noncorticated margins with edema suggest an acute rim fracture, and it may be associated with pincer-type FAI.","topic":"Variant/pitfall","joint":"hip"},
{"id":"d770","front":"How would you describe a herniation pit (fibrocystic change) of the femoral neck?","find":"There is a small well-defined round subcortical lucency at the anterosuperior femoral neck, T2-hyperintense with a thin sclerotic/low-signal rim, measuring <1 cm, without aggressive features.","impr":"Herniation pit (synovial herniation/fibrocystic change) of the femoral neck, a benign finding; may be associated with cam-type FAI.","pearl":"Characteristic anterosuperior femoral neck location, small size, and thin rim distinguish it from an infection or aggressive lesion.","topic":"Variant/pitfall","joint":"hip"},
{"id":"d771","front":"How would you describe an os trigonum (and distinguish it from a fracture)?","find":"There is a well-corticated ossicle posterior to the lateral talar tubercle separated by a smooth synchondrosis, without marrow edema across the cleft, on sagittal images.","impr":"Os trigonum, an accessory ossicle; no acute fracture.","pearl":"Smooth corticated margins indicate os trigonum; a Shepherd fracture of the lateral tubercle has sharp noncorticated margins with marrow edema, and synchondrosis edema indicates symptomatic os trigonum syndrome.","topic":"Variant/pitfall","joint":"ankle"},
{"id":"d772","front":"How would you describe an accessory navicular?","find":"There is an accessory ossicle at the medial navicular tuberosity (type II) joined by a fibrocartilaginous synchondrosis at the posterior tibialis tendon insertion, without marrow edema in the asymptomatic state.","impr":"Accessory navicular (type II), an anatomic variant; posterior tibialis tendon insertion intact.","pearl":"Marrow edema across the synchondrosis and the adjacent navicular indicates a symptomatic accessory navicular; without edema it is an incidental variant.","topic":"Variant/pitfall","joint":"ankle"},
{"id":"d773","front":"How would you describe a peroneus quartus muscle?","find":"There is an accessory muscle in the lateral compartment posterior to the peroneus brevis and longus, with normal muscle signal, typically inserting on the retrotrochlear eminence of the calcaneus.","impr":"Peroneus quartus, an accessory muscle (normal variant); not a longitudinal split tear of peroneus brevis.","pearl":"A discrete separate muscle belly with its own tendon distinguishes peroneus quartus from a longitudinal split of peroneus brevis, which shows a chevron/boomerang-shaped tendon.","topic":"Variant/pitfall","joint":"ankle"},
{"id":"d774","front":"How would you describe an os peroneum?","find":"There is a corticated ossicle within the peroneus longus tendon at the level of the cuboid (plantar/lateral midfoot), with smooth margins and intact surrounding tendon.","impr":"Os peroneum, a sesamoid within the peroneus longus tendon; a normal variant.","pearl":"Proximal migration or a gap of the os peroneum suggests peroneus longus rupture (painful os peroneum syndrome); a smooth ossicle in normal position is incidental.","topic":"Variant/pitfall","joint":"ankle"},
{"id":"d775","front":"How would you describe a low-lying / normal flexor hallucis longus muscle belly?","find":"The flexor hallucis longus muscle belly extends distally to or below the level of the tibiotalar joint behind the medial malleolus, with normal muscle signal and an intact tendon within its sheath.","impr":"Low-lying flexor hallucis longus muscle belly, an anatomic variant; not a soft-tissue mass.","pearl":"Normal striated muscle signal continuous with the FHL distinguishes a low-lying belly from a posteromedial soft-tissue mass or os trigonum syndrome edema.","topic":"Variant/pitfall","joint":"ankle"},
{"id":"d776","front":"How would you describe the pseudodefect of the talar dome?","find":"At the posteromedial or posterolateral talar dome there is an apparent abrupt step-off or notch where the articular cartilage transitions to the nonarticular surface, with smooth corticated margins and no subchondral edema.","impr":"Pseudodefect of the talar dome, a normal anatomic transition; no osteochondral lesion.","pearl":"Its constant posterior location at the cartilage-bone transition and absence of subchondral marrow edema distinguish it from a true osteochondral lesion.","topic":"Variant/pitfall","joint":"ankle"},
{"id":"d777","front":"How would you describe an os styloideum (carpe bossu)?","find":"There is an accessory ossicle or bony prominence at the dorsal base of the second/third metacarpals and the capitate/trapezoid, corticated and smooth, on sagittal images of the dorsal wrist.","impr":"Os styloideum (carpal boss), a normal dorsal carpal variant; no fracture or aggressive lesion.","pearl":"Corticated smooth margins at the CMC junction distinguish carpal boss from a dorsal avulsion fracture or osteophyte with overlying ganglion.","topic":"Variant/pitfall","joint":"wrist"},
{"id":"d778","front":"How would you describe the pseudodefect of the capitellum?","find":"At the posterolateral aspect of the capitellum, at the junction of the articular capitellum and the nonarticular lateral epicondyle, there is a normal groove/notch with smooth corticated margins and no subchondral edema, seen on sagittal images.","impr":"Pseudodefect of the capitellum, a normal anatomic transition; no osteochondral lesion or osteochondritis dissecans.","pearl":"Located posterolaterally at the articular/nonarticular junction with intact cartilage and no marrow edema; osteochondral lesions and OCD are anterocentral with subchondral edema.","topic":"Variant/pitfall","joint":"elbow"},
{"id":"d779","front":"How would you describe the normal trochlear (transverse) groove of the elbow?","find":"There is a smooth transverse low-signal groove across the trochlea separating the capitellotrochlear sulcus regions, with intact overlying cartilage, seen on coronal images.","impr":"Normal trochlear groove, an anatomic variant; not a chondral fissure or osteophyte.","pearl":"A smooth symmetric transverse groove with intact cartilage is normal; a chondral defect shows cartilage loss and subchondral edema.","topic":"Variant/pitfall","joint":"elbow"},
{"id":"d780","front":"How would you describe physiologic ulnar variance and avoid overcalling impaction?","find":"The distal ulnar articular surface is within approximately 2 mm of the distal radius (neutral to slightly positive/negative variance), with normal lunate and TFCC signal and no subchondral marrow edema.","impr":"Physiologic ulnar variance; no ulnar impaction (abutment) syndrome.","pearl":"Ulnar variance alone is not pathologic; ulnar impaction requires positive variance PLUS subchondral edema/cysts at the ulnar lunate and a central TFCC perforation.","topic":"Variant/pitfall","joint":"wrist"},
{"id":"d781","front":"How would you describe a lunotriquetral coalition?","find":"There is osseous or fibrocartilaginous fusion between the lunate and triquetrum with a smooth contour and no marrow edema, most commonly a complete osseous bridge (Minnaar type), an incidental finding.","impr":"Lunotriquetral coalition, a congenital carpal fusion variant; not a fracture or instability.","pearl":"Smooth confluent contour without edema indicates coalition; a fracture shows a sharp lucent line with marrow edema, and the LT interval should not be mistaken for ligament disruption.","topic":"Variant/pitfall","joint":"wrist"},
{"id":"d782","front":"How would you describe normal red (hematopoietic) marrow and avoid calling it a lesion?","find":"There is symmetric, ill-defined intermediate marrow signal in the metaphyses (e.g., proximal femur/humerus) that is hyperintense to muscle but hypointense to fat on T1, isointense to muscle, with no focal mass, and which suppresses incompletely but preserves interspersed fatty signal.","impr":"Normal residual/reconverted red marrow; no marrow-replacing lesion.","pearl":"Red marrow remains brighter than skeletal muscle and intervertebral disc on T1 and spares epiphyses/apophyses; signal that is darker than muscle/disc or focal is suspicious for a true lesion.","topic":"Variant/pitfall","joint":"general"},
{"id":"d783","front":"How would you describe a Schmorl node and indicate it is usually incidental?","find":"There is a focal endplate depression with herniation of disc material into the adjacent vertebral body, with a thin sclerotic/low-signal rim and no soft-tissue mass; acute nodes may show surrounding marrow edema.","impr":"Schmorl node (intravertebral disc herniation), typically an incidental degenerative finding.","pearl":"A corticated rim and absence of a soft-tissue component indicate a benign Schmorl node; an edematous acute node can be painful but should not be mistaken for a metastasis or infection.","topic":"Variant/pitfall","joint":"spine"},
{"id":"d784","front":"How would you describe a normal nutrient vessel/canal in bone?","find":"There is a thin linear low-signal channel traversing the cortex obliquely into the medullary cavity with a smooth corticated margin, without surrounding marrow edema or periosteal reaction.","impr":"Normal nutrient canal; not a fracture line.","pearl":"A nutrient canal is smooth, obliquely oriented, corticated, and lacks marrow edema; a nondisplaced fracture shows surrounding edema and is oriented perpendicular to the trabeculae.","topic":"Variant/pitfall","joint":"general"},
{"id":"d785","front":"How would you describe a physeal scar (physeal line) and avoid calling it a fracture?","find":"There is a thin, undulating low-signal line at the site of the former growth plate (e.g., metaphyseal-epiphyseal junction), of uniform thickness, without marrow edema or cortical disruption.","impr":"Normal physeal scar (residual growth plate); no fracture.","pearl":"A physeal scar is a smooth, undulating line in the expected metaphyseal location without edema; a fracture is associated with marrow edema and cortical break.","topic":"Variant/pitfall","joint":"general"},
{"id":"d786","front":"How would you describe chemical shift artifact at a bone-fat interface and avoid misinterpreting it?","find":"Along the frequency-encoding direction at fat-water interfaces (e.g., vertebral endplate, bone-marrow margins) there is a black/bright band that shifts with phase-encode/frequency direction and is absent on fat-suppressed sequences.","impr":"Chemical shift artifact (type 1); not a true endplate lesion or marrow abnormality.","pearl":"The artifact follows the frequency-encoding direction and disappears with swapped direction or fat suppression; a real lesion is independent of acquisition geometry.","topic":"Variant/pitfall","joint":"general"},
{"id":"d787","front":"How would you describe the magic angle effect in a tendon (general principle)?","find":"On short-TE sequences (T1, PD, GRE) there is intermediate signal within a tendon segment oriented near 55 degrees to the main magnetic field (e.g., supraspinatus critical zone, peroneal/posterior tibial tendons at the malleolus), which normalizes on long-TE T2 images.","impr":"Magic angle artifact; no tendinosis or tear.","pearl":"Signal present only on short-TE and absent on T2, with normal tendon caliber, confirms magic angle; persistent T2 signal with thickening indicates true tendinopathy.","topic":"Variant/pitfall","joint":"general"},
{"id":"d788","front":"How would you describe a partial volume averaging pseudolesion?","find":"At the margin of a curved structure or at a slice edge there is apparent intermediate signal or an apparent defect (e.g., meniscus, labrum, cartilage) on a single image that does not persist or reconstruct on adjacent thin slices or the orthogonal plane.","impr":"Partial volume averaging artifact; no true structural defect.","pearl":"A finding seen on only one slice that does not corroborate on adjacent images or the orthogonal plane is partial volume artifact, not a real tear or defect.","topic":"Variant/pitfall","joint":"general"},
{"id":"d789","front":"How would you describe a Stieda process (and distinguish it from an os trigonum)?","find":"There is an elongated bony projection extending posteriorly from the lateral talar tubercle in continuity with the talus (no separating synchondrosis), with smooth corticated margins, on sagittal images.","impr":"Stieda process, an elongated lateral talar tubercle (normal variant); not a separate ossicle or fracture.","pearl":"A Stieda process is continuous with the talus, whereas an os trigonum is separated by a synchondrosis; both can cause posterior impingement when enlarged.","topic":"Variant/pitfall","joint":"ankle"},
{"id":"d790","front":"How would you describe a discoid lateral meniscus and avoid overcalling a tear?","find":"The lateral meniscus shows abnormal enlargement with continuous bow-tie morphology on 3 or more consecutive 4-5 mm sagittal slices and increased transverse width on coronal images, with normal internal signal.","impr":"Discoid lateral meniscus, a morphologic variant; no tear in the absence of surface-reaching signal.","pearl":"A complete bow-tie on 3+ slices defines discoid morphology; do not overcall the increased intrasubstance signal common in discoid menisci as a tear unless it reaches the surface.","topic":"Variant/pitfall","joint":"knee"},
{"id":"d791","front":"How would you describe a pseudo-subluxation or speckled appearance of intra-articular gas mimicking loose bodies?","find":"There are multiple small signal-void foci within the joint that bloom on gradient-echo sequences and are uniformly dark on all pulse sequences, conforming to dependent or nondependent gas pockets.","impr":"Intra-articular vacuum gas; not osteochondral loose bodies.","pearl":"Gas blooms and is uniformly signal-void; loose bodies contain marrow fat or cartilage signal and do not bloom on GRE.","topic":"Variant/pitfall","joint":"general"},
{"id":"d792","front":"How would you describe a normal ACL?","find":"The ACL is intact and demonstrates uniformly low T2 signal with taut, parallel fibers oriented parallel to Blumensaat line, normal anteroposterior thickness, and a normal acute insertion angle without intrasubstance edema.","impr":"Normal, intact ACL.","pearl":"Normal ACL fibers parallel Blumensaat line; mild striated signal can be normal due to intervening fat between bundles.","topic":"Normal","joint":"knee"},
{"id":"d793","front":"How would you describe a normal PCL?","find":"The PCL is intact with uniformly low signal on all sequences, a smooth gentle posterior arcuate (hockey-stick) contour, normal thickness < 7 mm, and continuous fibers from femoral to tibial attachments.","impr":"Normal, intact PCL.","pearl":"The PCL is the strongest knee ligament and is normally thicker and darker than the ACL.","topic":"Normal","joint":"knee"},
{"id":"d794","front":"How would you describe a normal medial meniscus?","find":"The medial meniscus is normal in size and morphology with a uniformly low-signal triangular configuration, smooth surfaces, and no signal extending to an articular surface to indicate a tear.","impr":"Normal medial meniscus, no tear.","pearl":"A tear requires intrameniscal signal that unequivocally contacts a meniscal surface on a fluid-sensitive sequence.","topic":"Normal","joint":"knee"},
{"id":"d795","front":"How would you describe a normal lateral meniscus?","find":"The lateral meniscus is normal in morphology and signal with intact anterior and posterior horns, a normal popliteomeniscal fascicle relationship to the popliteus tendon, and no surface-extending signal.","impr":"Normal lateral meniscus, no tear.","topic":"Normal","joint":"knee"},
{"id":"d796","front":"How would you describe normal knee articular cartilage?","find":"The articular cartilage along the patellofemoral, medial, and lateral compartments is of normal thickness with a smooth surface, normal intermediate signal, and no fissuring, focal thinning, or subchondral signal abnormality.","impr":"Normal articular cartilage.","topic":"Normal","joint":"knee"},
{"id":"d797","front":"How would you describe a normal extensor mechanism (knee)?","find":"The quadriceps and patellar tendons are intact with normal low signal, normal thickness, and smooth fibers continuous to their patellar attachments, and the patella is normally positioned with a normal Insall-Salvati ratio.","impr":"Intact extensor mechanism.","topic":"Normal","joint":"knee"},
{"id":"d798","front":"How would you describe normal knee bone marrow?","find":"The osseous structures demonstrate normal marrow signal with the expected age-appropriate fatty conversion, no marrow edema, contusion, or replacing lesion, and normal trabecular and cortical architecture.","impr":"Normal marrow signal.","pearl":"Hematopoietic (red) marrow in the metaphyses is a normal finding in adults and should not be mistaken for infiltration.","topic":"Normal","joint":"knee"},
{"id":"d799","front":"How would you describe a normal supraspinatus tendon?","find":"The supraspinatus tendon is intact with uniformly low signal, normal thickness, and a smooth footprint insertion on the greater tuberosity, without tendinosis, partial- or full-thickness tear, or retraction.","impr":"Intact supraspinatus tendon.","topic":"Normal","joint":"shoulder"},
{"id":"d800","front":"How would you describe a normal rotator cuff?","find":"The rotator cuff is intact with the supraspinatus, infraspinatus, subscapularis, and teres minor tendons demonstrating normal low signal and morphology and intact footprint insertions, with normal muscle bulk and no fatty atrophy.","impr":"Intact rotator cuff.","topic":"Normal","joint":"shoulder"},
{"id":"d801","front":"How would you describe a normal glenoid labrum?","find":"The glenoid labrum is intact and uniformly low in signal with a normal triangular morphology and smooth attachment to the glenoid rim circumferentially, without surface-extending signal or detachment.","impr":"Intact glenoid labrum.","pearl":"A sublabral foramen and Buford complex are normal anterosuperior variants that should not be called a tear.","topic":"Normal","joint":"shoulder"},
{"id":"d802","front":"How would you describe a normal biceps tendon (long head)?","find":"The long head of the biceps tendon is intact with normal low signal and caliber, located normally within the bicipital groove, and the biceps anchor and superior labrum are intact.","impr":"Normal long head biceps tendon, normally located.","topic":"Normal","joint":"shoulder"},
{"id":"d803","front":"How would you describe a normal AC joint?","find":"The acromioclavicular joint is normally aligned with preserved joint space, no capsular hypertrophy or osteophytes, no subacromial spurring, and no fluid or marrow edema to suggest osteoarthritis.","impr":"Normal acromioclavicular joint.","topic":"Normal","joint":"shoulder"},
{"id":"d804","front":"How would you describe a normal hip labrum?","find":"The acetabular labrum is intact with a normal triangular low-signal morphology and smooth chondrolabral junction circumferentially, without surface-extending signal, paralabral cyst, or detachment.","impr":"Intact acetabular labrum.","topic":"Normal","joint":"hip"},
{"id":"d805","front":"How would you describe normal hip articular cartilage?","find":"The acetabular and femoral head articular cartilage is of normal thickness and signal with a smooth surface and no focal chondral defect, delamination, or subchondral cyst.","impr":"Normal hip articular cartilage.","topic":"Normal","joint":"hip"},
{"id":"d806","front":"How would you describe a normal femoral head-neck offset?","find":"The femoral head-neck junction demonstrates a normal concave anterolateral contour with a normal alpha angle and preserved head-neck offset, without an osseous bump to suggest cam morphology.","impr":"Normal femoral head-neck offset, no cam deformity.","pearl":"An alpha angle greater than 55 degrees suggests cam-type FAI.","topic":"Normal","joint":"hip"},
{"id":"d807","front":"How would you describe normal hip bone marrow?","find":"The proximal femora and acetabula demonstrate normal age-appropriate marrow signal without edema, fracture, avascular necrosis, or replacing lesion.","impr":"Normal hip marrow signal.","topic":"Normal","joint":"hip"},
{"id":"d808","front":"How would you describe a normal ATFL?","find":"The anterior talofibular ligament is intact, demonstrated as a thin uniformly low-signal band coursing from the anterior fibula to the talus with no thickening, discontinuity, or surrounding edema.","impr":"Intact ATFL.","topic":"Normal","joint":"ankle"},
{"id":"d809","front":"How would you describe a normal CFL?","find":"The calcaneofibular ligament is intact as a thin low-signal band extending from the fibular tip to the lateral calcaneus deep to the peroneal tendons, without thickening, discontinuity, or adjacent edema.","impr":"Intact CFL.","topic":"Normal","joint":"ankle"},
{"id":"d810","front":"How would you describe a normal Achilles tendon?","find":"The Achilles tendon is intact with uniformly low signal, a normal flat or concave anterior margin, normal anteroposterior thickness < 7 mm, and no intrasubstance signal, fusiform thickening, or peritendinous edema.","impr":"Normal, intact Achilles tendon.","topic":"Normal","joint":"ankle"},
{"id":"d811","front":"How would you describe a normal posterior tibial tendon?","find":"The posterior tibial tendon is intact with uniformly low signal and normal caliber, coursing normally posterior to the medial malleolus to its navicular insertion, without tendinosis, split, or tenosynovial fluid.","impr":"Normal posterior tibial tendon.","topic":"Normal","joint":"ankle"},
{"id":"d812","front":"How would you describe normal peroneal tendons?","find":"The peroneus longus and brevis tendons are intact with normal low signal and caliber, normally positioned within the retromalleolar groove behind an intact superior peroneal retinaculum, without split, subluxation, or tenosynovitis.","impr":"Normal peroneal tendons.","topic":"Normal","joint":"ankle"},
{"id":"d813","front":"How would you describe a normal plantar fascia?","find":"The plantar fascia is intact with uniformly low signal and normal thickness < 4 mm at the calcaneal origin, without fusiform thickening, intrasubstance signal, or perifascial edema.","impr":"Normal plantar fascia.","topic":"Normal","joint":"foot"},
{"id":"d814","front":"How would you describe a normal talar dome?","find":"The talar dome demonstrates a smooth intact articular surface with normal overlying cartilage and normal subchondral marrow signal, without osteochondral defect, cyst, or edema.","impr":"Normal talar dome.","topic":"Normal","joint":"ankle"},
{"id":"d815","front":"How would you describe a normal elbow UCL?","find":"The ulnar (medial) collateral ligament is intact, with the anterior bundle seen as a uniformly low-signal band from the medial epicondyle to the sublime tubercle, without thickening, surface irregularity, or undersurface detachment.","impr":"Intact ulnar collateral ligament.","topic":"Normal","joint":"elbow"},
{"id":"d816","front":"How would you describe a normal elbow LUCL?","find":"The lateral ulnar collateral ligament is intact as a low-signal band from the lateral epicondyle to the supinator crest of the ulna, without thickening or discontinuity, and the common extensor origin is intact.","impr":"Intact lateral ulnar collateral ligament.","topic":"Normal","joint":"elbow"},
{"id":"d817","front":"How would you describe a normal common extensor tendon?","find":"The common extensor tendon origin at the lateral epicondyle is intact with uniformly low signal and normal thickness, without tendinosis, partial tearing, or peritendinous edema.","impr":"Normal common extensor origin.","topic":"Normal","joint":"elbow"},
{"id":"d818","front":"How would you describe a normal TFCC?","find":"The triangular fibrocartilage complex is intact with a uniformly low-signal articular disc, smooth surfaces, and intact radial and ulnar (foveal) attachments, without perforation or surface-extending signal.","impr":"Intact triangular fibrocartilage complex.","topic":"Normal","joint":"wrist"},
{"id":"d819","front":"How would you describe a normal scapholunate ligament?","find":"The scapholunate interosseous ligament is intact with a normal low-signal triangular dorsal band, maintained scapholunate interval, and normal carpal alignment without dynamic or static instability.","impr":"Intact scapholunate ligament.","pearl":"The dorsal band is the strongest and most important component for stability.","topic":"Normal","joint":"wrist"},
{"id":"d820","front":"How would you describe normal flexor pulleys (finger)?","find":"The A2 and A4 flexor pulleys are intact with normal low signal and the flexor tendons maintain close apposition to the underlying phalanges without bowstringing.","impr":"Intact flexor pulleys.","topic":"Normal","joint":"hand"},
{"id":"d821","front":"How would you describe normal disc hydration and height?","find":"The intervertebral discs maintain normal T2 signal hydration and normal height without desiccation, loss of height, bulge, or focal protrusion.","impr":"Normal disc hydration and height.","topic":"Normal","joint":"spine"},
{"id":"d822","front":"How would you describe a normal spinal canal and cord caliber?","find":"The spinal canal is of normal caliber at all levels without stenosis, and the spinal cord is normal in caliber and signal without compression, edema, or intrinsic signal abnormality.","impr":"Normal spinal canal and cord.","topic":"Normal","joint":"spine"},
{"id":"d823","front":"How would you describe normal spinal alignment?","find":"Normal vertebral alignment is maintained with preserved lordosis/kyphosis, no spondylolisthesis or focal kyphotic angulation, and normal vertebral body heights.","impr":"Normal alignment.","topic":"Normal","joint":"spine"},
{"id":"d824","front":"How would you describe a normal conus medullaris?","find":"The conus medullaris terminates at a normal level (about T12-L1) with normal signal and caliber, and the cauda equina nerve roots are normally distributed without clumping or enhancement.","impr":"Normal conus medullaris.","topic":"Normal","joint":"spine"},
{"id":"d825","front":"How would you describe normal muscle bulk and signal?","find":"The visualized musculature demonstrates normal bulk and architecture with normal signal on all sequences, without edema, fatty atrophy, or mass.","impr":"Normal muscle bulk and signal.","topic":"Normal","joint":"general"},
{"id":"d826","front":"How would you describe a normal peripheral nerve?","find":"The visualized nerve is of normal caliber and fascicular architecture with normal signal, without thickening, T2 hyperintensity, or perineural mass.","impr":"Normal nerve.","topic":"Normal","joint":"general"},
{"id":"d827","front":"How would you describe a normal bursa?","find":"The bursa is unremarkable with no distension by fluid, synovial thickening, or enhancement to suggest bursitis.","impr":"No bursitis.","topic":"Normal","joint":"general"},
{"id":"d828","front":"How would you describe a normal joint (no effusion or synovitis)?","find":"The joint demonstrates a physiologic amount of fluid without a tense effusion, and the synovium is normal in thickness without proliferation, hyperemia, or enhancement to suggest synovitis.","impr":"No effusion or synovitis.","topic":"Normal","joint":"general"},
{"id":"d829","front":"How would you describe normal age-appropriate bone marrow?","find":"The bone marrow demonstrates normal signal for the patient's age with expected fatty conversion and a normal distribution of residual hematopoietic marrow, without focal lesion, diffuse infiltration, or edema.","impr":"Normal marrow for age.","topic":"Normal","joint":"general"},
{"id":"d830","front":"What does a fluid-sensitive sequence (STIR or fat-suppressed T2/PD) show, and how do you phrase it?","find":"Fluid-sensitive sequences make water bright while suppressing fat, so edema, joint effusion, marrow edema, cysts and acute injury stand out as high signal against a dark fat background. Report-style: \"Increased signal on fluid-sensitive sequences within the [bone/soft tissue] compatible with edema.\" Use this language for marrow contusions, stress reaction, tendinosis and effusions.","impr":"Fluid bright, fat dark - the workhorse for detecting edema and injury.","pearl":"STIR and fat-suppressed T2 are both fluid-sensitive but not interchangeable in wording - say which technique was used if it matters (e.g., near metal STIR is more robust).","topic":"Technique","joint":"general"},
{"id":"d831","front":"How do you describe what a T1-weighted sequence shows?","find":"T1 best depicts anatomy, marrow and fat: normal fatty marrow and subcutaneous fat are bright, fluid and most pathology are dark to intermediate. Report-style: \"Normal T1 marrow signal\" reassures against infiltration; \"T1-hypointense marrow replacing the normal fatty signal\" describes a lesion. T1 is the sequence for marrow assessment and for pre-contrast comparison.","impr":"T1 = anatomy and marrow; fat bright, fluid dark.","pearl":"Always assess marrow on T1 first - a lesion that is darker than skeletal muscle or adjacent disc on T1 is suspicious for true marrow replacement.","topic":"Technique","joint":"general"},
{"id":"d832","front":"How do you phrase findings on a proton density (PD) sequence?","find":"PD gives high signal-to-noise and excellent contrast for internal joint structures - menisci, cartilage and ligaments - with intermediate fluid signal. Fat-suppressed PD is the standard cartilage and meniscus sequence. Report-style: \"Fat-suppressed PD demonstrates a full-thickness cartilage defect\" or \"Intrasubstance increased PD signal within the meniscus not extending to a surface (Grade 2).\"","impr":"PD (esp. fat-sat) is the cartilage and meniscus workhorse.","pearl":"Only signal reaching an articular surface on PD/fat-sat sequences counts as a meniscal tear; intrasubstance Grade 1-2 signal is degenerative.","topic":"Technique","joint":"general"},
{"id":"d833","front":"What is the difference between STIR and fat-suppressed (spectral) T2, and when do you choose each?","find":"STIR suppresses fat by its short T1 (inversion recovery) and is uniform even in large or off-isocenter fields, but has lower SNR and cannot be used after gadolinium (it nulls enhancing fat-like signal). Spectral/chemical fat-sat T2 suppresses the fat resonance peak and gives higher SNR but is sensitive to field inhomogeneity. Report-style: prefer STIR for large fields, off-center anatomy and near metal; use spectral fat-sat for high-resolution joint imaging and after contrast.","impr":"STIR = robust but low SNR; spectral fat-sat = sharper but inhomogeneity-prone.","pearl":"Never use STIR after gadolinium - it can null enhancing tissue; use fat-suppressed T1 instead.","topic":"Technique","joint":"general"},
{"id":"d834","front":"How do you recognize and describe fat-saturation failure?","find":"Failed fat sat appears as a region of incompletely suppressed bright fat, usually at the periphery of the field, near air-tissue interfaces, near metal, or off magnet isocenter, creating asymmetric bright and dark zones. It can mimic or mask edema. Report-style: \"Heterogeneous/incomplete fat suppression at the periphery limits evaluation; findings correlated with non-fat-suppressed sequences.\"","impr":"Geographic incomplete fat suppression at field edge - artifact, not pathology.","pearl":"Do not call edema in a zone of failed fat sat - confirm on STIR or correlate with T1; conversely failed suppression can hide real edema.","topic":"Artifact","joint":"general"},
{"id":"d835","front":"How does Dixon imaging work and how do you report in- and opposed-phase findings?","find":"Dixon acquires images at echo times where fat and water signals are in-phase and opposed-phase, then reconstructs separate water-only (fat-suppressed), fat-only, in-phase and opposed-phase images in one acquisition. Signal drop on opposed-phase relative to in-phase indicates microscopic intravoxel fat (e.g., normal marrow, benign hemangioma). Report-style: \"Signal loss on opposed-phase images indicates intralesional microscopic fat, favoring a benign etiology.\"","impr":"Dixon = uniform fat suppression plus fat/water quantification in one scan.","pearl":"Lack of opposed-phase signal drop in marrow raises concern for tumor replacing fat-containing marrow.","topic":"Technique","joint":"general"},
{"id":"d836","front":"How do you describe and use fat fraction (Dixon-derived)?","find":"Fat fraction = fat signal / (fat + water signal), expressed as a percentage, quantifying how much of the marrow or muscle is fat. Normal marrow is high fat fraction; tumor, edema or fibrosis lowers it, while fatty muscle atrophy raises it. Report-style: \"Reduced marrow fat fraction within the lesion supports cellular marrow replacement\" or \"Elevated intramuscular fat fraction consistent with fatty atrophy.\"","impr":"Fat fraction quantifies marrow/muscle fat - low in tumor/edema, high in fatty atrophy.","pearl":"A measurable drop in fat fraction is more objective than subjective signal and helps distinguish benign red marrow from infiltrative disease.","topic":"Technique","joint":"general"},
{"id":"d837","front":"What do gradient-echo (GRE/MERGE/T2*) sequences show, and how do you describe blooming?","find":"GRE/T2* sequences are highly sensitive to magnetic susceptibility, so hemosiderin and calcium cause exaggerated signal loss that is larger than the actual deposit - termed blooming. Report-style: \"Blooming low signal on gradient-echo images indicates hemosiderin, compatible with prior hemorrhage / PVNS.\" GRE also shows cartilage well but exaggerates susceptibility.","impr":"GRE/T2* blooms hemosiderin and calcium into dark, enlarged foci.","pearl":"Blooming overestimates lesion size - do not measure hemosiderin or calcium on GRE; the dark area exceeds the true deposit.","topic":"Technique","joint":"general"},
{"id":"d838","front":"How do you report a post-contrast T1 fat-suppressed sequence?","find":"Fat-suppressed T1 after gadolinium shows enhancing tissue as bright against suppressed fat, identifying hyperemia, synovitis, infection, tumor and viable versus necrotic tissue. Report-style: \"Avid enhancement on fat-suppressed post-contrast T1\" or \"Peripheral rim enhancement surrounding a non-enhancing center compatible with an abscess.\" Always compare to pre-contrast T1.","impr":"Post-contrast fat-sat T1 = enhancement bright; the sequence for inflammation, infection and tumor.","pearl":"Enhancement must be confirmed against a matched pre-contrast (ideally subtraction) image - intrinsically T1-bright fat, blood or proteinaceous fluid can mimic enhancement.","topic":"Technique","joint":"general"},
{"id":"d839","front":"What is the difference between direct and indirect MR arthrography?","find":"Direct MR arthrography injects dilute gadolinium directly into the joint, distending the capsule so contrast outlines labral and ligament tears and intra-articular bodies (high signal tracking into a defect). Indirect arthrography gives IV gadolinium and images after exercise/delay, relying on synovial diffusion - less distension but no needle. Report-style: \"On direct MR arthrogram, intra-articular contrast tracks into the labral base compatible with a tear.\"","impr":"Direct = intra-articular injection with distension; indirect = IV contrast diffusing into the joint.","pearl":"Indirect arthrography also enhances vascular/inflamed tissue (not just the joint space), which can be a pitfall when assessing the labrum.","topic":"Technique","joint":"general"},
{"id":"d840","front":"What is bright versus dark on a fluid-sensitive sequence for the common MSK tissues?","find":"On fluid-sensitive (STIR / fat-sat T2/PD): fluid/edema bright; fat dark (suppressed); hemosiderin dark; calcium and cortical bone dark; fibrocartilage (meniscus, labrum) dark; hyaline cartilage intermediate-to-gray; normal ligaments and tendons dark (low signal). Report-style: phrase abnormal signal relative to these expectations, e.g., \"abnormal high signal within the normally low-signal tendon.\"","impr":"Fluid bright; fat/bone/fibrocartilage/tendon dark; hyaline cartilage gray.","pearl":"Normal tendons and ligaments are dark on all sequences - any internal high signal (except magic angle) implies pathology.","topic":"Technique","joint":"general"},
{"id":"d841","front":"What is bright versus dark on T1 for the common MSK tissues?","find":"On T1: fat and fatty marrow bright; subacute hemorrhage (methemoglobin) and melanin/proteinaceous material bright; fluid dark; muscle intermediate; cortical bone, tendon, ligament and fibrocartilage dark. Report-style: \"T1-hyperintense\" should prompt a differential of fat, blood, melanin or gadolinium/contrast effect.","impr":"T1 bright = fat, subacute blood, melanin, proteinaceous fluid, or gadolinium.","pearl":"Intrinsic T1 hyperintensity (fat or subacute blood) can be mistaken for enhancement - always compare pre- and post-contrast, ideally with subtraction.","topic":"Technique","joint":"general"},
{"id":"d842","front":"How do you recognize and report the magic angle artifact?","find":"Magic angle is artifactual increased signal in tendons or ligaments oriented near 55 degrees to the main magnetic field, seen on short-TE sequences (T1, PD, GRE) and disappearing on long-TE T2. It commonly affects the supraspinatus, peroneal and posterior tibial tendons as they curve. Report-style: \"Increased signal within the [tendon] on short-TE sequences that resolves on T2, compatible with magic angle artifact rather than tendinopathy.\"","impr":"55-degree tendon signal on short-TE sequences that vanishes on T2 = magic angle.","pearl":"If apparent tendinosis is bright on PD/T1 but dark on a long-TE T2, it is magic angle, not pathology - check the T2.","topic":"Artifact","joint":"general"},
{"id":"d843","front":"How do you recognize and report chemical shift artifact (India ink / etching)?","find":"Chemical shift of the second kind (opposed-phase GRE) produces a black outline - India ink etching - at fat-water interfaces such as around organs, muscle and marrow boundaries. Chemical shift of the first kind shifts fat and water along the frequency-encode direction, creating a bright/dark misregistration band at fat-fluid interfaces. Report-style: \"India ink artifact at fat-water interfaces on opposed-phase images, an expected finding.\"","impr":"Black outline at fat-water interfaces on opposed-phase = India ink chemical shift.","pearl":"India ink etching is normal/expected and confirms you are on an opposed-phase image - do not mistake it for a real low-signal rim.","topic":"Artifact","joint":"general"},
{"id":"d844","front":"How do you recognize susceptibility (blooming) artifact?","find":"Susceptibility artifact is signal loss with geometric distortion from local field inhomogeneity caused by metal, air, hemosiderin or calcium, worst on gradient-echo and at high field, and minimized on spin-echo/fast spin-echo. Report-style: \"Susceptibility artifact from adjacent metallic hardware limits evaluation of the [structure].\" The dark region blooms beyond the true material.","impr":"Susceptibility = blooming signal void with distortion, worst on GRE and near metal.","pearl":"Use spin-echo/FSE and lower-field or MARS techniques to reduce susceptibility; GRE maximizes it (useful for detecting hemosiderin, harmful near metal).","topic":"Artifact","joint":"general"},
{"id":"d845","front":"What are metal artifact reduction (MARS) techniques and how do you describe their use?","find":"MARS techniques reduce metal-induced distortion: use FSE/spin-echo not GRE, STIR not spectral fat-sat, high bandwidth, thin slices, low TE, increased echo train, and advanced methods VAT (view-angle tilting) and SEMAC (slice-encoding for metal artifact correction) or MAVRIC. Report-style: \"Imaging performed with metal artifact reduction technique; residual susceptibility artifact adjacent to hardware.\"","impr":"MARS = FSE + STIR + high bandwidth + VAT/SEMAC/MAVRIC to image around metal.","pearl":"Spectral fat saturation fails near metal - substitute STIR or Dixon-based suppression for reliable fat suppression around hardware.","topic":"Technique","joint":"general"},
{"id":"d846","front":"How do you recognize and report motion artifact?","find":"Motion produces ghosting and blurring propagated along the phase-encode direction, degrading edge sharpness and creating replicated edges of moving structures. Report-style: \"Motion artifact limits evaluation\" or \"Findings are degraded by patient motion; correlation or repeat imaging recommended if clinically indicated.\"","impr":"Motion = ghosting/blur along the phase-encode direction.","pearl":"Ghosts always propagate in the phase-encode (not frequency) direction - this helps confirm an artifact and can be reduced by swapping phase/frequency directions.","topic":"Artifact","joint":"general"},
{"id":"d847","front":"How do you recognize and report truncation (Gibbs) artifact?","find":"Truncation/Gibbs artifact produces alternating parallel bright and dark lines paralleling high-contrast boundaries (e.g., spinal cord, cartilage surface), from undersampling of sharp edges. In cartilage it can mimic a defect; in the cord it can mimic a syrinx. Report-style: \"Linear alternating signal paralleling the [interface] compatible with truncation (Gibbs) artifact.\"","impr":"Gibbs = parallel ringing lines at high-contrast edges; can mimic syrinx or cartilage defect.","pearl":"A central linear cord signal that parallels the cord and matches the truncation pattern is Gibbs, not a true syrinx - increase matrix to reduce it.","topic":"Artifact","joint":"general"},
{"id":"d848","front":"How do you recognize and report partial volume artifact?","find":"Partial volume averaging occurs when a voxel contains more than one tissue, blending their signals and blurring small or obliquely oriented structures so a thin defect or small body appears indistinct. Report-style: \"Apparent finding may reflect partial volume averaging given slice thickness; thin-section or orthogonal images recommended for confirmation.\"","impr":"Partial volume = mixed-tissue voxels blurring small/oblique structures.","pearl":"Confirm questionable small lesions or thin cartilage defects on a thinner slice or an orthogonal plane before reporting them.","topic":"Artifact","joint":"general"},
{"id":"d849","front":"How do you recognize and report pulsation/flow artifact?","find":"Pulsatile flow from vessels produces discrete ghost copies of the vessel propagated along the phase-encode direction, which can overlie adjacent structures (e.g., popliteal artery ghosts across the knee) and mimic a lesion. Report-style: \"Pulsation artifact from the [vessel] projecting along the phase-encode direction, not a true lesion.\"","impr":"Vessel ghosts repeating along phase-encode = pulsation/flow artifact.","pearl":"Trace suspected lesions back to a vessel and check the phase-encode direction; saturation bands or gating reduce pulsation ghosts.","topic":"Artifact","joint":"general"},
{"id":"d850","front":"How do you recognize and report wrap-around (aliasing) artifact?","find":"Wrap-around/aliasing occurs when anatomy outside the field of view is mismapped to the opposite side of the image, typically along the phase-encode direction, overlapping the area of interest. Report-style: \"Aliasing/wrap-around artifact from anatomy outside the field of view overlapping the [region].\"","impr":"Wrap-around = out-of-FOV anatomy folding onto the opposite image side.","pearl":"Reduce aliasing with a larger FOV, no-phase-wrap/oversampling, or by swapping the phase-encode direction.","topic":"Artifact","joint":"general"},
{"id":"d851","front":"How should you phrase signal intensity relative to a sequence?","find":"Always anchor signal to the specific sequence and a reference tissue, because the same tissue varies by sequence. Report-style: \"T1-hypointense and T2-hyperintense relative to skeletal muscle\" or \"isointense to fat on T1, suppressing on fat-sat sequences.\" State whether fat suppression was applied, since it changes expected appearances.","impr":"Name the sequence and a reference tissue when describing any signal.","pearl":"Avoid bare terms like bright or dark - \"T2-hyperintense\" with a comparator is unambiguous, whereas isolated bright is sequence-dependent and confusing.","topic":"Technique","joint":"general"},
{"id":"d852","front":"How do you describe enhancement accurately?","find":"Describe enhancement by comparing matched pre- and post-contrast fat-suppressed T1 (ideally subtraction): note presence, pattern and degree. Report-style: \"Avid homogeneous enhancement,\" \"thin peripheral rim enhancement,\" \"septal/nodular enhancement,\" or \"no enhancement to suggest a solid component.\" Specify the sequence and that fat suppression was used.","impr":"Enhancement = pre/post comparison; describe presence, pattern and degree.","pearl":"Subtraction imaging is the most reliable way to prove enhancement when intrinsic T1-bright material (fat, blood, proteinaceous fluid) is present.","topic":"Technique","joint":"general"},
{"id":"d853","front":"What is the T1 rule for a marrow lesion, and how do you apply it?","find":"On a non-fat-suppressed T1 image, normal hematopoietic/fatty marrow should be brighter than (or equal to) skeletal muscle and intervertebral disc. A focal marrow lesion that is hypointense to muscle or disc on T1 is suspicious for true marrow replacement (tumor, infection). Report-style: \"Focal T1 signal lower than adjacent skeletal muscle, suspicious for marrow-replacing process.\"","impr":"Marrow darker than muscle/disc on T1 = suspicious for replacement.","pearl":"Window the T1 image to compare directly with muscle and disc - benign red marrow stays brighter than muscle, whereas tumor drops below it.","topic":"Technique","joint":"general"},
{"id":"d854","front":"How do you describe T2* and quantitative cartilage techniques (T1rho, dGEMRIC, T2 mapping)?","find":"Compositional cartilage MRI assesses matrix before morphologic loss: T2 mapping reflects collagen and water (elevated T2 = early degeneration), T1rho reflects proteoglycan loss (elevated T1rho = depletion), and dGEMRIC uses delayed gadolinium uptake to map glycosaminoglycan (low dGEMRIC index = GAG loss). Report-style: \"Regional T2 prolongation/elevated T1rho in the [compartment] cartilage suggesting early matrix degeneration.\"","impr":"T2 map/T1rho/dGEMRIC quantify cartilage matrix before structural defects appear.","pearl":"These are research/advanced techniques - elevated T2 and T1rho indicate degeneration, while LOW dGEMRIC index indicates GAG loss (opposite directionality).","topic":"Technique","joint":"general"},
{"id":"d855","front":"How do you describe what GRE/MERGE shows for cartilage and small structures?","find":"3D GRE (e.g., MERGE, SPGR, DESS) provides thin contiguous high-resolution slices that depict cartilage surfaces, small ligaments and the labrum with multiplanar reformatting. Report-style: \"3D gradient-echo images demonstrate a focal cartilage surface irregularity.\" However GRE underrepresents marrow edema and exaggerates susceptibility.","impr":"3D GRE = thin high-res cartilage/labral imaging, but poor for marrow edema.","pearl":"GRE is insensitive to bone marrow edema - never exclude a stress injury or contusion on GRE alone; confirm with fluid-sensitive FSE/STIR.","topic":"Technique","joint":"general"},
{"id":"d856","front":"How do you choose and describe imaging planes for localizing MSK findings?","find":"Localize a finding in at least two planes and name plane-specific landmarks: axial for tendon position/subluxation and cross-sectional anatomy, sagittal for meniscus/cartilage and longitudinal tendon, coronal for collateral ligaments, marrow and overall alignment. Report-style: \"Best seen on the [sagittal] images, the [finding] is confirmed on the orthogonal [axial] plane.\"","impr":"Confirm and localize every finding in two orthogonal planes.","pearl":"A finding present on only a single slice in one plane is often artifact or partial volume - require confirmation on a second plane before reporting.","topic":"Technique","joint":"general"},
{"id":"d857","front":"How do you recognize and report a zipper or radiofrequency artifact?","find":"RF interference/zipper artifact appears as a band of alternating bright and dark spots (a stripe) across the image at a fixed frequency, from external RF leakage (e.g., open shield door, electronic equipment). Report-style: \"Linear radiofrequency (zipper) artifact across the image; if obscuring the area of interest, repeat imaging with the scan room sealed.\"","impr":"Zipper = fixed alternating bright/dark stripe from external RF leakage.","pearl":"A zipper running across the image at a constant position usually means the magnet room door was open or external electronics interfered - it is a hardware/environment issue, not pathology.","topic":"Artifact","joint":"general"},
{"id":"d858","front":"How would you describe the enhancement of a soft-tissue abscess?","find":"There is a rim-enhancing fluid collection measuring 3.2 x 2.8 x 4.1 cm in the [location] with a thick, irregular peripherally enhancing wall and a central non-enhancing component that demonstrates restricted diffusion (high signal on DWI with corresponding low ADC). Surrounding T2-hyperintense edema and stranding are present.","impr":"Rim-enhancing collection with central restricted diffusion, consistent with abscess.","pearl":"Thick irregular rim + central diffusion restriction distinguishes abscess from a simple/necrotic cyst, which lacks central restricted diffusion.","topic":"Enhancement","joint":"general"},
{"id":"d859","front":"How would you describe the enhancement of a necrotic soft-tissue tumor?","find":"There is a heterogeneously enhancing soft-tissue mass measuring 6.5 x 5.2 cm with thick, nodular, irregular peripheral and septal enhancement surrounding a central non-enhancing necrotic zone. The non-enhancing center does NOT restrict diffusion.","impr":"Heterogeneous mass with central necrosis, suspicious for aggressive/malignant neoplasm.","pearl":"Necrotic tumor shows nodular irregular internal/septal enhancement and lacks the uniform diffusion restriction of pus; correlate with solid enhancing nodular components for biopsy targeting.","topic":"Enhancement","joint":"general"},
{"id":"d860","front":"How would you describe the enhancement of a simple ganglion cyst?","find":"There is a well-defined T2-hyperintense lobulated cystic lesion measuring 1.4 x 0.9 cm adjacent to the [joint/tendon] demonstrating only a thin, smooth, imperceptible rim of enhancement with no internal or solid enhancement.","impr":"Thin rim-enhancing cyst, consistent with ganglion.","pearl":"Thin smooth rim with NO internal enhancement; any solid/nodular internal enhancement should prompt reconsideration of a solid or complicated lesion.","topic":"Enhancement","joint":"general"},
{"id":"d861","front":"How would you describe the enhancement of inflammatory synovitis / pannus?","find":"There is diffuse, avid, frond-like synovial enhancement lining the [joint] with synovial thickening up to 4 mm and an associated enhancing joint effusion. Subjacent marrow and periarticular soft tissues show reactive enhancement.","impr":"Avid frond-like synovial enhancement, consistent with active inflammatory synovitis/pannus.","pearl":"Early dynamic enhancement of synovium (rapid wash-in) favors active inflammatory pannus over inert fibrotic pannus; the latter enhances slowly/late.","topic":"Enhancement","joint":"general"},
{"id":"d862","front":"How would you describe the enhancement in septic arthritis?","find":"There is a complex enhancing effusion with thick, irregular, avidly enhancing synovium, periarticular soft-tissue and capsular enhancement, and reactive perisynovial marrow enhancement. Restricted diffusion may be seen within the effusion.","impr":"Avid synovial and periarticular enhancement with complex effusion, concerning for septic arthritis.","pearl":"Synovitis enhancement is nonspecific; the combination of periarticular soft-tissue/capsular enhancement plus marrow edema raises concern for infection over sterile synovitis.","topic":"Enhancement","joint":"general"},
{"id":"d863","front":"How would you describe the enhancement of PVNS / tenosynovial giant cell tumor?","find":"There is a lobulated, avidly enhancing synovial-based mass with frond-like and nodular morphology that demonstrates blooming low signal on gradient-echo/SWI from hemosiderin. The mass enhances heterogeneously with intervening non-enhancing hemosiderin-laden regions.","impr":"Enhancing hemosiderin-laden synovial proliferation, consistent with PVNS/TSGCT.","pearl":"Avid synovial enhancement WITH gradient-echo blooming (hemosiderin) is the discriminator from bland inflammatory synovitis, which lacks blooming.","topic":"Enhancement","joint":"general"},
{"id":"d864","front":"How would you describe the enhancement of lipoma arborescens?","find":"There are frond-like synovial projections of macroscopic fat (high T1, suppressing on fat-saturated sequences) within a distended joint. The fatty fronds do NOT enhance; only mild enhancement of the thin intervening synovial covering is seen.","impr":"Non-enhancing fatty frond-like synovial proliferation, consistent with lipoma arborescens.","pearl":"Absence of enhancement of the fatty fronds (which suppress on fat-sat) distinguishes this from enhancing inflammatory pannus or PVNS.","topic":"Enhancement","joint":"general"},
{"id":"d865","front":"How would you describe the enhancement of osteomyelitis?","find":"There is geographic marrow signal replacement (T1-hypointense, T2/STIR-hyperintense) in the [bone] with avid intramedullary enhancement, cortical breakthrough, and adjacent periosteal and soft-tissue enhancement. A non-enhancing focus surrounded by an enhancing rim suggests intraosseous abscess.","impr":"Marrow replacement with avid enhancement, consistent with osteomyelitis.","pearl":"The 'penumbra sign' (T1 hyperintense rim around an abscess cavity) and confluent T1 marrow replacement favor osteomyelitis over reactive edema.","topic":"Enhancement","joint":"general"},
{"id":"d866","front":"How would you describe the enhancement of avascular necrosis (osteonecrosis)?","find":"There is a serpiginous geographic lesion in the [epiphysis] with a double-line sign on T2. The necrotic segment is NON-enhancing centrally, bounded by an enhancing reactive/granulation interface at the margin.","impr":"Non-enhancing necrotic segment with peripheral reactive enhancement, consistent with avascular necrosis.","pearl":"Absence of central enhancement of the necrotic segment is the hallmark; reactive marginal enhancement should not be mistaken for tumor.","topic":"Enhancement","joint":"general"},
{"id":"d867","front":"How would you describe the enhancement pattern of a healing/subacute fracture?","find":"There is a [linear/band-like] region of marrow edema along the fracture plane with associated fracture-line and periosteal enhancement and enhancing adjacent soft tissue. No focal soft-tissue mass.","impr":"Linear fracture-line and periosteal enhancement, consistent with [healing] fracture rather than a mass lesion.","pearl":"Linear/band-like enhancement following a fracture plane (not a rounded mass) supports trauma; a confluent enhancing soft-tissue mass should raise concern for pathologic fracture/tumor.","topic":"Enhancement","joint":"general"},
{"id":"d868","front":"How would you describe the enhancement of a soft-tissue hemangioma?","find":"There is a lobulated T2-hyperintense intramuscular lesion with interspersed fat and serpentine vessels demonstrating peripheral nodular discontinuous enhancement with progressive centripetal fill-in on delayed sequences, paralleling the blood pool.","impr":"Peripheral nodular discontinuous enhancement with fill-in, consistent with hemangioma.","pearl":"Enhancement that follows the blood pool (nodular discontinuous fill-in) is characteristic; phleboliths (blooming foci) further support the diagnosis.","topic":"Enhancement","joint":"general"},
{"id":"d869","front":"How would you describe the enhancement of a venous malformation?","find":"There are dilated tortuous T2-hyperintense vascular channels with phleboliths demonstrating gradual, progressive enhancement that fills in over delayed phases. Slow flow is reflected by lack of arterial-phase flow voids.","impr":"Slow-filling enhancing vascular channels with phleboliths, consistent with low-flow venous malformation.","pearl":"Slow progressive fill-in and phleboliths characterize venous (low-flow) malformations; arterial-phase enhancement with flow voids and no phleboliths suggests an arteriovenous (high-flow) malformation.","topic":"Enhancement","joint":"general"},
{"id":"d870","front":"How would you describe the enhancement of a peripheral nerve sheath tumor (schwannoma/neurofibroma)?","find":"There is a well-circumscribed fusiform mass along the expected course of the [nerve] with entering/exiting nerve, a target sign on T2, and a split-fat sign. The mass enhances avidly, often with central or target-pattern enhancement.","impr":"Avidly enhancing fusiform nerve-associated mass with target sign, consistent with benign nerve sheath tumor.","pearl":"Target enhancement and the split-fat/entering-exiting nerve signs favor a benign PNST; rapid growth, ill-defined margins, peripheral enhancement and central necrosis raise concern for malignant transformation (MPNST).","topic":"Enhancement","joint":"general"},
{"id":"d871","front":"How would you describe the enhancement of perineural tumor spread?","find":"There is abnormal thickening and avid enhancement of the [named nerve] with effacement of the surrounding perineural fat and enlargement of the corresponding neural foramen/canal, tracking contiguously from the primary tumor.","impr":"Enhancing thickened nerve with foraminal expansion, consistent with perineural tumor spread.","pearl":"Loss of perineural fat, nerve enlargement, and foraminal widening distinguish perineural spread from normal nerve enhancement; denervation muscle changes may be downstream.","topic":"Enhancement","joint":"general"},
{"id":"d872","front":"How would you describe the enhancement of postoperative epidural fibrosis (scar) versus recurrent disc?","find":"There is soft tissue in the [right/left] [level] epidural space that enhances homogeneously and immediately on early post-contrast images and conforms to/retracts the thecal sac, consistent with fibrosis. Recurrent disc would show peripheral or no enhancement.","impr":"Homogeneously enhancing epidural soft tissue, consistent with postoperative scar/fibrosis.","pearl":"Scar enhances homogeneously on early post-contrast imaging; recurrent/residual disc material enhances only peripherally (or not at all) early, with possible delayed central enhancement from imbibition.","topic":"Enhancement","joint":"spine"},
{"id":"d873","front":"How would you describe the enhancement of a benign solid soft-tissue mass?","find":"There is a well-circumscribed soft-tissue mass measuring 2.6 x 2.1 cm with homogeneous, solid enhancement, smooth margins, no necrosis, and no aggressive perilesional features.","impr":"Homogeneously enhancing well-marginated solid mass, with imaging features favoring a benign process.","pearl":"Homogeneous solid enhancement with smooth margins favors benignity, but enhancement pattern alone is not definitive; size, growth, depth, and margins must be integrated.","topic":"Enhancement","joint":"general"},
{"id":"d874","front":"How would you describe the enhancement of an aggressive/malignant soft-tissue sarcoma?","find":"There is a large (>5 cm) deep soft-tissue mass with heterogeneous avid enhancement, internal necrotic non-enhancing zones, irregular infiltrative margins, peritumoral edema, and early/rapid enhancement on dynamic imaging.","impr":"Large deep heterogeneously enhancing infiltrative mass, suspicious for soft-tissue sarcoma.","pearl":"Heterogeneous enhancement with necrosis, infiltrative margins, peritumoral enhancement/edema, and rapid dynamic wash-in are features that favor malignancy.","topic":"Enhancement","joint":"general"},
{"id":"d875","front":"How would you describe a target enhancement pattern?","find":"The lesion demonstrates a target appearance with relative central enhancement (or central low signal) surrounded by a peripheral zone of differing signal/enhancement, producing concentric layering.","impr":"Target enhancement pattern, classically associated with benign neurogenic tumors.","pearl":"On T2 the target sign (central low, peripheral high) and target enhancement favor neurofibroma/schwannoma; loss of the target sign in a known PNST is worrisome for malignant change.","topic":"Enhancement","joint":"general"},
{"id":"d876","front":"How would you describe the enhancement of infectious tenosynovitis?","find":"There is a distended tendon sheath with a complex enhancing fluid component, thick irregular avidly enhancing synovial lining, and surrounding soft-tissue enhancement and edema. Restricted diffusion may be present within the sheath fluid.","impr":"Thick enhancing tenosynovium with complex sheath fluid, concerning for infectious tenosynovitis.","pearl":"Thick irregular enhancing synovium with surrounding soft-tissue inflammation and complex/restricting fluid favors infection over the smoother synovial enhancement of inflammatory tenosynovitis.","topic":"Enhancement","joint":"general"},
{"id":"d877","front":"How would you describe the enhancement of inflammatory (e.g., rheumatoid) tenosynovitis?","find":"There is tendon sheath distension with smooth, frond-like synovial thickening that enhances avidly, surrounding simple-appearing sheath fluid, without aggressive surrounding soft-tissue inflammation.","impr":"Avid frond-like synovial enhancement within the tendon sheath, consistent with inflammatory tenosynovitis.","pearl":"Enhancing synovium with relatively simple sheath fluid and lack of aggressive perisheath inflammation favors inflammatory over infectious tenosynovitis; clinical correlation is essential.","topic":"Enhancement","joint":"general"},
{"id":"d878","front":"How would you describe the enhancement of myositis (e.g., pyomyositis early phase)?","find":"There is diffuse enlargement and abnormal T2/STIR hyperintensity of the [muscle] with diffuse, ill-defined muscular enhancement and surrounding fascial and subcutaneous edema, without a discrete drainable rim-enhancing collection.","impr":"Diffuse muscular enhancement, consistent with myositis (pre-suppurative phase).","pearl":"Diffuse ill-defined intramuscular enhancement is the early phase; progression to a rim-enhancing collection with restricted diffusion marks abscess formation requiring drainage.","topic":"Enhancement","joint":"general"},
{"id":"d879","front":"How would you describe the enhancement of myositis ossificans (subacute phase)?","find":"There is a soft-tissue mass with marked surrounding edema demonstrating peripheral enhancement and a peripheral zone of maturing ossification (low signal rim with peripheral mineralization on radiograph/CT), with a less-enhancing center.","impr":"Peripherally enhancing/ossifying soft-tissue lesion with zonal maturation, consistent with myositis ossificans.","pearl":"Peripheral (centripetal/zonal) maturation with peripheral ossification is reassuring; central-to-peripheral disorganized mineralization would be atypical and raise concern for extraskeletal osteosarcoma.","topic":"Enhancement","joint":"general"},
{"id":"d880","front":"How would you describe a simple cyst (absence of enhancement) versus a solid lesion on post-contrast imaging?","find":"There is a T2-hyperintense lesion measuring 1.8 x 1.5 cm that shows NO internal enhancement on subtracted post-contrast images, with at most a thin imperceptible rim, confirming its cystic nature.","impr":"Non-enhancing T2-hyperintense lesion, consistent with a simple cyst.","pearl":"Use subtraction images to confirm true absence of enhancement; intrinsic T1-hyperintense (proteinaceous/hemorrhagic) cyst contents can mimic enhancement on non-subtracted post-contrast images.","topic":"Enhancement","joint":"general"},
{"id":"d881","front":"How would you describe enhancement that distinguishes a myxoid tumor from a cyst?","find":"There is a T2-hyperintense lesion that mimics a cyst but demonstrates internal solid/septal/lacy enhancement on post-contrast subtracted images, indicating a solid myxoid neoplasm rather than fluid.","impr":"T2-bright lesion with internal enhancement, consistent with a myxoid soft-tissue tumor (not a simple cyst).","pearl":"Any true internal enhancement in an apparently cystic T2-bright lesion should prompt consideration of a myxoid neoplasm (e.g., myxoma, myxoid liposarcoma) and biopsy.","topic":"Enhancement","joint":"general"},
{"id":"d882","front":"How should you phrase common enhancement descriptors in an MRI report (avid, progressive, fill-in, rim, septal, non-enhancing)?","find":"Use precise modifiers: <avid> (intense early enhancement), <progressive> (increasing on delayed phases), <peripheral nodular discontinuous with centripetal fill-in> (blood-pool lesions), <thin/thick rim> (peripheral), <septal/internal> (within a mass), and <non-enhancing> (no signal change on subtracted images).","impr":"Standardized enhancement terminology improves clarity and differential diagnosis.","pearl":"Always specify timing (early vs delayed) and distribution (rim vs solid vs septal vs nodular); dynamic phase descriptors (rapid wash-in, washout) carry diagnostic weight.","topic":"Enhancement","joint":"general"},
{"id":"d883","front":"How would you describe delayed cartilage enhancement (dGEMRIC) findings?","find":"On delayed gadolinium-enhanced imaging of cartilage, regions of low glycosaminoglycan content demonstrate increased contrast accumulation and a correspondingly lower T1(Gd) index, indicating early cartilage degeneration.","impr":"Reduced dGEMRIC index, indicating glycosaminoglycan depletion and early chondral degeneration.","pearl":"In dGEMRIC, anionic contrast accumulates inversely to glycosaminoglycan content, so MORE enhancement (lower T1[Gd]) signifies cartilage degradation, opposite to typical 'enhancement = lesion' intuition.","topic":"Enhancement","joint":"general"},
{"id":"d884","front":"How would you describe sternoclavicular joint dislocation?","find":"Asymmetry of the sternoclavicular joint with the medial clavicle displaced relative to the manubrium. Anterior dislocation shows the medial clavicular head displaced ventral to the manubrial articular surface; posterior (retrosternal) dislocation shows the medial clavicle displaced dorsally [toward the mediastinum], with assessment of mass effect on the trachea, esophagus, and great vessels. Joint space widening, capsuloligamentous disruption, and periarticular edema are present. In skeletally immature patients [<25 years] consider medial clavicular physeal Salter-Harris injury rather than true dislocation.","impr":"Posterior sternoclavicular dislocation with retrosternal displacement; evaluate for mediastinal vascular/airway compromise.","pearl":"Posterior dislocation is a surgical emergency owing to risk to mediastinal structures; CTA is often warranted.","topic":"Chest wall","joint":"shoulder"},
{"id":"d885","front":"How would you describe sternoclavicular joint osteoarthritis/arthropathy?","find":"Sternoclavicular joint space narrowing with subchondral sclerosis, marginal osteophytes, and subchondral cystic change involving the medial clavicle and manubrium. Mild capsular hypertrophy and low-grade periarticular marrow edema. No aggressive erosion or fluid collection.","impr":"Sternoclavicular joint degenerative arthropathy.","pearl":"Commonly degenerative in middle-aged women (condensing osteitis of the medial clavicle is a benign mimic showing triangular sclerosis without joint destruction).","topic":"Chest wall","joint":"shoulder"},
{"id":"d886","front":"How would you describe septic arthritis of the sternoclavicular joint?","find":"Sternoclavicular joint effusion with synovial enhancement, periarticular marrow edema involving the medial clavicle and manubrium, and surrounding soft-tissue edema/phlegmon. Bone erosion and possible adjacent abscess or extension into the mediastinum/retrosternal space. Restricted diffusion within any rim-enhancing collection.","impr":"Septic sternoclavicular arthritis with osteomyelitis; assess for parasternal/mediastinal abscess.","pearl":"Associated with IV drug use and immunocompromise; low threshold for aspiration.","topic":"Chest wall","joint":"shoulder"},
{"id":"d887","front":"How would you describe acromioclavicular joint separation and its Rockwood grading?","find":"Acromioclavicular joint widening with disruption of the AC and coracoclavicular ligaments and increased coracoclavicular distance. Rockwood type I: AC ligament sprain, normal CC distance, no displacement. Type II: AC ligament tear with CC ligament sprain, mild superior clavicular displacement [<25%]. Type III: complete AC and CC ligament tears with superior clavicular displacement, CC distance increased 25-100%. Type IV: posterior clavicular displacement into/through the trapezius. Type V: severe superior displacement, CC distance increased >100-300%. Type VI: inferior (subacromial/subcoracoid) clavicular displacement. Periligamentous edema and distal clavicle/acromion marrow edema.","impr":"Acromioclavicular separation, Rockwood type [III] with coracoclavicular ligament disruption.","pearl":"Types IV-VI and many type III injuries are typically managed surgically; types I-II conservatively.","topic":"Chest wall","joint":"shoulder"},
{"id":"d888","front":"How would you describe a sternalis muscle?","find":"A vertically oriented accessory muscle paralleling the sternum, lying superficial to the pectoralis major and the parasternal portion of the pectoralis fascia, with normal muscle signal. Demonstrates fat planes separating it from the underlying pectoralis. No mass-like enhancement.","impr":"Sternalis muscle, an incidental anatomic variant.","pearl":"Important mimic of a parasternal mass on mammography/CT; recognizing its muscle signal avoids workup.","topic":"Chest wall","joint":"general"},
{"id":"d889","front":"How would you describe a rib stress fracture?","find":"Linear or band-like marrow edema crossing a rib with a faint hypointense fracture line on T1, periosteal edema, and surrounding soft-tissue/intercostal edema. No displacement or aggressive features. Typically in the posterolateral or first rib in repetitive-loading athletes.","impr":"Rib stress fracture.","pearl":"First-rib stress fractures occur in throwing/overhead athletes; lower posterolateral ribs in rowers.","topic":"Chest wall","joint":"general"},
{"id":"d890","front":"How would you describe SAPHO syndrome / sternocostoclavicular hyperostosis?","find":"Hyperostosis, sclerosis, and bony expansion of the manubrium, medial clavicles, and first costal cartilages with marrow edema, ossification of the costoclavicular ligaments, and bridging across the sternocostoclavicular region. Soft-tissue ossification and enthesopathy. Active phase shows marrow edema and enhancement; chronic phase shows dense sclerosis and ankylosis.","impr":"Sternocostoclavicular hyperostosis within the spectrum of SAPHO syndrome.","pearl":"SAPHO = Synovitis, Acne, Pustulosis, Hyperostosis, Osteitis; the anterior chest wall 'bull's head' sign on bone scan is characteristic.","topic":"Chest wall","joint":"general"},
{"id":"d891","front":"How would you describe Tietze syndrome?","find":"Focal nonsuppurative enlargement and edema of a costal cartilage [most often the second or third costochondral junction] with surrounding soft-tissue and perichondral edema and mild enhancement, without erosion or destructive change. Visible/palpable swelling correlates with imaging findings.","impr":"Tietze syndrome (benign costochondral inflammation with cartilaginous swelling).","pearl":"Distinguished from costochondritis by the presence of visible/palpable swelling.","topic":"Chest wall","joint":"general"},
{"id":"d892","front":"How would you describe a snapping scapula / scapulothoracic bursitis?","find":"Fluid distension of the scapulothoracic bursa along the superomedial scapular angle with synovial thickening and enhancement. Associated osseous abnormalities may include a Luschka tubercle, scapular osteochondroma, or bony excrescence at the superomedial angle, with reactive marrow edema. Adjacent muscle (serratus anterior, subscapularis) edema.","impr":"Scapulothoracic bursitis with snapping scapula syndrome; evaluate for underlying osteochondroma/Luschka tubercle.","pearl":"Always search for a bony lesion (osteochondroma) at the superomedial scapular angle as the mechanical trigger.","topic":"Chest wall","joint":"shoulder"},
{"id":"d893","front":"How would you describe a pectoralis major tear?","find":"Disruption of the pectoralis major at the [musculotendinous junction / humeral insertion on the lateral lip of the bicipital groove] with retraction, fluid-filled tendon gap, and hematoma. Quantify retraction and characterize as low-grade partial, high-grade partial, or full-thickness. Assess sternal vs clavicular head involvement and integrity of the tendon footprint. Loss of the normal bilaminar tendon insertion.","impr":"Full-thickness pectoralis major tendon avulsion from the humeral insertion with [X] cm retraction.","pearl":"Distal tendon avulsions in weightlifters (bench press) are surgical; specify sternal vs clavicular head and retraction for repair planning.","topic":"Chest wall","joint":"shoulder"},
{"id":"d894","front":"How would you describe osteitis pubis?","find":"Symmetric subchondral marrow edema flanking the pubic symphysis involving both pubic bodies, with subchondral cystic change, sclerosis, marginal irregularity/erosion, and variable fibrocartilaginous disc degeneration. Periarticular soft-tissue edema and possible secondary cleft sign. No drainable collection.","impr":"Osteitis pubis (chronic stress-related symphyseal osteitis).","pearl":"Common in athletes; symmetry and absence of soft-tissue abscess distinguish from septic symphysitis.","topic":"Pelvis","joint":"general"},
{"id":"d895","front":"How would you describe pubic symphysis instability?","find":"Widening of the pubic symphysis [>10 mm] with vertical (craniocaudal) malalignment of the pubic bodies, often accentuated on flamingo/single-leg-stance views. Marrow edema, subchondral cysts, the secondary cleft sign (curvilinear fluid extending inferolaterally from the symphysis), and degenerated symphyseal disc. Associated adductor/rectus aponeurosis injury.","impr":"Pubic symphyseal instability with secondary cleft sign.","pearl":"The secondary cleft sign indicates microinstability and correlates with adductor/rectus enthesopathy (athletic pubalgia).","topic":"Pelvis","joint":"general"},
{"id":"d896","front":"How would you describe a sacral insufficiency fracture (Honda sign)?","find":"Bilateral vertical T1-hypointense fracture lines through the sacral alae paralleling the SI joints with extensive surrounding marrow edema, joined by a transverse component across the sacral body, producing an H-shaped (Honda sign) pattern. No soft-tissue mass; no cortical destruction.","impr":"Sacral insufficiency fracture with classic H-shaped (Honda sign) edema pattern.","pearl":"Seen in osteoporosis, pelvic radiation, and chronic steroid use; the H/Honda pattern is pathognomonic and avoids misdiagnosis as metastasis.","topic":"Pelvis","joint":"general"},
{"id":"d897","front":"How would you describe a sacral stress (fatigue) fracture in an athlete?","find":"Unilateral vertical band of alar marrow edema paralleling the SI joint with a hypointense fracture line on T1, periosteal edema, and no soft-tissue mass. Occurs in distance runners/military recruits with normal bone density.","impr":"Sacral fatigue stress fracture (zone I, alar).","pearl":"Fatigue fracture = normal bone, abnormal load (athlete); insufficiency = abnormal bone, normal load (osteoporosis).","topic":"Pelvis","joint":"general"},
{"id":"d898","front":"How would you describe coccydynia / coccygeal abnormality on MRI?","find":"Coccygeal angulation or subluxation at the sacrococcygeal or intercoccygeal joint with marrow edema, retrococcygeal soft-tissue edema, and possible bursal fluid anterior to the coccyx. Evaluate for fracture, hypermobility, or a coccygeal spicule. No mass or destructive lesion.","impr":"Coccydynia with sacrococcygeal/intercoccygeal subluxation and retrococcygeal edema.","pearl":"Dynamic sitting/standing radiographs assess hypermobility; MRI excludes mass and characterizes marrow edema.","topic":"Pelvis","joint":"general"},
{"id":"d899","front":"How would you describe mechanical versus inflammatory sacroiliitis?","find":"Inflammatory sacroiliitis: bilateral (often symmetric) periarticular subchondral marrow edema/osteitis, erosions, subchondral sclerosis, fatty marrow metaplasia, capsulitis, enthesitis, and ankylosis; iliac and sacral sides both involved. Mechanical/degenerative: focal anteroinferior subchondral sclerosis (predominantly iliac), osteophytes, vacuum phenomenon, and limited edema without erosions; osteitis condensans ilii shows triangular iliac-sided sclerosis without erosion.","impr":"Findings favor [inflammatory (active sacroiliitis) vs mechanical/degenerative] SI joint disease.","pearl":"ASAS criteria require subchondral bone marrow edema clearly in a periarticular location on STIR for active inflammatory sacroiliitis.","topic":"Pelvis","joint":"spine"},
{"id":"d900","front":"How would you describe an obturator (externus/internus) abnormality or obturator hernia?","find":"Obturator externus/internus muscle edema or tear with intramuscular fluid; for obturator hernia, a bowel-containing sac passing through the obturator canal between the pectineus and obturator externus, with possible obstruction. Assess for fatty atrophy and enhancement.","impr":"Obturator hernia traversing the obturator canal [with small-bowel obstruction].","pearl":"Obturator hernia classically in elderly thin women; Howship-Romberg sign (medial thigh pain) is the clinical clue.","topic":"Pelvis","joint":"general"},
{"id":"d901","front":"How would you describe scoliosis on imaging?","find":"Lateral curvature of the spine measured by the Cobb angle between the most-tilted end vertebrae [report apex level, convexity side, and Cobb angle in degrees]. Note rotational component (pedicle/spinous process rotation), structural versus compensatory curves, sagittal balance, and any underlying congenital (hemivertebra, bar) or neuromuscular cause. Assess for cord/canal compromise.","impr":"[Right thoracic] scoliosis, apex [T8], Cobb angle [X] degrees.","pearl":"A left thoracic curve or atypical/rapidly progressive curve warrants MRI to exclude an intraspinal cause (syrinx, tumor, Chiari).","topic":"Spine","joint":"spine"},
{"id":"d902","front":"How would you describe a tethered cord?","find":"Low-lying conus medullaris terminating below the L2-L3 level with a thickened [>2 mm] and/or fatty filum terminale, posterior displacement of the cord against the dorsal thecal sac, and reduced normal CSF motion. Search for associated lipoma, dermal sinus, diastematomyelia, or spinal dysraphism.","impr":"Tethered cord syndrome with low-lying conus and thickened/fatty filum terminale.","pearl":"Normal conus tip is at or above L2-L3 by term; a conus below L2-L3 plus a thick/fatty filum confirms tethering.","topic":"Spine","joint":"spine"},
{"id":"d903","front":"How would you describe conus medullaris position and a conus lesion?","find":"The conus medullaris normally terminates at the T12-L2 level [report exact level]. A conus lesion is described by intramedullary T2 signal, enhancement pattern, expansion, and associated cysts/syrinx; specify intramedullary versus exophytic. Note effect on adjacent nerve roots of the cauda equina.","impr":"[Normal conus position at L1] OR [Intramedullary conus lesion at L1 — differential includes ependymoma, astrocytoma].","pearl":"Myxopapillary ependymoma is the classic conus/filum tumor and may hemorrhage.","topic":"Spine","joint":"spine"},
{"id":"d904","front":"How would you describe a filum terminale lipoma?","find":"A linear focus of T1- and T2-hyperintense signal that suppresses on fat-saturated sequences within or along the filum terminale, with associated filar thickening. Assess conus level for tethering. No enhancement or soft-tissue mass.","impr":"Filum terminale (fibrolipoma) lipoma; correlate for tethered cord if conus is low-lying.","pearl":"A small fatty filum can be an incidental normal variant; significance rises when the conus is low-lying or symptoms are present.","topic":"Spine","joint":"spine"},
{"id":"d905","front":"How would you describe dural ectasia?","find":"Widening of the dural sac with posterior vertebral body scalloping, enlarged/widened neural foramina, thinned pedicles, and meningoceles/nerve root sleeve dilatation, predominantly in the lower lumbar and sacral spine. Measure the dural sac ratio.","impr":"Dural ectasia.","pearl":"A major diagnostic criterion for Marfan syndrome; also seen in neurofibromatosis type 1, Ehlers-Danlos, and ankylosing spondylitis.","topic":"Spine","joint":"spine"},
{"id":"d906","front":"How would you describe a facet (zygapophyseal) synovial cyst?","find":"A well-defined juxta-articular cystic lesion arising from a degenerated facet joint, with variable T2 signal (often with low-signal hemosiderin/calcified rim) and peripheral enhancement, projecting into the [posterolateral epidural space / lateral recess] and compressing the traversing nerve root or thecal sac. Associated facet arthrosis and effusion.","impr":"Lumbar facet synovial cyst [at L4-L5] with lateral recess narrowing and nerve root compression.","pearl":"Almost always associated with facet osteoarthritis and segmental instability; recurs if instability is untreated.","topic":"Spine","joint":"spine"},
{"id":"d907","front":"How would you describe DISH (diffuse idiopathic skeletal hyperostosis)?","find":"Flowing ossification along the anterolateral aspect of at least four contiguous vertebral bodies bridging the disc spaces, with relative preservation of disc height and absence of significant facet ankylosis or SI joint erosion/fusion. Anterior longitudinal ligament ossification and possible dysphagia from cervical osteophytes.","impr":"Diffuse idiopathic skeletal hyperostosis (DISH).","pearl":"Distinguished from ankylosing spondylitis by preserved disc heights, lack of sacroiliitis, and flowing (rather than thin/marginal) syndesmophytes; DISH spines fracture easily after minor trauma.","topic":"Spine","joint":"spine"},
{"id":"d908","front":"How would you describe ankylosis in ankylosing spondylitis?","find":"Thin marginal vertically oriented syndesmophytes bridging vertebral bodies producing a 'bamboo spine', squaring of vertebral bodies with shiny corners (Romanus lesions/corner marrow edema), facet and SI joint fusion, and ossification of the interspinous ligaments (dagger sign). Active disease shows corner/vertebral marrow edema.","impr":"Ankylosing spondylitis with bamboo spine and fused sacroiliac joints.","pearl":"The rigid fused spine is prone to unstable three-column (Andersson) fractures after minor trauma; image the entire spine.","topic":"Spine","joint":"spine"},
{"id":"d909","front":"How would you describe a typical vertebral hemangioma versus an aggressive one?","find":"Typical: a well-defined intraosseous lesion with coarse vertical trabeculae ('corduroy'/'polka-dot') that is T1- and T2-hyperintense owing to fat content, with no cortical breach or soft-tissue component. Aggressive: low T1 signal (decreased fat), high T2 signal, extraosseous/epidural soft-tissue extension, cortical expansion, and avid enhancement, potentially causing cord compression.","impr":"[Typical (fatty) vertebral hemangioma — incidental] OR [Aggressive vertebral hemangioma with epidural extension].","pearl":"Loss of the normal high T1 fat signal and the presence of epidural soft tissue signal an aggressive hemangioma at risk for cord compression.","topic":"Spine","joint":"spine"},
{"id":"d910","front":"How would you describe benign versus malignant vertebral compression fracture?","find":"Benign (osteoporotic/acute): preserved (band-like, retropulsion-sparing) marrow signal with a horizontal fracture line, retropulsed posterior fragment, fluid sign, normal posterior elements, and preserved marrow elsewhere. Malignant: complete/convex (bulging) posterior cortex, pedicle/posterior-element involvement, focal or diffuse marrow replacement (low T1), epidural/paraspinal soft-tissue mass, and additional discrete bony lesions.","impr":"Vertebral compression fracture with features favoring [benign osteoporotic vs pathologic/malignant] etiology.","pearl":"Convex posterior cortical bulge, pedicle involvement, and a paraspinal soft-tissue mass favor malignancy; the 'fluid sign' and band-like edema favor benign.","topic":"Spine","joint":"spine"},
{"id":"d911","front":"How would you describe a hibernoma?","find":"A well-circumscribed soft-tissue mass that is predominantly fat-signal (T1- and T2-hyperintense, suppressing on fat-sat) but with intervening non-suppressing internal septa/branching vessels and intermediate-signal components, showing prominent flow voids and avid enhancement. Common in the thigh, scapular region, and retroperitoneum.","impr":"Hibernoma (benign brown-fat tumor).","pearl":"More vascular/enhancing and FDG-avid than a simple lipoma owing to brown fat; can mimic a well-differentiated liposarcoma.","topic":"Soft tissue","joint":"general"},
{"id":"d912","front":"How would you describe fibrolipomatous hamartoma of nerve?","find":"Fusiform enlargement of a nerve [most often the median nerve] with thickened nerve fascicles surrounded by and interspersed with fat, producing a 'coaxial cable'/'spaghetti' appearance on axial and longitudinal images respectively, without enhancement. Fat suppresses on fat-sat sequences.","impr":"Fibrolipomatous hamartoma of the median nerve.","pearl":"Pathognomonic 'coaxial cable' appearance; frequently associated with macrodystrophia lipomatosa (digital macrodactyly).","topic":"Soft tissue","joint":"general"},
{"id":"d913","front":"How would you describe macrodystrophia lipomatosa?","find":"Localized overgrowth (gigantism) of a digit/extremity with marked fibrofatty proliferation in the subcutaneous and deep tissues, splaying of fat along a nerve distribution, and associated osseous overgrowth/degenerative change. Fat-signal predominance suppressing on fat-sat.","impr":"Macrodystrophia lipomatosa (localized fibrolipomatous overgrowth/macrodactyly).","pearl":"Often coexists with fibrolipomatous hamartoma of nerve; growth is along a specific nerve territory (median/plantar).","topic":"Soft tissue","joint":"general"},
{"id":"d914","front":"How would you describe melorheostosis?","find":"Undulating, flowing cortical hyperostosis resembling 'dripping candle wax' along the [long bone] cortex, typically in a sclerotomal distribution affecting one limb, with associated soft-tissue ossification/contracture. Marrow signal is preserved beneath dense cortical thickening.","impr":"Melorheostosis ('flowing candle wax' cortical hyperostosis).","pearl":"Follows a sclerotomal (single nerve segment) distribution; usually monomelic and may cause pain and joint contracture.","topic":"Bone","joint":"general"},
{"id":"d915","front":"How would you describe osteopoikilosis?","find":"Numerous small, well-defined, round/ovoid sclerotic foci clustered in a periarticular and epiphyseal/metaphyseal distribution, symmetric and bilateral, low signal on all MRI sequences with no marrow edema, soft-tissue component, or uptake on bone scan.","impr":"Osteopoikilosis (benign 'spotted bone' enostosis).","pearl":"Photopenic/normal on bone scan, helping distinguish from blastic metastases; may be associated with connective-tissue nevi in Buschke-Ollendorff syndrome.","topic":"Bone","joint":"general"},
{"id":"d916","front":"How would you describe a bone infarct versus an enchondroma?","find":"Bone infarct: a serpentine geographic lesion with a peripheral sclerotic/T2-hyperintense rim ('double-line sign') enclosing central fat-signal marrow, located diametaphyseally, without chondroid matrix. Enchondroma: a lobulated medullary lesion with internal arcs-and-rings/punctate chondroid mineralization, mildly T2-hyperintense lobules, and peripheral/septal enhancement, without aggressive features.","impr":"[Medullary bone infarct with serpiginous double-line sign] OR [Enchondroma with chondroid matrix].","pearl":"The serpentine peripheral double-line sign and central fat signal define an infarct; rings-and-arcs chondroid matrix defines an enchondroma — endosteal scalloping or pain raises concern for chondrosarcoma.","topic":"Bone","joint":"general"},
{"id":"d917","front":"How would you describe periosteal reaction patterns as a standalone descriptor?","find":"Benign/non-aggressive patterns: solid, thick, uniform, or wavy/undulating periosteal new bone. Aggressive patterns: laminated/'onion-skin' multilayered periosteum, spiculated 'sunburst'/'hair-on-end' perpendicular reaction, and a Codman triangle (periosteal elevation at the lesion margin). Describe location, continuity, and associated marrow/soft-tissue findings.","impr":"[Solid/benign] versus [interrupted/aggressive (onion-skin, sunburst, Codman triangle)] periosteal reaction.","pearl":"Continuity and thickness reflect biologic aggressiveness: uninterrupted/solid = slow/benign; interrupted/lamellated/spiculated = rapid/aggressive.","topic":"Bone","joint":"general"},
{"id":"d918","front":"How would you describe a Maisonneuve fracture?","find":"Spiral fracture of the proximal fibula (within ~6 cm of the fibular head) with marrow edema and a transverse cortical break. Associated disruption of the distal tibiofibular syndesmosis (anteroinferior tibiofibular and interosseous ligaments) with widening of the tibiofibular clear space measuring [__] mm. Tear of the deep deltoid ligament and/or transverse medial malleolar fracture, with medial clear space widening to [__] mm. Tibiotalar joint demonstrates lateral talar shift.","impr":"Maisonneuve injury: proximal fibular fracture with syndesmotic disruption and deltoid/medial malleolar failure — an unstable ankle.","pearl":"Always image the proximal fibula when the medial clear space is widened without a visible distal fibular fracture.","topic":"Fracture","joint":"ankle"},
{"id":"d919","front":"How would you describe a Weber A fibular fracture?","find":"Transverse avulsion-type fracture of the distal fibula BELOW the level of the tibiotalar joint line (infrasyndesmotic), with marrow edema and a horizontally oriented lucent line. The distal tibiofibular syndesmosis is intact and the tibiofibular/medial clear spaces are preserved. May be accompanied by oblique vertical medial malleolar fracture.","impr":"Weber A (infrasyndesmotic) lateral malleolar fracture — typically stable.","pearl":"Mechanism is supination-adduction; look for the associated vertical medial malleolar fracture.","topic":"Fracture","joint":"ankle"},
{"id":"d920","front":"How would you describe a Weber B fibular fracture?","find":"Oblique or spiral fracture of the distal fibula AT the level of the tibiotalar joint (transsyndesmotic), extending from anteroinferior to posterosuperior, with marrow edema. Variable syndesmotic injury — assess the tibiofibular clear space ([__] mm) and anteroinferior tibiofibular ligament. Evaluate the medial side for deltoid tear or medial malleolar fracture and medial clear space widening ([__] mm).","impr":"Weber B (transsyndesmotic) lateral malleolar fracture — stability depends on medial-side integrity.","pearl":"Medial-side injury (deltoid tear or medial malleolar fracture) converts a Weber B into an unstable bimalleolar-equivalent.","topic":"Fracture","joint":"ankle"},
{"id":"d921","front":"How would you describe a Weber C fibular fracture?","find":"Fracture of the fibula ABOVE the level of the tibiotalar joint (suprasyndesmotic) with marrow edema. Obligate disruption of the distal tibiofibular syndesmosis below the fracture, with widening of the tibiofibular clear space to [__] mm. Medial-side failure with deltoid ligament tear or medial malleolar fracture and medial clear space widening ([__] mm); lateral talar shift.","impr":"Weber C (suprasyndesmotic) fibular fracture — unstable with syndesmotic disruption.","pearl":"The higher the fibular fracture, the longer the segment of torn syndesmosis and the greater the instability (pronation-external rotation).","topic":"Fracture","joint":"ankle"},
{"id":"d922","front":"How would you describe a Bosworth fracture-dislocation?","find":"Fracture of the distal fibula with fixed posterior dislocation of the proximal fibular fragment behind the posterolateral tibial ridge, where it becomes entrapped/locked. Marrow edema at the fracture and the trapped proximal segment lies posterior to the tibia. Associated syndesmotic disruption and the ankle mortise is malaligned and irreducible by closed means.","impr":"Bosworth fracture-dislocation: posteriorly entrapped fibula behind the tibia — irreducible, requires open reduction.","pearl":"Recognize the fibula locked behind the tibial ridge; closed reduction will fail.","topic":"Dislocation","joint":"ankle"},
{"id":"d923","front":"How would you describe a Lisfranc fracture-dislocation?","find":"Disruption of the tarsometatarsal complex with malalignment at the Lisfranc joint. Avulsion fragment in the first intermetatarsal/Lisfranc interval ('fleck sign') with marrow edema at the base of the second metatarsal and medial cuneiform. Tear or detachment of the Lisfranc ligament (dorsal, interosseous, plantar bundles); the medial border of the second metatarsal base is malaligned with the medial border of the middle cuneiform. Diastasis between the first and second metatarsal bases measuring [__] mm.","impr":"Lisfranc fracture-dislocation with tarsometatarsal instability.","pearl":"On MRI, focus on the plantar Lisfranc ligament from medial cuneiform to bases of second/third metatarsals — its integrity dictates stability.","topic":"Fracture","joint":"foot"},
{"id":"d924","front":"How would you describe a Chopart fracture-dislocation?","find":"Injury through the midtarsal (Chopart) joint — the talonavicular and calcaneocuboid articulations. Fracture fragments and marrow edema involving the navicular, cuboid (compression/'nutcracker' pattern) and/or anterior process of the calcaneus, with malalignment across the midtarsal line. Associated ligamentous disruption (bifurcate, dorsal talonavicular).","impr":"Chopart (midtarsal) fracture-dislocation.","pearl":"Look for a lateral cuboid compression fracture and medial avulsion — the nutcracker mechanism of midtarsal injury.","topic":"Fracture","joint":"foot"},
{"id":"d925","front":"How would you describe a Jones fracture?","find":"Transverse fracture at the metaphyseal-diaphyseal junction of the fifth metatarsal, located [__] mm distal to the tuberosity and involving the fourth-fifth intermetatarsal articulation, with marrow edema and a transverse fracture line. No proximal extension into the tuberosity.","impr":"Jones fracture (zone 2, metadiaphyseal junction of the fifth metatarsal).","pearl":"This zone is a watershed for blood supply — high nonunion risk, unlike the more proximal pseudo-Jones avulsion.","topic":"Fracture","joint":"foot"},
{"id":"d926","front":"How would you describe a pseudo-Jones fracture?","find":"Avulsion fracture of the proximal tuberosity (styloid) of the fifth metatarsal at the insertion of the peroneus brevis / lateral band of the plantar fascia, with marrow edema and a fracture line oriented transverse to the metatarsal axis (do not mistake for the longitudinally oriented apophysis). The fracture lies proximal to the fourth-fifth intermetatarsal joint.","impr":"Pseudo-Jones (avulsion) fracture of the fifth metatarsal tuberosity.","pearl":"An apophysis runs parallel to the shaft; an avulsion fracture runs transverse to it.","topic":"Fracture","joint":"foot"},
{"id":"d927","front":"How would you describe a calcaneal fracture (Sanders classification)?","find":"Comminuted intra-articular fracture of the calcaneus with marrow edema and depression of the posterior subtalar facet; the Bohler angle is decreased to [__] degrees (normal 20-40) and Gissane angle increased. Number and location of articular fracture lines on the coronal/semicoronal plane determine the Sanders type (I nondisplaced; II one line/two fragments; III two lines/three fragments; IV >3 fragments, comminuted).","impr":"Intra-articular calcaneal fracture, Sanders type [__], with posterior facet involvement.","pearl":"Sanders grading is based on the coronal CT/MRI at the widest posterior facet — number of articular fragments predicts outcome.","topic":"Fracture","joint":"foot"},
{"id":"d928","front":"How would you describe a talar neck fracture (Hawkins classification)?","find":"Fracture through the talar neck with marrow edema and a fracture line separating head from body. Classify by displacement: Hawkins I nondisplaced; II with subtalar subluxation/dislocation; III with subtalar and tibiotalar dislocation; IV with additional talonavicular dislocation. Assess body marrow signal for early osteonecrosis.","impr":"Talar neck fracture, Hawkins type [__].","pearl":"The more dislocated the fracture, the higher the avascular necrosis risk; loss of subchondral signal/sclerosis of the talar dome signals AVN.","topic":"Fracture","joint":"ankle"},
{"id":"d929","front":"How would you describe a Tillaux fracture?","find":"Salter-Harris III avulsion fracture of the anterolateral distal tibial epiphysis at the insertion of the anteroinferior tibiofibular ligament, in an adolescent with a partially fused physis. Marrow edema and an intra-articular fracture line with epiphyseal fragment displacement of [__] mm.","impr":"Tillaux fracture: SH III avulsion of the anterolateral tibial epiphysis.","pearl":"Occurs during the transitional period when the medial physis has fused but the lateral remains open; the AITFL avulses the unfused lateral epiphysis.","topic":"Fracture","joint":"ankle"},
{"id":"d930","front":"How would you describe a pilon fracture?","find":"Comminuted intra-articular fracture of the distal tibial plafond from axial loading, with marrow edema, articular impaction and depression of the weightbearing tibial plafond, and a fracture line extending into the tibiotalar joint. Associated fibular fracture and articular step-off measuring [__] mm; assess for chondral injury of the talar dome.","impr":"Pilon (tibial plafond) fracture with intra-articular comminution and impaction.","pearl":"Distinguish from a rotational malleolar fracture — pilon is an axial-loading injury with central plafond impaction.","topic":"Fracture","joint":"ankle"},
{"id":"d931","front":"How would you describe an accessory navicular (os naviculare) stress injury?","find":"Type II accessory navicular synchondrosis with marrow edema spanning both the os and the adjacent navicular tuberosity, fluid signal across the synchondrosis, and edema/thickening at the posterior tibial tendon insertion. No discrete acute cortical fracture line; findings indicate chronic stress across the synchondrosis.","impr":"Symptomatic type II accessory navicular with synchondrosis stress reaction.","pearl":"Bilateral marrow edema bridging the synchondrosis with posterior tibial tendinosis confirms a symptomatic os naviculare.","topic":"Fracture","joint":"foot"},
{"id":"d932","front":"How would you describe a deep lateral femoral notch sign?","find":"Abnormally deep osteochondral impaction of the lateral femoral condyle at the condylopatellar sulcus measuring > 1.5 mm in depth, with subjacent marrow edema, representing a pivot-shift impaction injury. Associated kissing bone contusion of the posterolateral tibial plateau.","impr":"Deep lateral femoral notch sign — pivot-shift impaction indicating ACL rupture.","pearl":"A condylopatellar sulcus deeper than 1.5-2 mm is highly specific for an acute ACL tear.","topic":"Fracture","joint":"knee"},
{"id":"d933","front":"How would you describe a tibial plateau fracture (Schatzker classification)?","find":"Intra-articular fracture of the proximal tibia with marrow edema and an articular fracture line; characterize per Schatzker: I lateral split; II lateral split-depression; III pure lateral central depression; IV medial plateau; V bicondylar; VI metaphyseal-diaphyseal dissociation. Quantify articular depression/widening ([__] mm) and assess associated meniscal and cruciate/collateral ligament injury.","impr":"Tibial plateau fracture, Schatzker type [__].","pearl":"Medial plateau (Schatzker IV) and bicondylar (V/VI) patterns carry high rates of peroneal nerve and popliteal vascular injury — describe the soft tissues.","topic":"Fracture","joint":"knee"},
{"id":"d934","front":"How would you describe a tibial spine (eminence) avulsion fracture?","find":"Avulsion fracture of the anterior tibial eminence at the ACL footprint, with marrow edema and an elevated bony fragment; classify by displacement (Meyers-McKeever I nondisplaced; II hinged/partially elevated; III completely displaced). The ACL fibers remain in continuity with the avulsed fragment.","impr":"Tibial eminence avulsion — the bony equivalent of an ACL tear.","pearl":"Common in skeletally immature patients; the ACL avulses its bony attachment rather than tearing midsubstance.","topic":"Fracture","joint":"knee"},
{"id":"d935","front":"How would you describe an arcuate sign (fibular head avulsion)?","find":"Avulsion fracture of the fibular styloid (head) at the insertion of the arcuate ligament complex / conjoined posterolateral structures, with marrow edema and a small cortical fragment displaced superomedially. Associated posterolateral corner injury, often with PCL and/or ACL tears.","impr":"Arcuate sign — fibular styloid avulsion indicating posterolateral corner disruption.","pearl":"Even a tiny fibular tip avulsion mandates a search for PLC and cruciate injury — these are frequently missed unstable knees.","topic":"Fracture","joint":"knee"},
{"id":"d936","front":"How would you describe a femoral neck fracture (Garden and Pauwels)?","find":"Intracapsular fracture through the femoral neck with marrow edema and a fracture line; grade per Garden (I incomplete/valgus impacted; II complete nondisplaced; III complete partially displaced with disrupted trabeculae; IV completely displaced). Pauwels angle of the fracture line relative to horizontal measures [__] degrees (I <30, II 30-50, III >50) predicting shear instability.","impr":"Femoral neck fracture, Garden [__] / Pauwels [__].","pearl":"Higher Pauwels (more vertical) angles and displaced Garden grades increase shear, nonunion, and femoral head osteonecrosis risk.","topic":"Fracture","joint":"hip"},
{"id":"d937","front":"How would you describe a Pipkin (femoral head) fracture?","find":"Fracture of the femoral head, typically associated with posterior hip dislocation, with marrow edema and an articular fragment. Classify by Pipkin: I fragment inferior to the fovea; II fragment superior to the fovea (weightbearing); III with associated femoral neck fracture; IV with associated acetabular fracture. Assess for intra-articular fragments and labral injury.","impr":"Pipkin femoral head fracture, type [__], post-dislocation.","pearl":"Fragments superior to the fovea (type II) involve the weightbearing surface and carry worse prognosis; exclude AVN on follow-up.","topic":"Fracture","joint":"hip"},
{"id":"d938","front":"How would you describe an acetabular column fracture?","find":"Fracture of the acetabulum with marrow edema; characterize by Letournel columns — anterior column (iliopubic) versus posterior column (ilioischial), wall versus column, transverse, and associated patterns. Assess articular step-off ([__] mm), comminution, marginal impaction, and intra-articular fragments; evaluate the femoral head for impaction.","impr":"Acetabular fracture involving the [anterior/posterior] column.","pearl":"Disruption of the iliopubic line indicates anterior column, the ilioischial line indicates posterior column — map both to classify the pattern.","topic":"Fracture","joint":"hip"},
{"id":"d939","front":"How would you describe sacral insufficiency fractures (Honda sign)?","find":"Bilateral vertically oriented marrow edema and fracture lines through the sacral alae paralleling the sacroiliac joints, connected by a horizontal component across the sacral body — producing an H- or Honda-shaped pattern of edema/uptake. Low-signal fracture lines on T1 within the edema; no soft tissue mass.","impr":"Sacral insufficiency fractures in an H (Honda) configuration.","pearl":"In an osteoporotic patient with low back/pelvic pain, the Honda sign is diagnostic of insufficiency fracture, not malignancy.","topic":"Fracture","joint":"general"},
{"id":"d940","front":"How would you describe a pelvic apophyseal avulsion fracture?","find":"Avulsion of an apophysis at a muscular origin with marrow edema and a displaced cortical fragment: ASIS (sartorius/tensor fasciae latae), AIIS (rectus femoris direct head), ischial tuberosity (hamstring origin), lesser trochanter (iliopsoas), iliac crest (abdominal wall), or pubic symphysis (adductors). Fragment displacement measures [__] mm with adjacent muscle/tendon edema.","impr":"Apophyseal avulsion fracture at the [named] origin.","pearl":"A lesser trochanter avulsion in an ADULT (non-athlete) is pathologic until proven otherwise — search for underlying metastasis.","topic":"Fracture","joint":"general"},
{"id":"d941","front":"How would you describe a pubic rami fracture?","find":"Fracture(s) of the superior and/or inferior pubic ramus with marrow edema and a fracture line; assess for unilateral versus bilateral involvement and associated posterior pelvic ring injury (sacral ala or SI joint). Evaluate for adjacent hematoma; in elderly patients consider insufficiency etiology.","impr":"Pubic rami fracture(s); assess posterior ring for combined instability.","pearl":"An anterior ring (rami) fracture is rarely isolated — always interrogate the posterior ring (sacrum/SI joints) for a second break.","topic":"Fracture","joint":"general"},
{"id":"d942","front":"How would you describe a scaphoid waist fracture?","find":"Transverse fracture through the scaphoid waist with marrow edema and a low-signal T1 fracture line; assess for displacement/offset ([__] mm) and humpback deformity. Critically evaluate the proximal pole for diminished marrow signal indicating compromised retrograde blood supply and early osteonecrosis. Assess scapholunate alignment.","impr":"Scaphoid waist fracture; evaluate proximal pole vascularity.","pearl":"Retrograde blood supply means proximal pole fractures risk AVN and nonunion — comment specifically on proximal pole marrow signal.","topic":"Fracture","joint":"wrist"},
{"id":"d943","front":"How would you describe a Colles fracture?","find":"Extra-articular fracture of the distal radial metaphysis with DORSAL angulation and dorsal displacement of the distal fragment, marrow edema, and dorsal cortical impaction. Loss of normal volar tilt (dorsal tilt measuring [__] degrees); assess for associated ulnar styloid avulsion and DRUJ involvement.","impr":"Colles fracture: dorsally angulated extra-articular distal radius fracture.","pearl":"Classic 'dinner-fork' deformity from a FOOSH; the apex-volar/dorsal-tilt distinguishes it from Smith.","topic":"Fracture","joint":"wrist"},
{"id":"d944","front":"How would you describe a Smith fracture?","find":"Extra-articular fracture of the distal radius with VOLAR angulation and volar displacement of the distal fragment ('reverse Colles'), marrow edema, and volar cortical impaction. Increased volar tilt measuring [__] degrees; assess DRUJ and ulnar styloid.","impr":"Smith fracture: volarly angulated distal radius fracture.","pearl":"Volar tilt of the distal fragment is the mirror image of Colles and is mechanically unstable, often requiring fixation.","topic":"Fracture","joint":"wrist"},
{"id":"d945","front":"How would you describe a Barton fracture (dorsal and volar)?","find":"INTRA-articular fracture-dislocation of the distal radius in which a rim fragment displaces with the carpus. Dorsal Barton: dorsal articular rim fragment with dorsal subluxation of the carpus. Volar Barton: volar articular rim fragment with volar carpal subluxation. Marrow edema, intra-articular fracture line, and radiocarpal malalignment with articular step-off measuring [__] mm.","impr":"Barton fracture-dislocation ([dorsal/volar] rim) of the distal radius.","pearl":"The hallmark is carpal subluxation following the displaced articular rim fragment — it is a fracture-dislocation, not a simple fracture.","topic":"Fracture","joint":"wrist"},
{"id":"d946","front":"How would you describe a chauffeur (Hutchinson) fracture?","find":"Intra-articular oblique fracture of the radial styloid with marrow edema and a fracture line extending into the radiocarpal joint, often at the attachment of the radioscaphocapitate/radial collateral ligaments. Assess for associated scapholunate ligament disruption and SL widening ([__] mm).","impr":"Chauffeur (Hutchinson) fracture of the radial styloid.","pearl":"The radial styloid is the anchor for extrinsic radiocarpal ligaments — look for an associated scapholunate or perilunate injury.","topic":"Fracture","joint":"wrist"},
{"id":"d947","front":"How would you describe a die-punch fracture?","find":"Depressed intra-articular fracture of the lunate fossa of the distal radius, where the lunate is driven into the articular surface, with focal marrow edema and articular depression measuring [__] mm. Assess for sigmoid notch/DRUJ involvement and chondral damage of the lunate fossa.","impr":"Die-punch fracture: depressed lunate fossa of the distal radius.","pearl":"Even small articular step-off in the lunate fossa predisposes to radiocarpal arthrosis — measure depression precisely.","topic":"Fracture","joint":"wrist"},
{"id":"d948","front":"How would you describe a Bennett fracture?","find":"Intra-articular fracture-dislocation at the base of the first metacarpal: a small volar-ulnar fragment (the 'beak') remains attached to the anterior oblique ligament at the trapezium, while the metacarpal shaft subluxes/dislocates radially and proximally under abductor pollicis longus pull. Marrow edema and articular incongruity at the first CMC joint with displacement of [__] mm.","impr":"Bennett fracture-dislocation of the thumb metacarpal base.","pearl":"The intact volar-ulnar beak fragment is the stable anchor; the shaft is pulled away by APL — describe the subluxation direction.","topic":"Fracture","joint":"hand"},
{"id":"d949","front":"How would you describe a Rolando fracture?","find":"Comminuted intra-articular fracture of the base of the first metacarpal in a Y- or T-configuration (versus the two-part Bennett), with marrow edema, multiple articular fragments, and incongruity of the first CMC joint. Quantify articular step-off ([__] mm) and comminution.","impr":"Rolando fracture: comminuted intra-articular thumb metacarpal base fracture.","pearl":"A comminuted (3+ fragment) thumb base fracture is a Rolando; it carries a worse prognosis than the two-part Bennett.","topic":"Fracture","joint":"hand"},
{"id":"d950","front":"How would you describe a boxer's fracture?","find":"Fracture of the neck of the fifth (or fourth) metacarpal with marrow edema and VOLAR angulation of the distal fragment/metacarpal head, measuring [__] degrees of apex-dorsal angulation. Assess for rotational malalignment and associated extensor/dorsal soft tissue injury.","impr":"Boxer's fracture: volarly angulated fifth metacarpal neck fracture.","pearl":"Report the degree of volar angulation and any rotational deformity — these drive the decision to reduce.","topic":"Fracture","joint":"hand"},
{"id":"d951","front":"How would you describe a gamekeeper's/skier's thumb avulsion?","find":"Avulsion fracture at the base of the proximal phalanx of the thumb at the insertion of the ulnar collateral ligament of the first MCP joint, with marrow edema and a displaced fragment. Assess UCL integrity and for a Stener lesion — the torn distal UCL displaced superficial to the adductor aponeurosis.","impr":"Gamekeeper/skier thumb: UCL avulsion of the first MCP joint; exclude Stener lesion.","pearl":"A Stener lesion (UCL retracted above the adductor aponeurosis) cannot heal without surgery — always specify its presence or absence.","topic":"Fracture","joint":"hand"},
{"id":"d952","front":"How would you describe a Galeazzi fracture-dislocation?","find":"Fracture of the distal third of the RADIAL shaft with marrow edema and angulation, accompanied by dislocation/subluxation of the distal radioulnar joint (widened DRUJ, dorsal/volar ulnar head displacement) and disruption of the triangular fibrocartilage complex. DRUJ widening measures [__] mm.","impr":"Galeazzi fracture-dislocation: distal radial shaft fracture with DRUJ disruption.","pearl":"The fracture of necessity — never accept an isolated distal radial shaft fracture without scrutinizing the DRUJ.","topic":"Fracture","joint":"general"},
{"id":"d953","front":"How would you describe a Monteggia fracture-dislocation?","find":"Fracture of the proximal ULNA (typically with apex-anterior angulation) accompanied by dislocation of the radial head, with marrow edema at the ulnar fracture and malalignment of the radiocapitellar line. Assess annular ligament disruption and the direction of radial head dislocation (Bado type).","impr":"Monteggia fracture-dislocation: proximal ulnar fracture with radial head dislocation.","pearl":"The radiocapitellar line must intersect the capitellum in all views — if it does not with an ulnar fracture, the radial head is dislocated.","topic":"Fracture","joint":"general"},
{"id":"d954","front":"How would you describe a radial head fracture (Mason classification)?","find":"Fracture of the radial head with marrow edema and an articular fracture line; classify per Mason: I nondisplaced; II displaced/depressed (>2 mm step or >30% articular surface); III comminuted involving the entire head; IV with associated elbow dislocation. Assess articular step-off ([__] mm), joint effusion/lipohemarthrosis, and for capitellar chondral injury.","impr":"Radial head fracture, Mason type [__].","pearl":"An elbow effusion with anterior and posterior fat-pad signs and no visible fracture should prompt a search for a subtle radial head fracture.","topic":"Fracture","joint":"elbow"},
{"id":"d955","front":"How would you describe a coronoid process fracture (Regan-Morrey)?","find":"Fracture of the coronoid process of the ulna with marrow edema and a fracture line; grade per Regan-Morrey: I tip avulsion; II <50% of the coronoid height; III >50% of the height. Assess for anterior elbow instability, brachialis insertion involvement, and associated radial head fracture/dislocation.","impr":"Coronoid process fracture, Regan-Morrey type [__].","pearl":"The coronoid is the key anterior buttress against posterior subluxation — even tip fractures may signal an unstable elbow.","topic":"Fracture","joint":"elbow"},
{"id":"d956","front":"How would you describe a terrible triad of the elbow?","find":"Triad of elbow injuries: posterior/posterolateral elbow dislocation, radial head fracture, and coronoid process fracture. Marrow edema at the radial head and coronoid, disruption of the lateral collateral (lateral ulnar collateral) ligament complex, and frequently the anterior band of the medial collateral ligament; recurrent posterolateral rotatory instability.","impr":"Terrible triad of the elbow: dislocation with radial head and coronoid fractures.","pearl":"Name all three components plus the LUCL tear — this combination is highly unstable and almost always operative.","topic":"Fracture","joint":"elbow"},
{"id":"d957","front":"How would you describe an Essex-Lopresti injury?","find":"Comminuted radial head fracture combined with disruption of the interosseous membrane of the forearm and dissociation of the distal radioulnar joint, producing longitudinal forearm instability with proximal migration of the radius. Marrow edema at the radial head, interosseous membrane signal disruption, and positive ulnar variance at the DRUJ.","impr":"Essex-Lopresti injury: radial head fracture with interosseous membrane and DRUJ disruption.","pearl":"With any comminuted radial head fracture, examine the wrist and interosseous membrane — missing this leads to chronic forearm instability.","topic":"Fracture","joint":"general"},
{"id":"d958","front":"How would you describe an olecranon fracture?","find":"Fracture through the olecranon process of the ulna at the triceps insertion, with marrow edema and a transverse or oblique intra-articular fracture line; the proximal fragment is retracted by triceps pull. Assess articular involvement of the trochlear notch, displacement ([__] mm), and comminution.","impr":"Olecranon fracture with triceps-mediated proximal fragment retraction.","pearl":"Quantify the articular gap and displacement — triceps pull makes these inherently distracted, displaced fractures.","topic":"Fracture","joint":"elbow"},
{"id":"d959","front":"How would you describe a capitellar (Kocher) fracture?","find":"Coronal-plane shear fracture of the capitellum with marrow edema and an anteriorly displaced osteochondral fragment (Hahn-Steinthal involving subchondral bone, or Kocher-Lorenz a thin chondral shell). Assess for involvement of the trochlea and for intra-articular fragments; double-arc sign on sagittal images.","impr":"Capitellar (coronal shear) fracture of the distal humerus.","pearl":"These osteochondral shear fractures are easily missed on radiographs — the double-arc sign and an anterior osteochondral fragment are clues.","topic":"Fracture","joint":"elbow"},
{"id":"d960","front":"How would you describe a greater tuberosity avulsion fracture?","find":"Avulsion fracture of the greater tuberosity of the humerus at the rotator cuff (supraspinatus/infraspinatus) insertion, with marrow edema and a superiorly/posteriorly retracted fragment displaced [__] mm. Assess the rotator cuff tendons for associated tear and the glenohumeral joint for prior anterior dislocation.","impr":"Greater tuberosity avulsion fracture at the rotator cuff footprint.","pearl":"A greater tuberosity fracture is the bony equivalent of a cuff tear and is commonly associated with anterior shoulder dislocation — examine the labrum.","topic":"Fracture","joint":"shoulder"},
{"id":"d961","front":"How would you describe a surgical neck fracture of the humerus?","find":"Fracture through the surgical neck of the proximal humerus (below the tuberosities) with marrow edema and a transverse/oblique fracture line; assess angulation and displacement ([__] mm/degrees). Part of Neer classification when combined with tuberosity and anatomic neck involvement. Evaluate the axillary nerve region and articular surface.","impr":"Surgical neck fracture of the proximal humerus.","pearl":"Use the Neer 4-part system (anatomic neck, surgical neck, greater and lesser tuberosities) and watch for axillary nerve injury.","topic":"Fracture","joint":"shoulder"},
{"id":"d962","front":"How would you describe a bony Bankart lesion?","find":"Avulsion fracture of the anteroinferior glenoid rim with marrow edema and an osseous fragment attached to the detached anteroinferior labroligamentous complex, following anterior glenohumeral dislocation. Quantify glenoid bone loss as a percentage/width of the inferior glenoid ([__] mm or %). Associated Hill-Sachs impaction of the posterosuperolateral humeral head.","impr":"Bony Bankart lesion: anteroinferior glenoid rim fracture from anterior instability.","pearl":"Glenoid bone loss >20-25% is critical and predicts recurrent instability — always quantify it and assess engagement with the Hill-Sachs.","topic":"Fracture","joint":"shoulder"},
{"id":"d963","front":"How would you describe a reverse bony Bankart lesion?","find":"Avulsion fracture of the POSTEROINFERIOR glenoid rim with marrow edema and an osseous fragment attached to the posterior labrum, following posterior glenohumeral dislocation. Associated reverse Hill-Sachs (McLaughlin) impaction of the anteromedial humeral head; quantify posterior glenoid bone loss ([__] mm).","impr":"Reverse bony Bankart: posteroinferior glenoid rim fracture from posterior instability.","pearl":"Posterior dislocation (seizure, electrocution) produces a reverse Hill-Sachs and reverse bony Bankart — look posteriorly.","topic":"Fracture","joint":"shoulder"},
{"id":"d964","front":"How would you describe a floating shoulder injury?","find":"Combined fracture of the glenoid neck and an ipsilateral clavicular fracture (with disruption of the superior shoulder suspensory complex), producing a disconnected, 'floating' glenoid segment. Marrow edema at both fracture sites with displacement of the glenoid fragment measuring [__] mm; assess the coracoclavicular and acromioclavicular ligaments.","impr":"Floating shoulder: ipsilateral glenoid neck and clavicle fractures (double disruption of the suspensory complex).","pearl":"Two breaks in the superior shoulder suspensory complex render the glenoid unstable — identify both components.","topic":"Fracture","joint":"shoulder"},
{"id":"d965","front":"How would you describe a Malgaigne fracture of the pelvis?","find":"Vertically unstable pelvic ring injury with ipsilateral fractures of both the anterior ring (superior and inferior pubic rami) and the posterior ring (sacral ala, iliac wing, or SI joint disruption), with marrow edema at all sites and superior/cephalad migration of the hemipelvis. Vertical displacement measures [__] mm.","impr":"Malgaigne fracture: vertically unstable pelvic ring disruption (anterior + posterior).","pearl":"Both anterior and posterior ring disruption on the same side equals vertical instability — high risk for vascular and visceral injury.","topic":"Fracture","joint":"general"},
{"id":"d966","front":"How would you describe a deep notch / Segond-equivalent in the pediatric knee?","find":"Avulsion fracture of the anterolateral tibia or pivot-shift impaction marrow edema involving the posterolateral tibial plateau and mid lateral femoral condyle (kissing contusions), in the setting of an ACL injury. In skeletally immature patients the ACL may avulse the tibial eminence rather than tear midsubstance.","impr":"Pivot-shift contusion pattern / Segond-equivalent indicating ACL injury.","pearl":"The lateral femoral condyle and posterolateral tibial bone contusions are the MRI footprint of the pivot-shift mechanism.","topic":"Fracture","joint":"knee"},
{"id":"d967","front":"How do you apply the Pfirrmann classification of lumbar disc degeneration?","find":"On sagittal T2, grade disc degeneration I-V: Grade I = bright homogeneous hyperintense nucleus, clear nucleus/anulus distinction, normal disc height; Grade II = inhomogeneous hyperintense nucleus +/- horizontal gray band, distinction still clear, normal height; Grade III = intermediate gray inhomogeneous signal, unclear nucleus/anulus distinction, normal to slightly decreased height; Grade IV = dark gray to black inhomogeneous signal, lost distinction, normal to moderately decreased height; Grade V = black collapsed disc with lost signal and significantly decreased height. Report as e.g. [L4-L5 disc demonstrates Pfirrmann grade IV degeneration].","impr":"Pfirrmann is a 5-grade T2-based scale of nucleus signal, nucleus/anulus distinction, and disc height.","pearl":"The two key transition points are loss of the bright nucleus (II->III) and loss of disc height (IV->V).","topic":"Classification","joint":"spine"},
{"id":"d968","front":"How do you apply the combined task force (Fardon/Williams) lumbar disc herniation nomenclature?","find":"First call the contour: a normal disc has no extension beyond the apophyseal margins; bulge = symmetric/circumferential extension >25% (>90 degrees) of the disc circumference (not a herniation); herniation = focal displacement <25% (<90 degrees) of circumference. Subclassify herniations: protrusion = base (width at disc of origin) GREATER than the AP distance of displaced material; extrusion = displaced material AP distance GREATER than base, OR any superior/inferior extension beyond the disc space; sequestration = extruded fragment with NO continuity to the parent disc. Add zone (central, subarticular/lateral recess, foraminal, extraforaminal) and craniocaudal level, and whether it is contained or uncontained.","impr":"Protrusion = wide base; extrusion = neck narrower than dome or migrated; sequestration = free fragment.","pearl":"A focal abnormality involving <25% of circumference is a herniation; 25-100% is a bulge, never a herniation.","topic":"Classification","joint":"spine"},
{"id":"d969","front":"How do you apply the Schatzker classification of tibial plateau fractures?","find":"Type I = lateral plateau pure split (wedge) fracture without depression; Type II = lateral plateau split PLUS depression of the articular surface; Type III = lateral plateau pure central depression with intact rim (further III-A peripheral, III-B central); Type IV = medial plateau fracture (split and/or depression) - associated with higher-energy/dislocation and neurovascular and cruciate injury; Type V = bicondylar fracture (both plateaus) with the metaphysis-diaphysis still in continuity (inverted-Y); Type VI = plateau fracture with metaphyseal-diaphyseal dissociation. Report the type and quantify depression and split-fragment widening, plus associated meniscal/ligamentous injury.","impr":"Types I-III are lateral, IV is medial, V is bicondylar, VI has metadiaphyseal dissociation; higher number = higher energy.","pearl":"Type IV (medial) and VI carry the highest rates of neurovascular injury and warrant CT angiography consideration.","topic":"Classification","joint":"knee"},
{"id":"d970","front":"How do you apply the Ahlback classification of knee osteoarthritis?","find":"A weight-bearing/MR-correlated severity scale: Grade I = joint space narrowing (<3 mm or <50% of the opposite compartment) without bone loss; Grade II = joint space obliteration (bone-on-bone) without bone attrition; Grade III = minor bone attrition/loss (0-5 mm); Grade IV = moderate bone attrition (5-10 mm); Grade V = severe bone attrition (>10 mm) often with subluxation. Report the affected compartment and degree of attrition.","impr":"Ahlback escalates from joint-space narrowing (I) through obliteration (II) to progressive bone attrition (III-V).","pearl":"Ahlback specifically tracks bone loss/attrition, which distinguishes it from purely osteophyte-based scales.","topic":"Classification","joint":"knee"},
{"id":"d971","front":"How do you apply the Kellgren-Lawrence grading of osteoarthritis?","find":"A radiographic 5-grade scheme: Grade 0 = no features; Grade 1 = doubtful joint-space narrowing and possible osteophytic lipping; Grade 2 = definite osteophytes with possible joint-space narrowing (minimal/mild OA); Grade 3 = moderate multiple osteophytes, definite joint-space narrowing, some sclerosis and possible bony deformity; Grade 4 = large osteophytes, marked joint-space narrowing, severe sclerosis and definite bony deformity. Report the grade per compartment.","impr":"K-L is osteophyte-anchored: grade 2 (definite osteophyte) is the threshold for definite OA.","pearl":"K-L weights osteophytes heavily, so it can lag behind cartilage-loss-dominant disease seen on MRI.","topic":"Classification","joint":"general"},
{"id":"d972","front":"How do you apply the ISAKOS meniscal tear classification?","find":"Describe each tear by: (1) depth/completeness (partial vs full-thickness), (2) tear pattern - longitudinal-vertical, horizontal, radial, root tear, displaced/flap, complex, or bucket-handle; (3) tear length in mm; (4) rim width / zone (red-red <3 mm peripheral/vascular, red-white 3-5 mm, white-white >5 mm central/avascular); (5) location (anterior horn, body, posterior horn, root) and percentage of meniscus involved; (6) tissue quality and whether the tear is in a previously operated meniscus. This structured descriptor guides reparability (peripheral longitudinal red-red tears are most repairable).","impr":"ISAKOS standardizes meniscal reporting by pattern, depth, length, rim/zone, and location to predict reparability.","pearl":"Rim width (red-red vs white-white) is the single best predictor of healing potential after repair.","topic":"Classification","joint":"knee"},
{"id":"d973","front":"How do you grade tibial (and other) stress injuries with the Fredericson classification?","find":"MRI grading of bone stress injury (originally tibial): Grade 1 = periosteal edema only (high signal on fluid-sensitive/STIR) without marrow change; Grade 2 = periosteal edema PLUS marrow edema visible only on T2/STIR; Grade 3 = periosteal edema with marrow edema on BOTH T1 and T2/STIR (no fracture line); Grade 4 = grade 4a multiple discrete intracortical signal abnormalities (T1 and T2) or 4b a frank linear fracture line in cortex/marrow. Higher grade predicts longer return-to-play.","impr":"Fredericson escalates from periosteal edema alone to T1+T2 marrow edema to a discrete fracture line (grade 4b).","pearl":"The jump from grade 2 to 3 is marrow edema becoming visible on T1, signaling a more advanced injury.","topic":"Classification","joint":"knee"},
{"id":"d974","front":"How do you apply the Garden classification of femoral neck fractures?","find":"Based on completeness and displacement on the AP radiograph/coronal images: Garden I = incomplete/valgus-impacted fracture (trabeculae angulated but cortex intact on one side); Garden II = complete fracture without displacement (trabecular lines unbroken and aligned across the fracture); Garden III = complete fracture with partial displacement (trabeculae of head and acetabulum no longer aligned, but fragments still partly opposed); Garden IV = complete fracture with full displacement (the femoral head trabeculae realign parallel to the acetabular trabeculae because the head is free). Report displacement because III-IV carry high AVN/nonunion risk.","impr":"Garden I-II are non/minimally displaced; III-IV are displaced; AVN risk rises sharply with displacement.","pearl":"Clinically often dichotomized into nondisplaced (I-II) vs displaced (III-IV) since that drives fixation vs arthroplasty.","topic":"Classification","joint":"hip"},
{"id":"d975","front":"How do you apply the Pauwels classification of femoral neck fractures?","find":"Based on the angle of the fracture line relative to the horizontal: Pauwels I = <30 degrees (more horizontal, predominantly compressive forces, most stable); Pauwels II = 30-50 degrees; Pauwels III = >50 degrees (more vertical, predominantly shear forces, least stable, highest nonunion risk). Report the angle because a more vertical (high Pauwels) fracture demands stronger fixation to resist shear.","impr":"Pauwels grades verticality of the femoral neck fracture line; more vertical = more shear = less stable.","pearl":"Pauwels III (vertical) fractures are biomechanically unstable and prone to varus collapse and nonunion.","topic":"Classification","joint":"hip"},
{"id":"d976","front":"How do you apply the Ficat-Arlet classification of femoral head avascular necrosis?","find":"A staging system combining radiographs and MRI: Stage 0 = preclinical, normal imaging (suspected); Stage I = normal or minimal radiographs but MRI/bone scan positive, hip pain present; Stage II = radiographic changes (sclerosis, cysts, osteopenia) WITHOUT collapse and with a preserved spherical head and joint space; Stage III = subchondral collapse / crescent sign and/or femoral head flattening; Stage IV = osteoarthritis with joint-space narrowing and acetabular involvement. The crescent sign (stage III) is the pivotal point - head sphericity is lost.","impr":"Ficat-Arlet pivots at stage III (subchondral collapse/crescent sign), the transition to irreversible structural failure.","pearl":"Stage II still has a round head and intact joint space; once you see the crescent (III) joint preservation surgery options narrow.","topic":"Classification","joint":"hip"},
{"id":"d977","front":"How do you apply the Steinberg (University of Pennsylvania) staging of femoral head AVN?","find":"A 7-stage quantitative system: Stage 0 = normal imaging (all studies); Stage I = normal radiograph, abnormal MRI/bone scan; Stage II = lucent/sclerotic changes in the head; Stage III = subchondral collapse (crescent sign) WITHOUT head flattening; Stage IV = head flattening WITHOUT joint-space narrowing; Stage V = flattening with joint-space narrowing and/or acetabular changes; Stage VI = advanced degenerative changes. Crucially, stages I-V are subdivided A/B/C by SIZE of head involvement: A = mild (<15%), B = moderate (15-30%), C = severe (>30%).","impr":"Steinberg refines Ficat by quantifying lesion SIZE (A/B/C) and separating crescent (III) from flattening (IV).","pearl":"The A/B/C size subclassification is what makes Steinberg prognostically powerful - extent predicts collapse risk.","topic":"Classification","joint":"hip"},
{"id":"d978","front":"How do you apply the Mitchell MRI classification of femoral head AVN?","find":"Classifies the central signal of the necrotic segment relative to four reference tissues: Class A = signal of fat (T1 bright, T2 intermediate) - earliest; Class B = signal of blood/subacute hemorrhage (T1 bright, T2 bright); Class C = signal of fluid (T1 low, T2 bright); Class D = signal of fibrous tissue (T1 low, T2 low) - most advanced. The pathognomonic feature is the double-line sign (inner T2-bright granulation tissue, outer T2-dark sclerosis) at the reactive interface.","impr":"Mitchell categorizes the AVN segment by analogy to fat/blood/fluid/fibrous signal (A->D = progressive degeneration).","pearl":"The double-line sign on T2 is the MRI hallmark of AVN and marks the reactive zone around the necrotic segment.","topic":"Classification","joint":"hip"},
{"id":"d979","front":"How do you apply the ARCO staging of osteonecrosis?","find":"The revised 2019 ARCO system: Stage 1 = X-ray/CT normal, MRI shows the osteonecrotic lesion; Stage 2 = X-ray abnormal (sclerosis, focal osteoporosis, cysts) but NO subchondral fracture, collapse, or joint-space narrowing; Stage 3 = subchondral fracture +/- head flattening - subdivided 3A (early, depression <=2 mm) and 3B (late, depression >2 mm); Stage 4 = osteoarthritis with joint-space narrowing, acetabular changes, and joint destruction. Quantify lesion location and extent.","impr":"ARCO 2019 hinges on subchondral fracture: stage 2 has none, stage 3 has it (3A <=2 mm vs 3B >2 mm depression).","pearl":"The 2019 revision dropped the old quantitative size percentages and made the subchondral fracture the key stage-3 criterion.","topic":"Classification","joint":"hip"},
{"id":"d980","front":"How do you apply the Weber (Danis-Weber) classification of ankle/lateral malleolar fractures?","find":"Based on the level of the FIBULAR fracture relative to the tibiotalar joint/syndesmosis: Weber A = fibular fracture BELOW the syndesmosis (infrasyndesmotic), syndesmosis intact, usually stable; Weber B = fracture AT the level of the syndesmosis (spiral, transsyndesmotic), variable syndesmotic injury - stability depends on the medial side; Weber C = fracture ABOVE the syndesmosis (suprasyndesmotic), syndesmosis disrupted, unstable (includes Maisonneuve when proximal fibula). Report the level and assess the medial malleolus/deltoid and syndesmosis.","impr":"Weber locates the fibular fracture vs the syndesmosis: A below, B at, C above; higher = greater syndesmotic disruption.","pearl":"In Weber C always check the proximal fibula - a high fracture (Maisonneuve) implies a torn syndesmosis up to that level.","topic":"Classification","joint":"ankle"},
{"id":"d981","front":"How do you apply the Lauge-Hansen classification of ankle fractures?","find":"A mechanistic system naming foot position then deforming force, in order of increasing energy/stages: Supination-Adduction (SA) - transverse low fibular avulsion + vertical medial malleolar fracture; Supination-External Rotation (SER, most common) - 4 stages: anterior tibiofibular ligament, spiral distal fibula (Weber B), posterior malleolus/PITFL, then medial malleolus/deltoid; Pronation-Abduction (PA) - medial first, then syndesmosis, then transverse comminuted fibula; Pronation-External Rotation (PER) - medial first, anterior syndesmosis, high fibula (Weber C/Maisonneuve), posterior structures. Read the injury sequence to predict occult components.","impr":"Lauge-Hansen = [foot position]-[force]; the named stages predict the sequence and which ligaments/malleoli are injured.","pearl":"SER is the most common pattern; recognizing stage helps you hunt for the medial-side or posterior malleolar injury that determines stability.","topic":"Classification","joint":"ankle"},
{"id":"d982","front":"How do you grade osteochondral lesions of the talus with the Hepple MRI classification?","find":"An MRI staging that modifies Berndt-Hardy: Stage 1 = articular cartilage damage only; Stage 2a = cartilage injury with underlying fracture and surrounding bone edema (acute); Stage 2b = same as 2a but WITHOUT surrounding bone edema (chronic); Stage 3 = detached but undisplaced osteochondral fragment; Stage 4 = detached and displaced fragment; Stage 5 = subchondral cyst formation. Report stability and the presence of fluid undercutting the fragment.","impr":"Hepple grades talar OLT on MRI from cartilage-only (1) through detachment (3-4) to subchondral cyst (5).","pearl":"T2-bright fluid completely undercutting the fragment signals instability - a key MRI sign favoring surgery.","topic":"Classification","joint":"ankle"},
{"id":"d983","front":"How do you apply the Berndt-Hardy classification of osteochondral talar lesions?","find":"The original radiographic staging of transchondral talar dome fractures: Stage I = small area of subchondral compression/trabecular injury; Stage II = partially detached osteochondral fragment; Stage III = completely detached fragment that remains in its crater (nondisplaced); Stage IV = detached fragment displaced from its bed. Report location (classically posteromedial - deeper/cup-shaped from inversion + plantarflexion, vs anterolateral - shallower/wafer-shaped from inversion + dorsiflexion).","impr":"Berndt-Hardy: I compression, II partial detachment, III detached in situ, IV displaced.","pearl":"Posteromedial lesions are usually deeper and atraumatic-appearing; anterolateral lesions are shallower and more clearly trauma-related.","topic":"Classification","joint":"ankle"},
{"id":"d984","front":"How do you apply the Sanders classification of calcaneal fractures?","find":"A CT-based classification using the coronal image at the widest point of the posterior facet, divided by two fracture lines (A lateral, B middle) into three columns plus the sustentaculum: Type I = all nondisplaced fractures (<2 mm) regardless of line number; Type II = ONE fracture line / two posterior-facet fragments (IIA, IIB, IIC by line location); Type III = TWO fracture lines / three fragments with a depressed middle fragment (IIIAB, IIIAC, IIIBC); Type IV = highly comminuted with FOUR or more fragments. Report the posterior facet involvement because it drives surgical planning and prognosis.","impr":"Sanders counts posterior-facet fragments on coronal CT: I non-displaced, II two-part, III three-part, IV comminuted.","pearl":"It is defined specifically on the coronal CT image at the widest posterior facet - the number of articular fragments sets the type.","topic":"Classification","joint":"ankle"},
{"id":"d985","front":"How do you apply the Hawkins classification of talar neck fractures?","find":"Based on displacement and joint involvement, predicting AVN risk: Type I = nondisplaced talar neck fracture (AVN ~10%); Type II = displaced fracture with subluxation/dislocation of the SUBTALAR joint (AVN ~20-50%); Type III = displaced with dislocation of BOTH the subtalar AND tibiotalar (ankle) joints (AVN ~80-100%); Type IV (Canale addition) = type III plus talonavicular joint dislocation/subluxation (AVN approaching 100%). Report dislocated joints because each additional disrupted articulation removes a blood supply route.","impr":"Hawkins escalates by number of dislocated joints (subtalar -> +ankle -> +talonavicular); AVN risk rises with each.","pearl":"The Hawkins SIGN (subchondral lucency in the talar dome at 6-8 weeks) indicates preserved vascularity and predicts viability.","topic":"Classification","joint":"ankle"},
{"id":"d986","front":"How do you apply the Rockwood classification of acromioclavicular joint injury?","find":"Six types by AC and coracoclavicular (CC) ligament status and clavicle displacement: Type I = AC ligament sprain, no displacement, normal CC distance; Type II = AC ligaments torn, CC ligaments intact/sprained, <25% increase in CC distance / minimal vertical subluxation; Type III = both AC and CC ligaments torn, clavicle elevated with 25-100% increase in CC distance; Type IV = clavicle displaced POSTERIORLY into/through the trapezius (best seen on axial); Type V = severe superior displacement, CC distance increased 100-300% with detachment of deltotrapezial fascia; Type VI = clavicle displaced INFERIORLY (subacromial or subcoracoid). Report CC distance and direction of clavicular displacement.","impr":"Rockwood I-II are sprains, III is complete superior, IV posterior, V exaggerated superior (100-300%), VI inferior.","pearl":"Type IV (posterior) is best appreciated on axial imaging and, like V and VI, is operative; III is the surgical gray zone.","topic":"Classification","joint":"shoulder"},
{"id":"d987","front":"How do you apply the Zlatkin grading of rotator cuff tendinopathy/tears on MRI?","find":"A 3-grade signal/morphology scale of the cuff: Grade 1 = increased intratendinous signal on short-TE images that does NOT increase on T2 and normal tendon morphology (tendinosis/degeneration); Grade 2 = increased signal with abnormal morphology - tendon thinning, irregularity, or fraying, but no fluid-signal gap (severe tendinopathy/partial tear); Grade 3 = fluid-bright signal traversing the tendon with a discontinuity/gap (full-thickness tear) - report the gap size and tendon retraction. Distinguish articular- vs bursal-sided partial tears.","impr":"Zlatkin: grade 1 tendinosis, grade 2 abnormal morphology/partial tear, grade 3 full-thickness fluid-signal gap.","pearl":"The key discriminator for grade 3 is FLUID-bright signal (T2) spanning the full tendon thickness, not just intermediate signal.","topic":"Classification","joint":"shoulder"},
{"id":"d988","front":"How do you apply the Habermeyer classification of biceps pulley lesions?","find":"Classifies superior labrum-biceps pulley (SGHL/CHL sling) lesions: Type 1 = isolated lesion of the superior glenohumeral ligament (SGHL); Type 2 = SGHL lesion PLUS partial articular-sided supraspinatus tear; Type 3 = SGHL lesion plus partial articular-sided subscapularis tear; Type 4 = SGHL lesion with partial tears of BOTH supraspinatus and subscapularis. The result is biceps instability/medial subluxation of the long head into or over the subscapularis. Look on axial/sagittal for medial displacement of the long head of biceps and a torn pulley.","impr":"Habermeyer grades pulley lesions by which adjacent cuff tendon is also torn (SSP and/or SSC), all causing biceps instability.","pearl":"A medially subluxed/dislocated long head of biceps relative to the bicipital groove is the imaging clue to a pulley lesion.","topic":"Classification","joint":"shoulder"},
{"id":"d989","front":"How do you apply the Ideberg (and Goss) classification of glenoid fossa fractures?","find":"Six types of intra-articular glenoid fractures: Type I = anteroinferior glenoid rim fracture (Ia anterior, Ib posterior); Type II = fracture line through the glenoid fossa exiting the LATERAL scapular border (transverse/oblique with inferior triangle fragment); Type III = fracture exiting the SUPERIOR scapular border (involving the coracoid); Type IV = fracture exiting the MEDIAL scapular border (horizontal); Type V = combination of types II, III and/or IV; Type VI (Goss addition) = comminuted glenoid fossa. Report articular step-off and fragment size because rim fractures relate to instability.","impr":"Ideberg: I rim, II exits lateral border, III exits superior (coracoid), IV exits medial, V combinations, VI comminuted.","pearl":"Type I (rim) fractures correlate with glenohumeral instability/bony Bankart, whereas II-VI are higher-energy fossa fractures.","topic":"Classification","joint":"shoulder"},
{"id":"d990","front":"How do you apply the Mason (Hotchkiss-modified) classification of radial head fractures?","find":"Type I = nondisplaced or minimally displaced (<2 mm) fracture, no mechanical block to rotation; Type II = displaced (>2 mm) partial-articular fracture with a discrete fragment, possible mechanical block; Type III = comminuted fracture of the entire radial head not amenable to reconstruction; Type IV (Johnston addition) = radial head fracture associated with elbow dislocation. Report displacement, fragment number, mechanical block, and associated injuries (coronoid, MCL, interosseous membrane).","impr":"Mason: I nondisplaced, II displaced single fragment, III comminuted/unreconstructable, IV with dislocation.","pearl":"Always look for associated injuries - radial head fracture + coronoid fracture + dislocation defines the terrible triad.","topic":"Classification","joint":"elbow"},
{"id":"d991","front":"How do you apply the Regan-Morrey classification of coronoid process fractures?","find":"Based on the height of the coronoid fragment on the lateral view/sagittal images: Type I = avulsion of the coronoid TIP only; Type II = fragment involving <=50% of the coronoid height; Type III = fragment involving >50% of the coronoid height (often with elbow instability). A modifier 'A' or 'B' denotes absence/presence of associated dislocation. Report fragment size and anteromedial facet involvement (O'Driscoll) since that subtype drives varus posteromedial rotatory instability.","impr":"Regan-Morrey grades coronoid fractures by height: I tip, II <=50%, III >50%.","pearl":"The anteromedial facet (O'Driscoll) coronoid fracture, even if small, causes posteromedial rotatory instability and is easily missed.","topic":"Classification","joint":"elbow"},
{"id":"d992","front":"How do you apply the Geissler arthroscopic classification (and its MRI correlate) of scapholunate / intercarpal injury?","find":"An arthroscopic grading of interosseous ligament tears with MR/fluoroscopic correlates: Grade I = ligament attenuation/hemorrhage seen from the radiocarpal joint, no incongruency, no midcarpal step-off; Grade II = incongruency/step-off of carpal alignment with a slight gap (<width of a probe); Grade III = incongruency seen from BOTH radiocarpal and midcarpal joints, a probe can pass through the gap; Grade IV = gross instability with frank widening - an arthroscope can pass through the SL interval (the 'drive-through' sign). On MRI/MR arthrography correlate with widening of the SL interval and contrast crossing the interosseous ligament.","impr":"Geissler I-IV escalates from ligament attenuation to a frank gap allowing the arthroscope through (drive-through sign).","pearl":"Grade III-IV (probe or scope passes through) corresponds to a complete, often dynamically unstable, SL tear.","topic":"Classification","joint":"wrist"},
{"id":"d993","front":"How do you apply the Palmer classification of TFCC lesions?","find":"Two classes: Class 1 = TRAUMATIC lesions, subtyped 1A central perforation/tear of the horizontal disc, 1B peripheral ulnar avulsion off the distal ulna/fovea (+/- ulnar styloid fracture, the most clinically unstable), 1C distal avulsion from the carpus (ulnolunate/ulnotriquetral ligaments), 1D radial avulsion off the sigmoid notch. Class 2 = DEGENERATIVE lesions from ulnar impaction, staged A through E: 2A TFCC wear without perforation, 2B wear + lunate/ulnar chondromalacia, 2C TFCC perforation + chondromalacia, 2D + lunotriquetral ligament tear, 2E + ulnocarpal arthritis. Report ulnar variance, which drives the degenerative class.","impr":"Palmer 1 = traumatic (1A-D by location), Palmer 2 = degenerative ulnar impaction (2A-E by progression).","pearl":"Class 1B (peripheral foveal avulsion) is the one most associated with DRUJ instability and is the key reparable tear; positive ulnar variance drives the class 2 degenerative spectrum.","topic":"Classification","joint":"wrist"},
{"id":"d994","front":"How do you apply the Eaton-Littler classification of thumb carpometacarpal (basal joint) osteoarthritis?","find":"A radiographic staging of trapeziometacarpal OA: Stage I = normal joint contours with possible slight widening (joint effusion/laxity), no osteophytes; Stage II = slight joint-space narrowing of the trapeziometacarpal joint with osteophytes/loose bodies <2 mm; Stage III = marked trapeziometacarpal narrowing, subchondral sclerosis/cysts and osteophytes >2 mm, but the SCAPHOTRAPEZIAL joint is spared; Stage IV = pantrapezial arthritis involving BOTH the trapeziometacarpal AND scaphotrapezial joints. Report subluxation of the metacarpal base.","impr":"Eaton-Littler stages thumb CMC OA; stage III spares the STT joint while stage IV is pantrapezial.","pearl":"The III->IV distinction is whether the scaphotrapezial joint is involved - pantrapezial disease changes surgical management.","topic":"Classification","joint":"wrist"},
{"id":"d995","front":"How do you apply the Lodwick classification of bone lesion aggressiveness?","find":"Grades the geographic/permeative pattern and margin (zone of transition): Grade IA = geographic lesion with a sclerotic rim (narrow zone of transition) - least aggressive; Grade IB = geographic with a well-defined but NON-sclerotic margin; Grade IC = geographic with an ILL-DEFINED margin (wide zone of transition); Grade II = MOTH-EATEN pattern (multiple clustered lytic holes); Grade III = PERMEATIVE pattern (ill-defined infiltrating tiny lucencies) - most aggressive. The width of the zone of transition is the single most reliable indicator: narrow = nonaggressive, wide = aggressive.","impr":"Lodwick rises from geographic-sclerotic (IA) to moth-eaten (II) to permeative (III); zone of transition width = aggressiveness.","pearl":"A sharp sclerotic margin (Lodwick IA) implies slow growth; a wide zone of transition or moth-eaten/permeative pattern implies an aggressive process.","topic":"Classification","joint":"general"},
{"id":"d996","front":"How do you apply the Enneking (MSTS) staging of musculoskeletal tumors?","find":"For BENIGN lesions, use Arabic stage 1 (latent - well-marginated, inactive), 2 (active - growing, well-marginated), 3 (aggressive - locally destructive, may breach the cortex). For MALIGNANT lesions, use Roman staging combining grade (G), site (T), and metastasis (M): Stage I = low grade (G1); Stage II = high grade (G2); Stage III = any grade WITH regional/distant metastasis (M1). Each is subdivided A = INTRAcompartmental (T1, confined by a natural barrier) and B = EXTRAcompartmental (T2, beyond the compartment). So IA = low grade intracompartmental, IIB = high grade extracompartmental.","impr":"Enneking malignant staging = grade (I low/II high) + compartment (A intra/B extra) + metastasis (III); benign = 1/2/3 latent/active/aggressive.","pearl":"The intra- vs extracompartmental distinction (A vs B) is the imaging-driven element that dictates surgical margins.","topic":"Classification","joint":"general"},
{"id":"d997","front":"How do you apply the ASAS MRI criteria for active sacroiliitis?","find":"A positive MRI for active sacroiliitis (ASAS definition) requires bone marrow edema/osteitis - high signal on STIR or enhancement on post-contrast T1FS - in a typical subchondral/periarticular location. It must be present either in >=2 SI joint quadrants on a single slice OR in the SAME quadrant on >=2 consecutive slices. Bone marrow edema is the mandatory active lesion; other corroborating lesions (capsulitis, enthesitis, synovitis) and structural lesions (erosions, sclerosis, fat metaplasia, ankylosis) support but do not replace it. Report active inflammation separately from chronic structural change.","impr":"ASAS-positive sacroiliitis = subchondral BME on STIR in >=2 quadrants on one slice or the same quadrant on >=2 consecutive slices.","pearl":"Bone marrow edema is mandatory - structural lesions alone (erosion, fat) do not meet the ASAS active sacroiliitis definition.","topic":"Classification","joint":"spine"},
{"id":"d998","front":"How do you apply the SPARCC scoring of SI joint inflammation?","find":"A quantitative MRI inflammation score on STIR/T2FS over 6 consecutive semicoronal slices through the cartilaginous SI joint. Each joint is divided into 4 quadrants (2 iliac, 2 sacral) per side; for each of the 6 slices score presence (0/1) of bone marrow edema in each quadrant - giving up to 24 per side, 48 total. Then add intensity (1 point per slice if INTENSE, defined as signal >= local vein) and depth (1 point per slice if DEEP, homogeneous edema extending >=1 cm from the joint surface), up to 12 more. Total range 0-72. Report the score to track treatment response.","impr":"SPARCC sums BME presence across 6 slices/4 quadrants/2 sides plus intensity and depth bonuses, total 0-72.","pearl":"SPARCC is a longitudinal response metric - its value is comparing scores over time, not a single threshold for diagnosis.","topic":"Classification","joint":"spine"},
{"id":"d999","front":"How do you apply the RAMRIS scoring of rheumatoid arthritis in the wrist/hand on MRI?","find":"The OMERACT RA MRI scoring system grades three components in defined bones/sites of the wrist and MCP joints: SYNOVITIS scored 0-3 per site by enhancing synovial volume (0 normal, 1 mild, 2 moderate, 3 severe); BONE MARROW EDEMA (osteitis) scored 0-3 per bone by the proportion of bone with edema (1 = 1-33%, 2 = 34-66%, 3 = 67-100%); and EROSIONS scored 0-10 per bone by the proportion of eroded bone volume in 10% increments. Use fat-suppressed T2/STIR for edema and post-contrast T1FS for synovitis/erosions. Report each component because BME predicts erosive progression.","impr":"RAMRIS scores synovitis (0-3), bone marrow edema/osteitis (0-3), and erosions (0-10) per site on contrast-enhanced MRI.","pearl":"Bone marrow edema (osteitis) is the strongest predictor of subsequent erosive progression, so it is the key RAMRIS component to track.","topic":"Classification","joint":"wrist"},
{"id":"d1000","front":"How do you apply the Larsen classification of rheumatoid arthritis joint damage?","find":"A 0-5 radiographic grading: Grade 0 = normal; Grade 1 = soft-tissue swelling, periarticular osteoporosis, and slight joint-space narrowing; Grade 2 = early definite abnormality with erosion and joint-space narrowing (one small erosion); Grade 3 = medium destructive abnormality with marked erosions and narrowing; Grade 4 = severe destructive abnormality with erosions, marked narrowing and bone deformity; Grade 5 = mutilating abnormality with loss of the original articular surfaces and gross deformity/ankylosis. Compare against standard reference films for the joint.","impr":"Larsen grades RA radiographic destruction 0-5 from osteopenia/swelling (1) to mutilating joint loss (5).","pearl":"Grade 2 is the threshold of definite erosion; Larsen relies on comparison to standardized reference radiographs.","topic":"Classification","joint":"general"},
{"id":"d1001","front":"How does ICRS cartilage grading differ from the Outerbridge classification?","find":"Both grade chondral injury 0-4 but with different anchors. Outerbridge (originally for patellar chondromalacia): 0 normal, I signal heterogeneity (intact surface), II fragmentation/fissures <1.3 cm (or partial-thickness fissures), III fissuring extending to subchondral bone / fragmentation >1.3 cm, IV exposed subchondral bone. ICRS is depth-percentage based: grade 0 normal, 1 superficial (1A soft indentation/fibrillation, 1B superficial fissures), 2 abnormality extending <50% of cartilage depth, 3 defect >50% depth (3A->C down to but not through calcified layer/subchondral plate, 3D blisters), 4 full-thickness through the subchondral bone. Report defect depth (% thickness) and area.","impr":"Outerbridge keys on fissure size/fragmentation; ICRS keys on % cartilage depth, making ICRS more reproducible for MRI/arthroscopy.","pearl":"ICRS's percent-depth criteria (especially the <50% vs >50% threshold) translate better to MRI than Outerbridge's size-based grades.","topic":"Classification","joint":"knee"},
{"id":"d1002","front":"How do you apply the Mink grading of muscle/tendon strain injury on MRI?","find":"A 3-grade scale of musculotendinous injury on fluid-sensitive sequences: Grade 1 (mild strain) = feathery interstitial/perifascial edema and hemorrhage with <5% fiber disruption and no architectural distortion; Grade 2 (partial tear) = partial fiber disruption with a focal fluid collection/hematoma at the myotendinous junction, some retraction, but tendon continuity preserved; Grade 3 (complete tear) = full-thickness discontinuity of the muscle-tendon unit with retraction, a gap, and surrounding hematoma. Report the location (typically myotendinous junction), the percentage of cross-section involved, and the gap/retraction distance.","impr":"Mink: grade 1 edema/feathery strain, grade 2 partial tear with fluid collection, grade 3 complete tear with retraction.","pearl":"Most strains occur at the myotendinous junction; report the craniocaudal length of edema and any discrete gap, which guide return-to-play.","topic":"Classification","joint":"general"},
{"id":"d1003","front":"How do you apply the Anderson-Montesano classification of occipital condyle fractures?","find":"Three types on CT: Type I = impaction/comminuted fracture of the occipital condyle from axial loading, with the alar ligament and tectorial membrane intact - STABLE; Type II = condylar fracture as an extension of a basilar skull fracture (linear fracture through the skull base into the condyle), generally STABLE; Type III = avulsion fracture of the condyle at the alar ligament insertion, with a fragment displaced toward the dens - potentially UNSTABLE because of the craniocervical ligamentous involvement. Assess the alar ligament and atlanto-occipital alignment.","impr":"Anderson-Montesano: I comminuted/impaction, II basilar-skull extension, III alar-ligament avulsion (the unstable one).","pearl":"Type III (alar avulsion) is the concern for craniocervical instability; the Tuli classification adds displacement/ligament integrity for management.","topic":"Classification","joint":"spine"},
{"id":"d1004","front":"How do you apply the AO/OTA fracture classification concept?","find":"An alphanumeric system: the first digit is the BONE (1 humerus, 2 radius/ulna, 3 femur, 4 tibia/fibula, etc.), the second the SEGMENT (1 proximal, 2 diaphyseal, 3 distal, 4 malleolar). A letter encodes morphology - for diaphyseal: A = simple (one line: spiral/oblique/transverse), B = wedge (third fragment, fragments still in contact after reduction), C = complex/comminuted (no contact between main fragments after reduction). For articular segments: A = extra-articular, B = partial-articular, C = complete-articular. Numbers further subgroup severity. Report so the code conveys location and severity universally.","impr":"AO/OTA = bone + segment + type letter (A simple/extra-articular, B wedge/partial, C complex/complete-articular) + subgroup.","pearl":"For articular fractures the letter shifts meaning to joint involvement: A extra-articular, B partial-articular, C complete-articular - severity always increases A->B->C.","topic":"Classification","joint":"general"},
{"id":"d1005","front":"How would you distinguish true marrow infection from reactive marrow edema in the diabetic foot?","find":"True osteomyelitis shows CONFLUENT geographic T1 marrow signal replacement (darker than muscle, replacing fatty marrow). Reactive/sympathetic edema shows HAZY, indistinct, reticulated low T1 with preserved interspersed fat and T2 hyperintensity but no discrete T1 replacement. Contiguity with an ulcer/sinus and cortical destruction favor infection.","impr":"Reactive marrow edema without confluent T1 replacement to suggest osteomyelitis.","pearl":"Hazy/reticulated T1 = edema; confluent geographic T1 loss = infection.","topic":"Infection","joint":"foot"},
{"id":"d1006","front":"How would you describe chronic osteomyelitis on MRI?","find":"Thickened sclerotic cortex with low-signal involucrum surrounding the focus; sequestrum = devitalized non-enhancing bone fragment of low signal on all sequences within granulation tissue. Cloaca = cortical defect through which the sinus tract drains. Surrounding low-grade marrow signal change with mature peripheral enhancement and a sinus tract extending to skin.","impr":"Chronic osteomyelitis with sequestrum and involucrum.","pearl":"Sequestrum = dead non-enhancing bone; involucrum = living reactive bone shell; cloaca = the drainage opening.","topic":"Infection","joint":"general"},
{"id":"d1007","front":"How would you describe a Brodie abscess?","find":"Well-defined intramedullary lesion, typically metaphyseal in a long bone, with central T2-hyperintense fluid/pus, a surrounding low-T1/low-T2 fibrous rim, and an outer zone of sclerosis and marrow edema. Avid rim enhancement around the non-enhancing necrotic center. Often shows the penumbra sign.","impr":"Brodie abscess (subacute intraosseous osteomyelitis).","pearl":"Concentric target appearance: pus, fibrous rim, sclerosis, edema.","topic":"Infection","joint":"general"},
{"id":"d1008","front":"How would you describe the penumbra sign?","find":"On unenhanced T1, a thin discrete rim of relatively HIGH signal (granulation tissue) lining the wall of an intraosseous abscess, intermediate between the low-signal central pus and the surrounding low-signal edematous/sclerotic bone. Highly specific for subacute osteomyelitis/Brodie abscess.","impr":"Penumbra sign supporting subacute osteomyelitis.","pearl":"The penumbra is seen on NON-contrast T1 and is highly specific for osteomyelitis.","topic":"Infection","joint":"general"},
{"id":"d1009","front":"How would you use the ghost sign to distinguish osteomyelitis from neuropathic disease?","find":"Ghost sign positive = a bone that appears indistinct/lost (very low T1, low T2) on non-contrast images but reappears with defined margins and enhancement after contrast, favoring osteomyelitis. Ghost sign absent = bone margins remain sharply defined throughout, favoring acute Charcot neuroarthropathy. Combine with location and ancillary signs.","impr":"Positive ghost sign favoring superimposed osteomyelitis.","pearl":"Ghost (bone reappears after contrast) = infection; ghost absent (margins stay sharp) = neuropathic.","topic":"Infection","joint":"foot"},
{"id":"d1010","front":"How would you distinguish osteomyelitis from neuropathic (Charcot) arthropathy in the diabetic foot?","find":"Osteomyelitis: forefoot/calcaneus at pressure points beneath an ulcer, confluent T1 marrow replacement contiguous with skin defect/sinus, positive ghost sign, secondary soft-tissue ulcer. Neuropathic: MIDFOOT (Lisfranc/tarsometatarsal) centered on JOINTS, deformity/dislocation, subchondral cysts, intra-articular debris, T1-preserved or sharply marginated marrow, NO contiguous ulcer/sinus, ghost sign absent.","impr":"Distribution and ghost sign favor [osteomyelitis] over [neuropathic arthropathy].","pearl":"Location is the strongest clue: midfoot + joint-centered = Charcot; pressure-point + ulcer-contiguous = osteomyelitis.","topic":"Infection","joint":"foot"},
{"id":"d1011","front":"How would you describe a diabetic foot ulcer with a tracking sinus to bone on MRI?","find":"Focal skin/subcutaneous defect with surrounding T2-hyperintense inflammation and rim-enhancing tract extending toward bone; measure ulcer width and depth. A T2-bright fluid/granulation tract bridging to cortex with adjacent confluent T1 marrow replacement = contiguous osteomyelitis. Document the named pressure point (e.g., beneath first/fifth metatarsal head, calcaneal tuberosity).","impr":"Plantar ulcer with sinus tract to bone and contiguous osteomyelitis.","pearl":"Always trace the ulcer/sinus to the nearest bone; contiguity + confluent T1 loss confirms osteomyelitis.","topic":"Infection","joint":"foot"},
{"id":"d1012","front":"How would you distinguish septic arthritis from a reactive (sympathetic) effusion?","find":"Septic: complex effusion with debris, thick (>3 mm) irregular nodular synovial enhancement, bone erosions, marrow edema flanking the joint, and inflamed enhancing periarticular soft tissue. Reactive: simple thin-walled effusion, smooth thin synovium, no erosions, and only mild adjacent edema from a neighboring process (e.g., adjacent osteomyelitis).","impr":"Findings favor [septic arthritis] over [reactive effusion].","pearl":"Thick irregular synovitis + erosions + bone marrow edema = septic; simple effusion with thin synovium = reactive.","topic":"Infection","joint":"general"},
{"id":"d1013","front":"How would you distinguish cellulitis from necrotizing fasciitis on MRI?","find":"Cellulitis: reticulated subcutaneous T2 hyperintensity and skin thickening with enhancement, NO deep fascial fluid. Necrotizing fasciitis: thick (>3 mm) T2-hyperintense fluid tracking along the DEEP FASCIA involving multiple compartments, NON-enhancing fascia/necrosis, and gas (T2/T1 signal voids). Multi-compartment deep fascial involvement is the alarm finding.","impr":"Deep fascial fluid and non-enhancement concerning for necrotizing fasciitis.","pearl":"Thick deep-fascial fluid, non-enhancement, and gas across compartments = necrotizing fasciitis (surgical emergency).","topic":"Infection","joint":"general"},
{"id":"d1014","front":"How would you describe pyomyositis on MRI?","find":"Early: diffuse muscle enlargement with T2/STIR hyperintense edema and homogeneous enhancement (myositis phase). Late: intramuscular rim-enhancing abscess with central T2-bright pus, restricted diffusion, and surrounding muscle edema and fascial inflammation. Document involved muscle and abscess size.","impr":"Pyomyositis with intramuscular abscess formation.","pearl":"Look for the rim-enhancing intramuscular collection with restricted diffusion within an edematous muscle.","topic":"Infection","joint":"general"},
{"id":"d1015","front":"How would you describe septic tenosynovitis on MRI?","find":"Distended tendon sheath with complex T2-hyperintense fluid and DEBRIS, thick irregular peripheral synovial enhancement, peritendinous soft-tissue edema, and possible tendon thickening or signal change. Restricted diffusion of sheath fluid supports infection. Contrast with simple tenosynovitis (thin smooth enhancement, clear fluid).","impr":"Septic tenosynovitis with complex sheath fluid and thick synovial enhancement.","pearl":"Complex fluid + thick irregular sheath enhancement + peritendinous edema = septic, not mechanical, tenosynovitis.","topic":"Infection","joint":"general"},
{"id":"d1016","front":"How would you describe an infected bursa (septic bursitis) on MRI?","find":"Distended bursa (e.g., olecranon, prepatellar) with complex/heterogeneous T2-hyperintense fluid, thick irregular peripheral enhancement, surrounding subcutaneous inflammatory edema and cellulitis, and possible restricted diffusion. Adjacent cortical erosion or marrow edema raises concern for spread to bone.","impr":"Septic bursitis with complex fluid and thick rim enhancement.","pearl":"Superficial bursa + complex fluid + overlying cellulitis = septic bursitis; thin smooth wall favors aseptic.","topic":"Infection","joint":"general"},
{"id":"d1017","front":"How would you describe pyogenic spondylodiscitis on MRI?","find":"Confluent low T1 / high T2 (STIR) signal in TWO adjacent vertebral endplates with endplate erosion/destruction, T2-hyperintense disc with loss of the intranuclear cleft, disc and endplate enhancement, and paravertebral/epidural phlegmon or rim-enhancing abscess. The disc is the epicenter and is destroyed.","impr":"Pyogenic spondylodiscitis with endplate destruction and paravertebral involvement.","pearl":"Disc destruction with T2-bright disc spanning two endplates is the hallmark of pyogenic discitis-osteomyelitis.","topic":"Infection","joint":"spine"},
{"id":"d1018","front":"How would you distinguish an epidural phlegmon from an epidural abscess on MRI?","find":"Phlegmon: homogeneously enhancing epidural soft tissue without a fluid center, no restricted diffusion. Abscess: peripherally (rim) enhancing collection with central non-enhancing T2-bright fluid and central restricted diffusion, exerting thecal sac/cord compression. Report craniocaudal extent and degree of canal compromise.","impr":"Rim-enhancing epidural abscess with central restricted diffusion and canal compromise.","pearl":"Homogeneous enhancement = phlegmon; rim enhancement with restricting center = drainable abscess.","topic":"Infection","joint":"spine"},
{"id":"d1019","front":"How would you describe facet (zygapophyseal) septic arthritis on MRI?","find":"Facet joint effusion with thick synovial and periarticular enhancement, subchondral marrow edema in the articular processes, and surrounding T2-hyperintense soft-tissue/muscle inflammation that may extend into the epidural space or paraspinal muscles. Often unilateral with juxta-articular abscess.","impr":"Septic facet arthritis with periarticular abscess.","pearl":"Unilateral facet effusion with bright periarticular and paraspinal edema and enhancement signals facet sepsis.","topic":"Infection","joint":"spine"},
{"id":"d1020","front":"How would you describe prosthetic (periprosthetic) joint infection on MRI?","find":"Joint effusion with LAMELLATED hyperintense synovial debris/membrane (alternating signal layers), thick irregular synovitis, periprosthetic marrow edema and osteolysis, extracapsular fluid collections, and a sinus tract extending to skin. Reactive lymphadenopathy may be present. Use MARS/metal-artifact-reduction sequences.","impr":"Periprosthetic joint infection with lamellated synovitis and sinus tract.","pearl":"Lamellated hyperintense synovitis and a sinus tract are the most specific MRI signs of prosthetic joint infection.","topic":"Infection","joint":"general"},
{"id":"d1021","front":"How would you describe tuberculous (Pott) spondylitis and distinguish it from pyogenic spondylodiscitis?","find":"TB: RELATIVELY PRESERVED disc with anterior subligamental spread across MULTIPLE vertebral levels, large well-defined paravertebral/psoas COLD abscess with thin smooth rim enhancement and possible calcification, subligamentous skip lesions, gibbus deformity. Pyogenic: disc destroyed early, two-level endplate disease, thick ill-defined abscess wall.","impr":"Findings favor tuberculous (Pott) spondylitis over pyogenic infection.","pearl":"Preserved disc + large thin-walled subligamentous cold abscess + multilevel/skip disease = TB.","topic":"Infection","joint":"spine"},
{"id":"d1022","front":"How would you describe a tuberculous (cold) soft-tissue abscess on MRI?","find":"Large well-circumscribed fluid collection with a THIN smooth enhancing rim and relatively little surrounding inflammatory edema (cold), often tracking along fascial planes or psoas. May contain debris/calcification and show restricted diffusion. Contrast with the thick irregular wall and intense surrounding edema of a pyogenic abscess.","impr":"Cold abscess consistent with tuberculous infection.","pearl":"Thin smooth wall + minimal surrounding edema + along fascial planes = cold (TB) abscess.","topic":"Infection","joint":"general"},
{"id":"d1023","front":"How would you describe mycetoma (Madura foot) on MRI?","find":"Multiple small T2-hyperintense soft-tissue abscess-like granulomas, each containing a tiny central low-signal grain producing the DOT-IN-CIRCLE sign (low-signal grain within a high-signal granuloma with a low-signal capsule). Conglomerate masses, sinus tracts, and underlying bone destruction/marrow infiltration in advanced disease.","impr":"Mycetoma with characteristic dot-in-circle sign.","pearl":"The dot-in-circle sign (T2-bright granuloma with central low-signal grain) is specific for mycetoma.","topic":"Infection","joint":"foot"},
{"id":"d1024","front":"How would you describe childhood acute osteomyelitis with physeal involvement on MRI?","find":"Metaphyseal confluent T1 marrow replacement with T2/STIR hyperintensity and enhancement, subperiosteal abscess (rim-enhancing fluid lifting the periosteum), and possible transphyseal spread to the epiphysis in young children (vessels cross the physis under ~18 months). Adjacent joint effusion may indicate secondary septic arthritis.","impr":"Pediatric acute osteomyelitis with subperiosteal abscess.","pearl":"In infants, vessels cross the physis, so metaphyseal osteomyelitis can spread transphyseally to the epiphysis and joint.","topic":"Infection","joint":"general"},
{"id":"d1025","front":"How would you confirm osteomyelitis underlying a diabetic ulcer and report its key supporting features?","find":"Report: (1) confluent low T1 marrow signal replacing fat in the bone beneath the ulcer; (2) corresponding T2/STIR marrow hyperintensity and avid marrow enhancement; (3) contiguity via a sinus tract/ulcer to the cortex; (4) cortical destruction; and ancillary signs of soft-tissue abscess, sinus tract, and ghost sign. State the involved bone and pressure point.","impr":"Osteomyelitis confirmed by confluent T1 marrow replacement contiguous with overlying ulcer.","pearl":"All three (low T1, high T2, enhancement) plus contiguity to an ulcer maximize specificity for osteomyelitis.","topic":"Infection","joint":"foot"},
{"id":"d1026","front":"How would you describe MRI features favoring psoriatic arthritis over rheumatoid arthritis?","find":"Asymmetric, ray-pattern distribution with DIP and PIP predilection; bone proliferation (fluffy periostitis, enthesophytes, paramarginal new bone) accompanying erosions rather than the pure osteopenic destructive erosions of RA; prominent enthesitis with peritendinous and pericapsular soft-tissue edema; dactylitis with diffuse flexor tenosynovitis and subcutaneous edema giving sausage digit; periarticular marrow edema extending into enthuses; relative preservation of periarticular bone density.","impr":"Asymmetric DIP-dominant arthropathy with bone proliferation and enthesitis, favoring psoriatic over rheumatoid arthritis.","pearl":"Proliferative new bone (periostitis/enthesophytes) coexisting with erosion is the cardinal PsA discriminator; RA erosions are purely destructive with osteopenia.","topic":"Arthropathy","joint":"hand"},
{"id":"d1027","front":"How would you describe MRI features of rheumatoid arthritis erosions and synovitis?","find":"Symmetric, bilateral MCP and PIP and wrist involvement with marginal (bare-area) erosions at the synovial reflection; florid pannus that is intermediate-to-low on T1, intermediate-high on T2, and avidly enhancing; periarticular osteopenia and marrow edema (osteitis) as a pre-erosive marker; uniform cartilage loss and joint-space narrowing; tenosynovitis of extensor and flexor tendons; absence of bone proliferation.","impr":"Symmetric proliferative synovitis with marginal erosions and osteitis, characteristic of rheumatoid arthritis.","pearl":"Osteitis (marrow edema) predicts future erosion in RA and is the strongest MRI predictor of structural progression.","topic":"Arthropathy","joint":"hand"},
{"id":"d1028","front":"How would you describe MRI features distinguishing gouty arthropathy from rheumatoid arthritis?","find":"Tophi as juxta-articular and intra-articular soft-tissue masses that are intermediate-to-low on T1 and heterogeneously low-to-intermediate on T2 (variable, reflecting urate and fibrosis), with peripheral or heterogeneous enhancement; well-corticated erosions with sclerotic margins and overhanging edges (Martel sign) remote from the joint margin; relative preservation of joint space until late; asymmetric distribution favoring first MTP and feet; minimal osteopenia.","impr":"Tophaceous masses with overhanging-edge erosions and preserved joint space, characteristic of gout.","pearl":"Low-to-intermediate T2 signal of tophi and the overhanging sclerotic erosion margin separate gout from the high-T2 pannus and bare-area erosions of RA.","topic":"Arthropathy","joint":"general"},
{"id":"d1029","front":"How would you describe MRI/imaging features of CPPD (calcium pyrophosphate) arthropathy?","find":"Chondrocalcinosis as linear and punctate calcification within hyaline and fibrocartilage, best seen on radiographs/CT or as low-signal foci on all MRI sequences; predilection for fibrocartilage of the knee menisci, triangular fibrocartilage complex of the wrist, symphysis pubis, and acetabular labrum; arthropathy in unusual sites such as the radiocarpal and patellofemoral and MCP compartments; prominent subchondral cysts and osteophytes with relatively preserved joint space; scapholunate advanced collapse pattern (SLAC) in the wrist.","impr":"Chondrocalcinosis with arthropathy in atypical compartments, characteristic of CPPD.","pearl":"TFCC and meniscal/labral chondrocalcinosis with patellofemoral and radiocarpal predominance points to CPPD over primary OA.","topic":"Arthropathy","joint":"general"},
{"id":"d1030","front":"How would you describe MRI features distinguishing erosive (inflammatory) osteoarthritis from rheumatoid and psoriatic arthritis?","find":"Central (subchondral) erosions producing the gull-wing and saw-tooth configuration at the DIP and PIP joints, with central collapse and marginal osteophytes; bilateral but often asymmetric IP involvement sparing MCP joints; marrow edema and synovitis localized to interphalangeal joints during flares; central rather than marginal erosion pattern; preservation of bone density.","impr":"Central gull-wing erosions at the interphalangeal joints, characteristic of erosive osteoarthritis.","pearl":"Central erosion (gull-wing) versus marginal erosion (RA) versus erosion-with-proliferation (PsA) is the key three-way discriminator at the IP joints.","topic":"Arthropathy","joint":"hand"},
{"id":"d1031","front":"How would you describe the MRI appearance of a gouty tophus and its signal behavior?","find":"Nodular or amorphous juxta-articular soft-tissue mass; intermediate-to-low signal on T1; characteristically heterogeneous low-to-intermediate signal on T2 (distinguishing from most cellular masses which are bright); homogeneous, peripheral rim, or heterogeneous enhancement; adjacent well-defined erosions with sclerotic overhanging margins; may show low-signal foci of dystrophic calcification within long-standing tophi; surrounding reactive marrow and soft-tissue edema during acute flare.","impr":"Heterogeneously low-T2 juxta-articular soft-tissue mass with adjacent corticated erosion, consistent with tophaceous gout.","pearl":"Low-to-intermediate T2 signal of a periarticular mass should prompt gout in the differential; dual-energy CT confirms urate.","topic":"Arthropathy","joint":"general"},
{"id":"d1032","front":"How would you describe MRI features of psoriatic dactylitis (sausage digit)?","find":"Diffuse, uniform enlargement of the entire digit; flexor tendon tenosynovitis with peritendinous soft-tissue edema and enhancement; subcutaneous and periarticular soft-tissue edema extending beyond the joint capsule; enthesitis at the flexor and extensor insertions; variable synovitis of the small joints and marrow edema; sometimes periostitis along the phalangeal shafts.","impr":"Diffuse flexor tenosynovitis with peri-tendinous and soft-tissue edema spanning the digit, consistent with psoriatic dactylitis.","pearl":"Dactylitis edema is centered on the flexor sheath and extends beyond the joint, unlike the joint-centered synovitis of RA.","topic":"Arthropathy","joint":"hand"},
{"id":"d1033","front":"How would you describe the pencil-in-cup and acro-osteolysis features of psoriatic arthritis?","find":"Marked erosion of the distal end of a phalanx tapering it to a point (pencil) which sits within the cupped, eroded and proliferative base of the more distal phalanx (cup); arthritis mutilans with telescoping digits in severe disease; tuftal resorption and acro-osteolysis; coexisting fluffy periostitis and bony ankylosis distinguishing the proliferative nature.","impr":"Pencil-in-cup deformity with proliferative change and acro-osteolysis, characteristic of advanced psoriatic arthritis.","pearl":"Coexisting bony proliferation and ankylosis separate psoriatic pencil-in-cup from the purely resorptive deformities of other arthropathies.","topic":"Arthropathy","joint":"hand"},
{"id":"d1034","front":"How would you describe active versus structural sacroiliitis lesions on MRI in axial spondyloarthritis?","find":"Active inflammatory lesions: subchondral bone marrow edema/osteitis (high STIR/T2-FS, low T1, enhancing) adjacent to the SI joints, capsulitis, enthesitis, and synovitis; deep and extensive periarticular edema is more specific. Structural lesions: erosions of the subchondral cortex, subchondral sclerosis, fatty marrow metaplasia (T1-bright), backfill (bright tissue filling erosions), and bony ankylosis. Iliac side often affected earlier and more than sacral.","impr":"Subchondral osteitis with erosions and fatty metaplasia at the SI joints, consistent with sacroiliitis of axial spondyloarthritis.","pearl":"Bone marrow edema in the subchondral SI bone is the defining ASAS active lesion; backfill and fat metaplasia mark the transition to structural disease.","topic":"Arthropathy","joint":"spine"},
{"id":"d1035","front":"How would you describe MRI features of juvenile idiopathic arthritis distinguishing it from adult arthritis?","find":"Synovial hypertrophy and effusion with enhancing pannus; growth disturbances including epiphyseal overgrowth (ballooned epiphyses), accelerated skeletal maturation, premature physeal fusion with limb-length discrepancy, and gracile diaphyses; early cartilage loss and erosions; tendency toward bony ankylosis (notably cervical spine and wrist/carpal coalition); periarticular osteopenia; involvement of the temporomandibular joints.","impr":"Enhancing synovitis with epiphyseal overgrowth and ankylosis, characteristic of juvenile idiopathic arthritis.","pearl":"Growth disturbance (epiphyseal ballooning, premature fusion, limb-length discrepancy) and carpal/cervical ankylosis are unique to skeletally immature JIA patients.","topic":"Arthropathy","joint":"general"},
{"id":"d1036","front":"How would you describe enthesitis on MRI in enthesitis-related/spondyloarthritis?","find":"High T2/STIR signal and enhancement at tendon, ligament, and capsule insertions; perientheseal soft-tissue edema and adjacent bone marrow edema (osteitis) at the enthesis; enthesophyte formation and cortical erosion or irregularity at insertion; common sites include calcaneal Achilles and plantar fascia insertions, patellar tendon, quadriceps, and pelvic entheses.","impr":"Insertional soft-tissue and bone marrow edema with enthesophytes, characteristic of enthesitis in spondyloarthritis.","pearl":"Perientheseal bone marrow edema extending into the adjacent bone (not just tendon signal) is the discriminating feature of true enthesitis.","topic":"Arthropathy","joint":"general"},
{"id":"d1037","front":"How would you describe imaging features of SAPHO syndrome?","find":"Synovitis, acne, pustulosis, hyperostosis, osteitis complex; anterior chest wall hyperostosis and osteitis of the sternoclavicular and manubriosternal regions (bull-head appearance) with marrow edema and enhancement; multifocal sterile osteomyelitis with mixed sclerosis and lysis; vertebral corner lesions, paravertebral ossification, and erosions; chronic recurrent multifocal osteomyelitis in younger patients.","impr":"Anterior chest wall hyperostosis with multifocal osteitis, consistent with SAPHO syndrome.","pearl":"Sternocostoclavicular hyperostosis (bull-head sign) with sterile multifocal osteitis is the hallmark of SAPHO.","topic":"Arthropathy","joint":"general"},
{"id":"d1038","front":"How would you describe imaging features of RS3PE syndrome?","find":"Remitting seronegative symmetric synovitis with pitting edema; symmetric distal extensor and flexor tenosynovitis with marked peritendinous and dorsal subcutaneous soft-tissue edema of the hands and feet; synovitis and effusions without erosions; striking pitting edema of dorsa of hands/feet; absence of bony destruction distinguishing it from RA.","impr":"Symmetric tenosynovitis with marked dorsal soft-tissue edema and no erosions, consistent with RS3PE.","pearl":"Florid tenosynovitis with dorsal pitting edema and complete absence of erosions in an elderly patient suggests RS3PE.","topic":"Arthropathy","joint":"hand"},
{"id":"d1039","front":"How would you describe MRI features of amyloid arthropathy?","find":"Periarticular and intra-articular soft-tissue and synovial deposits that are characteristically low-to-intermediate signal on both T1 and T2 (similar to muscle), distinguishing from the bright synovitis of inflammatory arthritis; bilateral symmetric large-joint involvement (shoulders, hips, wrists) with juxta-articular subchondral cysts and erosions with preserved joint space; thickened low-signal synovium with mild enhancement; common in long-term dialysis (beta-2 microglobulin), causing carpal tunnel and destructive spondyloarthropathy.","impr":"Low-T1/low-T2 synovial and periarticular deposits with subchondral cysts, characteristic of amyloid arthropathy.","pearl":"Low T2 signal of synovial/soft-tissue deposits with preserved joint space distinguishes amyloid from high-T2 inflammatory pannus.","topic":"Arthropathy","joint":"general"},
{"id":"d1040","front":"How would you describe imaging features of hemochromatosis arthropathy?","find":"Arthropathy targeting the second and third metacarpophalangeal joints with characteristic hook-shaped (beak) osteophytes on the radial aspect of the metacarpal heads; chondrocalcinosis from secondary CPPD; subchondral cysts and sclerosis; relatively uniform joint-space narrowing; symmetric involvement; may involve wrists, hips, and knees.","impr":"Second and third MCP arthropathy with hook osteophytes and chondrocalcinosis, characteristic of hemochromatosis.","pearl":"Hook osteophytes at the radial MCP heads (especially 2nd and 3rd) plus chondrocalcinosis is the classic hemochromatosis signature.","topic":"Arthropathy","joint":"hand"},
{"id":"d1041","front":"How would you describe MRI features of hemophilic arthropathy?","find":"Recurrent hemarthrosis with hemosiderin-laden synovial hypertrophy that blooms and shows marked low signal on gradient-echo and low signal on T1/T2 (susceptibility); joint effusions of varying age with layering blood products; cartilage destruction, subchondral cysts, and erosions; epiphyseal overgrowth and squaring (e.g., widened intercondylar notch of the knee, enlarged radial head); target joints knee, elbow, ankle.","impr":"Hemosiderin-laden synovitis with blooming and joint destruction, characteristic of hemophilic arthropathy.","pearl":"Diffuse low-signal blooming hemosiderin synovitis with epiphyseal overgrowth (widened intercondylar notch) in a young male indicates hemophilia.","topic":"Arthropathy","joint":"general"},
{"id":"d1042","front":"How would you differentiate hemophilic arthropathy from PVNS/TGCT, both of which bloom?","find":"Both show hemosiderin-laden, low-signal blooming synovium; PVNS/diffuse TGCT is typically monoarticular (commonly knee) with focal nodular or villous masslike synovial proliferation and erosions on both sides of a tight joint, no systemic bleeding disorder; hemophilic arthropathy is bilateral/multifocal in target joints, with epiphyseal overgrowth, growth disturbance, and a clinical bleeding history; hemophilia distributes diffusely rather than as a discrete intra-articular mass.","impr":"Monoarticular masslike blooming synovitis favors PVNS/TGCT; bilateral target-joint disease with epiphyseal overgrowth favors hemophilia.","pearl":"Monoarticular nodular mass = TGCT/PVNS; bilateral target joints with growth changes = hemophilic arthropathy.","topic":"Arthropathy","joint":"general"},
{"id":"d1043","front":"How would you describe imaging features of scleroderma (systemic sclerosis) musculoskeletal involvement?","find":"Acro-osteolysis with resorption of distal phalangeal tufts; soft-tissue calcinosis (subcutaneous and periarticular dystrophic calcification) that is low signal on MRI and dense on radiographs; soft-tissue atrophy and tapering of fingertips; flexion contractures; erosive change at the first carpometacarpal joint; calcinosis circumscripta.","impr":"Distal tuft acro-osteolysis with soft-tissue calcinosis, characteristic of scleroderma.","pearl":"Combination of tuftal acro-osteolysis and subcutaneous calcinosis with fingertip soft-tissue atrophy is the scleroderma hallmark.","topic":"Arthropathy","joint":"hand"},
{"id":"d1044","front":"How would you describe imaging features of SLE arthropathy (Jaccoud-type)?","find":"Reducible, nonerosive deformities including ulnar deviation at the MCP joints, swan-neck and boutonnière deformities, and thumb Z-deformity that correct on positioning views; ligamentous and capsular laxity with malalignment but preserved cortex and joint space; absence of true erosions and absence of pannus-related destruction; soft-tissue swelling and mild synovitis only.","impr":"Reversible nonerosive MCP malalignment, characteristic of Jaccoud arthropathy in SLE.","pearl":"Deformity without erosion that reduces on stress views distinguishes Jaccoud/SLE arthropathy from RA.","topic":"Arthropathy","joint":"hand"},
{"id":"d1045","front":"How would you describe imaging features of reactive arthritis?","find":"Asymmetric lower-extremity oligoarthritis with enthesitis; calcaneal enthesitis at Achilles and plantar fascia insertions with erosive and proliferative (fluffy periostitis) change; dactylitis; sacroiliitis (often asymmetric); periostitis along metatarsals and phalanges; soft-tissue edema; relative sparing of upper extremities.","impr":"Asymmetric lower-limb enthesitis with calcaneal erosive-proliferative change, consistent with reactive arthritis.","pearl":"Asymmetric lower-extremity enthesitis with fluffy calcaneal periostitis and a post-infectious history points to reactive arthritis.","topic":"Arthropathy","joint":"general"},
{"id":"d1046","front":"How would you describe imaging features of sarcoid arthropathy and osseous sarcoidosis?","find":"Lacy, reticulated trabecular pattern with cystic and lytic lesions in the phalanges (especially middle and distal); cortical tunneling and a coarse honeycomb appearance; soft-tissue swelling (dactylitis) overlying involved bones; nonaggressive well-defined lesions; marrow signal abnormality on MRI with enhancing granulomatous foci; tuftal resorption in some.","impr":"Lacy reticulated phalangeal lytic lesions with soft-tissue swelling, characteristic of osseous sarcoidosis.","pearl":"Lace-like trabecular and cystic phalangeal lesions with overlying soft-tissue dactylitis is the classic sarcoid pattern.","topic":"Arthropathy","joint":"hand"},
{"id":"d1047","front":"How would you describe imaging features of multicentric reticulohistiocytosis?","find":"Severe, rapidly progressive, symmetric erosive arthropathy with a striking predilection for the DIP joints; well-marginated marginal erosions widening to involve the joint with arthritis mutilans; preservation of bone density (no periarticular osteopenia) and minimal periosteal reaction distinguishing it from PsA; soft-tissue nodules around joints and over the face; rapid joint destruction out of proportion.","impr":"Symmetric severe DIP-dominant erosive arthritis with preserved bone density, consistent with multicentric reticulohistiocytosis.","pearl":"Aggressive symmetric DIP erosions WITHOUT osteopenia or proliferation, plus periarticular nodules, separates MRH from RA and PsA.","topic":"Arthropathy","joint":"hand"},
{"id":"d1048","front":"How would you differentiate neuropathic (Charcot) arthropathy from inflammatory arthritis on MRI?","find":"Neuropathic: the 6 D's (joint Destruction, Dislocation, Debris, increased Density, Disorganization, Distension) with large effusions, intra-articular bodies, subluxation, and bony fragmentation centered on midfoot/ankle in diabetics; marrow signal abnormality follows subchondral distribution and may mimic osteomyelitis; relative preservation of bone mineral density; rapid progression with disorganization out of proportion to symptoms. Inflammatory arthritis shows symmetric erosions, synovitis, and osteopenia without the gross disorganization and debris.","impr":"Joint disorganization with debris, fragmentation, and subluxation, characteristic of neuropathic arthropathy.","pearl":"Gross disorganization, debris, and dislocation in a neuropathic patient distinguish Charcot from the orderly erosive pattern of inflammatory arthritis.","topic":"Arthropathy","joint":"general"},
{"id":"d1049","front":"How would you differentiate septic arthritis from an inflammatory arthritis flare on MRI?","find":"Septic: joint effusion with synovial thickening and enhancement, perisynovial/periarticular soft-tissue edema and enhancement extending beyond the capsule, adjacent osteomyelitis (confluent low-T1 marrow replacement with enhancement), abscess/fluid collections, and rapid cartilage destruction; usually monoarticular with intense surrounding inflammation. Inflammatory flare: synovitis and effusion confined to the joint with erosions, typically polyarticular/symmetric, without aggressive transarticular soft-tissue inflammation or marrow replacement.","impr":"Monoarticular effusion with transcapsular soft-tissue inflammation and adjacent osteomyelitis, concerning for septic arthritis.","pearl":"Extensive periarticular soft-tissue edema/enhancement extending beyond the capsule with adjacent osteomyelitis favors infection over a sterile flare; aspirate to confirm.","topic":"Arthropathy","joint":"general"},
{"id":"d1050","front":"How would you describe MRI features of tenosynovial giant cell tumor (PVNS) as a monoarticular mimic?","find":"Frondlike or nodular synovial proliferation with diffuse low signal on T1 and T2 and marked blooming on gradient-echo from hemosiderin; recurrent serosanguineous effusion; pressure erosions on both sides of the joint with sclerotic margins and preserved joint space until late; avid enhancement of the soft-tissue synovial component; knee most common, then hip/ankle.","impr":"Monoarticular blooming hemosiderin-laden synovial proliferation with juxta-articular erosions, characteristic of PVNS/diffuse TGCT.","pearl":"Monoarticular blooming low-signal synovitis with bilateral pressure erosions and preserved joint space is the PVNS signature.","topic":"Arthropathy","joint":"general"},
{"id":"d1051","front":"How would you describe MRI features of synovial (osteo)chondromatosis as a monoarticular mimic?","find":"Multiple intra-articular bodies of similar size; when cartilaginous, lobulated soft-tissue bodies that are bright on T2 with low-signal mineralization; when ossified, peripheral cortical low signal with central marrow fat (T1-bright) and arc-and-ring calcification on radiographs; distended joint with synovial proliferation; pressure erosions; knee, hip, elbow, shoulder.","impr":"Multiple similar-sized intra-articular bodies with chondral/osseous signal, characteristic of synovial chondromatosis.","pearl":"Numerous uniform-sized bodies with ring-and-arc mineralization distinguish synovial chondromatosis from degenerative loose bodies.","topic":"Arthropathy","joint":"general"},
{"id":"d1052","front":"How would you summarize the erosion-character discriminators across the major arthropathies in report language?","find":"Marginal (bare-area) erosions with osteopenia and high-T2 pannus = rheumatoid arthritis; erosion plus bone proliferation/fluffy periostitis with DIP predilection = psoriatic arthritis; overhanging-edge sclerotic erosions remote from the joint with low-T2 tophi and preserved space = gout; central gull-wing IP erosions = erosive osteoarthritis; symmetric aggressive DIP erosions WITHOUT osteopenia or proliferation = multicentric reticulohistiocytosis; subchondral cysts with low-T2 deposits and preserved space = amyloid; pressure erosions on both sides with blooming synovium = PVNS.","impr":"Erosion morphology (marginal vs proliferative vs overhanging vs central vs pressure) is the unifying discriminator across arthropathies.","pearl":"Always characterize erosion location (marginal/central/remote), margin (sclerotic/ill-defined/overhanging), and accompanying proliferation versus osteopenia to narrow the arthropathy differential.","topic":"Arthropathy","joint":"general"},
{"id":"d1053","front":"How would you describe MRI features distinguishing inflammatory synovitis from degenerative joint disease?","find":"Inflammatory synovitis: thick, hypertrophic, avidly and diffusely enhancing pannus with frondlike villous proliferation, marrow edema/osteitis, bare-area erosions, and tenosynovitis. Degenerative: thin smooth synovium with mild or no enhancement, osteophytes, subchondral sclerosis and cysts, focal cartilage loss, and effusion without florid pannus or marrow osteitis.","impr":"Hypertrophic enhancing pannus with osteitis and erosions favors inflammatory synovitis over degenerative disease.","pearl":"Volume and avidity of synovial enhancement plus presence of subchondral osteitis separate active inflammatory synovitis from bland degenerative effusion.","topic":"Arthropathy","joint":"general"},
{"id":"d1054","front":"What is the normal Achilles tendon AP thickness and what defines tendinosis?","find":"The Achilles tendon measures up to 6 mm in AP thickness on sagittal images; thickening > 6-7 mm with intrasubstance intermediate signal indicates tendinosis.","impr":"Normal Achilles AP <= 6 mm; tendinosis when > 6-7 mm with abnormal signal.","pearl":"Measure AP diameter on sagittal at the level of maximal thickening, several cm above the calcaneal insertion (mid-portion).","topic":"Measurements","joint":"ankle"},
{"id":"d1055","front":"What plantar fascia thickness threshold defines plantar fasciitis?","find":"Normal plantar fascia is < 4 mm thick at the calcaneal origin; thickening > 4 mm (often 5-7 mm) with perifascial edema indicates plantar fasciitis.","impr":"Plantar fascia > 4 mm at the calcaneal origin = fasciitis.","pearl":"Measure perpendicular thickness on sagittal just distal to the calcaneal tuberosity insertion.","topic":"Measurements","joint":"ankle"},
{"id":"d1056","front":"What is the normal patellar tendon thickness and the threshold for patellar tendinopathy?","find":"The patellar tendon normally measures up to 5-7 mm AP; focal proximal thickening > 7 mm with intrasubstance T2 hyperintensity indicates patellar tendinopathy (jumper's knee).","impr":"Patellar tendon > 7 mm, especially proximal/posterior, suggests tendinopathy.","pearl":"Measure AP thickness on sagittal 1-2 cm distal to the inferior patellar pole, where jumper's knee typically occurs.","topic":"Measurements","joint":"knee"},
{"id":"d1057","front":"What is the normal quadriceps tendon thickness?","find":"The quadriceps tendon normally measures approximately 5-8 mm in AP thickness; focal thickening with signal abnormality suggests tendinosis or partial tear.","impr":"Normal quadriceps tendon ~5-8 mm AP; thicker with signal = tendinosis.","pearl":"Measure on sagittal just proximal to the superior patellar pole.","topic":"Measurements","joint":"knee"},
{"id":"d1058","front":"What median nerve cross-sectional area at the carpal tunnel suggests carpal tunnel syndrome?","find":"Normal median nerve CSA at the carpal tunnel inlet (pisiform level) is < 10 mm^2; a CSA > 10-12 mm^2 supports carpal tunnel syndrome.","impr":"Median nerve CSA > 10-12 mm^2 at the inlet supports CTS.","pearl":"Trace within the hyperintense epineurial rim on axial T2 at the pisiform/distal radius level; compare to the more proximal forearm nerve.","topic":"Measurements","joint":"wrist"},
{"id":"d1059","front":"What is the normal cervical spinal canal AP diameter and the thresholds for stenosis?","find":"Normal subaxial cervical canal AP diameter is approximately 17-18 mm; developmental (relative) stenosis is < 13 mm and absolute stenosis is < 10 mm.","impr":"Cervical canal < 13 mm = developmental stenosis; < 10 mm = absolute stenosis.","pearl":"Measure midsagittal AP from posterior vertebral body to the spinolaminar line at each level.","topic":"Measurements","joint":"spine"},
{"id":"d1060","front":"What is the Torg-Pavlov ratio and the threshold for developmental cervical stenosis?","find":"The Torg-Pavlov ratio is the canal AP diameter divided by the vertebral body AP diameter; a ratio < 0.8 indicates developmental cervical canal stenosis.","impr":"Torg-Pavlov ratio < 0.8 = developmental cervical stenosis.","pearl":"Ratio corrects for radiographic magnification; measured at C3-C6, normal is ~1.0.","topic":"Measurements","joint":"spine"},
{"id":"d1061","front":"What are the lumbar spinal canal AP diameter thresholds for stenosis?","find":"Normal lumbar canal AP diameter is approximately 15-25 mm; relative stenosis is < 12 mm and absolute stenosis is < 10 mm.","impr":"Lumbar canal < 12 mm = relative, < 10 mm = absolute stenosis.","pearl":"Measure midsagittal AP at the disc level; dural sac cross-sectional area < 100 mm^2 is an alternative axial criterion for stenosis.","topic":"Measurements","joint":"spine"},
{"id":"d1062","front":"What dural (thecal) sac cross-sectional area on axial MRI defines lumbar central stenosis?","find":"A dural sac cross-sectional area < 100 mm^2 indicates relative lumbar central canal stenosis, and < 75-80 mm^2 indicates severe (absolute) stenosis.","impr":"Thecal sac CSA < 100 mm^2 = relative, < 75 mm^2 = severe lumbar stenosis.","pearl":"Trace the thecal sac on axial T2 at the disc level; combine with morphologic grading of CSF effacement.","topic":"Measurements","joint":"spine"},
{"id":"d1063","front":"What is the normal meniscal extrusion threshold on coronal MRI of the knee?","find":"Meniscal body extrusion > 3 mm beyond the tibial margin is considered pathologic (major extrusion), associated with root tears and osteoarthritis.","impr":"Meniscal extrusion > 3 mm = pathologic; correlates with root tears/OA.","pearl":"Measure on the mid-coronal image from the tibial plateau edge (excluding osteophytes) to the outer meniscal margin.","topic":"Measurements","joint":"knee"},
{"id":"d1064","front":"What short-axis size defines a pathologic lymph node on MRI?","find":"A short-axis diameter > 10 mm is generally abnormal for nodes; the retroperitoneal threshold is > 8-10 mm and a rounded shape or loss of fatty hilum increases suspicion.","impr":"Short axis > 10 mm (> 8 mm retroperitoneal) suggests pathologic nodes.","pearl":"Always measure the short axis, not long axis; morphology (round, necrotic, lost hilum) matters as much as size.","topic":"Measurements","joint":"general"},
{"id":"d1065","front":"What is the vertebral body T1 marrow signal rule for distinguishing benign from malignant marrow?","find":"Marrow that is hyperintense or isointense to skeletal muscle and adjacent disc on T1 is benign; marrow hypointense (darker) than muscle or disc on T1 is suspicious for tumor infiltration.","impr":"T1 marrow darker than muscle/disc = suspicious for malignant infiltration.","pearl":"Use non-fat-suppressed T1; preserved fatty marrow brighter than disc favors a benign process.","topic":"Measurements","joint":"spine"},
{"id":"d1066","front":"What fat fraction threshold on chemical-shift (Dixon) MRI distinguishes benign from malignant marrow lesions?","find":"A signal-intensity drop > 20% on opposed-phase (or fat fraction > 20%) indicates microscopic fat and favors a benign lesion; < 20% drop suggests marrow-replacing tumor.","impr":"Opposed-phase signal drop > 20% (fat fraction > 20%) favors benign marrow.","pearl":"Compare in-phase vs opposed-phase ROI; sclerotic metastases and red marrow can be exceptions.","topic":"Measurements","joint":"general"},
{"id":"d1067","front":"What is the normal glenoid version on axial MRI?","find":"Normal glenoid version is approximately 0 to -7 degrees (slight retroversion); retroversion > 10-15 degrees is associated with posterior instability and dysplasia.","impr":"Normal glenoid version ~0 to -7 deg; > 10-15 deg retroversion is abnormal.","pearl":"Measure on axial at mid-glenoid: angle between the glenoid line and the perpendicular to the scapular body axis (Friedman method).","topic":"Measurements","joint":"shoulder"},
{"id":"d1068","front":"What is normal femoral anteversion and the abnormal thresholds?","find":"Normal femoral anteversion is approximately 10-20 degrees; > 25 degrees is excessive anteversion and < 5 degrees (or negative) indicates retroversion.","impr":"Normal femoral anteversion 10-20 deg; > 25 deg excessive, < 5 deg retroverted.","pearl":"On axial CT/MRI, angle between the femoral neck axis and the posterior femoral condylar tangent.","topic":"Measurements","joint":"hip"},
{"id":"d1069","front":"What are the rotator cuff tear size categories on MRI?","find":"Full-thickness tears are categorized by maximal dimension as small (< 1 cm), medium (1-3 cm), large (3-5 cm), and massive (> 5 cm or involving 2 or more tendons).","impr":"Small < 1 cm, medium 1-3 cm, large 3-5 cm, massive > 5 cm or >= 2 tendons.","pearl":"Report both AP (sagittal) and ML retraction (coronal) dimensions; massive can be defined by size or multi-tendon involvement.","topic":"Measurements","joint":"shoulder"},
{"id":"d1070","front":"What is the normal calcaneal pitch angle and the threshold for pes planus?","find":"Normal calcaneal pitch is approximately 20-30 degrees; < 18-20 degrees indicates pes planus (flatfoot) and > 30 degrees suggests pes cavus.","impr":"Calcaneal pitch < 18-20 deg = pes planus; > 30 deg = pes cavus.","pearl":"Angle between the inferior calcaneal cortex and the supporting horizontal surface on lateral weightbearing imaging.","topic":"Measurements","joint":"ankle"},
{"id":"d1071","front":"What is the normal Bohler angle and the threshold for calcaneal fracture?","find":"Normal Bohler (tuber joint) angle is 20-40 degrees; an angle < 20 degrees indicates collapse from a calcaneal compression fracture.","impr":"Bohler angle < 20 deg = calcaneal fracture collapse (normal 20-40 deg).","pearl":"Angle between a line along the posterior facet/tuberosity and a line to the anterior process apex on sagittal/lateral.","topic":"Measurements","joint":"ankle"},
{"id":"d1072","front":"What is the normal angle of Gissane?","find":"The angle of Gissane (critical angle) normally measures 120-145 degrees; an increased angle indicates collapse of the posterior facet in calcaneal fracture.","impr":"Normal angle of Gissane 120-145 deg; increased with posterior facet collapse.","pearl":"Formed by the downward and upward cortical struts at the lateral calcaneal angle on lateral/sagittal images.","topic":"Measurements","joint":"ankle"},
{"id":"d1073","front":"What are the normal hallux valgus and intermetatarsal angles?","find":"Normal hallux valgus angle is < 15 degrees and normal 1st-2nd intermetatarsal angle is < 9 degrees; hallux valgus > 15 degrees and IMA > 9 degrees indicate bunion deformity.","impr":"HVA < 15 deg and IMA < 9 deg are normal; greater values = hallux valgus.","pearl":"HVA between 1st metatarsal and proximal phalanx shaft axes; IMA between 1st and 2nd metatarsal shaft axes.","topic":"Measurements","joint":"foot"},
{"id":"d1074","front":"What is the acetabular index (acetabular angle) and its normal values by age in infants?","find":"The acetabular index normally is < 30 degrees at birth and < 25 degrees by 6 months; values above these thresholds indicate acetabular dysplasia (DDH).","impr":"Acetabular index > 30 deg (newborn) or > 25 deg (6 mo) = dysplasia.","pearl":"Angle between Hilgenreiner line and a line along the bony acetabular roof; decreases with normal development.","topic":"Measurements","joint":"hip"},
{"id":"d1075","front":"What ulnar nerve cross-sectional area at the cubital tunnel suggests cubital tunnel syndrome?","find":"Normal ulnar nerve CSA at the elbow is approximately 6-8 mm^2; a CSA > 8-10 mm^2 with T2 hyperintensity supports cubital tunnel syndrome.","impr":"Ulnar nerve CSA > 8-10 mm^2 at the cubital tunnel supports neuropathy.","pearl":"Measure on axial T2 at the retrocondylar (epicondylar) groove; compare to proximal segment and look for signal increase.","topic":"Measurements","joint":"elbow"},
{"id":"d1076","front":"What is the normal Cobb angle threshold for diagnosing scoliosis?","find":"A coronal Cobb angle >= 10 degrees defines scoliosis; angles of 25-40 degrees are moderate and > 40-50 degrees are typically surgical.","impr":"Scoliosis is a Cobb angle >= 10 deg; > 40-50 deg often surgical.","pearl":"Measure between the most tilted superior and inferior end vertebrae endplate lines of the curve.","topic":"Measurements","joint":"spine"},
{"id":"d1077","front":"How is spondylolisthesis graded by the Meyerding classification?","find":"Spondylolisthesis is graded by percent anterior slip of the vertebral body: grade 1 (0-25%), grade 2 (25-50%), grade 3 (50-75%), grade 4 (75-100%), and grade 5 (spondyloptosis, > 100%).","impr":"Meyerding grades by % slip: 1 (<25%), 2, 3, 4, 5 (>100%, ptosis).","pearl":"Measure slip of the superior body relative to the AP width of the superior endplate of the vertebra below.","topic":"Measurements","joint":"spine"},
{"id":"d1078","front":"What is the normal articular cartilage thickness by joint on MRI?","find":"Normal hyaline cartilage thickness is approximately 2-4 mm at the patella (thickest), 1.5-2 mm at the femoral condyles, ~1.3 mm at the hip, and < 1 mm at the ankle talar dome.","impr":"Patella ~2-4 mm (thickest), femur ~1.5-2 mm, hip ~1.3 mm, ankle < 1 mm.","pearl":"Patellar cartilage is the thickest in the body; thin ankle cartilage makes chondral lesions harder to detect.","topic":"Measurements","joint":"knee"},
{"id":"d1079","front":"What is the dGEMRIC index threshold suggesting cartilage glycosaminoglycan loss?","find":"On delayed gadolinium-enhanced MRI of cartilage, a dGEMRIC index (T1 in gadolinium) > 500-600 ms is normal; values < 400-450 ms indicate glycosaminoglycan depletion and early degeneration.","impr":"dGEMRIC index < 400-450 ms indicates GAG loss / early cartilage damage.","pearl":"Anionic Gd-DTPA distributes inversely to negatively charged GAG; lower T1 = lower GAG content.","topic":"Measurements","joint":"hip"},
{"id":"d1080","front":"What knee joint effusion size on MRI is considered physiologic versus abnormal?","find":"A small physiologic effusion measures < 5 mm depth in the suprapatellar recess; a depth > 10 mm (or capacious distension) indicates a moderate-to-large abnormal effusion.","impr":"Suprapatellar recess fluid < 5 mm physiologic; > 10 mm = significant effusion.","pearl":"Measure AP fluid depth in the suprapatellar pouch on sagittal; distinguish simple fluid from synovitis/complex fluid.","topic":"Measurements","joint":"knee"},
{"id":"d1081","front":"What is the glenoid track concept and the threshold for an off-track Hill-Sachs lesion?","find":"The glenoid track width is about 83% of the glenoid diameter; a Hill-Sachs interval that exceeds the glenoid track (off-track) predicts engagement and instability, while one within the track is on-track.","impr":"Hill-Sachs is off-track (engaging) when it exceeds 83% of glenoid diameter track.","pearl":"Glenoid track = 0.83 x (glenoid diameter - anterior bone loss); compare to Hill-Sachs interval (Hill-Sachs width + bone bridge).","topic":"Measurements","joint":"shoulder"},
{"id":"d1082","front":"What is the normal lateral talocalcaneal (Kite) angle and what does an abnormal value indicate?","find":"The normal lateral talocalcaneal angle is approximately 25-50 degrees; an increased angle indicates hindfoot valgus (pes planus) and a decreased angle indicates hindfoot varus (clubfoot/cavus).","impr":"Lateral talocalcaneal (Kite) angle 25-50 deg; increased = valgus, decreased = varus.","pearl":"Angle between the long axes of the talus and calcaneus on lateral; the AP talocalcaneal angle (normal 20-40 deg) complements it.","topic":"Measurements","joint":"foot"},
{"id":"d1083","front":"What bone lesion size or features warrant biopsy versus a periosteal reaction concerning for aggressiveness?","find":"Aggressive features include a wide zone of transition, lamellated/onion-skin or sunburst/spiculated periosteal reaction, and Codman triangle; an associated soft-tissue mass or matrix-producing lesion warrants biopsy regardless of size.","impr":"Interrupted periosteal reaction (sunburst, Codman, onion-skin) = aggressive; biopsy.","pearl":"Solid/smooth periosteal reaction is slow/benign; lamellated, spiculated, or Codman triangle reflects rapid growth.","topic":"Measurements","joint":"general"},
{"id":"d1084","front":"What common peroneal nerve cross-sectional area at the fibular neck suggests neuropathy?","find":"Normal common peroneal nerve CSA at the fibular neck is approximately 8-12 mm^2; enlargement above this with T2 hyperintensity supports peroneal neuropathy or entrapment.","impr":"Enlarged common peroneal nerve (> ~12 mm^2) with T2 signal = neuropathy.","pearl":"Evaluate on axial T2 fat-sat at the fibular head/neck; look for fascicular enlargement and denervation edema in the anterior/lateral compartments.","topic":"Measurements","joint":"knee"},
{"id":"d1085","front":"What is the normal physeal width and what indicates physeal widening?","find":"The normal growth plate (physis) measures approximately 2-4 mm in width on MRI; widening > 4-5 mm suggests rickets, chronic stress (gymnast wrist), or physeal injury.","impr":"Physis ~2-4 mm; widening > 4-5 mm suggests rickets or chronic stress injury.","pearl":"Assess on coronal/sagittal images; metaphyseal cupping/fraying with widening favors rickets, focal widening favors stress (Salter-Harris) injury.","topic":"Measurements","joint":"wrist"},
{"id":"d1086","front":"How would you describe a type I SLAP tear?","find":"Fraying and intrasubstance increased signal at the free margin of the superior labrum without a fluid/contrast-signal cleft to the glenoid and without detachment of the biceps anchor, which remains firmly attached to the supraglenoid tubercle.","impr":"Type I SLAP — degenerative superior labral fraying with an intact biceps anchor.","pearl":"Type I is degenerative/age-related and often incidental — no anchor detachment, no displaced fragment.","topic":"SLAP / labrum","joint":"shoulder"},
{"id":"d1087","front":"How would you describe a type II SLAP tear?","find":"Irregular, laterally curved fluid/contrast-signal cleft undermining the superior labrum and extending medial to the biceps anchor, with detachment of the biceps-labral complex from the supraglenoid tubercle ([anterior/posterior/combined] subtype). Signal exceeds a normal sublabral recess.","impr":"Type II SLAP — detachment of the biceps-labral anchor from the superior glenoid.","pearl":"The classic unstable SLAP. Distinguish from a normal sublabral recess: a recess is smooth, medial, and parallel to the glenoid; a SLAP cleft is irregular, laterally curved, and extends posterior to the anchor.","topic":"SLAP / labrum","joint":"shoulder"},
{"id":"d1088","front":"How would you describe a type III SLAP tear?","find":"Bucket-handle tear of the superior labrum with a displaced inner labral fragment into the joint, while the peripheral labrum and the biceps-labral anchor remain attached to the glenoid. The biceps tendon itself is intact.","impr":"Type III SLAP — bucket-handle superior labral tear with a displaced fragment and intact biceps anchor.","pearl":"Key discriminator from type IV: in type III the biceps tendon is NOT involved.","topic":"SLAP / labrum","joint":"shoulder"},
{"id":"d1089","front":"How would you describe a type IV SLAP tear?","find":"Bucket-handle tear of the superior labrum with longitudinal extension into the long head of the biceps tendon, demonstrating an intrasubstance split of the biceps with a displaced labral fragment. The biceps anchor is variably involved.","impr":"Type IV SLAP — bucket-handle superior labral tear extending into the biceps tendon.","pearl":"Type IV = type III plus a longitudinal split propagating into the long head of the biceps.","topic":"SLAP / labrum","joint":"shoulder"},
{"id":"d1090","front":"How would you describe a type V SLAP tear?","find":"Type II superior labral detachment of the biceps anchor that extends inferiorly and is contiguous with an anteroinferior labral (Bankart) tear, producing a continuous tear from the superior to the anteroinferior glenoid.","impr":"Type V SLAP — type II superior labral tear continuous with an anteroinferior (Bankart) lesion.","pearl":"A Maffet extension; look for associated Hill-Sachs and glenoid bone loss since it overlaps anterior instability.","topic":"SLAP / labrum","joint":"shoulder"},
{"id":"d1091","front":"How would you describe a type VI SLAP tear?","find":"Unstable displaced labral flap arising from the superior labrum ([anterior/posterior]) with associated separation/detachment of the biceps-labral anchor from the supraglenoid tubercle. The flap is mobile.","impr":"Type VI SLAP — unstable superior labral flap tear with separation of the biceps anchor.","pearl":"Maffet type VI = an unstable flap component plus biceps-anchor separation.","topic":"SLAP / labrum","joint":"shoulder"}
]);
